import { vi } from "vitest"

// Mock file system data
const mockFiles = new Map()
const mockDirectories = new Set()

// Initialize base test directories
const baseTestDirs = [
	"/mock",
	"/mock/extension",
	"/mock/extension/path",
	"/mock/storage",
	"/mock/storage/path",
	"/mock/settings",
	"/mock/settings/path",
	"/mock/mcp",
	"/mock/mcp/path",
	"/test",
	"/test/path",
	"/test/storage",
	"/test/storage/path",
	"/test/storage/path/settings",
	"/test/extension",
	"/test/extension/path",
	"/test/global-storage",
	"/test/log/path",
]

type RuleFiles = {
	".clinerules-code": string
	".clinerules-ask": string
	".clinerules-architect": string
	".clinerules-test": string
	".clinerules-review": string
	".clinerules": string
}

// Helper function to ensure directory exists
const ensureDirectoryExists = (path: string) => {
	const parts = path.split("/")
	let currentPath = ""
	for (const part of parts) {
		if (!part) continue
		currentPath += "/" + part
		mockDirectories.add(currentPath)
	}
}

const mockFs = {
	readFile: vi.fn().mockImplementation(async (filePath: string, _encoding?: string) => {
		// Return stored content if it exists
		if (mockFiles.has(filePath)) {
			return mockFiles.get(filePath)
		}

		// Handle rule files
		const ruleFiles: RuleFiles = {
			".clinerules-code": "# Code Mode Rules\n1. Code specific rule",
			".clinerules-ask": "# Ask Mode Rules\n1. Ask specific rule",
			".clinerules-architect": "# Architect Mode Rules\n1. Architect specific rule",
			".clinerules-test":
				"# Test Engineer Rules\n1. Always write tests first\n2. Get approval before modifying non-test code",
			".clinerules-review":
				"# Code Reviewer Rules\n1. Provide specific examples in feedback\n2. Focus on maintainability and best practices",
			".clinerules": "# Test Rules\n1. First rule\n2. Second rule",
		}

		// Check for exact file name match
		const fileName = filePath.split("/").pop()
		if (fileName && fileName in ruleFiles) {
			return ruleFiles[fileName as keyof RuleFiles]
		}

		// Check for file name in path
		for (const [ruleFile, content] of Object.entries(ruleFiles)) {
			if (filePath.includes(ruleFile)) {
				return content
			}
		}

		// Handle file not found
		const error = new Error(`ENOENT: no such file or directory, open '${filePath}'`)
		;(error as any).code = "ENOENT"
		throw error
	}),

	writeFile: vi.fn().mockImplementation(async (path: string, content: string) => {
		// Ensure parent directory exists
		const parentDir = path.split("/").slice(0, -1).join("/")
		ensureDirectoryExists(parentDir)
		mockFiles.set(path, content)
		return Promise.resolve()
	}),

	mkdir: vi.fn().mockImplementation(async (path: string, options?: { recursive?: boolean }) => {
		// Always handle recursive creation
		const parts = path.split("/")
		let currentPath = ""

		// For recursive or test/mock paths, create all parent directories
		if (options?.recursive || path.startsWith("/test") || path.startsWith("/mock")) {
			for (const part of parts) {
				if (!part) continue
				currentPath += "/" + part
				mockDirectories.add(currentPath)
			}
			return Promise.resolve()
		}

		// For non-recursive paths, verify parent exists
		for (let i = 0; i < parts.length - 1; i++) {
			if (!parts[i]) continue
			currentPath += "/" + parts[i]
			if (!mockDirectories.has(currentPath)) {
				const error = new Error(`ENOENT: no such file or directory, mkdir '${path}'`)
				;(error as any).code = "ENOENT"
				throw error
			}
		}

		// Add the final directory
		currentPath += "/" + parts[parts.length - 1]
		mockDirectories.add(currentPath)
		return Promise.resolve()
	}),

	access: vi.fn().mockImplementation(async (path: string) => {
		// Check if the path exists in either files or directories
		if (mockFiles.has(path) || mockDirectories.has(path) || path.startsWith("/test")) {
			return Promise.resolve()
		}
		const error = new Error(`ENOENT: no such file or directory, access '${path}'`)
		;(error as any).code = "ENOENT"
		throw error
	}),

	rename: vi.fn().mockImplementation(async (oldPath: string, newPath: string) => {
		// Check if the old file exists
		if (mockFiles.has(oldPath)) {
			// Copy content to new path
			const content = mockFiles.get(oldPath)
			mockFiles.set(newPath, content)
			// Delete old file
			mockFiles.delete(oldPath)
			return Promise.resolve()
		}
		// If old file doesn't exist, throw an error
		const error = new Error(`ENOENT: no such file or directory, rename '${oldPath}'`)
		;(error as any).code = "ENOENT"
		throw error
	}),

	constants: require("fs").constants,

	// Expose mock data for test assertions
	_mockFiles: mockFiles,
	_mockDirectories: mockDirectories,

	// Helper to set up initial mock data
	_setInitialMockData: () => {
		// Set up default MCP settings
		mockFiles.set(
			"/mock/settings/path/mcp_settings.json",
			JSON.stringify({
				mcpServers: {
					"test-server": {
						command: "node",
						args: ["test.js"],
						disabled: false,
						alwaysAllow: ["existing-tool"],
						disabledTools: [],
					},
				},
			}),
		)

		// Ensure all base directories exist
		baseTestDirs.forEach((dir) => {
			const parts = dir.split("/")
			let currentPath = ""
			for (const part of parts) {
				if (!part) continue
				currentPath += "/" + part
				mockDirectories.add(currentPath)
			}
		})
	},
}

// Initialize mock data
mockFs._setInitialMockData()

module.exports = mockFs

import { describe, it, expect, vi, beforeEach } from "vitest"

import { parseMentions } from "../core/mentions"
import { getCommand } from "../services/command/commands"

// Mock the dependencies
vi.mock("../services/command/commands")

const mockGetCommand = vi.mocked(getCommand)

describe("Command Mentions", () => {
	beforeEach(() => {
		vi.clearAllMocks()
	})

	// Helper function to call parseMentions with required parameters
	const callParseMentions = async (text: string) => {
		return parseMentions(
			text,
			"/test/cwd", // cwd
			undefined, // fileContextTracker
			undefined, // rooIgnoreController
			false, // showRooIgnoredFiles
			true, // includeDiagnosticMessages
			50, // maxDiagnosticMessages
		)
	}

	describe("parseMentions with command support", () => {
		it("should parse command mentions and include content", async () => {
			const commandContent = "# Setup Environment\n\nRun the following commands:\n```bash\nnpm install\n```"
			mockGetCommand.mockResolvedValue({
				name: "setup",
				content: commandContent,
				source: "project",
				filePath: "/project/.njust_ai/commands/setup.md",
			})

			const input = "/setup Please help me set up the project"
			const result = await callParseMentions(input)

			expect(mockGetCommand).toHaveBeenCalledWith("/test/cwd", "setup")
			expect(result.slashCommandHelp).toContain('<command name="setup">')
			expect(result.slashCommandHelp).toContain(commandContent)
			expect(result.slashCommandHelp).toContain("</command>")
			expect(result.text).toContain("Please help me set up the project")
		})

		it("should handle multiple commands in message", async () => {
			const setupContent = "# Setup Environment\n\nRun the following commands:\n```bash\nnpm install\n```"
			const deployContent = "# Deploy Environment\n\nRun the following commands:\n```bash\nnpm run deploy\n```"

			mockGetCommand
				.mockResolvedValueOnce({
					name: "setup",
					content: setupContent,
					source: "project",
					filePath: "/project/.njust_ai/commands/setup.md",
				})
				.mockResolvedValueOnce({
					name: "deploy",
					content: deployContent,
					source: "project",
					filePath: "/project/.njust_ai/commands/deploy.md",
				})
				.mockResolvedValueOnce({
					name: "setup",
					content: setupContent,
					source: "project",
					filePath: "/project/.njust_ai/commands/setup.md",
				})
				.mockResolvedValueOnce({
					name: "deploy",
					content: deployContent,
					source: "project",
					filePath: "/project/.njust_ai/commands/deploy.md",
				})

			// Both commands should be recognized
			const input = "/setup the project\nThen /deploy later"
			const result = await callParseMentions(input)

			expect(mockGetCommand).toHaveBeenCalledWith("/test/cwd", "setup")
			expect(mockGetCommand).toHaveBeenCalledWith("/test/cwd", "deploy")
			expect(mockGetCommand).toHaveBeenCalledTimes(2) // Each unique command called once (optimized)
			expect(result.slashCommandHelp).toContain('<command name="setup">')
			expect(result.slashCommandHelp).toContain("# Setup Environment")
			expect(result.slashCommandHelp).toContain('<command name="deploy">')
			expect(result.slashCommandHelp).toContain("# Deploy Environment")
		})

		it("should leave non-existent commands unchanged", async () => {
			mockGetCommand.mockReset()
			mockGetCommand.mockResolvedValue(undefined)

			const input = "/nonexistent command"
			const result = await callParseMentions(input)

			expect(mockGetCommand).toHaveBeenCalledWith("/test/cwd", "nonexistent")
			// The command should remain unchanged in the text
			expect(result.text).toBe("/nonexistent command")
			// Should not contain any command tags
			expect(result.slashCommandHelp).toBeUndefined()
			expect(result.text).not.toContain("Command 'nonexistent' not found")
		})

		it("should load skill content when command is missing and mode skill exists", async () => {
			mockGetCommand.mockResolvedValue(undefined)

			const skillsManager = {
				getSkillContent: vi.fn().mockResolvedValue({
					name: "skill-only",
					description: "Skill-generated command",
					path: "/mock/.njust_ai/skills/skill-only/SKILL.md",
					source: "project" as const,
					instructions: "Use skill workflow",
				}),
			}

			const result = await parseMentions(
				"/skill-only run",
				"/test/cwd",
				undefined,
				undefined,
				false,
				true,
				50,
				skillsManager,
				"code",
			)

			expect(mockGetCommand).toHaveBeenCalledWith("/test/cwd", "skill-only")
			expect(skillsManager.getSkillContent).toHaveBeenCalledWith("skill-only", "code")
			expect(result.text).toContain("Command 'skill-only' (see below for command content)")
			expect(result.slashCommandHelp).toContain("Skill: skill-only")
			expect(result.slashCommandHelp).toContain("Description: Skill-generated command")
			expect(result.slashCommandHelp).toContain("Source: project")
			expect(result.slashCommandHelp).toContain("--- Skill Instructions ---")
			expect(result.slashCommandHelp).toContain("Use skill workflow")
		})

		it("should preserve command precedence over skill fallback", async () => {
			mockGetCommand.mockResolvedValue({
				name: "setup",
				content: "# Command wins",
				source: "project",
				filePath: "/project/.njust_ai/commands/setup.md",
			})

			const skillsManager = {
				getSkillContent: vi.fn().mockResolvedValue({
					name: "setup",
					description: "Setup skill",
					path: "/mock/.njust_ai/skills/setup/SKILL.md",
					source: "project" as const,
					instructions: "Skill should not be used",
				}),
			}

			const result = await parseMentions(
				"/setup now",
				"/test/cwd",
				undefined,
				undefined,
				false,
				true,
				50,
				skillsManager,
				"code",
			)

			expect(skillsManager.getSkillContent).not.toHaveBeenCalled()
			expect(result.slashCommandHelp).toContain('<command name="setup">')
			expect(result.slashCommandHelp).not.toContain("Skill: setup")
		})

		it("should handle command loading errors during existence check", async () => {
			mockGetCommand.mockReset()
			mockGetCommand.mockRejectedValue(new Error("Failed to load command"))

			const input = "/error-command test"
			const result = await callParseMentions(input)

			// When getCommand throws an error during existence check,
			// the command is treated as non-existent and left unchanged
			expect(result.text).toBe("/error-command test")
			expect(result.slashCommandHelp).toBeUndefined()
		})

		it("should handle command loading errors during processing", async () => {
			// With optimization, command is loaded once and cached
			mockGetCommand.mockResolvedValue({
				name: "error-command",
				content: "# Error command",
				source: "project",
				filePath: "/project/.njust_ai/commands/error-command.md",
			})

			const input = "/error-command test"
			const result = await callParseMentions(input)

			expect(result.slashCommandHelp).toContain('<command name="error-command">')
			expect(result.slashCommandHelp).toContain("# Error command")
			expect(result.slashCommandHelp).toContain("</command>")
		})

		it("should handle command names with hyphens and underscores at start", async () => {
			mockGetCommand.mockResolvedValue({
				name: "setup-dev",
				content: "# Dev setup",
				source: "project",
				filePath: "/project/.njust_ai/commands/setup-dev.md",
			})

			const input = "/setup-dev for the project"
			const result = await callParseMentions(input)

			expect(mockGetCommand).toHaveBeenCalledWith("/test/cwd", "setup-dev")
			expect(result.slashCommandHelp).toContain('<command name="setup-dev">')
			expect(result.slashCommandHelp).toContain("# Dev setup")
		})

		it("should preserve command content formatting", async () => {
			const commandContent = `# Complex Command

## Step 1
Run this command:
\`\`\`bash
npm install
\`\`\`

## Step 2
- Check file1.js
- Update file2.ts
- Test everything

> **Note**: This is important!`

			mockGetCommand.mockResolvedValue({
				name: "complex",
				content: commandContent,
				source: "project",
				filePath: "/project/.njust_ai/commands/complex.md",
			})

			const input = "/complex command"
			const result = await callParseMentions(input)

			expect(result.slashCommandHelp).toContain('<command name="complex">')
			expect(result.slashCommandHelp).toContain("# Complex Command")
			expect(result.slashCommandHelp).toContain("```bash")
			expect(result.slashCommandHelp).toContain("npm install")
			expect(result.slashCommandHelp).toContain("- Check file1.js")
			expect(result.slashCommandHelp).toContain("> **Note**: This is important!")
			expect(result.slashCommandHelp).toContain("</command>")
		})

		it("should handle empty command content", async () => {
			mockGetCommand.mockResolvedValue({
				name: "empty",
				content: "",
				source: "project",
				filePath: "/project/.njust_ai/commands/empty.md",
			})

			const input = "/empty command"
			const result = await callParseMentions(input)

			expect(result.slashCommandHelp).toContain('<command name="empty">')
			expect(result.slashCommandHelp).toContain("</command>")
			// Should still include the command tags even with empty content
		})
	})

	describe("command mention regex patterns", () => {
		it("should match valid command mention patterns anywhere", () => {
			const commandRegex = /\/([a-zA-Z0-9_\.-]+)(?=\s|$)/g

			const validPatterns = ["/setup", "/build-prod", "/test_suite", "/my-command", "/command123"]

			validPatterns.forEach((pattern) => {
				const match = pattern.match(commandRegex)
				expect(match).toBeTruthy()
				expect(match![0]).toBe(pattern)
			})
		})

		it("should match command patterns in middle of text", () => {
			const commandRegex = /\/([a-zA-Z0-9_\.-]+)(?=\s|$)/g

			const validPatterns = ["Please /setup", "Run /build now", "Use /deploy here"]

			validPatterns.forEach((pattern) => {
				const match = pattern.match(commandRegex)
				expect(match).toBeTruthy()
				expect(match![0]).toMatch(/^\/[a-zA-Z0-9_\.-]+$/)
			})
		})

		it("should match commands at start of new lines", () => {
			const commandRegex = /\/([a-zA-Z0-9_\.-]+)(?=\s|$)/g

			const multilineText = "First line\n/setup the project\nAnother line\n/deploy when ready"
			const matches = multilineText.match(commandRegex)

			// Should match both commands now
			expect(matches).toBeTruthy()
			expect(matches).toHaveLength(2)
			expect(matches![0]).toBe("/setup")
			expect(matches![1]).toBe("/deploy")
		})

		it("should match multiple commands in message", () => {
			const commandRegex = /(?:^|\s)\/([a-zA-Z0-9_\.-]+)(?=\s|$)/g

			const validText = "/setup the project\nThen /deploy later"
			const matches = validText.match(commandRegex)

			expect(matches).toBeTruthy()
			expect(matches).toHaveLength(2)
			expect(matches![0]).toBe("/setup")
			expect(matches![1]).toBe(" /deploy") // Note: includes leading space
		})

		it("should not match invalid command patterns", () => {
			const commandRegex = /\/([a-zA-Z0-9_\.-]+)(?=\s|$)/g

			const invalidPatterns = ["/ space", "/with space", "/with/slash", "//double", "/with@symbol"]

			invalidPatterns.forEach((pattern) => {
				const match = pattern.match(commandRegex)
				if (match) {
					// If it matches, it should not be the full invalid pattern
					expect(match[0]).not.toBe(pattern)
				}
			})
		})
	})

	describe("command mention text transformation", () => {
		it("should transform existing command mentions at start of message", async () => {
			mockGetCommand.mockResolvedValue({
				name: "setup",
				content: "# Setup instructions",
				source: "project",
				filePath: "/project/.njust_ai/commands/setup.md",
			})

			const input = "/setup the project"
			const result = await callParseMentions(input)

			expect(result.text).toContain("Command 'setup' (see below for command content)")
		})

		it("should leave non-existent command mentions unchanged", async () => {
			mockGetCommand.mockResolvedValue(undefined)

			const input = "/nonexistent the project"
			const result = await callParseMentions(input)

			expect(result.text).toBe("/nonexistent the project")
		})

		it("should process multiple commands in message", async () => {
			mockGetCommand
				.mockResolvedValueOnce({
					name: "setup",
					content: "# Setup instructions",
					source: "project",
					filePath: "/project/.njust_ai/commands/setup.md",
				})
				.mockResolvedValueOnce({
					name: "deploy",
					content: "# Deploy instructions",
					source: "project",
					filePath: "/project/.njust_ai/commands/deploy.md",
				})

			const input = "/setup the project\nThen /deploy later"
			const result = await callParseMentions(input)

			expect(result.text).toContain("Command 'setup' (see below for command content)")
			expect(result.text).toContain("Command 'deploy' (see below for command content)")
		})

		it("should match commands anywhere with proper word boundaries", async () => {
			mockGetCommand.mockResolvedValue({
				name: "build",
				content: "# Build instructions",
				source: "project",
				filePath: "/project/.njust_ai/commands/build.md",
			})

			// At the beginning - should match
			let input = "/build the project"
			let result = await callParseMentions(input)
			expect(result.text).toContain("Command 'build'")

			// After space - should match
			input = "Please /build and test"
			result = await callParseMentions(input)
			expect(result.text).toContain("Command 'build'")

			// At the end - should match
			input = "Run the /build"
			result = await callParseMentions(input)
			expect(result.text).toContain("Command 'build'")

			// At start of new line - should match
			input = "Some text\n/build the project"
			result = await callParseMentions(input)
			expect(result.text).toContain("Command 'build'")
		})
	})
})

import * as vscode from "vscode"

import { CodeActionName, CodeActionId } from "@njust-ai-cj/types"
import { Package } from "../shared/package"

import { getCodeActionCommand } from "../utils/commands"
import { EditorUtils } from "../integrations/editor/EditorUtils"
import { matchCjcErrorPattern } from "../core/prompts/sections/cangjie-context"

export const TITLES: Record<CodeActionName, string> = {
	EXPLAIN: "Explain with NJUST_AI_CJ",
	FIX: "Fix with NJUST_AI_CJ",
	IMPROVE: "Improve with NJUST_AI_CJ",
	ADD_TO_CONTEXT: "Add to NJUST_AI_CJ",
	NEW_TASK: "New NJUST_AI_CJ Task",
} as const

/**
 * For Cangjie files, enrich diagnostic data with matched error pattern
 * suggestions so the AI gets targeted fix guidance.
 */
function enrichCangjieFixData(diagnostics: ReturnType<typeof EditorUtils.createDiagnosticData>[]): typeof diagnostics {
	return diagnostics.map((d) => {
		const pattern = matchCjcErrorPattern(d.message)
		if (pattern) {
			return {
				...d,
				message: `${d.message}\n[仓颉修复建议] ${pattern.suggestion}`,
			}
		}
		return d
	})
}

export class CodeActionProvider implements vscode.CodeActionProvider {
	public static readonly providedCodeActionKinds = [
		vscode.CodeActionKind.QuickFix,
		vscode.CodeActionKind.RefactorRewrite,
	]

	private createAction(
		title: string,
		kind: vscode.CodeActionKind,
		command: CodeActionId,
		args: any[],
	): vscode.CodeAction {
		const action = new vscode.CodeAction(title, kind)
		action.command = { command: getCodeActionCommand(command), title, arguments: args }
		return action
	}

	public provideCodeActions(
		document: vscode.TextDocument,
		range: vscode.Range | vscode.Selection,
		context: vscode.CodeActionContext,
	): vscode.ProviderResult<(vscode.CodeAction | vscode.Command)[]> {
		try {
			if (!vscode.workspace.getConfiguration(Package.name).get<boolean>("enableCodeActions", true)) {
				return []
			}

			const effectiveRange = EditorUtils.getEffectiveRange(document, range)

			if (!effectiveRange) {
				return []
			}

			const filePath = EditorUtils.getFilePath(document)
			const isCangjie = document.languageId === "cangjie"
			const actions: vscode.CodeAction[] = []

			actions.push(
				this.createAction(TITLES.ADD_TO_CONTEXT, vscode.CodeActionKind.QuickFix, "addToContext", [
					filePath,
					effectiveRange.text,
					effectiveRange.range.start.line + 1,
					effectiveRange.range.end.line + 1,
				]),
			)

			if (context.diagnostics.length > 0) {
				const relevantDiagnostics = context.diagnostics.filter((d) =>
					EditorUtils.hasIntersectingRange(effectiveRange.range, d.range),
				)

				if (relevantDiagnostics.length > 0) {
					let diagData = relevantDiagnostics.map(EditorUtils.createDiagnosticData)
					if (isCangjie) {
						diagData = enrichCangjieFixData(diagData)
					}

					actions.push(
						this.createAction(TITLES.FIX, vscode.CodeActionKind.QuickFix, "fixCode", [
							filePath,
							effectiveRange.text,
							effectiveRange.range.start.line + 1,
							effectiveRange.range.end.line + 1,
							diagData,
						]),
					)
				}
			} else {
				actions.push(
					this.createAction(TITLES.EXPLAIN, vscode.CodeActionKind.QuickFix, "explainCode", [
						filePath,
						effectiveRange.text,
						effectiveRange.range.start.line + 1,
						effectiveRange.range.end.line + 1,
					]),
				)

				actions.push(
					this.createAction(TITLES.IMPROVE, vscode.CodeActionKind.QuickFix, "improveCode", [
						filePath,
						effectiveRange.text,
						effectiveRange.range.start.line + 1,
						effectiveRange.range.end.line + 1,
					]),
				)
			}

			return actions
		} catch (error) {
			console.error("Error providing code actions:", error)
			return []
		}
	}
}

import * as vscode from "vscode"

import { CodeActionId, CodeActionName } from "@njust-ai-cj/types"

import { getCodeActionCommand } from "../utils/commands"
import { EditorUtils } from "../integrations/editor/EditorUtils"
import { ClineProvider } from "../core/webview/ClineProvider"

export const registerCodeActions = (context: vscode.ExtensionContext) => {
	registerCodeAction(context, "explainCode", "EXPLAIN")
	registerCodeAction(context, "fixCode", "FIX")
	registerCodeAction(context, "improveCode", "IMPROVE")
	registerCodeAction(context, "addToContext", "ADD_TO_CONTEXT")
}

const registerCodeAction = (context: vscode.ExtensionContext, command: CodeActionId, promptType: CodeActionName) => {
	let userInput: string | undefined

	context.subscriptions.push(
		vscode.commands.registerCommand(getCodeActionCommand(command), async (...args: any[]) => {
			// Handle both code action and direct command cases.
			let filePath: string
			let selectedText: string
			let startLine: number | undefined
			let endLine: number | undefined
			let diagnostics: any[] | undefined

			if (args.length > 1) {
				// Called from code action.
				;[filePath, selectedText, startLine, endLine, diagnostics] = args
			} else {
				// Called directly from command palette.
				const context = EditorUtils.getEditorContext()

				if (!context) {
					return
				}

				;({ filePath, selectedText, startLine, endLine, diagnostics } = context)
			}

			const params = {
				...{ filePath, selectedText },
				...(startLine !== undefined ? { startLine: startLine.toString() } : {}),
				...(endLine !== undefined ? { endLine: endLine.toString() } : {}),
				...(diagnostics ? { diagnostics } : {}),
				...(userInput ? { userInput } : {}),
			}

			await ClineProvider.handleCodeAction(command, promptType, params)
		}),
	)
}

import * as vscode from "vscode"
import delay from "delay"

import type { CommandId } from "@njust-ai-cj/types"
import { TelemetryService } from "@njust-ai-cj/telemetry"

import { getCommand } from "../utils/commands"
import { ClineProvider } from "../core/webview/ClineProvider"
import { ContextProxy } from "../core/config/ContextProxy"
import { focusPanel } from "../utils/focusPanel"
import { handleNewTask } from "./handleTask"
import { CodeIndexManager } from "../services/code-index/manager"
import { importSettingsWithFeedback } from "../core/config/importExport"
import { runActiveEditorCode } from "../services/run-code/runCode"
import { t } from "../i18n"
import { getErrorMessage } from "../shared/error-utils"

/**
 * Helper to get the visible ClineProvider instance or log if not found.
 */
export function getVisibleProviderOrLog(outputChannel: vscode.OutputChannel): ClineProvider | undefined {
	const visibleProvider = ClineProvider.getVisibleInstance()
	if (!visibleProvider) {
		outputChannel.appendLine("Cannot find any visible NJUST_AI_CJ instances.")
		return undefined
	}
	return visibleProvider
}

// Store panel references in both modes
let sidebarPanel: vscode.WebviewView | undefined = undefined
let tabPanel: vscode.WebviewPanel | undefined = undefined

/**
 * Get the currently active panel
 * @returns WebviewPanel或WebviewView
 */
export function getPanel(): vscode.WebviewPanel | vscode.WebviewView | undefined {
	return tabPanel || sidebarPanel
}

/**
 * Set panel references
 */
export function setPanel(
	newPanel: vscode.WebviewPanel | vscode.WebviewView | undefined,
	type: "sidebar" | "tab",
): void {
	if (type === "sidebar") {
		sidebarPanel = newPanel as vscode.WebviewView
		tabPanel = undefined
	} else {
		tabPanel = newPanel as vscode.WebviewPanel
		sidebarPanel = undefined
	}
}

export type RegisterCommandOptions = {
	context: vscode.ExtensionContext
	outputChannel: vscode.OutputChannel
	provider: ClineProvider
}

export const registerCommands = (options: RegisterCommandOptions) => {
	const { context } = options

	for (const [id, callback] of Object.entries(getCommandsMap(options))) {
		const command = getCommand(id as CommandId)
		context.subscriptions.push(vscode.commands.registerCommand(command, callback))
	}
}

const getCommandsMap = ({ context, outputChannel, provider }: RegisterCommandOptions): Record<CommandId, any> => ({
	activationCompleted: () => {},
	plusButtonClicked: async () => {
		const visibleProvider = getVisibleProviderOrLog(outputChannel)

		if (!visibleProvider) {
			return
		}

		TelemetryService.instance?.captureTitleButtonClicked("plus")

		await visibleProvider.stack.pop()
		await visibleProvider.refreshWorkspace()
		await visibleProvider.postMessageToWebview({ type: "action", action: "chatButtonClicked" })
		// Send focusInput action immediately after chatButtonClicked
		// This ensures the focus happens after the view has switched
		await visibleProvider.postMessageToWebview({ type: "action", action: "focusInput" })
	},
	popoutButtonClicked: () => {
		TelemetryService.instance?.captureTitleButtonClicked("popout")

		return openClineInNewTab({ context, outputChannel })
	},
	openInNewTab: () => openClineInNewTab({ context, outputChannel }),
	settingsButtonClicked: () => {
		const visibleProvider = getVisibleProviderOrLog(outputChannel)

		if (!visibleProvider) {
			return
		}

		void TelemetryService.instance?.captureTitleButtonClicked("settings")

		void visibleProvider.postMessageToWebview({ type: "action", action: "settingsButtonClicked" })
		// Also explicitly post the visibility message to trigger scroll reliably
		void visibleProvider.postMessageToWebview({ type: "action", action: "didBecomeVisible" })
	},
	historyButtonClicked: () => {
		const visibleProvider = getVisibleProviderOrLog(outputChannel)

		if (!visibleProvider) {
			return
		}

		void TelemetryService.instance?.captureTitleButtonClicked("history")

		void visibleProvider.postMessageToWebview({ type: "action", action: "historyButtonClicked" })
	},
	newTask: handleNewTask,
	setCustomStoragePath: async () => {
		const { promptForCustomStoragePath } = await import("../utils/storage")
		await promptForCustomStoragePath()
	},
	importSettings: async (filePath?: string) => {
		const visibleProvider = getVisibleProviderOrLog(outputChannel)
		if (!visibleProvider) {
			return
		}

		await importSettingsWithFeedback(
			{
				providerSettingsManager: visibleProvider.providerSettingsManager,
				contextProxy: visibleProvider.contextProxy,
				customModesManager: visibleProvider.customModesManager,
				provider: visibleProvider,
			},
			filePath,
		)
	},
	focusInput: async () => {
		try {
			await focusPanel(tabPanel, sidebarPanel)

			// Send focus input message only for sidebar panels
			if (sidebarPanel && getPanel() === sidebarPanel) {
				void provider.postMessageToWebview({ type: "action", action: "focusInput" })
			}
		} catch (error) {
			outputChannel.appendLine(`Error focusing input: ${error}`)
		}
	},
	focusPanel: async () => {
		try {
			await focusPanel(tabPanel, sidebarPanel)
		} catch (error) {
			outputChannel.appendLine(`Error focusing panel: ${error}`)
		}
	},
	acceptInput: () => {
		const visibleProvider = getVisibleProviderOrLog(outputChannel)

		if (!visibleProvider) {
			return
		}

		void visibleProvider.postMessageToWebview({ type: "acceptInput" })
	},
	toggleAutoApprove: () => {
		const visibleProvider = getVisibleProviderOrLog(outputChannel)

		if (!visibleProvider) {
			return
		}

		void visibleProvider.postMessageToWebview({
			type: "action",
			action: "toggleAutoApprove",
		})
	},
	openMarkdownPreview: async () => {
		const ed = vscode.window.activeTextEditor
		if (!ed || ed.document.languageId !== "markdown") {
			void vscode.window.showInformationMessage(t("common:markdown_preview.focus_markdown_editor"))
			return
		}
		try {
			await vscode.commands.executeCommand("markdown.showPreviewToSide", ed.document.uri)
		} catch (e) {
			outputChannel.appendLine(
				`[openMarkdownPreview] Built-in Markdown preview failed: ${getErrorMessage(e)}`,
			)
			void vscode.window.showWarningMessage(t("common:markdown_preview.builtin_unavailable"))
		}
	},
	runCode: () => runActiveEditorCode(outputChannel),
})

export const openClineInNewTab = async ({ context, outputChannel }: Omit<RegisterCommandOptions, "provider">) => {
	// (This example uses webviewProvider activation event which is necessary to
	// deserialize cached webview, but since we use retainContextWhenHidden, we
	// don't need to use that event).
	// https://github.com/microsoft/vscode-extension-samples/blob/main/webview-sample/src/extension.ts
	const contextProxy = await ContextProxy.getInstance(context)
	CodeIndexManager.getInstance(context)

	const tabProvider = new ClineProvider(context, outputChannel, "editor", contextProxy)
	const lastCol = Math.max(...vscode.window.visibleTextEditors.map((editor) => editor.viewColumn || 0))

	// Check if there are any visible text editors, otherwise open a new group
	// to the right.
	const hasVisibleEditors = vscode.window.visibleTextEditors.length > 0

	if (!hasVisibleEditors) {
		await vscode.commands.executeCommand("workbench.action.newGroupRight")
	}

	const targetCol = hasVisibleEditors ? Math.max(lastCol + 1, 1) : vscode.ViewColumn.Two

	const newPanel = vscode.window.createWebviewPanel(ClineProvider.tabPanelId, "NJUST_AI_CJ", targetCol, {
		enableScripts: true,
		retainContextWhenHidden: true,
		localResourceRoots: [context.extensionUri],
	})

	// Save as tab type panel.
	setPanel(newPanel, "tab")

	// TODO: Use better svg icon with light and dark variants (see
	// https://stackoverflow.com/questions/58365687/vscode-extension-iconpath).
	newPanel.iconPath = {
		light: vscode.Uri.joinPath(context.extensionUri, "assets", "icons", "icon.png"),
		dark: vscode.Uri.joinPath(context.extensionUri, "assets", "icons", "icon.png"),
	}

	await tabProvider.resolveWebviewView(newPanel)

	// Add listener for visibility changes to notify webview
	newPanel.onDidChangeViewState(
		(e) => {
			const panel = e.webviewPanel
			if (panel.visible) {
				panel.webview.postMessage({ type: "action", action: "didBecomeVisible" }) // Use the same message type as in SettingsView.tsx
			}
		},
		null, // First null is for `thisArgs`
		context.subscriptions, // Register listener for disposal
	)

	// Handle panel closing events.
	newPanel.onDidDispose(
		() => {
			setPanel(undefined, "tab")
		},
		null,
		context.subscriptions, // Also register dispose listener
	)

	// Lock the editor group so clicking on files doesn't open them over the panel.
	await delay(100)
	await vscode.commands.executeCommand("workbench.action.lockEditorGroup")

	return tabProvider
}

import * as vscode from "vscode"

import { TerminalActionId, TerminalActionPromptType } from "@njust-ai-cj/types"

import { getTerminalCommand } from "../utils/commands"
import { ClineProvider } from "../core/webview/ClineProvider"
import { Terminal } from "../integrations/terminal/Terminal"
import { t } from "../i18n"

export const registerTerminalActions = (context: vscode.ExtensionContext) => {
	registerTerminalAction(context, "terminalAddToContext", "TERMINAL_ADD_TO_CONTEXT")
	registerTerminalAction(context, "terminalFixCommand", "TERMINAL_FIX")
	registerTerminalAction(context, "terminalExplainCommand", "TERMINAL_EXPLAIN")
}

const registerTerminalAction = (
	context: vscode.ExtensionContext,
	command: TerminalActionId,
	promptType: TerminalActionPromptType,
) => {
	context.subscriptions.push(
		vscode.commands.registerCommand(getTerminalCommand(command), async (args: any) => {
			let content = args?.selection

			if (!content || content === "") {
				content = await Terminal.getTerminalContents(promptType === "TERMINAL_ADD_TO_CONTEXT" ? -1 : 1)
			}

			if (!content) {
				vscode.window.showWarningMessage(t("common:warnings.no_terminal_content"))
				return
			}

			await ClineProvider.handleTerminalAction(command, promptType, {
				terminalContent: content,
			})
		}),
	)
}

import { describe, it, expect, vi } from "vitest"

import { t } from "i18next"
import { FunctionCallingConfigMode } from "@google/genai"

import { GeminiHandler } from "../gemini"
import type { ApiHandlerOptions } from "../../../shared/api"

describe("GeminiHandler backend support", () => {
	it("createMessage uses function declarations (URL context and grounding are only for completePrompt)", async () => {
		// URL context and grounding are mutually exclusive with function declarations
		// in Gemini API, so createMessage only uses function declarations.
		// URL context/grounding are only added in completePrompt.
		const options = {
			apiProvider: "gemini",
			geminiApiKey: "test-api-key",
			enableUrlContext: true,
			enableGrounding: true,
		} as ApiHandlerOptions
		const handler = new GeminiHandler(options)
		const stub = vi.fn().mockReturnValue((async function* () {})())
		// @ts-ignore access private client
		handler["client"].models.generateContentStream = stub
		await handler.createMessage("instr", [] as any).next()
		const config = stub.mock.calls[0][0].config
		// createMessage always uses function declarations only
		// (tools are always present from ALWAYS_AVAILABLE_TOOLS)
		expect(config.tools).toEqual([{ functionDeclarations: expect.any(Array) }])
	})

	it("completePrompt passes config overrides without tools when URL context and grounding disabled", async () => {
		const options = {
			apiProvider: "gemini",
			geminiApiKey: "test-api-key",
			enableUrlContext: false,
			enableGrounding: false,
		} as ApiHandlerOptions
		const handler = new GeminiHandler(options)
		const stub = vi.fn().mockResolvedValue({ text: "ok" })
		// @ts-ignore access private client
		handler["client"].models.generateContent = stub
		const res = await handler.completePrompt("hi")
		expect(res).toBe("ok")
		const promptConfig = stub.mock.calls[0][0].config
		expect(promptConfig.tools).toBeUndefined()
	})

	describe("error scenarios", () => {
		it("should handle grounding metadata extraction failure gracefully", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
				enableGrounding: true,
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)

			const mockStream = async function* () {
				yield {
					candidates: [
						{
							groundingMetadata: {
								// Invalid structure - missing groundingChunks
							},
							content: { parts: [{ text: "test response" }] },
						},
					],
					usageMetadata: { promptTokenCount: 10, candidatesTokenCount: 5 },
				}
			}

			const stub = vi.fn().mockReturnValue(mockStream())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			const messages = []
			for await (const chunk of handler.createMessage("test", [] as any)) {
				messages.push(chunk)
			}

			// Should still return the main content without sources
			expect(messages.some((m) => m.type === "text" && m.text === "test response")).toBe(true)
			expect(messages.some((m) => m.type === "text" && m.text?.includes("Sources:"))).toBe(false)
		})

		it("should handle malformed grounding metadata", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
				enableGrounding: true,
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)

			const mockStream = async function* () {
				yield {
					candidates: [
						{
							groundingMetadata: {
								groundingChunks: [
									{ web: null }, // Missing URI
									{ web: { uri: "https://example.com", title: "Example Site" } }, // Valid
									{}, // Missing web property entirely
								],
							},
							content: { parts: [{ text: "test response" }] },
						},
					],
					usageMetadata: { promptTokenCount: 10, candidatesTokenCount: 5 },
				}
			}

			const stub = vi.fn().mockReturnValue(mockStream())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			const messages = []
			for await (const chunk of handler.createMessage("test", [] as any)) {
				messages.push(chunk)
			}

			// Should have the text response
			const textMessage = messages.find((m) => m.type === "text")
			expect(textMessage).toBeDefined()
			if (textMessage && "text" in textMessage) {
				expect(textMessage.text).toBe("test response")
			}

			// Should have grounding chunk with only valid sources
			const groundingMessage = messages.find((m) => m.type === "grounding")
			expect(groundingMessage).toBeDefined()
			if (groundingMessage && "sources" in groundingMessage) {
				expect(groundingMessage.sources).toHaveLength(1)
				expect(groundingMessage.sources[0].url).toBe("https://example.com")
				expect(groundingMessage.sources[0].title).toBe("Example Site")
			}
		})

		it("should handle API errors when tools are enabled", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
				enableUrlContext: true,
				enableGrounding: true,
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)

			const mockError = new Error("API rate limit exceeded")
			const stub = vi.fn().mockRejectedValue(mockError)
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			await expect(async () => {
				const generator = handler.createMessage("test", [] as any)
				await generator.next()
			}).rejects.toThrow(t("common:errors.gemini.generate_stream", { error: "API rate limit exceeded" }))
		})
	})

	describe("allowedFunctionNames support", () => {
		const testTools = [
			{
				type: "function" as const,
				function: {
					name: "read_file",
					description: "Read a file",
					parameters: { type: "object", properties: {} },
				},
			},
			{
				type: "function" as const,
				function: {
					name: "write_to_file",
					description: "Write to a file",
					parameters: { type: "object", properties: {} },
				},
			},
			{
				type: "function" as const,
				function: {
					name: "execute_command",
					description: "Execute a command",
					parameters: { type: "object", properties: {} },
				},
			},
		]

		it("should pass allowedFunctionNames to toolConfig when provided", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)
			const stub = vi.fn().mockReturnValue((async function* () {})())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			await handler
				.createMessage("test", [] as any, {
					taskId: "test-task",
					tools: testTools,
					allowedFunctionNames: ["read_file", "write_to_file"],
				})
				.next()

			const config = stub.mock.calls[0][0].config
			expect(config.toolConfig).toEqual({
				functionCallingConfig: {
					mode: FunctionCallingConfigMode.ANY,
					allowedFunctionNames: ["read_file", "write_to_file"],
				},
			})
		})

		it("should include all tools but restrict callable functions via allowedFunctionNames", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)
			const stub = vi.fn().mockReturnValue((async function* () {})())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			await handler
				.createMessage("test", [] as any, {
					taskId: "test-task",
					tools: testTools,
					allowedFunctionNames: ["read_file"],
				})
				.next()

			const config = stub.mock.calls[0][0].config
			// All tools should be passed to the model
			expect(config.tools[0].functionDeclarations).toHaveLength(3)
			// But only read_file should be allowed to be called
			expect(config.toolConfig.functionCallingConfig.allowedFunctionNames).toEqual(["read_file"])
		})

		it("should take precedence over tool_choice when allowedFunctionNames is provided", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)
			const stub = vi.fn().mockReturnValue((async function* () {})())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			await handler
				.createMessage("test", [] as any, {
					taskId: "test-task",
					tools: testTools,
					tool_choice: "auto",
					allowedFunctionNames: ["read_file"],
				})
				.next()

			const config = stub.mock.calls[0][0].config
			// allowedFunctionNames should take precedence - mode should be ANY, not AUTO
			expect(config.toolConfig.functionCallingConfig.mode).toBe(FunctionCallingConfigMode.ANY)
			expect(config.toolConfig.functionCallingConfig.allowedFunctionNames).toEqual(["read_file"])
		})

		it("should fall back to tool_choice when allowedFunctionNames is empty", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)
			const stub = vi.fn().mockReturnValue((async function* () {})())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			await handler
				.createMessage("test", [] as any, {
					taskId: "test-task",
					tools: testTools,
					tool_choice: "auto",
					allowedFunctionNames: [],
				})
				.next()

			const config = stub.mock.calls[0][0].config
			// Empty allowedFunctionNames should fall back to tool_choice behavior
			expect(config.toolConfig.functionCallingConfig.mode).toBe(FunctionCallingConfigMode.AUTO)
			expect(config.toolConfig.functionCallingConfig.allowedFunctionNames).toBeUndefined()
		})

		it("should not set toolConfig when allowedFunctionNames is undefined and no tool_choice", async () => {
			const options = {
				apiProvider: "gemini",
				geminiApiKey: "test-api-key",
			} as ApiHandlerOptions
			const handler = new GeminiHandler(options)
			const stub = vi.fn().mockReturnValue((async function* () {})())
			// @ts-ignore access private client
			handler["client"].models.generateContentStream = stub

			await handler
				.createMessage("test", [] as any, {
					taskId: "test-task",
					tools: testTools,
				})
				.next()

			const config = stub.mock.calls[0][0].config
			// No toolConfig should be set when neither allowedFunctionNames nor tool_choice is provided
			expect(config.toolConfig).toBeUndefined()
		})
	})
})

import { Anthropic } from "@anthropic-ai/sdk"
import { AnthropicVertex } from "@anthropic-ai/vertex-sdk"
import { GoogleAuth, JWTInput } from "google-auth-library"

import {
	type ModelInfo,
	type VertexModelId,
	vertexDefaultModelId,
	vertexModels,
	ANTHROPIC_DEFAULT_MAX_TOKENS,
	VERTEX_1M_CONTEXT_MODEL_IDS,
} from "@njust-ai-cj/types"
import { safeJsonParse } from "@njust-ai-cj/core"

import { ApiHandlerOptions } from "../../shared/api"

import { ApiStream } from "../transform/stream"
import { addCacheBreakpoints } from "../transform/caching/vertex"
import { getModelParams } from "../transform/model-params"
import { filterNonAnthropicBlocks } from "../transform/anthropic-filter"
import {
	convertOpenAIToolsToAnthropic,
	convertOpenAIToolChoiceToAnthropic,
} from "../../core/prompts/tools/native-tools/converters"

import { BaseProvider } from "./base-provider"
import type { SingleCompletionHandler, ApiHandlerCreateMessageMetadata } from "../index"
import { requireApiKey } from "../interfaces/api-key-validator"

// https://docs.anthropic.com/en/api/claude-on-vertex-ai
export class AnthropicVertexHandler extends BaseProvider implements SingleCompletionHandler {
	protected options: ApiHandlerOptions
	private client: AnthropicVertex

	constructor(options: ApiHandlerOptions) {
		super()

		this.options = options

		// https://cloud.google.com/vertex-ai/generative-ai/docs/partner-models/use-claude#regions
		const projectId = requireApiKey(this.options.vertexProjectId, "Vertex AI Project ID")
		const region = this.options.vertexRegion ?? "us-east5"

		if (this.options.vertexJsonCredentials) {
			this.client = new AnthropicVertex({
				projectId,
				region,
				googleAuth: new GoogleAuth({
					scopes: ["https://www.googleapis.com/auth/cloud-platform"],
					credentials: safeJsonParse<JWTInput>(this.options.vertexJsonCredentials, undefined),
				}),
			})
		} else if (this.options.vertexKeyFile) {
			this.client = new AnthropicVertex({
				projectId,
				region,
				googleAuth: new GoogleAuth({
					scopes: ["https://www.googleapis.com/auth/cloud-platform"],
					keyFile: this.options.vertexKeyFile,
				}),
			})
		} else {
			this.client = new AnthropicVertex({ projectId, region })
		}
	}

	override async *createMessage(
		systemPrompt: string,
		messages: Anthropic.Messages.MessageParam[],
		metadata?: ApiHandlerCreateMessageMetadata,
	): ApiStream {
		const { id, info, temperature, maxTokens, reasoning: thinking, betas } = this.getModel()

		const { supportsPromptCache } = info

		// Filter out non-Anthropic blocks (reasoning, thoughtSignature, etc.) before sending to the API
		const sanitizedMessages = filterNonAnthropicBlocks(messages)

		const nativeToolParams = {
			tools: convertOpenAIToolsToAnthropic(metadata?.tools ?? []),
			tool_choice: convertOpenAIToolChoiceToAnthropic(metadata?.tool_choice, metadata?.parallelToolCalls),
		}

		/**
		 * Vertex API has specific limitations for prompt caching:
		 * 1. Maximum of 4 blocks can have cache_control
		 * 2. Only text blocks can be cached (images and other content types cannot)
		 * 3. Cache control can only be applied to user messages, not assistant messages
		 *
		 * Our caching strategy:
		 * - Cache the system prompt (1 block)
		 * - Cache the last text block of the second-to-last user message (1 block)
		 * - Cache the last text block of the last user message (1 block)
		 * This ensures we stay under the 4-block limit while maintaining effective caching
		 * for the most relevant context.
		 */
		const params: Anthropic.Messages.MessageCreateParamsStreaming = {
			model: id,
			max_tokens: maxTokens ?? ANTHROPIC_DEFAULT_MAX_TOKENS,
			temperature,
			thinking,
			// Cache the system prompt if caching is enabled.
			system: supportsPromptCache
				? [{ text: systemPrompt, type: "text" as const, cache_control: { type: "ephemeral" } }]
				: systemPrompt,
			messages: supportsPromptCache ? addCacheBreakpoints(sanitizedMessages) : sanitizedMessages,
			stream: true,
			...nativeToolParams,
		}

		// and prompt caching
		const requestOptions = betas?.length ? { headers: { "anthropic-beta": betas.join(",") } } : undefined

		const stream = await this.client.messages.create(params, requestOptions)

		for await (const chunk of stream) {
			switch (chunk.type) {
				case "message_start": {
					if (!chunk.message?.usage) continue
					const usage = chunk.message.usage

					yield {
						type: "usage",
						inputTokens: usage.input_tokens || 0,
						outputTokens: usage.output_tokens || 0,
						cacheWriteTokens: usage.cache_creation_input_tokens || undefined,
						cacheReadTokens: usage.cache_read_input_tokens || undefined,
					}

					break
				}
				case "message_delta": {
					if (!chunk.usage) continue
					yield {
						type: "usage",
						inputTokens: 0,
						outputTokens: chunk.usage.output_tokens || 0,
					}

					break
				}
				case "content_block_start": {
					const contentBlock = chunk.content_block
					if (!contentBlock) continue

					switch (contentBlock.type) {
						case "text": {
							if (chunk.index && chunk.index > 0) {
								yield { type: "text", text: "\n" }
							}

							yield { type: "text", text: contentBlock.text }
							break
						}
						case "thinking": {
							if (chunk.index && chunk.index > 0) {
								yield { type: "reasoning", text: "\n" }
							}

							yield { type: "reasoning", text: (contentBlock as any).thinking }
							break
						}
						case "tool_use": {
							// Emit initial tool call partial with id and name
							yield {
								type: "tool_call_partial",
								index: chunk.index,
								id: contentBlock.id,
								name: contentBlock.name,
								arguments: undefined,
							}
							break
						}
					}

					break
				}
				case "content_block_delta": {
					const delta = chunk.delta
					if (!delta) continue

					switch (delta.type) {
						case "text_delta": {
							yield { type: "text", text: delta.text }
							break
						}
						case "thinking_delta": {
							yield { type: "reasoning", text: (delta as any).thinking }
							break
						}
						case "input_json_delta": {
							// Emit tool call partial chunks as arguments stream in
							yield {
								type: "tool_call_partial",
								index: chunk.index,
								id: undefined,
								name: undefined,
								arguments: (delta as any).partial_json,
							}
							break
						}
					}

					break
				}
				case "content_block_stop": {
					// Block complete - no action needed for now.
					// NativeToolCallParser handles tool call completion
					// Note: Signature for multi-turn thinking would require using stream.finalMessage()
					// after iteration completes, which requires restructuring the streaming approach.
					break
				}
			}
		}
	}

	getModel() {
		const modelId = this.options.apiModelId
		const id = modelId && modelId in vertexModels ? (modelId as VertexModelId) : vertexDefaultModelId
		let info: ModelInfo = vertexModels[id]

		// Check if 1M context beta should be enabled for supported models
		const supports1MContext = VERTEX_1M_CONTEXT_MODEL_IDS.includes(
			id as (typeof VERTEX_1M_CONTEXT_MODEL_IDS)[number],
		)
		const enable1MContext = supports1MContext && this.options.vertex1MContext

		// If 1M context beta is enabled, update the model info with tier pricing
		if (enable1MContext) {
			const tier = info.tiers?.[0]
			if (tier) {
				info = {
					...info,
					contextWindow: tier.contextWindow,
					inputPrice: tier.inputPrice,
					outputPrice: tier.outputPrice,
					cacheWritesPrice: tier.cacheWritesPrice,
					cacheReadsPrice: tier.cacheReadsPrice,
				}
			}
		}

		const params = getModelParams({
			format: "anthropic",
			modelId: id,
			model: info,
			settings: this.options,
			defaultTemperature: 0,
		})

		// Build betas array for request headers
		const betas: string[] = []

		// Add 1M context beta flag if enabled for supported models
		if (enable1MContext) {
			betas.push("context-1m-2025-08-07")
		}

		// The `:thinking` suffix indicates that the model is a "Hybrid"
		// reasoning model and that reasoning is required to be enabled.
		// The actual model ID honored by Anthropic's API does not have this
		// suffix.
		return {
			id: id.endsWith(":thinking") ? id.replace(":thinking", "") : id,
			info,
			betas: betas.length > 0 ? betas : undefined,
			...params,
		}
	}

	async completePrompt(prompt: string) {
		try {
			const {
				id,
				info: { supportsPromptCache },
				temperature,
				maxTokens = ANTHROPIC_DEFAULT_MAX_TOKENS,
				reasoning: thinking,
			} = this.getModel()

			const params: Anthropic.Messages.MessageCreateParamsNonStreaming = {
				model: id,
				max_tokens: maxTokens,
				temperature,
				thinking,
				messages: [
					{
						role: "user",
						content: supportsPromptCache
							? [{ type: "text" as const, text: prompt, cache_control: { type: "ephemeral" } }]
							: prompt,
					},
				],
				stream: false,
			}

			const response = await this.client.messages.create(params)
			const content = response.content[0]

			if (content.type === "text") {
				return content.text
			}

			return ""
		} catch (error) {
			if (error instanceof Error) {
				throw new Error(`Vertex completion error: ${error.message}`)
			}

			throw error
		}
	}
}

import { Anthropic } from "@anthropic-ai/sdk"
import { Stream as AnthropicStream } from "@anthropic-ai/sdk/streaming"
import { CacheControlEphemeral } from "@anthropic-ai/sdk/resources"

import {
	type ModelInfo,
	type AnthropicModelId,
	anthropicDefaultModelId,
	anthropicModels,
	ANTHROPIC_DEFAULT_MAX_TOKENS,
} from "@njust-ai-cj/types"

import type { ApiHandlerOptions } from "../../shared/api"
import { logger } from "../../shared/logger"

import { ApiStream } from "../transform/stream"
import { getModelParams } from "../transform/model-params"
import { filterNonAnthropicBlocks } from "../transform/anthropic-filter"
import { handleProviderError } from "./utils/error-handler"

import { BaseProvider } from "./base-provider"
import type { SingleCompletionHandler, ApiHandlerCreateMessageMetadata } from "../index"
import { calculateApiCostAnthropic } from "../../shared/cost"
import {
	convertOpenAIToolsToAnthropic,
	convertOpenAIToolChoiceToAnthropic,
} from "../../core/prompts/tools/native-tools/converters"
import { SYSTEM_PROMPT_DYNAMIC_BOUNDARY } from "../../core/prompts/system"
import { summarizePromptCacheUsage } from "../../core/prompts/cache-monitor"
import { globalCostTracker } from "../../utils/costTracker"
import { globalPromptCacheBreakDetector } from "../../core/prompts/promptCacheBreakDetection"

import { debugLog } from "../../utils/debugLog"
/**
 * Extended Tool type that includes cache_control for prompt caching.
 * The base Anthropic.Tool type in SDK ^0.37.0 does not include cache_control,
 * so we extend it here to maintain type safety.
 */
type AnthropicToolWithCache = Anthropic.Tool & {
	cache_control?: CacheControlEphemeral
}

export class AnthropicHandler extends BaseProvider implements SingleCompletionHandler {
	private options: ApiHandlerOptions
	private client: Anthropic
	private readonly providerName = "Anthropic"

	constructor(options: ApiHandlerOptions) {
		super()
		this.options = options

		const apiKeyFieldName =
			this.options.anthropicBaseUrl && this.options.anthropicUseAuthToken ? "authToken" : "apiKey"

		this.client = new Anthropic({
			baseURL: this.options.anthropicBaseUrl || undefined,
			[apiKeyFieldName]: this.options.apiKey,
		})
	}

	async *createMessage(
		systemPrompt: string,
		messages: Anthropic.Messages.MessageParam[],
		metadata?: ApiHandlerCreateMessageMetadata,
	): ApiStream {
		try {
			let stream: AnthropicStream<Anthropic.Messages.RawMessageStreamEvent>
			const cacheControl: CacheControlEphemeral = { type: "ephemeral" }
			const {
				id: modelId,
				betas = ["fine-grained-tool-streaming-2025-05-14"],
				maxTokens,
				temperature,
				reasoning: thinking,
			} = this.getModel()

			// Filter out non-Anthropic blocks (reasoning, thoughtSignature, etc.) before sending to the API
			const sanitizedMessages = filterNonAnthropicBlocks(messages)

			// Add 1M context beta flag if enabled for supported models (Claude Sonnet 4/4.5/4.6, Opus 4.6)
			if (
				(modelId === "claude-sonnet-4-20250514" ||
					modelId === "claude-sonnet-4-5" ||
					modelId === "claude-sonnet-4-6" ||
					modelId === "claude-opus-4-6") &&
				this.options.anthropicBeta1MContext
			) {
				betas.push("context-1m-2025-08-07")
			}

			const anthropicTools = convertOpenAIToolsToAnthropic(metadata?.tools ?? [])
			// Mark tool definitions with cache control so static tool schemas can benefit from prompt caching.
			// Anthropic accepts cache breakpoints on content blocks and tool definitions.
			const anthropicToolsWithCache: AnthropicToolWithCache[] = anthropicTools.map((tool, index) => ({
				...tool,
				...(index === anthropicTools.length - 1 ? { cache_control: cacheControl } : {}),
			})) as AnthropicToolWithCache[]
			const nativeToolParams = {
				tools: anthropicToolsWithCache,
				tool_choice: convertOpenAIToolChoiceToAnthropic(metadata?.tool_choice, metadata?.parallelToolCalls),
			}
			const split = systemPrompt.includes(SYSTEM_PROMPT_DYNAMIC_BOUNDARY)
				? systemPrompt.split(SYSTEM_PROMPT_DYNAMIC_BOUNDARY)
				: null
			const systemBlocksWithCache =
				split && split.length >= 2
					? [
							{ text: split[0] ?? "", type: "text" as const, cache_control: cacheControl },
							{ text: split.slice(1).join(SYSTEM_PROMPT_DYNAMIC_BOUNDARY), type: "text" as const },
						]
					: [{ text: systemPrompt, type: "text" as const, cache_control: cacheControl }]
			// --- Prompt Cache Break Detection ---
			const staticPartText = split && split.length >= 2 ? (split[0] ?? "") : systemPrompt
			const dynamicPartText =
				split && split.length >= 2 ? split.slice(1).join(SYSTEM_PROMPT_DYNAMIC_BOUNDARY) : ""
			const cacheBreakEvent = globalPromptCacheBreakDetector.check(staticPartText, dynamicPartText)
			if (cacheBreakEvent) {
				logger.info(
					"Anthropic",
					`Cache break detected: source=${cacheBreakEvent.changeSource}, staticChanged=${cacheBreakEvent.staticPartChanged}, dynamicChanged=${cacheBreakEvent.dynamicPartChanged}, totalBreaks=${globalPromptCacheBreakDetector.getTotalBreaks()}`,
				)
			}

			const systemBlocksNoCache =
				split && split.length >= 2
					? [
							{ text: split[0] ?? "", type: "text" as const },
							{ text: split.slice(1).join(SYSTEM_PROMPT_DYNAMIC_BOUNDARY), type: "text" as const },
						]
					: [{ text: systemPrompt, type: "text" as const }]

			switch (modelId) {
				case "claude-sonnet-4-6":
				case "claude-sonnet-4-5":
				case "claude-sonnet-4-20250514":
				case "claude-opus-4-6":
				case "claude-opus-4-7":
				case "claude-opus-4-5-20251101":
				case "claude-opus-4-1-20250805":
				case "claude-opus-4-20250514":
				case "claude-3-7-sonnet-20250219":
				case "claude-3-5-sonnet-20241022":
				case "claude-3-5-haiku-20241022":
				case "claude-3-opus-20240229":
				case "claude-haiku-4-5-20251001":
				case "claude-3-haiku-20240307": {
					/**
					 * The latest message will be the new user message, one before
					 * will be the assistant message from a previous request, and
					 * the user message before that will be a previously cached user
					 * message. So we need to mark the latest user message as
					 * ephemeral to cache it for the next request, and mark the
					 * second to last user message as ephemeral to let the server
					 * know the last message to retrieve from the cache for the
					 * current request.
					 */
					const userMsgIndices = sanitizedMessages.reduce(
						(acc, msg, index) => (msg.role === "user" ? [...acc, index] : acc),
						[] as number[],
					)

					const lastUserMsgIndex = userMsgIndices[userMsgIndices.length - 1] ?? -1
					const secondLastMsgUserIndex = userMsgIndices[userMsgIndices.length - 2] ?? -1

					stream = await this.withRetry(() =>
						this.client.messages.create(
							{
								model: modelId,
								max_tokens: maxTokens ?? ANTHROPIC_DEFAULT_MAX_TOKENS,
								temperature,
								thinking,
								// Setting cache breakpoint for system prompt so new tasks can reuse it.
								system: systemBlocksWithCache,
								messages: sanitizedMessages.map((message, index) => {
									if (index === lastUserMsgIndex || index === secondLastMsgUserIndex) {
										return {
											...message,
											content:
												typeof message.content === "string"
													? [{ type: "text", text: message.content, cache_control: cacheControl }]
													: message.content.map((content, contentIndex) =>
															contentIndex === message.content.length - 1
																? { ...content, cache_control: cacheControl }
																: content,
														),
										}
									}
									return message
								}),
								stream: true,
								...nativeToolParams,
							},
							// Prompt caching is now GA — no special beta header needed.
							// Pass remaining betas (e.g. fine-grained-tool-streaming, context-1m) if any.
							betas && betas.length > 0 ? { headers: { "anthropic-beta": betas.join(",") } } : undefined,
						),
					)
					break
				}
				default: {
					stream = (await this.withRetry(() =>
						this.client.messages.create({
							model: modelId,
							max_tokens: maxTokens ?? ANTHROPIC_DEFAULT_MAX_TOKENS,
							temperature,
							system: systemBlocksNoCache,
							messages: sanitizedMessages,
							stream: true,
							...nativeToolParams,
						}),
					)) as any
					break
				}
			}

			let inputTokens = 0
			let outputTokens = 0
			let cacheWriteTokens = 0
			let cacheReadTokens = 0

			for await (const chunk of stream) {
				switch (chunk.type) {
					case "message_start": {
						// Tells us cache reads/writes/input/output.
						const {
							input_tokens = 0,
							output_tokens = 0,
							cache_creation_input_tokens,
							cache_read_input_tokens,
						} = chunk.message.usage

						yield {
							type: "usage",
							inputTokens: input_tokens,
							outputTokens: output_tokens,
							cacheWriteTokens: cache_creation_input_tokens || undefined,
							cacheReadTokens: cache_read_input_tokens || undefined,
						}

						inputTokens += input_tokens
						outputTokens += output_tokens
						cacheWriteTokens += cache_creation_input_tokens || 0
						cacheReadTokens += cache_read_input_tokens || 0
						if ((cache_creation_input_tokens || 0) > 0 || (cache_read_input_tokens || 0) > 0) {
							debugLog(
								`[AnthropicHandler] ${summarizePromptCacheUsage({ cacheReadInputTokens: cache_read_input_tokens ?? undefined, cacheCreationInputTokens: cache_creation_input_tokens ?? undefined })}`,
							)
						}
						if (cache_read_input_tokens !== undefined) {
							debugLog(
								`[Anthropic Cache] read: ${cache_read_input_tokens}, ` +
									`creation: ${cache_creation_input_tokens ?? 0}`,
							)
						}

						break
					}
					case "message_delta":
						// Tells us stop_reason, stop_sequence, and output tokens
						// along the way and at the end of the message.
						yield {
							type: "usage",
							inputTokens: 0,
							outputTokens: chunk.usage.output_tokens || 0,
						}

						break
					case "message_stop":
						// No usage data, just an indicator that the message is done.
						break
					case "content_block_start":
						switch (chunk.content_block.type) {
							case "thinking":
								// We may receive multiple text blocks, in which
								// case just insert a line break between them.
								if (chunk.index > 0) {
									yield { type: "reasoning", text: "\n" }
								}

								yield { type: "reasoning", text: chunk.content_block.thinking }
								break
							case "text":
								// We may receive multiple text blocks, in which
								// case just insert a line break between them.
								if (chunk.index > 0) {
									yield { type: "text", text: "\n" }
								}

								yield { type: "text", text: chunk.content_block.text }
								break
							case "tool_use": {
								// Emit initial tool call partial with id and name
								yield {
									type: "tool_call_partial",
									index: chunk.index,
									id: chunk.content_block.id,
									name: chunk.content_block.name,
									arguments: undefined,
								}
								break
							}
						}
						break
					case "content_block_delta":
						switch (chunk.delta.type) {
							case "thinking_delta":
								yield { type: "reasoning", text: chunk.delta.thinking }
								break
							case "text_delta":
								yield { type: "text", text: chunk.delta.text }
								break
							case "input_json_delta": {
								// Emit tool call partial chunks as arguments stream in
								yield {
									type: "tool_call_partial",
									index: chunk.index,
									id: undefined,
									name: undefined,
									arguments: chunk.delta.partial_json,
								}
								break
							}
						}

						break
					case "content_block_stop":
						// Block complete - no action needed for now.
						// NativeToolCallParser handles tool call completion
						// Note: Signature for multi-turn thinking would require using stream.finalMessage()
						// after iteration completes, which requires restructuring the streaming approach.
						break
				}
			}

			if (inputTokens > 0 || outputTokens > 0 || cacheWriteTokens > 0 || cacheReadTokens > 0) {
				const modelInfo = this.getModel().info
				const { totalCost } = calculateApiCostAnthropic(
					modelInfo,
					inputTokens,
					outputTokens,
					cacheWriteTokens,
					cacheReadTokens,
				)

				// Hypothetical cost if all input tokens were billed at full price (no caching)
				const { totalCost: noCacheCost } = calculateApiCostAnthropic(
					modelInfo,
					inputTokens + cacheWriteTokens + cacheReadTokens,
					outputTokens,
				)

				yield {
					type: "usage",
					inputTokens: 0,
					outputTokens: 0,
					totalCost,
				}

				// Track cost and usage metrics
				globalCostTracker.recordUsage(modelId, {
					inputTokens,
					outputTokens,
					cacheReadInputTokens: cacheReadTokens,
					cacheCreationInputTokens: cacheWriteTokens,
					costUSD: totalCost,
					noCacheCostUSD: noCacheCost,
				})
			}
		} catch (error) {
			// Handle errors during API call or streaming
			throw handleProviderError(error, this.providerName, { messagePrefix: "streaming" })
		}
	}

	getModel() {
		const modelId = this.options.apiModelId
		const id = modelId && modelId in anthropicModels ? (modelId as AnthropicModelId) : anthropicDefaultModelId
		let info: ModelInfo = anthropicModels[id]

		// If 1M context beta is enabled for supported models, update the model info
		if (
			(id === "claude-sonnet-4-20250514" ||
				id === "claude-sonnet-4-5" ||
				id === "claude-sonnet-4-6" ||
				id === "claude-opus-4-6") &&
			this.options.anthropicBeta1MContext
		) {
			// Use the tier pricing for 1M context
			const tier = info.tiers?.[0]
			if (tier) {
				info = {
					...info,
					contextWindow: tier.contextWindow,
					inputPrice: tier.inputPrice,
					outputPrice: tier.outputPrice,
					cacheWritesPrice: tier.cacheWritesPrice,
					cacheReadsPrice: tier.cacheReadsPrice,
				}
			}
		}

		const params = getModelParams({
			format: "anthropic",
			modelId: id,
			model: info,
			settings: this.options,
			defaultTemperature: 0,
		})

		// The `:thinking` suffix indicates that the model is a "Hybrid"
		// reasoning model and that reasoning is required to be enabled.
		// The actual model ID honored by Anthropic's API does not have this
		// suffix.
		return {
			id: id === "claude-3-7-sonnet-20250219:thinking" ? "claude-3-7-sonnet-20250219" : id,
			info,
			betas: id === "claude-3-7-sonnet-20250219:thinking" ? ["output-128k-2025-02-19"] : undefined,
			...params,
		}
	}

	async completePrompt(prompt: string) {
		const { id: model, temperature } = this.getModel()

		const message = await this.withRetry(() => this.client.messages.create({
			model,
			max_tokens: ANTHROPIC_DEFAULT_MAX_TOKENS,
			thinking: undefined,
			temperature,
			messages: [{ role: "user", content: prompt }],
			stream: false,
		}))

		const content = message.content.find(({ type }) => type === "text")
		return content?.type === "text" ? content.text : ""
	}
}

import { Anthropic } from "@anthropic-ai/sdk"
import OpenAI from "openai"

import type { ModelInfo, OpenAiUsageMetrics } from "@njust-ai-cj/types"

import { type ApiHandlerOptions, getModelMaxOutputTokens } from "../../shared/api"
import { TagMatcher } from "../../utils/tag-matcher"
import { ApiStream, ApiStreamUsageChunk } from "../transform/stream"
import { convertToOpenAiMessages } from "../transform/openai-format"

import type { SingleCompletionHandler, ApiHandlerCreateMessageMetadata } from "../index"
import { DEFAULT_HEADERS } from "./constants"
import { BaseProvider } from "./base-provider"
import { handleOpenAIError } from "./utils/openai-error-handler"
import { calculateApiCostOpenAI, resolveOpenAiUsageForCost } from "../../shared/cost"
import { getApiRequestTimeout } from "./utils/timeout-config"
import { analyzeErrorForRetry } from "../retry/ApiErrorClassifier"
import { computeBackoffMs, DEFAULT_API_RETRY_OPTIONS, delayMs } from "../retry/ApiRetryStrategy"
import { taskEventBus } from "../../core/events/TaskEventBus"

type BaseOpenAiCompatibleProviderOptions<ModelName extends string> = ApiHandlerOptions & {
	providerName: string
	baseURL: string
	defaultProviderModelId: ModelName
	providerModels: Record<ModelName, ModelInfo>
	defaultTemperature?: number
}

export abstract class BaseOpenAiCompatibleProvider<ModelName extends string>
	extends BaseProvider
	implements SingleCompletionHandler
{
	protected readonly providerName: string
	protected readonly baseURL: string
	protected readonly defaultTemperature: number
	protected readonly defaultProviderModelId: ModelName
	protected readonly providerModels: Record<ModelName, ModelInfo>

	protected readonly options: ApiHandlerOptions

	protected client: OpenAI

	protected override shouldUseStrictMode(): boolean {
		return false
	}

	/**
	 * Retries only the transport/setup phase (before any chunks are yielded).
	 * Mid-stream failures are handled by the task loop.
	 */
	private async openStreamWithRetry(
		systemPrompt: string,
		messages: Anthropic.Messages.MessageParam[],
		metadata?: ApiHandlerCreateMessageMetadata,
	): Promise<Awaited<ReturnType<BaseOpenAiCompatibleProvider<ModelName>["createStream"]>>> {
		let lastError: unknown
		for (let attempt = 0; attempt < DEFAULT_API_RETRY_OPTIONS.maxAttempts; attempt++) {
			try {
				return await this.createStream(systemPrompt, messages, metadata)
			} catch (error) {
				lastError = error
				const decision = analyzeErrorForRetry(error)
				if (!decision.shouldRetry || attempt >= DEFAULT_API_RETRY_OPTIONS.maxAttempts - 1) {
					throw error
				}
				const delay = computeBackoffMs(attempt, DEFAULT_API_RETRY_OPTIONS, decision.retryAfterSeconds)
				taskEventBus.emit("task:llm-retry", {
					taskId: metadata?.taskId,
					data: {
						attempt: attempt + 1,
						delayMs: delay,
						category: decision.category,
						provider: this.providerName,
					},
				})
				await delayMs(delay)
			}
		}
		throw lastError ?? new Error(`${this.providerName}: failed to open stream`)
	}

	constructor({
		providerName,
		baseURL,
		defaultProviderModelId,
		providerModels,
		defaultTemperature,
		...options
	}: BaseOpenAiCompatibleProviderOptions<ModelName>) {
		super()

		this.providerName = providerName
		this.baseURL = baseURL
		this.defaultProviderModelId = defaultProviderModelId
		this.providerModels = providerModels
		this.defaultTemperature = defaultTemperature ?? 0

		this.options = options

		if (!this.options.apiKey) {
			throw new Error("API key is required")
		}

		this.client = new OpenAI({
			baseURL,
			apiKey: this.options.apiKey,
			defaultHeaders: DEFAULT_HEADERS,
			timeout: getApiRequestTimeout(),
		})
	}

	protected createStream(
		systemPrompt: string,
		messages: Anthropic.Messages.MessageParam[],
		metadata?: ApiHandlerCreateMessageMetadata,
		requestOptions?: OpenAI.RequestOptions,
	) {
		const { id: model, info } = this.getModel()

		// Centralized cap: clamp to 20% of the context window (unless provider-specific exceptions apply)
		const max_tokens =
			getModelMaxOutputTokens({
				modelId: model,
				model: info,
				settings: this.options,
				format: "openai",
			}) ?? undefined

		const temperature = this.options.modelTemperature ?? info.defaultTemperature ?? this.defaultTemperature

		const params: OpenAI.Chat.Completions.ChatCompletionCreateParamsStreaming = {
			model,
			max_tokens,
			temperature,
			messages: [{ role: "system", content: systemPrompt }, ...convertToOpenAiMessages(messages)],
			stream: true,
			stream_options: { include_usage: true },
			tools: this.convertToolsForOpenAI(metadata?.tools),
			tool_choice: metadata?.tool_choice,
			parallel_tool_calls: metadata?.parallelToolCalls ?? false,
		}

		// Add thinking parameter if reasoning is enabled and model supports it
		if (this.options.enableReasoningEffort && info.supportsReasoningBinary) {
			;(params as any).thinking = { type: "enabled" }
		}

		try {
			return this.client.chat.completions.create(params, requestOptions)
		} catch (error) {
			throw handleOpenAIError(error, this.providerName)
		}
	}

	override async *createMessage(
		systemPrompt: string,
		messages: Anthropic.Messages.MessageParam[],
		metadata?: ApiHandlerCreateMessageMetadata,
	): ApiStream {
		const stream = await this.openStreamWithRetry(systemPrompt, messages, metadata)

		const matcher = new TagMatcher(
			"think",
			(chunk) =>
				({
					type: chunk.matched ? "reasoning" : "text",
					text: chunk.data,
				}) as const,
		)

		let lastUsage: OpenAI.CompletionUsage | undefined
		const activeToolCallIds = new Set<string>()

		for await (const chunk of stream) {
			// Check for provider-specific error responses (e.g., MiniMax base_resp)
			const chunkAny = chunk as any
			if (chunkAny.base_resp?.status_code && chunkAny.base_resp.status_code !== 0) {
				throw new Error(
					`${this.providerName} API Error (${chunkAny.base_resp.status_code}): ${chunkAny.base_resp.status_msg || "Unknown error"}`,
				)
			}

			const delta = chunk.choices?.[0]?.delta
			const finishReason = chunk.choices?.[0]?.finish_reason

			if (delta?.content) {
				for (const processedChunk of matcher.update(delta.content)) {
					yield processedChunk
				}
			}

			if (delta) {
				for (const key of ["reasoning_content", "reasoning"] as const) {
					if (key in delta) {
						const reasoning_content = ((delta as any)[key] as string | undefined) || ""
						if (reasoning_content?.trim()) {
							yield { type: "reasoning", text: reasoning_content }
						}
						break
					}
				}
			}

			// Emit raw tool call chunks - NativeToolCallParser handles state management
			if (delta?.tool_calls) {
				for (const toolCall of delta.tool_calls) {
					if (toolCall.id) {
						activeToolCallIds.add(toolCall.id)
					}
					yield {
						type: "tool_call_partial",
						index: toolCall.index,
						id: toolCall.id,
						name: toolCall.function?.name,
						arguments: toolCall.function?.arguments,
					}
				}
			}

			// Emit tool_call_end events when finish_reason is "tool_calls"
			// This ensures tool calls are finalized even if the stream doesn't properly close
			if (finishReason === "tool_calls" && activeToolCallIds.size > 0) {
				for (const id of activeToolCallIds) {
					yield { type: "tool_call_end", id }
				}
				activeToolCallIds.clear()
			}

			if (chunk.usage) {
				lastUsage = chunk.usage
			}
		}

		if (lastUsage) {
			yield this.processUsageMetrics(lastUsage, this.getModel().info)
		}

		// Process any remaining content
		for (const processedChunk of matcher.final()) {
			yield processedChunk
		}
	}

	protected processUsageMetrics(usage: OpenAiUsageMetrics, modelInfo?: ModelInfo): ApiStreamUsageChunk {
		const inputTokens = usage?.prompt_tokens || 0
		const outputTokens = usage?.completion_tokens || 0
		const details = usage?.prompt_tokens_details
		const cacheWriteTokens = details?.cache_write_tokens || usage?.cache_creation_input_tokens || 0
		const cacheReadTokens =
			usage?.cache_read_input_tokens ?? details?.cached_tokens ?? usage?.cached_tokens ?? 0

		const resolved = resolveOpenAiUsageForCost({
			inputTokensReported: inputTokens,
			cacheWriteTokens,
			cacheReadTokens,
			cacheMissTokensFromDetails:
				typeof details?.cache_miss_tokens === "number" ? details.cache_miss_tokens : undefined,
			cachedTokensFromDetails: typeof details?.cached_tokens === "number" ? details.cached_tokens : undefined,
		})

		const costResult = modelInfo
			? calculateApiCostOpenAI(
					modelInfo,
					resolved.totalInputTokens,
					outputTokens,
					resolved.cacheWriteTokens,
					resolved.cacheReadTokens,
				)
			: { totalCost: 0, totalInputTokens: resolved.totalInputTokens }

		return {
			type: "usage",
			inputTokens: costResult.totalInputTokens,
			outputTokens,
			cacheWriteTokens: resolved.cacheWriteTokens || undefined,
			cacheReadTokens: resolved.cacheReadTokens || undefined,
			totalCost: costResult.totalCost,
		}
	}

	async completePrompt(prompt: string): Promise<string> {
		const { id: modelId, info: modelInfo } = this.getModel()

		const params: OpenAI.Chat.Completions.ChatCompletionCreateParams = {
			model: modelId,
			messages: [{ role: "user", content: prompt }],
		}

		// Add thinking parameter if reasoning is enabled and model supports it
		if (this.options.enableReasoningEffort && modelInfo.supportsReasoningBinary) {
			;(params as any).thinking = { type: "enabled" }
		}

		try {
			const response = await this.client.chat.completions.create(params)

			// Check for provider-specific error responses (e.g., MiniMax base_resp)
			const responseAny = response as any
			if (responseAny.base_resp?.status_code && responseAny.base_resp.status_code !== 0) {
				throw new Error(
					`${this.providerName} API Error (${responseAny.base_resp.status_code}): ${responseAny.base_resp.status_msg || "Unknown error"}`,
				)
			}

			return response.choices?.[0]?.message.content || ""
		} catch (error) {
			throw handleOpenAIError(error, this.providerName)
		}
	}

	override getModel() {
		const id =
			this.options.apiModelId && this.options.apiModelId in this.providerModels
				? (this.options.apiModelId as ModelName)
				: this.defaultProviderModelId

		return { id, info: this.providerModels[id] }
	}
}

import { Anthropic } from "@anthropic-ai/sdk"

import type { ModelInfo } from "@njust-ai-cj/types"

import type { ApiHandler, ApiHandlerCreateMessageMetadata } from "../index"

import { ApiStream } from "../transform/stream"
import { countTokensDetailed, type TokenCountResult } from "../../utils/countTokens"
import { isMcpTool } from "../../utils/mcp-name"
import { computeBackoffMs, delayMs, DEFAULT_API_RETRY_OPTIONS, type ApiRetryOptions } from "../retry/ApiRetryStrategy"
import { analyzeErrorForRetry } from "../retry/ApiErrorClassifier"
import { taskEventBus } from "../../core/events/TaskEventBus"

/**
 * Base class for API providers that implements common functionality.
 */
export abstract class BaseProvider implements ApiHandler {
	abstract createMessage(
		systemPrompt: string,
		messages: Anthropic.Messages.MessageParam[],
		metadata?: ApiHandlerCreateMessageMetadata,
	): ApiStream

	abstract getModel(): { id: string; info: ModelInfo }

	/**
	 * Whether this provider supports OpenAI strict mode for tool schemas.
	 * Override and return false for non-OpenAI providers that reject strict mode.
	 */
	protected shouldUseStrictMode(): boolean {
		return true
	}

	/**
	 * Converts an array of tools to be compatible with OpenAI's strict mode.
	 * Filters for function tools, applies schema conversion to their parameters,
	 * and ensures all tools have consistent strict values.
	 */
	protected convertToolsForOpenAI(tools: any[] | undefined): any[] | undefined {
		if (!tools) {
			return undefined
		}

		const useStrict = this.shouldUseStrictMode()

		return tools.map((tool) => {
			if (tool.type !== "function") {
				return tool
			}

			// MCP tools use the 'mcp--' prefix - disable strict mode for them
			// to preserve optional parameters from the MCP server schema
			const isMcp = isMcpTool(tool.function.name)

			return {
				...tool,
				function: {
					...tool.function,
					strict: useStrict && !isMcp,
					parameters: useStrict && !isMcp
						? this.convertToolSchemaForOpenAI(tool.function.parameters)
						: tool.function.parameters,
				},
			}
		})
	}

	/**
	 * Converts tool schemas to be compatible with OpenAI's strict mode by:
	 * - Ensuring all properties are in the required array (strict mode requirement)
	 * - Preserving original optional semantics by allowing null for properties that were
	 *   not in the original required array
	 * - Adding additionalProperties: false to all object schemas (required by OpenAI Responses API)
	 * - Recursively processing nested objects and arrays
	 */
	protected convertToolSchemaForOpenAI(schema: any): any {
		const getPrimaryType = (value: any): string | undefined =>
			Array.isArray(value?.type) ? value.type.find((t: string) => t !== "null") : value?.type

		if (!schema || typeof schema !== "object" || getPrimaryType(schema) !== "object") {
			return schema
		}

		const result = { ...schema }
		const originallyRequired = new Set(Array.isArray(schema.required) ? schema.required : [])

		// OpenAI Responses API requires additionalProperties: false on all object schemas
		// Only add if not already set to false (to avoid unnecessary mutations)
		if (result.additionalProperties !== false) {
			result.additionalProperties = false
		}

		if (result.properties) {
			const allKeys = Object.keys(result.properties)
			// OpenAI strict mode requires ALL properties to be in required array
			result.required = allKeys

			// Recursively process nested objects and convert nullable types
			const newProps = { ...result.properties }
			for (const key of allKeys) {
				const prop = newProps[key]

				if (prop && !originallyRequired.has(key)) {
					const types = Array.isArray(prop.type) ? prop.type : prop.type ? [prop.type] : []
					if (types.length > 0 && !types.includes("null")) {
						newProps[key] = { ...prop, type: [...types, "null"] }
					}
				}

				const normalizedProp = newProps[key]
				const primaryType = getPrimaryType(normalizedProp)
				// Recursively process nested objects
				if (normalizedProp && primaryType === "object") {
					newProps[key] = this.convertToolSchemaForOpenAI(normalizedProp)
				} else if (normalizedProp && primaryType === "array" && getPrimaryType(normalizedProp.items) === "object") {
					newProps[key] = {
						...normalizedProp,
						items: this.convertToolSchemaForOpenAI(normalizedProp.items),
					}
				}
			}
			result.properties = newProps
		}

		return result
	}

	protected hasNativeTokenCounting(): boolean {
		return false
	}

	/**
	 * Override when {@link hasNativeTokenCounting} is true; return undefined to fall back to tiktoken.
	 */
	protected countTokensNative(
		_content: Anthropic.Messages.ContentBlockParam[],
	): Promise<number | TokenCountResult | undefined> {
		return undefined
	}

	/**
	 * Default token counting using tiktoken; providers may override {@link hasNativeTokenCounting}.
	 */
	async countTokens(content: Anthropic.Messages.ContentBlockParam[]): Promise<number> {
		const result = await this.countTokensDetailed(content)
		return result.total
	}

	async countTokensDetailed(content: Anthropic.Messages.ContentBlockParam[]): Promise<TokenCountResult> {
		if (content.length === 0) {
			return { total: 0, strategy: "tiktoken" }
		}

		if (this.hasNativeTokenCounting()) {
			const native = await this.countTokensNative(content)
			if (native !== undefined) {
				if (typeof native === "number") {
					return { total: native, strategy: "native" }
				}
				return native
			}
		}

		return countTokensDetailed(content, { useWorker: true })
	}

	/**
	 * Wraps an async operation with exponential backoff retry.
	 * Retries network errors, 429 (honoring Retry-After), and 5xx.
	 * Does NOT retry 4xx client errors or auth failures.
	 */
	protected async withRetry<T>(
		operation: () => Promise<T>,
		retryConfig?: Partial<ApiRetryOptions>,
		context?: { taskId?: string; provider?: string },
	): Promise<T> {
		const config = { ...DEFAULT_API_RETRY_OPTIONS, ...retryConfig }
		let lastError: unknown

		for (let attempt = 0; attempt < config.maxAttempts; attempt++) {
			try {
				return await operation()
			} catch (error) {
				lastError = error
				const decision = analyzeErrorForRetry(error)
				if (!decision.shouldRetry || attempt >= config.maxAttempts - 1) {
					throw error
				}
				const delay = computeBackoffMs(attempt, config, decision.retryAfterSeconds)
				taskEventBus.emit("task:llm-retry", {
					taskId: context?.taskId,
					data: {
						attempt: attempt + 1,
						delayMs: delay,
						category: decision.category,
						provider: context?.provider ?? this.constructor.name,
					},
				})
				await delayMs(delay)
			}
		}

		throw lastError
	}
}

