/**
 * Registers Roo's native tools as VSCode Language Model Tools.
 * This allows VSCode's built-in Agent Mode (e.g., Copilot) to invoke
 * Roo's file editing, terminal execution, and code search capabilities.
 */
export function registerLMTools(
	context: vscode.ExtensionContext,
	provider: ClineProvider,
	outputChannel: vscode.OutputChannel,
): void {
	if (typeof vscode.lm?.registerTool !== "function") {
		outputChannel.appendLine("[LMTools] vscode.lm.registerTool not available in this VSCode version, skipping.")
		return
	}

	for (const def of TOOL_DEFINITIONS) {
		try {
			const tool = createLMTool(def, provider, outputChannel)
			const disposable = vscode.lm.registerTool(def.name, tool)
			context.subscriptions.push(disposable)
			outputChannel.appendLine(`[LMTools] Registered tool: ${def.name}`)
		} catch (error) {
			outputChannel.appendLine(
				`[LMTools] Failed to register tool ${def.name}: ${getErrorMessage(error)}`,
			)
		}
	}
}

function createLMTool(
	def: ToolDefinition,
	provider: ClineProvider,
	outputChannel: vscode.OutputChannel,
): vscode.LanguageModelTool<Record<string, unknown>> {
	return {
		async invoke(
			options: vscode.LanguageModelToolInvocationOptions<Record<string, unknown>>,
			token: vscode.CancellationToken,
		): Promise<vscode.LanguageModelToolResult> {
			const input = options.input
			outputChannel.appendLine(`[LMTools] Invoking ${def.name} with input: ${JSON.stringify(input)}`)

			try {
				const result = await executeTool(def.name, input, provider, token)
				return new vscode.LanguageModelToolResult([new vscode.LanguageModelTextPart(result)])
			} catch (error) {
				const message = getErrorMessage(error)
				outputChannel.appendLine(`[LMTools] Error in ${def.name}: ${message}`)
				return new vscode.LanguageModelToolResult([
					new vscode.LanguageModelTextPart(`Error: ${message}`),
				])
			}
		},

		prepareInvocation(
			_options: vscode.LanguageModelToolInvocationPrepareOptions<Record<string, unknown>>,
			_token: vscode.CancellationToken,
		): Promise<vscode.PreparedToolInvocation> {
			return {
				invocationMessage: `Running ${def.displayName}...`,
			}
		},
	}
}

async function executeTool(
	toolName: string,
	input: Record<string, unknown>,
	provider: ClineProvider,
	_token: vscode.CancellationToken,
): Promise<string> {
	const workspaceFolders = vscode.workspace.workspaceFolders
	const cwd = workspaceFolders?.[0]?.uri.fsPath || ""

	switch (toolName) {
		case "roo_readFile": {
			const filePath = resolveFilePath(cwd, input.path as string)
			const uri = vscode.Uri.file(filePath)
			const content = await vscode.workspace.fs.readFile(uri)
			return new TextDecoder().decode(content)
		}

		case "roo_editFile": {
			const filePath = resolveFilePath(cwd, input.path as string)
			const diff = input.diff as string
			const prompt = `Apply the following diff to the file ${filePath}:\n\n${diff}`
			await provider.createTask(prompt)
			return `Edit task created for ${filePath}. The Roo Agent is processing the change.`
		}

		case "roo_executeCommand": {
			const command = input.command as string
			const prompt = `Execute the following command: ${command}`
			await provider.createTask(prompt)
			return `Command execution task created: ${command}. The Roo Agent is processing.`
		}

		case "roo_searchFiles": {
			const pattern = input.pattern as string
			const searchPath = (input.path as string) || ""
			const fullPath = searchPath ? resolveFilePath(cwd, searchPath) : cwd

			const results: string[] = []
			const files = await vscode.workspace.findFiles(
				new vscode.RelativePattern(fullPath, "**/*"),
				"**/node_modules/**",
				100,
			)

			const regex = new RegExp(pattern, "gi")
			for (const file of files.slice(0, 50)) {
				try {
					const content = await vscode.workspace.fs.readFile(file)
					const text = new TextDecoder().decode(content)
					const lines = text.split("\n")
					for (let i = 0; i < lines.length; i++) {
						if (regex.test(lines[i])) {
							results.push(`${vscode.workspace.asRelativePath(file)}:${i + 1}: ${lines[i].trim()}`)
						}
						regex.lastIndex = 0
					}
				} catch {
					// Skip unreadable files
				}

				if (results.length > 200) break
			}

			return results.length > 0
				? results.join("\n")
				: `No matches found for pattern: ${pattern}`
		}

		case "roo_listFiles": {
			const listPath = resolveFilePath(cwd, (input.path as string) || ".")
			const recursive = (input.recursive as boolean) || false
			const pattern = recursive ? "**/*" : "*"
			const files = await vscode.workspace.findFiles(
				new vscode.RelativePattern(listPath, pattern),
				"**/node_modules/**",
				500,
			)

			return files
				.map((f) => vscode.workspace.asRelativePath(f))
				.sort()
				.join("\n") || "No files found"
		}

		case "roo_codebaseSearch": {
			const query = input.query as string
			const prompt = `Search the codebase for: ${query}`
			await provider.createTask(prompt)
			return `Codebase search task created for: ${query}. The Roo Agent is processing.`
		}

		default:
			throw new Error(`Unknown tool: ${toolName}`)
	}
}

function resolveFilePath(cwd: string, relativePath: string): string {
	if (!relativePath) return cwd
	const path = require("path")
	if (path.isAbsolute(relativePath)) return relativePath
	return path.join(cwd, relativePath)
}

/**
 * Agent Feature Integrations
 *
 * Wires AgentDefinition features (MCP servers, skills, hooks) into
 * the Task lifecycle. These are thin integration shims that connect
 * the new AgentDefinition system to the existing infrastructure.
 *
 * Full activation requires the agent lifecycle to call these at the
 * appropriate points: start → activate, stop → deactivate.
 */

import type { AgentDefinition } from "./types"
import { ToolHookManager } from "../tools/ToolHookManager"
import type { HookContext } from "../hooks/types"

// ── MCP Integration ──

/**
 * Resolve the effective MCP server list for an agent.
 * Built-in and parent servers are additive.
 */
export function resolveAgentMcpServers(
	agentDef: AgentDefinition,
	parentServers: string[] = [],
): string[] {
	const agentServers = agentDef.mcpServers ?? []
	// Deduplicate: agent-specific servers override parent duplicates
	const seen = new Set(agentServers)
	const all = [...agentServers]
	for (const s of parentServers) {
		if (!seen.has(s)) {
			all.push(s)
			seen.add(s)
		}
	}
	return all
}

// ── Skills Integration ──

/**
 * Resolve the effective skill list for an agent.
 */
export function resolveAgentSkills(agentDef: AgentDefinition): string[] {
	return agentDef.skills ?? []
}

// ── System Prompt Integration ──

/**
 * Resolve the system prompt for an agent.
 * Built-in agents use their defined prompt; custom agents use their Markdown body.
 */
export function resolveAgentSystemPrompt(
	agentDef: AgentDefinition,
	params: { taskDescription: string; mode: string },
): string {
	if (typeof agentDef.systemPrompt === "function") {
		return agentDef.systemPrompt(params)
	}
	if (typeof agentDef.systemPrompt === "string" && agentDef.systemPrompt.length > 0) {
		return agentDef.systemPrompt
	}
	// Fallback for agents without explicit prompt
	return `You are a delegated assistant (${agentDef.agentType}) working on a sub-task in ${params.mode} mode.\n\nTask: ${params.taskDescription}`
}

// ── Tool Resolution ──

/**
 * Resolve the effective tool set for an agent, filtering by allow/disallow lists.
 * Returns ["*"] for agents with full access.
 */
export function resolveAgentEffectiveTools(agentDef: AgentDefinition): string[] {
	if (agentDef.tools.includes("*")) {
		return ["*"]
	}
	const allowed = new Set(agentDef.tools)
	if (agentDef.disallowedTools) {
		for (const t of agentDef.disallowedTools) {
			allowed.delete(t)
		}
	}
	return Array.from(allowed)
}

// ── Lifecycle ──

/**
 * Features activated by a specific agent definition.
 */
export interface AgentFeatureState {
	mcpServers: string[]
	skills: string[]
	systemPrompt: string
	effectiveTools: string[]
	hooks: string[]
	/** Registered hook IDs for cleanup */
	hookIds: string[]
}

/**
 * Resolve hook identifiers from an agent definition.
 */
export function resolveAgentHooks(agentDef: AgentDefinition): string[] {
	return agentDef.hooks ?? []
}

/**
 * Activate agent-specific features.
 * Called at agent start. Resolves all feature configurations and fires
 * subagent-start hooks.
 */
export function activateAgentFeatures(
	agentDef: AgentDefinition,
	params: {
		taskDescription: string
		mode: string
		parentMcpServers?: string[]
		parentTaskId?: string
		taskId?: string
	},
): AgentFeatureState {
	const hookNames = resolveAgentHooks(agentDef)

	// Fire SubagentStartHook if any hooks are configured
	if (hookNames.length > 0 && params.parentTaskId) {
		const hookContext: HookContext = {
			hookType: "preToolUse" as any, // use generic context
			taskId: params.taskId,
			timestamp: Date.now(),
		}
		// Notify via ToolHookManager that a subagent started
		try {
			const manager = ToolHookManager.instance
			if (typeof (manager as any).runSubagentStartHooks === "function") {
				;(manager as any).runSubagentStartHooks(
					params.parentTaskId,
					agentDef.agentType,
					hookContext,
				)
			}
		} catch {
			// Hooks are fire-and-forget
		}
	}

	return {
		mcpServers: resolveAgentMcpServers(agentDef, params.parentMcpServers),
		skills: resolveAgentSkills(agentDef),
		systemPrompt: resolveAgentSystemPrompt(agentDef, params),
		effectiveTools: resolveAgentEffectiveTools(agentDef),
		hooks: hookNames,
		hookIds: [],
	}
}

/**
 * Deactivate agent-specific features.
 * Called at agent completion. Fires subagent-stop hooks and cleans up.
 */
export function deactivateAgentFeatures(
	state: AgentFeatureState,
	params: { success: boolean; parentTaskId?: string; taskId?: string },
): void {
	if (state.hooks.length > 0 && params.parentTaskId) {
		try {
			const manager = ToolHookManager.instance
			if (typeof (manager as any).runSubagentStopHooks === "function") {
				;(manager as any).runSubagentStopHooks(
					params.parentTaskId,
					"agent",
					params.success,
					{ hookType: "postToolUse" as any, taskId: params.taskId, timestamp: Date.now() },
				)
			}
		} catch {
			// Hooks are fire-and-forget
		}
	}
}

import { v7 as uuidv7 } from "uuid"
import * as vscode from "vscode"
import EventEmitter from "events"

import type { ClineProvider } from "../webview/ClineProvider"
import type { Task } from "../task/Task"
import type { SharedContext, AgentInfo } from "./types"
import { generateParentContextSummary } from "../task/SubTaskContextBuilder"
import { DEFAULT_FORKED_CONTEXT_CONFIG } from "../task/SubTaskOptions"
import type { ForkedContextConfig } from "../task/SubTaskOptions"
import { TIMING } from "../../shared/constants"
import { getErrorMessage } from "../../shared/error-utils"

type ApiMessage = { role: string; content: any; ts?: number }

interface SubtaskResult {
	agentId: string
	taskId: string
	resultSummary: string
	status: "completed" | "failed"
}

interface ParallelTaskSpec {
	mode: string
	message: string
	dependencies?: string[]
}

interface ParallelTaskResult {
	agentId: string
	taskId: string
	mode: string
	status: "completed" | "failed"
	result?: string
	error?: string
}

type OrchestratorEvents = {
	agentStarted: [agent: AgentInfo]
	agentCompleted: [agent: AgentInfo, result: string]
	agentFailed: [agent: AgentInfo, error: string]
	allCompleted: [results: ParallelTaskResult[]]
}

/**
 * AgentOrchestrator manages parallel task execution, enabling multiple
 * Agent instances to run concurrently while sharing context.
 *
 * It extends the existing single-task ClineProvider model by maintaining
 * a separate pool of background tasks that don't interfere with the
 * main task stack.
 */
export class AgentOrchestrator extends EventEmitter<OrchestratorEvents> {
	private agents: Map<string, AgentInfo> = new Map()
	private sharedContext: SharedContext
	private sharedContextMutex: Promise<void> = Promise.resolve() // Serializes writes to sharedContext
	private activeTasks: Map<string, Task> = new Map()

	constructor(
		private readonly provider: ClineProvider,
		private readonly outputChannel: vscode.OutputChannel,
	) {
		super()
		this.sharedContext = {
			id: uuidv7(),
			modifiedFiles: new Set(),
			results: new Map(),
			metadata: new Map(),
		}
	}

	/**
	 * Run multiple tasks in parallel, each in its own mode.
	 * Returns when all tasks have completed (or failed).
	 */
	async runParallel(specs: ParallelTaskSpec[]): Promise<ParallelTaskResult[]> {
		this.outputChannel.appendLine(
			`[AgentOrchestrator] Starting ${specs.length} parallel tasks`,
		)

		// Detect cycles in dependency graph before scheduling
		const cycleNodes = this.detectCycles(specs)
		if (cycleNodes.length > 0) {
			const cycleDescriptions = cycleNodes.join(" -> ")
			throw new Error(
				`Circular dependency detected among agents: ${cycleDescriptions}. ` +
				`Tasks involved in cycles cannot be scheduled.`,
			)
		}

		const independentSpecs = specs.filter((s) => !s.dependencies?.length)
		const dependentSpecs = specs.filter((s) => s.dependencies?.length)

		const independentResults = await this.runBatch(independentSpecs)
		const allResults = [...independentResults]
		const completedIds = new Set(
			independentResults.filter((r) => r.status === "completed").map((r) => r.agentId),
		)

		// Resolve dependencies level by level (topological order)
		let remainingDeps = [...dependentSpecs]
		while (remainingDeps.length > 0) {
			const readyDependents = remainingDeps.filter((s) =>
				s.dependencies!.every((dep) => completedIds.has(dep)),
			)

			if (readyDependents.length === 0) {
				// Dependencies can never be satisfied (should not happen after cycle check,
				// but handle gracefully for external dependency references)
				for (const spec of remainingDeps) {
					const missingDeps = spec.dependencies!.filter((dep) => !completedIds.has(dep))
					allResults.push({
						agentId: `unresolved-${spec.mode}`,
						taskId: "",
						mode: spec.mode,
						status: "failed",
						error: `Unresolved dependencies: ${missingDeps.join(", ")}`,
					})
				}
				break
			}

			const depResults = await this.runBatch(readyDependents)
			allResults.push(...depResults)
			for (const r of depResults) {
				if (r.status === "completed") {
					completedIds.add(r.agentId)
				}
			}
			remainingDeps = remainingDeps.filter(
				(s) => !readyDependents.includes(s),
			)
		}

		this.emit("allCompleted", allResults)
		this.outputChannel.appendLine(
			`[AgentOrchestrator] All parallel tasks completed. ` +
				`Success: ${allResults.filter((r) => r.status === "completed").length}, ` +
				`Failed: ${allResults.filter((r) => r.status === "failed").length}`,
		)

		return allResults
	}

	/**
	 * Detects cycles in the dependency graph using DFS.
	 * Returns the first cycle path found, or an empty array if the graph is acyclic.
	 */
	private detectCycles(specs: ParallelTaskSpec[]): string[] {
		const specNodes = new Map<string, ParallelTaskSpec>()
		for (const spec of specs) {
			specNodes.set(spec.mode, spec)
		}

		const WHITE = 0, _GRAY = 1, _BLACK = 2
		const color = new Map<string, number>()
		const parent = new Map<string, string>()

		for (const node of specNodes.keys()) {
			color.set(node, WHITE)
		}

		for (const node of specNodes.keys()) {
			if (color.get(node) === WHITE) {
				const cycle = this.dfsVisit(node, specNodes, color, parent)
				if (cycle.length > 0) return cycle
			}
		}
		return []
	}

	private dfsVisit(
		node: string,
		nodes: Map<string, ParallelTaskSpec>,
		color: Map<string, number>,
		parent: Map<string, string>,
	): string[] {
		color.set(node, 1) // GRAY

		const spec = nodes.get(node)
		if (spec?.dependencies) {
			for (const dep of spec.dependencies) {
				// Skip dependencies that reference agents outside the current spec set
				if (!nodes.has(dep)) continue

				const depColor = color.get(dep)
				if (depColor === 1) {
					// Back edge found — extract the cycle path
					const cycle: string[] = [dep, node]
					let current = node
					while (parent.has(current) && parent.get(current) !== dep) {
						current = parent.get(current)!
						cycle.push(current)
					}
					cycle.push(dep)
					cycle.reverse()
					return cycle
				} else if (depColor === 0) {
					parent.set(dep, node)
					const cycle = this.dfsVisit(dep, nodes, color, parent)
					if (cycle.length > 0) return cycle
				}
			}
		}

		color.set(node, 2) // BLACK
		return []
	}

	private async runBatch(specs: ParallelTaskSpec[]): Promise<ParallelTaskResult[]> {
		const promises = specs.map((spec) => this.runSingleAgent(spec))
		const settled = await Promise.allSettled(promises)

		return settled.map((result, i) => {
			if (result.status === "fulfilled") {
				return result.value
			}
			return {
				agentId: `failed-${i}`,
				taskId: "",
				mode: specs[i].mode,
				status: "failed" as const,
				error: result.reason instanceof Error ? result.reason.message : String(result.reason),
			}
		})
	}

	private async runSingleAgent(spec: ParallelTaskSpec): Promise<ParallelTaskResult> {
		const agentId = uuidv7()
		const agent: AgentInfo = {
			id: agentId,
			taskId: "",
			mode: spec.mode,
			status: "running",
			description: spec.message.slice(0, 100),
			startedAt: Date.now(),
		}

		this.agents.set(agentId, agent)
		this.emit("agentStarted", agent)

		try {
			const contextPrefix = this.buildSharedContextPrompt()
			const fullMessage = contextPrefix
				? `${contextPrefix}\n\nTask:\n${spec.message}`
				: spec.message

			await this.provider.handleModeSwitch(spec.mode as any)
			const task = await this.provider.createTask(fullMessage)

			agent.taskId = task.taskId
			this.activeTasks.set(agentId, task)
				let taskResult!: ParallelTaskResult
			try {

			const result = await this.waitForCompletion(task)

			agent.status = "completed"
			agent.completedAt = Date.now()
			this.sharedContext.results.set(agentId, result)

			this.emit("agentCompleted", agent, result)

			taskResult = {
				agentId,
				taskId: task.taskId,
				mode: spec.mode,
				status: "completed",
				result,
			}

			} finally {
				this.activeTasks.delete(agentId)
			}
			return taskResult
		} catch (error) {
			const errorMsg = getErrorMessage(error)
			agent.status = "failed"
			agent.completedAt = Date.now()

			this.emit("agentFailed", agent, errorMsg)

			return {
				agentId,
				taskId: agent.taskId,
				mode: spec.mode,
				status: "failed",
				error: errorMsg,
			}
		}
	}

	private waitForCompletion(task: any): Promise<string> {
		return new Promise((resolve, reject) => {
			const timeout = setTimeout(() => {
				reject(new Error("Agent task timed out after 10 minutes"))
			}, TIMING.AGENT_TASK_TIMEOUT_MS)

			const poll = setInterval(() => {
				try {
					const messages = task.clineMessages || []
					const lastMsg = messages[messages.length - 1]

					if (lastMsg?.type === "say" && lastMsg.say === "completion_result") {
						clearInterval(poll)
						clearTimeout(timeout)
						resolve(lastMsg.text || "Completed")
					}

					if (task.didFinishAbortingStream || task.abandoned) {
						clearInterval(poll)
						clearTimeout(timeout)

						const errorMsg = messages.find(
							(m: any) => m.type === "say" && m.say === "error",
						)
						if (errorMsg) {
							reject(new Error(errorMsg.text || "Task failed"))
						} else {
							resolve("Completed (no explicit result)")
						}
					}
				} catch (e) {
					clearInterval(poll)
					clearTimeout(timeout)
					reject(e)
				}
			}, 500)
		})
	}

	private buildSharedContextPrompt(): string {
		const parts: string[] = []

		if (this.sharedContext.modifiedFiles.size > 0) {
			parts.push(
				`Files modified by other agents:\n${Array.from(this.sharedContext.modifiedFiles).join("\n")}`,
			)
		}

		if (this.sharedContext.results.size > 0) {
			parts.push("Results from other agents:")
			for (const [id, result] of this.sharedContext.results) {
				const agent = this.agents.get(id)
				const label = agent ? `${agent.mode} agent` : id
				parts.push(`- ${label}: ${result.slice(0, 200)}`)
			}
		}

		return parts.length > 0
			? `[Shared Context]\n${parts.join("\n\n")}\n[End Shared Context]`
			: ""
	}

	// Run an async operation under the shared-context mutex to prevent
	// interleaved writes to Set/Map from parallel agents.
	private withSharedContextLock<T>(fn: () => Promise<T>): Promise<T> {
		const result = this.sharedContextMutex.then(fn, fn)
		this.sharedContextMutex = result.then(
			() => {},
			() => {},
		)
		return result
	}

	// Public API

	getSharedContext(): SharedContext {
		return this.sharedContext
	}

	addModifiedFile(filePath: string): void {
		this.sharedContext.modifiedFiles.add(filePath)
	}

	getActiveAgents(): AgentInfo[] {
		return Array.from(this.agents.values()).filter((a) => a.status === "running")
	}

	getAllAgents(): AgentInfo[] {
		return Array.from(this.agents.values())
	}

	async cancelAgent(agentId: string): Promise<void> {
		const task = this.activeTasks.get(agentId)
		if (task) {
			await (task as any).abortTask?.()
			this.activeTasks.delete(agentId)
		}

		const agent = this.agents.get(agentId)
		if (agent) {
			agent.status = "failed"
			agent.completedAt = Date.now()
		}
	}

	async cancelAll(): Promise<void> {
		for (const [agentId] of this.activeTasks) {
			await this.cancelAgent(agentId)
		}
	}

	resetContext(): void {
		this.sharedContext = {
			id: uuidv7(),
			modifiedFiles: new Set(),
			results: new Map(),
			metadata: new Map(),
		}
		this.agents.clear()
	}

	// --- Fork Context Methods ---

	/**
	 * Create a forked context for a subtask.
	 * The subtask gets a summarized snapshot of the parent's messages (not a shared reference).
	 * This prevents subtask conversation from polluting the parent context.
	 *
	 * @param parentMessages - The parent task's API conversation history
	 * @param taskDescription - Description of the subtask to be performed
	 * @param config - Optional forked context configuration
	 * @returns A new message array with a context bootstrap message for the subtask
	 */
	forkContextForSubtask(
		parentMessages: ApiMessage[],
		taskDescription: string,
		config?: ForkedContextConfig,
	): ApiMessage[] {
		const effectiveConfig = config ?? DEFAULT_FORKED_CONTEXT_CONFIG

		// Generate a concise summary of parent context (not exceeding summaryMaxTokens)
		const parentSummary = generateParentContextSummary(
			parentMessages,
			effectiveConfig.summaryMaxTokens,
			effectiveConfig,
		)

		// Build a bootstrap message array for the subtask with:
		// 1. A system-like context message with parent summary
		// 2. The actual task description
		const forkedMessages: ApiMessage[] = [
			{
				role: "user",
				content: [
					{
						type: "text" as const,
						text: `[Parent Context Summary]\n${parentSummary}\n[End Parent Context Summary]\n\nTask:\n${taskDescription}`,
					},
				],
				ts: Date.now(),
			},
		]

		this.outputChannel.appendLine(
			`[AgentOrchestrator] Forked context for subtask: ${parentMessages.length} parent messages → summary (${parentSummary.length} chars)`,
		)

		return forkedMessages
	}

	/**
	 * Aggregate subtask results back into parent context.
	 * Injects a structured result summary message into the parent's message array.
	 *
	 * @param subtaskResult - The result from the completed subtask
	 * @param parentMessages - The parent task's API conversation history (mutated in place)
	 * @returns The updated parent messages array
	 */
	aggregateSubtaskResult(
		subtaskResult: SubtaskResult,
		parentMessages: ApiMessage[],
	): ApiMessage[] {
		const resultMessage: ApiMessage = {
			role: "user",
			content: [
				{
					type: "text" as const,
					text: `[Subtask Result - ${subtaskResult.taskId}]\nStatus: ${subtaskResult.status}\n${subtaskResult.resultSummary}\n[End Subtask Result]`,
				},
			],
			ts: Date.now(),
		}

		parentMessages.push(resultMessage)

		this.outputChannel.appendLine(
			`[AgentOrchestrator] Aggregated subtask ${subtaskResult.taskId} result (${subtaskResult.status}) into parent context`,
		)

		return parentMessages
	}
}

import { getErrorMessage } from "../../shared/error-utils"
import { v7 as uuidv7 } from "uuid"
import * as vscode from "vscode"

import type { ClineProvider } from "../webview/ClineProvider"
import type {	Plan,
	PlanStep,
	PlanStepResult,
	PlanStepStatus,
	PlanGenerationOptions,
	PlanExecutionOptions,
} from "./types"

const PLAN_GENERATION_PROMPT = `You are a task planning assistant. Given a user's task description, generate a structured execution plan.

Output ONLY a valid JSON object with the following structure (no markdown, no explanation):
{
  "title": "Short title for the plan",
  "description": "Brief description of what the plan accomplishes",
  "steps": [
    {
      "description": "What this step does",
      "mode": "code|architect|ask|debug",
      "dependencies": []
    }
  ]
}

Rules:
- Each step should be a discrete, actionable unit of work
- Use "architect" mode for design/planning steps
- Use "code" mode for implementation steps
- Use "debug" mode for testing/debugging steps
- Use "ask" mode for research/analysis steps
- Dependencies are zero-indexed step numbers that must complete before this step
- Keep the plan concise (typically 3-8 steps)
- Order steps logically with proper dependency chains`

/**
 * PlanEngine provides Plan-and-Execute capability for the Agent.
 * It uses the LLM to generate structured plans, then executes them
 * step-by-step using the existing Task/ClineProvider infrastructure.
 */
export class PlanEngine {
	private plans: Map<string, Plan> = new Map()
	private activePlanId: string | undefined
	private abortController: AbortController | undefined

	constructor(
		private readonly provider: ClineProvider,
		private readonly outputChannel: vscode.OutputChannel,
	) {}

	async generatePlan(options: PlanGenerationOptions): Promise<Plan> {
		const { task, context, maxSteps = 10 } = options

		this.outputChannel.appendLine(`[PlanEngine] Generating plan for: ${task}`)

		const prompt = this.buildPlanGenerationPrompt(task, context, maxSteps)

		const plan = await this.callLLMForPlan(prompt)
		this.plans.set(plan.id, plan)

		this.outputChannel.appendLine(`[PlanEngine] Plan generated: ${plan.title} (${plan.steps.length} steps)`)

		return plan
	}

	async executePlan(planId: string, options: PlanExecutionOptions = {}): Promise<Plan> {
		const plan = this.plans.get(planId)
		if (!plan) {
			throw new Error(`Plan not found: ${planId}`)
		}

		if (plan.status !== "draft" && plan.status !== "approved" && plan.status !== "paused") {
			throw new Error(`Plan cannot be executed in status: ${plan.status}`)
		}

		plan.status = "executing"
		plan.updatedAt = Date.now()
		this.activePlanId = planId
		this.abortController = new AbortController()

		options.onPlanUpdate?.(plan)

		try {
			await this.executeSteps(plan, options)

			const allCompleted = plan.steps.every(
				(s) => s.status === "completed" || s.status === "skipped",
			)
			plan.status = allCompleted ? "completed" : "failed"
		} catch (error) {
			if (this.abortController?.signal.aborted) {
				plan.status = "paused"
			} else {
				plan.status = "failed"
			}
			this.outputChannel.appendLine(
				`[PlanEngine] Plan execution stopped: ${getErrorMessage(error)}`,
			)
		} finally {
			plan.updatedAt = Date.now()
			plan.completedSteps = plan.steps.filter((s) => s.status === "completed").length
			this.activePlanId = undefined
			this.abortController = undefined
			options.onPlanUpdate?.(plan)
		}

		return plan
	}

	private async executeSteps(plan: Plan, options: PlanExecutionOptions): Promise<void> {
		this.updateReadySteps(plan)

		while (this.hasExecutableSteps(plan)) {
			if (this.abortController?.signal.aborted) {
				throw new Error("Plan execution aborted")
			}

			const readySteps = plan.steps.filter((s) => s.status === "ready")
			if (readySteps.length === 0) break

			const maxParallel = options.maxParallel || 1
			const batch = readySteps.slice(0, maxParallel)

			const results = await Promise.allSettled(
				batch.map((step) => this.executeStep(plan, step, options)),
			)

			for (let i = 0; i < results.length; i++) {
				const result = results[i]
				const step = batch[i]

				if (result.status === "rejected") {
					step.status = "failed"
					step.error = result.reason instanceof Error ? result.reason.message : String(result.reason)
					step.completedAt = Date.now()

					this.cancelDependentSteps(plan, step.id)
				}

				options.onPlanUpdate?.(plan)
			}

			this.updateReadySteps(plan)
		}
	}

	private async executeStep(
		plan: Plan,
		step: PlanStep,
		options: PlanExecutionOptions,
	): Promise<PlanStepResult> {
		step.status = "running"
		step.startedAt = Date.now()
		options.onStepStart?.(step)
		options.onPlanUpdate?.(plan)

		this.outputChannel.appendLine(`[PlanEngine] Executing step ${step.index + 1}: ${step.description}`)

		try {
			const dependencyContext = this.buildDependencyContext(plan, step)
			const stepPrompt = this.buildStepPrompt(step, dependencyContext, plan)

			await this.provider.handleModeSwitch(step.mode as any)
			const task = await this.provider.createTask(stepPrompt)
			step.taskId = task.taskId

			const result = await this.waitForTaskCompletion(task)

			step.status = "completed"
			step.result = result
			step.completedAt = Date.now()
			plan.completedSteps++

			const stepResult: PlanStepResult = {
				stepId: step.id,
				status: "completed",
				result,
			}

			options.onStepComplete?.(step, stepResult)
			return stepResult
		} catch (error) {
			step.status = "failed"
			step.error = getErrorMessage(error)
			step.completedAt = Date.now()

			const stepResult: PlanStepResult = {
				stepId: step.id,
				status: "failed",
				error: step.error,
			}

			options.onStepComplete?.(step, stepResult)
			return stepResult
		}
	}

	private waitForTaskCompletion(task: any): Promise<string> {
		return new Promise((resolve, reject) => {
			const timeout = setTimeout(() => {
				reject(new Error("Task execution timed out"))
			}, 10 * 60 * 1000)

			const pollInterval = setInterval(() => {
				try {
					const messages = task.clineMessages || []
					const lastMsg = messages[messages.length - 1]

					if (lastMsg?.type === "say" && lastMsg.say === "completion_result") {
						clearInterval(pollInterval)
						clearTimeout(timeout)
						resolve(lastMsg.text || "Task completed")
					}

					if (task.didFinishAbortingStream || task.abandoned) {
						clearInterval(pollInterval)
						clearTimeout(timeout)

						const errorMsg = messages.find(
							(m: any) => m.type === "say" && m.say === "error",
						)
						if (errorMsg) {
							reject(new Error(errorMsg.text || "Task failed"))
						} else {
							resolve("Task completed (no explicit result)")
						}
					}
				} catch (error) {
					clearInterval(pollInterval)
					clearTimeout(timeout)
					reject(error)
				}
			}, 500)
		})
	}

	private buildPlanGenerationPrompt(task: string, context: string | undefined, maxSteps: number): string {
		let prompt = PLAN_GENERATION_PROMPT
		prompt += `\n\nMaximum steps: ${maxSteps}`
		if (context) {
			prompt += `\n\nAdditional context:\n${context}`
		}
		prompt += `\n\nUser's task:\n${task}`
		return prompt
	}

	private async callLLMForPlan(prompt: string): Promise<Plan> {
		const task = await this.provider.createTask(
			`You are a planning assistant. Generate a structured JSON plan for the following task. Output ONLY the JSON, no other text.\n\n${prompt}`,
		)

		const planJson = await this.waitForTaskCompletion(task)

		try {
			const parsed = JSON.parse(this.extractJson(planJson))
			return this.buildPlanFromJson(parsed)
		} catch {
			return this.buildDefaultPlan(prompt)
		}
	}

	private extractJson(text: string): string {
		const jsonMatch = text.match(/\{[\s\S]*\}/)
		return jsonMatch ? jsonMatch[0] : text
	}

	private buildPlanFromJson(json: any): Plan {
		const planId = uuidv7()
		const steps: PlanStep[] = (json.steps || []).map((s: any, index: number) => ({
			id: `${planId}-step-${index}`,
			index,
			description: s.description || `Step ${index + 1}`,
			mode: s.mode || "code",
			dependencies: (s.dependencies || []).map((d: number) => `${planId}-step-${d}`),
			status: "pending" as PlanStepStatus,
		}))

		return {
			id: planId,
			title: json.title || "Execution Plan",
			description: json.description || "",
			steps,
			status: "draft",
			createdAt: Date.now(),
			updatedAt: Date.now(),
			totalSteps: steps.length,
			completedSteps: 0,
		}
	}

	private buildDefaultPlan(task: string): Plan {
		const planId = uuidv7()
		return {
			id: planId,
			title: "Default Plan",
			description: task,
			steps: [
				{
					id: `${planId}-step-0`,
					index: 0,
					description: task,
					mode: "code",
					dependencies: [],
					status: "pending",
				},
			],
			status: "draft",
			createdAt: Date.now(),
			updatedAt: Date.now(),
			totalSteps: 1,
			completedSteps: 0,
		}
	}

	private buildStepPrompt(step: PlanStep, dependencyContext: string, plan: Plan): string {
		let prompt = `You are executing step ${step.index + 1} of ${plan.totalSteps} in the plan: "${plan.title}"\n\n`
		prompt += `Step description: ${step.description}\n`

		if (dependencyContext) {
			prompt += `\nResults from previous steps:\n${dependencyContext}\n`
		}

		prompt += `\nPlease complete this step. When done, use attempt_completion to report the result.`
		return prompt
	}

	private buildDependencyContext(plan: Plan, step: PlanStep): string {
		const parts: string[] = []
		for (const depId of step.dependencies) {
			const depStep = plan.steps.find((s) => s.id === depId)
			if (depStep?.result) {
				parts.push(`Step ${depStep.index + 1} (${depStep.description}): ${depStep.result}`)
			}
		}
		return parts.join("\n\n")
	}

	private updateReadySteps(plan: Plan): void {
		for (const step of plan.steps) {
			if (step.status !== "pending") continue

			const depsCompleted = step.dependencies.every((depId) => {
				const dep = plan.steps.find((s) => s.id === depId)
				return dep?.status === "completed" || dep?.status === "skipped"
			})

			if (depsCompleted) {
				step.status = "ready"
			}
		}
	}

	private hasExecutableSteps(plan: Plan): boolean {
		return plan.steps.some((s) => s.status === "ready" || s.status === "pending")
	}

	private cancelDependentSteps(plan: Plan, failedStepId: string): void {
		for (const step of plan.steps) {
			if (step.dependencies.includes(failedStepId) && step.status === "pending") {
				step.status = "cancelled"
				this.cancelDependentSteps(plan, step.id)
			}
		}
	}

	// Public API

	getPlan(planId: string): Plan | undefined {
		return this.plans.get(planId)
	}

	getActivePlan(): Plan | undefined {
		return this.activePlanId ? this.plans.get(this.activePlanId) : undefined
	}

	getAllPlans(): Plan[] {
		return Array.from(this.plans.values())
	}

	pausePlan(): void {
		this.abortController?.abort()
	}

	approvePlan(planId: string): Promise<void> {
		const plan = this.plans.get(planId)
		if (!plan) throw new Error(`Plan not found: ${planId}`)
		if (plan.status !== "draft") throw new Error(`Plan is not in draft status`)
		plan.status = "approved"
		plan.updatedAt = Date.now()
	}

	updateStep(planId: string, stepId: string, updates: Partial<PlanStep>): void {
		const plan = this.plans.get(planId)
		if (!plan) return

		const step = plan.steps.find((s) => s.id === stepId)
		if (!step) return

		Object.assign(step, updates)
		plan.updatedAt = Date.now()
	}

	reorderSteps(planId: string, stepIds: string[]): void {
		const plan = this.plans.get(planId)
		if (!plan) return

		const reordered: PlanStep[] = []
		for (const id of stepIds) {
			const step = plan.steps.find((s) => s.id === id)
			if (step) {
				step.index = reordered.length
				reordered.push(step)
			}
		}
		plan.steps = reordered
		plan.updatedAt = Date.now()
	}

	deletePlan(planId: string): void {
		if (this.activePlanId === planId) {
			this.pausePlan()
		}
		this.plans.delete(planId)
	}
}

/**
 * Agent Directory Loader
 *
 * Scans `.roo/agents/` for Markdown files defining custom agents.
 * Each file uses YAML frontmatter for metadata and the body for the
 * system prompt. Plugin agents are integrated via registerPluginAgent().
 *
 * Agent priority order for deduplication (highest wins):
 *   policySettings > projectSettings > userSettings > plugin > built-in
 */

import * as fs from "fs/promises"
import type { Dirent } from "fs"
import * as path from "path"
import type {
	AgentDefinition,
	CustomAgentDefinition,
	PluginAgentDefinition,
} from "./types"
import { BUILT_IN_AGENTS } from "./builtInAgents"

// ── Agent cache ──

let _cachedAgents: AgentDefinition[] | null = null
let _pluginAgents: PluginAgentDefinition[] = []

/** Register a plugin-provided agent definition */
export function registerPluginAgent(def: PluginAgentDefinition): void {
	_pluginAgents.push({ ...def, source: "plugin" })
	_cachedAgents = null // invalidate cache
}

/** Clear all plugin agent registrations */
export function clearPluginAgents(): void {
	_pluginAgents = []
	_cachedAgents = null
}

// ── YAML frontmatter parsing (lightweight, no dependency) ──

interface AgentFrontmatter {
	agentType?: string
	description?: string
	tools?: string[]
	disallowedTools?: string[]
	permissionMode?: string
	model?: string
	maxTurns?: number
	background?: boolean
	isolation?: string
	skills?: string[]
	mcpServers?: string[]
	memory?: string[]
	priority?: number
}

function parseFrontmatter(content: string): { fm: AgentFrontmatter; body: string } {
	const match = content.match(/^---\s*\n([\s\S]*?)\n---\s*\n?([\s\S]*)$/)
	if (!match) {
		return { fm: {}, body: content }
	}

	const raw = match[1] || ""
	const body = match[2] || ""

	const fm: AgentFrontmatter = {}
	for (const line of raw.split("\n")) {
		const kv = line.match(/^(\w[\w-]*)\s*:\s*(.+)$/)
		if (!kv) continue
		const key = kv[1]!
		let value: any = kv[2]!.trim()

		// Parse lists: "['a', 'b']" or "a, b, c"
		if (value.startsWith("[") && value.endsWith("]")) {
			value = value
				.slice(1, -1)
				.split(",")
				.map((s: string) => s.trim().replace(/^['"]|['"]$/g, ""))
				.filter(Boolean)
		}
		// Parse numbers
		else if (/^\d+$/.test(value)) {
			value = parseInt(value, 10)
		}
		// Parse booleans
		else if (value === "true") value = true
		else if (value === "false") value = false

		;(fm as any)[key] = value
	}

	return { fm, body }
}

// ── Directory loading ──

async function loadMarkdownAgents(
	dir: string,
	source: "userSettings" | "projectSettings",
): Promise<CustomAgentDefinition[]> {
	const results: CustomAgentDefinition[] = []

	let entries: Dirent[]
	try {
		entries = await fs.readdir(dir, { withFileTypes: true })
	} catch {
		return results // directory doesn't exist
	}

	for (const entry of entries) {
		if (!entry.isFile() || !entry.name.endsWith(".md")) continue

		const filePath = path.join(dir, entry.name)
		const raw = await fs.readFile(filePath, "utf-8")
		const { fm, body } = parseFrontmatter(raw)

		// agentType defaults to filename without extension
		const agentType = fm.agentType || path.basename(entry.name, ".md")
		const description = fm.description || `Custom agent: ${agentType}`
		const tools = fm.tools || body.match(/tools?:\s*\[([^\]]+)\]/)?.[1]?.split(/,\s*/) || ["*"]
		const priority = fm.priority ?? (source === "projectSettings" ? 200 : 150)

		results.push({
			agentType,
			description,
			source,
			tools,
			disallowedTools: fm.disallowedTools,
			permissionMode: fm.permissionMode as any,
			model: fm.model,
			maxTurns: fm.maxTurns,
			background: fm.background,
			isolation: fm.isolation as any,
			skills: fm.skills,
			mcpServers: fm.mcpServers,
			memory: fm.memory as any,
			systemPrompt: body.trim(),
			priority,
			filePath,
		})
	}

	return results
}

// ── Public API ──

/**
 * Get all available agent definitions, deduplicated by agentType.
 * Priority order: projectSettings > userSettings > plugin > built-in.
 */
export async function getAgentDefinitions(cwd?: string): Promise<AgentDefinition[]> {
	const userDir = cwd ? path.join(cwd, ".roo", "agents") : path.join(process.cwd(), ".roo", "agents")

	const [userAgents, projectAgents] = await Promise.all([
		loadMarkdownAgents(userDir, "userSettings"),
		// Project agents could also live in .roo/agents at the workspace root
		Promise.resolve([] as CustomAgentDefinition[]),
	])

	const all: AgentDefinition[] = [
		...BUILT_IN_AGENTS,
		..._pluginAgents,
		...userAgents,
		...projectAgents,
	]

	// Deduplicate: higher priority wins
	const seen = new Map<string, AgentDefinition>()
	for (const def of all) {
		const existing = seen.get(def.agentType)
		if (!existing || (def.priority ?? 0) >= (existing.priority ?? 0)) {
			seen.set(def.agentType, def)
		}
	}

	return Array.from(seen.values())
}

/** Synchronous variant using cached data (for REPL/perf-critical paths) */
export function getAgentDefinitionsSync(): AgentDefinition[] {
	if (_cachedAgents) return _cachedAgents

	const all: AgentDefinition[] = [...BUILT_IN_AGENTS, ..._pluginAgents]

	const seen = new Map<string, AgentDefinition>()
	for (const def of all) {
		const existing = seen.get(def.agentType)
		if (!existing || (def.priority ?? 0) >= (existing.priority ?? 0)) {
			seen.set(def.agentType, def)
		}
	}

	_cachedAgents = Array.from(seen.values())
	return _cachedAgents
}

/** Invalidate the agent cache (call after registering plugins or file changes) */
export function invalidateAgentCache(): void {
	_cachedAgents = null
}

import { parseJSON } from "partial-json"

import { type ToolName, toolNames, type FileEntry } from "@njust-ai-cj/types"
import { customToolRegistry } from "@njust-ai-cj/core"

import {
	type ToolUse,
	type McpToolUse,
	type ToolParamName,
	type NativeToolArgs,
	toolParamNames,
} from "../../shared/tools"
import { resolveToolAlias } from "../prompts/tools/filter-tools-for-mode"
import type {
	ApiStreamToolCallStartChunk,
	ApiStreamToolCallDeltaChunk,
	ApiStreamToolCallEndChunk,
} from "../../api/transform/stream"
import { MCP_TOOL_PREFIX, MCP_TOOL_SEPARATOR, parseMcpToolName, normalizeMcpToolName } from "../../utils/mcp-name"
import { getErrorMessage } from "../../shared/error-utils"
import { logger } from "../../shared/logger"

/**
 * Helper type to extract properly typed native arguments for a given tool.
 * Returns the type from NativeToolArgs if the tool is defined there, otherwise never.
 */
type NativeArgsFor<TName extends ToolName> = TName extends keyof NativeToolArgs ? NativeToolArgs[TName] : never

/**
 * Parser for native tool calls (OpenAI-style function calling).
 * Converts native tool call format to ToolUse format for compatibility
 * with existing tool execution infrastructure.
 *
 * For tools with refactored parsers (e.g., read_file), this parser provides
 * typed arguments via nativeArgs. Tool-specific handlers should consume
 * nativeArgs directly rather than relying on synthesized legacy params.
 */
/**
 * Event types returned from raw chunk processing.
 */
export type ToolCallStreamEvent = ApiStreamToolCallStartChunk | ApiStreamToolCallDeltaChunk | ApiStreamToolCallEndChunk

/**
 * Parser for native tool calls (OpenAI-style function calling).
 * Converts native tool call format to ToolUse format for compatibility
 * with existing tool execution infrastructure.
 *
 * For tools with refactored parsers (e.g., read_file), this parser provides
 * typed arguments via nativeArgs. Tool-specific handlers should consume
 * nativeArgs directly rather than relying on synthesized legacy params.
 *
 * This class also handles raw tool call chunk processing, converting
 * provider-level raw chunks into start/delta/end events.
 */

export class NativeToolCallParser {
	// Streaming state management for argument accumulation (keyed by tool call id)
	// Note: name is string to accommodate dynamic MCP tools (mcp--serverName--toolName)
	// Instance-level to prevent cross-task data corruption during concurrent streams.
	private streamingToolCalls = new Map<
		string,
		{
			id: string
			name: string
			argumentsAccumulator: string
		}
	>()

	// Raw chunk tracking state (keyed by index from API stream)
	private rawChunkTracker = new Map<
		number,
		{
			id: string
			name: string
			hasStarted: boolean
			deltaBuffer: string[]
		}
	>()

	/**
	 * Attempt to recover malformed tool call arguments that fail JSON.parse.
	 * Some models (e.g. DeepSeek) may output markdown-style content directly
	 * instead of proper JSON string values.
	 */
	private static tryRecoverMalformedArgs(
		toolName: string,
		rawArgs: string,
	): Record<string, unknown> | null {
		if (toolName === "update_todo_list") {
			const todosMatch = rawArgs.match(/\{"todos"\s*:\s*/)
			if (todosMatch) {
				const content = rawArgs.slice(todosMatch[0].length).replace(/\}?\s*$/, "")
				const unquoted = content.replace(/^"/, "").replace(/"$/, "")
				if (/\[[ x\-]\]/.test(unquoted)) {
					return { todos: unquoted }
				}
			}
			if (/\[[ x\-]\]/.test(rawArgs)) {
				return { todos: rawArgs.trim() }
			}
		}

		// Try extracting JSON from markdown code blocks
		const codeBlockMatch = rawArgs.match(/```(?:json)?\s*([\s\S]*?)```/)
		if (codeBlockMatch) {
			try { return JSON.parse(codeBlockMatch[1].trim()) } catch { /* ignore */ }
		}

		// Try extracting the first JSON object
		const jsonObjectMatch = rawArgs.match(/(\{[\s\S]*\})/)
		if (jsonObjectMatch) {
			try { return JSON.parse(jsonObjectMatch[1]) } catch { /* ignore */ }
		}

		// Try completing missing closing braces
		const trimmed = rawArgs.trim()
		if (trimmed.startsWith("{") && !trimmed.endsWith("}")) {
			try { return JSON.parse(trimmed + "}") } catch { /* ignore */ }
			const openBraces = (trimmed.match(/\{/g) || []).length
			const closeBraces = (trimmed.match(/\}/g) || []).length
			if (openBraces > closeBraces) {
				try { return JSON.parse(trimmed + "}".repeat(openBraces - closeBraces)) } catch { /* ignore */ }
			}
		}

		return null
	}

	/**
	 * Maps common parameter name aliases to the canonical names for each tool.
	 * Models sometimes use shorthand or alternate names that don't match the schema.
	 */
	private static readonly PARAM_ALIASES: Record<string, Record<string, string>> = {
		edit:                    { file: "file_path", path: "file_path", filename: "file_path" },
		search_and_replace:      { file: "file_path", path: "file_path", filename: "file_path" },
		edit_file:               { file: "file_path", path: "file_path", filename: "file_path" },
		search_replace:          { file: "file_path", path: "file_path", filename: "file_path" },
		read_file:               { file: "path", filepath: "path", filename: "path" },
		write_to_file:           { file: "path", filepath: "path", filename: "path" },
		apply_diff:              { file: "path", filepath: "path", filename: "path" },
		search_files:            { file: "path", filepath: "path", filename: "path" },
		list_files:              { file: "path", filepath: "path", filename: "path" },
		execute_command:         { cmd: "command", shell: "command", run: "command" },
		ask_followup_question:   { q: "question", text: "question" },
		attempt_completion:      { answer: "result", message: "result", response: "result" },
	}

	/**
	 * Remap parameter name aliases to canonical names for the given tool.
	 */
	private static remapParamAliases(toolName: string, args: Record<string, unknown>): void {
		const aliases = NativeToolCallParser.PARAM_ALIASES[toolName]
		if (!aliases) return

		for (const [oldKey, newKey] of Object.entries(aliases)) {
			if (oldKey in args && !(newKey in args)) {
				args[newKey] = args[oldKey]
				delete args[oldKey]
			}
		}
	}

	/**
	 * Coerce string values to their expected types (numbers, booleans).
	 */
	private static coerceArgTypes(args: Record<string, unknown>): void {
		const intKeys = ["offset", "limit", "timeout", "anchor_line", "max_levels",
			"max_lines", "contextLines", "expected_replacements", "count"]
		for (const key of intKeys) {
			if (typeof args[key] === "string") {
				const n = Number(args[key])
				if (Number.isFinite(n)) args[key] = Math.trunc(n)
			}
		}

		const boolKeys = ["recursive", "replace_all", "include_siblings",
			"include_header"]
		for (const key of boolKeys) {
			if (typeof args[key] === "string") {
				const lower = (args[key] as string).toLowerCase().trim()
				if (lower === "true") args[key] = true
				else if (lower === "false") args[key] = false
			}
		}
	}

	private static coerceOptionalBoolean(value: unknown): boolean | undefined {
		if (typeof value === "boolean") {
			return value
		}
		if (typeof value === "string") {
			const lower = value.trim().toLowerCase()
			if (lower === "true") {
				return true
			}
			if (lower === "false") {
				return false
			}
		}
		return undefined
	}

	/**
	 * Process a raw tool call chunk from the API stream.
	 * Handles tracking, buffering, and emits start/delta/end events.
	 *
	 * This is the entry point for providers that emit tool_call_partial chunks.
	 * Returns an array of events to be processed by the consumer.
	 */
	public processRawChunk(chunk: {
		index: number
		id?: string
		name?: string
		arguments?: string
	}): ToolCallStreamEvent[] {
		const events: ToolCallStreamEvent[] = []
		const { index, id, name, arguments: args } = chunk

		let tracked = this.rawChunkTracker.get(index)

		// Initialize new tool call tracking when we receive an id
		if (id && !tracked) {
			tracked = {
				id,
				name: name || "",
				hasStarted: false,
				deltaBuffer: [],
			}
			this.rawChunkTracker.set(index, tracked)
		}

		if (!tracked) {
			return events
		}

		// Update name if present in chunk and not yet set
		if (name) {
			tracked.name = name
		}

		// Emit start event when we have the name
		if (!tracked.hasStarted && tracked.name) {
			events.push({
				type: "tool_call_start",
				id: tracked.id,
				name: tracked.name,
			})
			tracked.hasStarted = true

			// Flush buffered deltas
			for (const bufferedDelta of tracked.deltaBuffer) {
				events.push({
					type: "tool_call_delta",
					id: tracked.id,
					delta: bufferedDelta,
				})
			}
			tracked.deltaBuffer = []
		}

		// Emit delta event for argument chunks
		if (args) {
			if (tracked.hasStarted) {
				events.push({
					type: "tool_call_delta",
					id: tracked.id,
					delta: args,
				})
			} else {
				tracked.deltaBuffer.push(args)
			}
		}

		return events
	}

	/**
	 * Process stream finish reason.
	 * Emits end events when finish_reason is 'tool_calls'.
	 */
	public processFinishReason(finishReason: string | null | undefined): ToolCallStreamEvent[] {
		const events: ToolCallStreamEvent[] = []

		if (finishReason === "tool_calls" && this.rawChunkTracker.size > 0) {
			for (const [, tracked] of this.rawChunkTracker.entries()) {
				events.push({
					type: "tool_call_end",
					id: tracked.id,
				})
			}
		}

		return events
	}

	/**
	 * Finalize any remaining tool calls that weren't explicitly ended.
	 * Should be called at the end of stream processing.
	 */
	public finalizeRawChunks(): ToolCallStreamEvent[] {
		const events: ToolCallStreamEvent[] = []

		if (this.rawChunkTracker.size > 0) {
			for (const [, tracked] of this.rawChunkTracker.entries()) {
				if (tracked.hasStarted) {
					events.push({
						type: "tool_call_end",
						id: tracked.id,
					})
				}
			}
			this.rawChunkTracker.clear()
		}

		return events
	}

	/**
	 * Clear all raw chunk tracking state.
	 * Should be called when a new API request starts.
	 */
	public clearRawChunkState(): void {
		this.rawChunkTracker.clear()
	}

	/**
	 * Start streaming a new tool call.
	 * Initializes tracking for incremental argument parsing.
	 * Accepts string to support both ToolName and dynamic MCP tools (mcp--serverName--toolName).
	 */
	public startStreamingToolCall(id: string, name: string): void {
		this.streamingToolCalls.set(id, {
			id,
			name,
			argumentsAccumulator: "",
		})
	}

	/**
	 * Clear all streaming tool call state.
	 * Should be called when a new API request starts to prevent memory leaks
	 * from interrupted streams.
	 */
	public clearAllStreamingToolCalls(): void {
		this.streamingToolCalls.clear()
	}

	/**
	 * Check if there are any active streaming tool calls.
	 * Useful for debugging and testing.
	 */
	public hasActiveStreamingToolCalls(): boolean {
		return this.streamingToolCalls.size > 0
	}

	/**
	 * Process a chunk of JSON arguments for a streaming tool call.
	 * Uses partial-json-parser to extract values from incomplete JSON immediately.
	 * Returns a partial ToolUse with currently parsed parameters.
	 */
	public processStreamingChunk(id: string, chunk: string): ToolUse | null {
		const toolCall = this.streamingToolCalls.get(id)
		if (!toolCall) {
			return null
		}

		// Accumulate the JSON string
		toolCall.argumentsAccumulator += chunk

		// For dynamic MCP tools, we don't return partial updates - wait for final
		const mcpPrefix = MCP_TOOL_PREFIX + MCP_TOOL_SEPARATOR
		if (toolCall.name.startsWith(mcpPrefix)) {
			return null
		}

		// Parse whatever we can from the incomplete JSON!
		// partial-json-parser extracts partial values (strings, arrays, objects) immediately
		try {
			const partialArgs = parseJSON(toolCall.argumentsAccumulator)

			// Resolve tool alias to canonical name
			const resolvedName = resolveToolAlias(toolCall.name) as ToolName
			// Preserve original name if it differs from resolved (i.e., it was an alias)
			const originalName = toolCall.name !== resolvedName ? toolCall.name : undefined

			// Create partial ToolUse with extracted values
			return NativeToolCallParser.createPartialToolUse(
				toolCall.id,
				resolvedName,
				partialArgs || {},
				true, // partial
				originalName,
			)
		} catch {
			// Even partial-json-parser can fail on severely malformed JSON
			// Return null and wait for next chunk
			return null
		}
	}

	/**
	 * Finalize a streaming tool call.
	 * Parses the complete JSON and returns the final ToolUse or McpToolUse.
	 */
	public finalizeStreamingToolCall(id: string): ToolUse | McpToolUse | null {
		const toolCall = this.streamingToolCalls.get(id)
		if (!toolCall) {
			return null
		}

		// Parse the complete accumulated JSON
		// Cast to any for the name since parseToolCall handles both ToolName and dynamic MCP tools
		const finalToolUse = NativeToolCallParser.parseToolCall({
			id: toolCall.id,
			name: toolCall.name as ToolName,
			arguments: toolCall.argumentsAccumulator,
		})

		// Clean up streaming state
		this.streamingToolCalls.delete(id)

		return finalToolUse
	}

	private static coerceOptionalNumber(value: unknown): number | undefined {
		if (typeof value === "number" && Number.isFinite(value)) {
			return value
		}
		if (typeof value === "string") {
			const n = Number(value)
			if (Number.isFinite(n)) {
				return n
			}
		}
		return undefined
	}

	/**
	 * Convert raw file entries from API (with line_ranges) to FileEntry objects
	 * (with lineRanges). Handles multiple formats for backward compatibility:
	 *
	 * New tuple format: { path: string, line_ranges: [[1, 50], [100, 150]] }
	 * Object format: { path: string, line_ranges: [{ start: 1, end: 50 }] }
	 * Legacy string format: { path: string, line_ranges: ["1-50"] }
	 *
	 * Returns: { path: string, lineRanges: [{ start: 1, end: 50 }] }
	 */
	private static convertFileEntries(files: unknown[]): FileEntry[] {
		return files.map((file: unknown) => {
			const f = file as Record<string, unknown>
			const entry: FileEntry = { path: f.path as string }
			if (f.line_ranges && Array.isArray(f.line_ranges)) {
				entry.lineRanges = (f.line_ranges as unknown[])
					.map((range: unknown) => {
						// Handle tuple format: [start, end]
						if (Array.isArray(range) && range.length >= 2) {
							return { start: Number(range[0]), end: Number(range[1]) }
						}
						// Handle object format: { start: number, end: number }
						if (typeof range === "object" && range !== null && "start" in range && "end" in range) {
							const r = range as { start: unknown; end: unknown }
							return { start: Number(r.start), end: Number(r.end) }
						}
						// Handle legacy string format: "1-50"
						if (typeof range === "string") {
							const match = range.match(/^(\d+)-(\d+)$/)
							if (match) {
								return { start: parseInt(match[1], 10), end: parseInt(match[2], 10) }
							}
						}
						return null
					})
					.filter((r): r is { start: number; end: number } => r !== null)
			}
			return entry
		})
	}

	/**
	 * Create a partial ToolUse from currently parsed arguments.
	 * Used during streaming to show progress.
	 * @param originalName - The original tool name as called by the model (if different from canonical name)
	 */
	private static createPartialToolUse(
		id: string,
		name: ToolName,
		partialArgs: Record<string, any>,
		partial: boolean,
		originalName?: string,
	): ToolUse | null {
		// Build stringified params for display/partial-progress UI.
		// NOTE: For streaming partial updates, we MUST populate params even for complex types
		// because tool.handlePartial() methods rely on params to show UI updates.
		const params: Partial<Record<ToolParamName, string>> = {}

		for (const [key, value] of Object.entries(partialArgs)) {
			if (toolParamNames.includes(key as ToolParamName)) {
				params[key as ToolParamName] = typeof value === "string" ? value : JSON.stringify(value)
			}
		}

		// Build partial nativeArgs based on what we have so far
		let nativeArgs: any = undefined

		// Track if legacy format was used (for telemetry)
		let usedLegacyFormat = false

		switch (name) {
			case "read_file":
				// Check for legacy format first: { files: [...] }
				// Handle both array and stringified array (some models double-stringify)
				if (partialArgs.files !== undefined) {
					let filesArray: unknown[] | null = null

					if (Array.isArray(partialArgs.files)) {
						filesArray = partialArgs.files
					} else if (typeof partialArgs.files === "string") {
						// Handle double-stringified case: files is a string containing JSON array
						try {
							const parsed = JSON.parse(partialArgs.files)
							if (Array.isArray(parsed)) {
								filesArray = parsed
							}
						} catch {
							// Not valid JSON, ignore
						}
					}

					if (filesArray && filesArray.length > 0) {
						usedLegacyFormat = true
						nativeArgs = {
							files: this.convertFileEntries(filesArray),
							_legacyFormat: true as const,
						}
					}
				}
				// New format: { path: "...", mode: "..." }
				if (!nativeArgs && partialArgs.path !== undefined) {
					const indent =
						partialArgs.indentation && typeof partialArgs.indentation === "object"
							? (partialArgs.indentation as Record<string, unknown>)
							: undefined
					nativeArgs = {
						path: partialArgs.path,
						mode: partialArgs.mode,
						offset: this.coerceOptionalNumber(partialArgs.offset),
						limit: this.coerceOptionalNumber(partialArgs.limit),
						indentation: indent
							? {
									anchor_line: this.coerceOptionalNumber(indent.anchor_line),
									max_levels: this.coerceOptionalNumber(indent.max_levels),
									max_lines: this.coerceOptionalNumber(indent.max_lines),
									include_siblings: this.coerceOptionalBoolean(indent.include_siblings),
									include_header: this.coerceOptionalBoolean(indent.include_header),
								}
							: undefined,
					}
				}
				break

			case "attempt_completion":
				if (partialArgs.result) {
					nativeArgs = { result: partialArgs.result }
				}
				break

			case "execute_command":
				if (partialArgs.command) {
					nativeArgs = {
						command: partialArgs.command,
						cwd: partialArgs.cwd,
						timeout: partialArgs.timeout,
					}
				}
				break

			case "write_to_file":
				if (partialArgs.path || partialArgs.content) {
					nativeArgs = {
						path: partialArgs.path,
						content: partialArgs.content,
					}
				}
				break

			case "ask_followup_question":
				if (partialArgs.question !== undefined || partialArgs.follow_up !== undefined) {
					nativeArgs = {
						question: partialArgs.question,
						follow_up: Array.isArray(partialArgs.follow_up) ? partialArgs.follow_up : undefined,
					}
				}
				break

			case "apply_diff":
				if (partialArgs.path !== undefined || partialArgs.diff !== undefined) {
					nativeArgs = {
						path: partialArgs.path,
						diff: partialArgs.diff,
					}
				}
				break

			case "codebase_search":
				if (partialArgs.query !== undefined) {
					nativeArgs = {
						query: partialArgs.query,
						path: partialArgs.path,
					}
				}
				break

			case "generate_image":
				if (partialArgs.prompt !== undefined || partialArgs.path !== undefined) {
					nativeArgs = {
						prompt: partialArgs.prompt,
						path: partialArgs.path,
						image: partialArgs.image,
					}
				}
				break

			case "web_search":
				if (partialArgs.search_query !== undefined) {
					nativeArgs = {
						search_query: partialArgs.search_query,
						count: this.coerceOptionalNumber(partialArgs.count),
					}
				}
				break

			case "run_slash_command":
				if (partialArgs.command !== undefined) {
					nativeArgs = {
						command: partialArgs.command,
						args: partialArgs.args,
					}
				}
				break

			case "skill":
				if (partialArgs.skill !== undefined) {
					nativeArgs = {
						skill: partialArgs.skill,
						args: partialArgs.args,
					}
				}
				break

			case "search_files":
				if (partialArgs.path !== undefined || partialArgs.regex !== undefined) {
					nativeArgs = {
						path: partialArgs.path,
						regex: partialArgs.regex,
						file_pattern: partialArgs.file_pattern,
						semantic_query: partialArgs.semantic_query,
					}
				}
				break

			case "switch_mode":
				if (partialArgs.mode_slug !== undefined || partialArgs.reason !== undefined) {
					nativeArgs = {
						mode_slug: partialArgs.mode_slug,
						reason: partialArgs.reason,
					}
				}
				break

			case "update_todo_list":
				if (partialArgs.todos !== undefined) {
					nativeArgs = {
						todos: partialArgs.todos,
					}
				}
				break

			case "use_mcp_tool":
				if (partialArgs.server_name !== undefined || partialArgs.tool_name !== undefined) {
					nativeArgs = {
						server_name: partialArgs.server_name,
						tool_name: partialArgs.tool_name,
						arguments: partialArgs.arguments,
					}
				}
				break

			case "apply_patch":
				if (partialArgs.patch !== undefined) {
					nativeArgs = {
						patch: partialArgs.patch,
					}
				}
				break

			case "search_replace":
				if (
					partialArgs.file_path !== undefined ||
					partialArgs.old_string !== undefined ||
					partialArgs.new_string !== undefined
				) {
					nativeArgs = {
						file_path: partialArgs.file_path,
						old_string: partialArgs.old_string,
						new_string: partialArgs.new_string,
					}
				}
				break

			case "edit":
			case "search_and_replace":
				if (
					partialArgs.file_path !== undefined ||
					partialArgs.old_string !== undefined ||
					partialArgs.new_string !== undefined
				) {
					nativeArgs = {
						file_path: partialArgs.file_path,
						old_string: partialArgs.old_string,
						new_string: partialArgs.new_string,
						replace_all: this.coerceOptionalBoolean(partialArgs.replace_all),
					}
				}
				break

			case "edit_file":
				if (
					partialArgs.file_path !== undefined ||
					partialArgs.old_string !== undefined ||
					partialArgs.new_string !== undefined
				) {
					nativeArgs = {
						file_path: partialArgs.file_path,
						old_string: partialArgs.old_string,
						new_string: partialArgs.new_string,
						expected_replacements: partialArgs.expected_replacements,
					}
				}
				break

			case "list_files":
				if (partialArgs.path !== undefined || partialArgs.recursive !== undefined) {
					const p = partialArgs.path
					const pathStr = typeof p === "string" ? p.trim() : ""
					nativeArgs = {
						path: pathStr || ".",
						recursive: this.coerceOptionalBoolean(partialArgs.recursive),
					}
				}
				break

			case "new_task":
				if (partialArgs.mode !== undefined || partialArgs.message !== undefined) {
					nativeArgs = {
						mode: partialArgs.mode,
						message: partialArgs.message,
						todos: partialArgs.todos,
					}
				}
				break

			default:
				if (toolNames.includes(name) || customToolRegistry.has(name)) {
					nativeArgs = partialArgs
				}
				break
		}

		const result: ToolUse = {
			type: "tool_use" as const,
			name,
			params,
			partial,
			nativeArgs,
		}

		// Preserve original name for API history when an alias was used
		if (originalName) {
			result.originalName = originalName
		}

		// Track legacy format usage for telemetry
		if (usedLegacyFormat) {
			result.usedLegacyFormat = true
		}

		return result
	}

	/**
	 * Convert a native tool call chunk to a ToolUse object.
	 *
	 * @param toolCall - The native tool call from the API stream
	 * @returns A properly typed ToolUse object
	 */
	public static parseToolCall<TName extends ToolName>(toolCall: {
		id: string
		name: TName
		arguments: string
	}): ToolUse<TName> | McpToolUse | null {
		// Check if this is a dynamic MCP tool (mcp--serverName--toolName)
		// Also handle models that output underscores instead of hyphens (mcp__serverName__toolName)
		const mcpPrefix = MCP_TOOL_PREFIX + MCP_TOOL_SEPARATOR

		if (typeof toolCall.name === "string") {
			// Normalize the tool name to handle models that output underscores instead of hyphens
			const normalizedName = normalizeMcpToolName(toolCall.name)
			if (normalizedName.startsWith(mcpPrefix)) {
				// Pass the original tool call but with normalized name for parsing
				return this.parseDynamicMcpTool({ ...toolCall, name: normalizedName })
			}
		}

		// Resolve tool alias to canonical name
		const resolvedName = resolveToolAlias(toolCall.name as string) as TName

		// Validate tool name (after alias resolution).
		if (!toolNames.includes(resolvedName as ToolName) && !customToolRegistry.has(resolvedName)) {
			logger.error("NativeToolCallParser", `Invalid tool name: ${toolCall.name} (resolved: ${resolvedName})`)
			logger.error("NativeToolCallParser", `Valid tool names:`, toolNames)
			return null
		}

		try {
			// Parse the arguments JSON string, with recovery for malformed tool calls
			let args: Record<string, unknown>
			try {
				args = toolCall.arguments === "" ? {} : JSON.parse(toolCall.arguments)
			} catch (parseError) {
				const recovered = this.tryRecoverMalformedArgs(resolvedName, toolCall.arguments)
				if (recovered) {
					args = recovered
				} else {
					throw parseError
				}
			}

			// Remap common parameter name aliases to canonical names
			this.remapParamAliases(resolvedName, args)

			// Coerce string values to expected types (numbers, booleans)
			this.coerceArgTypes(args)

			// Build stringified params for display/logging.
			// Tool execution MUST use nativeArgs (typed) and does not support legacy fallbacks.
			const params: Partial<Record<ToolParamName, string>> = {}

			for (const [key, value] of Object.entries(args)) {
				// Validate parameter name
				if (!toolParamNames.includes(key as ToolParamName) && !customToolRegistry.has(resolvedName)) {
					logger.warn("NativeToolCallParser", `Unknown parameter '${key}' for tool '${resolvedName}'`)
					logger.warn("NativeToolCallParser", `Valid param names:`, toolParamNames)
					continue
				}

				// Convert to string for legacy params format
				const stringValue = typeof value === "string" ? value : JSON.stringify(value)
				params[key as ToolParamName] = stringValue
			}

			// Build typed nativeArgs for tool execution.
			// Each case validates the minimum required parameters and constructs a properly typed
			// nativeArgs object. If validation fails, we treat the tool call as invalid and fail fast.
			let nativeArgs: NativeArgsFor<TName> | undefined = undefined

			// Track if legacy format was used (for telemetry)
			let usedLegacyFormat = false

			switch (resolvedName) {
				case "read_file":
					// Check for legacy format first: { files: [...] }
					// Handle both array and stringified array (some models double-stringify)
					if (args.files !== undefined) {
						let filesArray: unknown[] | null = null

						if (Array.isArray(args.files)) {
							filesArray = args.files
						} else if (typeof args.files === "string") {
							// Handle double-stringified case: files is a string containing JSON array
							try {
								const parsed = JSON.parse(args.files)
								if (Array.isArray(parsed)) {
									filesArray = parsed
								}
							} catch {
								// Not valid JSON, ignore
							}
						}

						if (filesArray && filesArray.length > 0) {
							usedLegacyFormat = true
							nativeArgs = {
								files: this.convertFileEntries(filesArray),
								_legacyFormat: true as const,
							} as NativeArgsFor<TName>
						}
					}
					// New format: { path: "...", mode: "..." }
					if (!nativeArgs && args.path !== undefined) {
						const indent =
							args.indentation && typeof args.indentation === "object"
								? (args.indentation as Record<string, unknown>)
								: undefined
						nativeArgs = {
							path: args.path,
							mode: args.mode,
							offset: this.coerceOptionalNumber(args.offset),
							limit: this.coerceOptionalNumber(args.limit),
							indentation: indent
								? {
										anchor_line: this.coerceOptionalNumber(indent.anchor_line),
										max_levels: this.coerceOptionalNumber(indent.max_levels),
										max_lines: this.coerceOptionalNumber(indent.max_lines),
										include_siblings: this.coerceOptionalBoolean(indent.include_siblings),
										include_header: this.coerceOptionalBoolean(indent.include_header),
									}
								: undefined,
						} as NativeArgsFor<TName>
					}
					break

				case "attempt_completion":
					if (args.result) {
						nativeArgs = { result: args.result } as NativeArgsFor<TName>
					}
					break

				case "execute_command":
					if (args.command) {
						nativeArgs = {
							command: args.command,
							cwd: args.cwd,
							timeout: args.timeout,
						} as NativeArgsFor<TName>
					}
					break

				case "apply_diff":
					if (args.path !== undefined && args.diff !== undefined) {
						nativeArgs = {
							path: args.path,
							diff: args.diff,
						} as NativeArgsFor<TName>
					}
					break

				case "edit":
				case "search_and_replace":
					if (
						args.file_path !== undefined &&
						args.old_string !== undefined &&
						args.new_string !== undefined
					) {
						nativeArgs = {
							file_path: args.file_path,
							old_string: args.old_string,
							new_string: args.new_string,
							replace_all: this.coerceOptionalBoolean(args.replace_all),
						} as NativeArgsFor<TName>
					}
					break

				case "ask_followup_question":
					if (args.question !== undefined && args.follow_up !== undefined) {
						nativeArgs = {
							question: args.question,
							follow_up: args.follow_up,
						} as NativeArgsFor<TName>
					}
					break

				case "codebase_search":
					if (args.query !== undefined) {
						nativeArgs = {
							query: args.query,
							path: args.path,
						} as NativeArgsFor<TName>
					}
					break

				case "generate_image":
					if (args.prompt !== undefined && args.path !== undefined) {
						nativeArgs = {
							prompt: args.prompt,
							path: args.path,
							image: args.image,
						} as NativeArgsFor<TName>
					}
					break

				case "web_search":
					if (args.search_query !== undefined) {
						nativeArgs = {
							search_query: args.search_query,
							count: typeof args.count === "number" ? args.count : undefined,
						} as NativeArgsFor<TName>
					}
					break

				case "run_slash_command":
					if (args.command !== undefined) {
						nativeArgs = {
							command: args.command,
							args: args.args,
						} as NativeArgsFor<TName>
					}
					break

				case "skill":
					if (args.skill !== undefined) {
						nativeArgs = {
							skill: args.skill,
							args: args.args,
						} as NativeArgsFor<TName>
					}
					break

				case "search_files":
					if (args.path !== undefined && args.regex !== undefined) {
						nativeArgs = {
							path: args.path,
							regex: args.regex,
							file_pattern: args.file_pattern,
							semantic_query: args.semantic_query,
						} as NativeArgsFor<TName>
					}
					break

				case "switch_mode":
					if (args.mode_slug !== undefined && args.reason !== undefined) {
						nativeArgs = {
							mode_slug: args.mode_slug,
							reason: args.reason,
						} as NativeArgsFor<TName>
					}
					break

				case "update_todo_list":
					if (args.todos !== undefined) {
						nativeArgs = {
							todos: args.todos,
						} as NativeArgsFor<TName>
					}
					break

				case "read_command_output":
					if (args.artifact_id !== undefined) {
						nativeArgs = {
							artifact_id: args.artifact_id,
							search: args.search,
							offset: args.offset,
							limit: args.limit,
						} as NativeArgsFor<TName>
					}
					break

				case "write_to_file":
					if (args.path !== undefined && args.content !== undefined) {
						nativeArgs = {
							path: args.path,
							content: args.content,
						} as NativeArgsFor<TName>
					}
					break

				case "use_mcp_tool":
					if (args.server_name !== undefined && args.tool_name !== undefined) {
						nativeArgs = {
							server_name: args.server_name,
							tool_name: args.tool_name,
							arguments: args.arguments,
						} as NativeArgsFor<TName>
					}
					break

				case "access_mcp_resource":
					if (args.server_name !== undefined && args.uri !== undefined) {
						nativeArgs = {
							server_name: args.server_name,
							uri: args.uri,
						} as NativeArgsFor<TName>
					}
					break

				case "apply_patch":
					if (args.patch !== undefined) {
						nativeArgs = {
							patch: args.patch,
						} as NativeArgsFor<TName>
					}
					break

				case "search_replace":
					if (
						args.file_path !== undefined &&
						args.old_string !== undefined &&
						args.new_string !== undefined
					) {
						nativeArgs = {
							file_path: args.file_path,
							old_string: args.old_string,
							new_string: args.new_string,
						} as NativeArgsFor<TName>
					}
					break

				case "edit_file":
					if (
						args.file_path !== undefined &&
						args.old_string !== undefined &&
						args.new_string !== undefined
					) {
						nativeArgs = {
							file_path: args.file_path,
							old_string: args.old_string,
							new_string: args.new_string,
							expected_replacements: args.expected_replacements,
						} as NativeArgsFor<TName>
					}
					break

				case "list_files": {
					const rawPath = args.path
					const pathNorm =
						typeof rawPath === "string"
							? rawPath.trim()
							: typeof rawPath === "number"
								? String(rawPath)
								: ""
					const coercedRec = this.coerceOptionalBoolean(args.recursive)
					nativeArgs = {
						path: pathNorm || ".",
						recursive: coercedRec ?? false,
					} as NativeArgsFor<TName>
					break
				}

				case "new_task":
					if (args.mode !== undefined && args.message !== undefined) {
						nativeArgs = {
							mode: args.mode,
							message: args.message,
							todos: args.todos,
						} as NativeArgsFor<TName>
					}
					break

				default:
					if (toolNames.includes(resolvedName as ToolName) || customToolRegistry.has(resolvedName)) {
						nativeArgs = args as NativeArgsFor<TName>
					}

					break
			}

			// Native-only: core tools must always have typed nativeArgs.
			// If we couldn't construct it, the model produced an invalid tool call payload.
			if (!nativeArgs && !customToolRegistry.has(resolvedName)) {
				throw new Error(
					`[NativeToolCallParser] Invalid arguments for tool '${resolvedName}'. ` +
						`Native tool calls require a valid JSON payload matching the tool schema. ` +
						`Received: ${JSON.stringify(args)}`,
				)
			}

			const result: ToolUse<TName> = {
				type: "tool_use" as const,
				name: resolvedName,
				params,
				partial: false, // Native tool calls are always complete when yielded
				nativeArgs,
			}

			// Preserve original name for API history when an alias was used
			if (toolCall.name !== resolvedName) {
				result.originalName = toolCall.name
			}

			// Track legacy format usage for telemetry
			if (usedLegacyFormat) {
				result.usedLegacyFormat = true
			}

			return result
		} catch (error) {
			logger.error("NativeToolCallParser", 
				`Failed to parse tool call arguments: ${getErrorMessage(error)}`,
			)

			logger.error("NativeToolCallParser", `Tool call: ${JSON.stringify(toolCall, null, 2)}`)
			return null
		}
	}

	/**
	 * Parse dynamic MCP tools (named mcp--serverName--toolName).
	 * These are generated dynamically by getMcpServerTools() and are returned
	 * as McpToolUse objects that preserve the original tool name.
	 */
	public static parseDynamicMcpTool(toolCall: { id: string; name: string; arguments: string }): McpToolUse | null {
		try {
			// Parse the arguments - these are the actual tool arguments passed directly
			const args = JSON.parse(toolCall.arguments || "{}")

			// Normalize the tool name to handle models that output underscores instead of hyphens
			// e.g., mcp__serverName__toolName -> mcp--serverName--toolName
			const normalizedName = normalizeMcpToolName(toolCall.name)

			// Extract server_name and tool_name from the tool name itself
			// Format: mcp--serverName--toolName (using -- separator)
			const parsed = parseMcpToolName(normalizedName)
			if (!parsed) {
				logger.error("NativeToolCallParser", `Invalid dynamic MCP tool name format: ${toolCall.name} (normalized: ${normalizedName})`)
				return null
			}

			const { serverName, toolName } = parsed

			const result: McpToolUse = {
				type: "mcp_tool_use" as const,
				id: toolCall.id,
				// Keep the original tool name (e.g., "mcp--serverName--toolName") for API history
				name: toolCall.name,
				serverName,
				toolName,
				arguments: args,
				partial: false,
			}

			return result
		} catch (error) {
			logger.error("NativeToolCallParser", `Failed to parse dynamic MCP tool:`, error)
			return null
		}
	}

