// Public API
// ═══════════════════════════════════════════════════════════════════

/** Task-scoped cache for EMA smoothing across manageContext calls */
const _adaptiveParamsByTask = new Map<string, AdaptiveParams>()
/** Max entries before evicting oldest (prevents unbounded growth across tasks) */
const MAX_CACHED_TASKS = 50

/**
 * Build a hierarchical context representation from flat conversation messages.
 *
 * Extracts turn-level metadata, constructs a file reference graph,
 * and computes an N×N turn self-attention matrix using CSA-inspired
 * multi-factor similarity scoring. Parameters are automatically tuned
 * based on conversation statistics (file density, write ratio, etc.)
 * with EMA smoothing across calls, scoped per taskId.
 *
 * Returns null when there are fewer than 3 turns (hierarchy provides
 * no benefit over flat evaluation in such cases).
 */
export function buildContextHierarchy(messages: ApiMessage[], taskId?: string): ContextHierarchy | null {
	// Step 1: Group into API turns (reuse existing utility)
	const turnGroups = groupMessagesByApiTurn(messages)
	if (turnGroups.length < 3) return null

	// Step 2: Extract per-turn metadata
	let globalMsgIndex = 0
	const turns: TurnMeta[] = []

	for (let ti = 0; ti < turnGroups.length; ti++) {
		const group = turnGroups[ti]
		const startMsgIndex = globalMsgIndex
		globalMsgIndex += group.length
		const endMsgIndex = globalMsgIndex - 1
		const toolInfo = extractToolInfo(group)

		turns.push({
			turnIndex: ti,
			startMsgIndex,
			endMsgIndex,
			messageCount: group.length,
			concatenatedText: concatTextBlocks(group, "user") + " " + concatTextBlocks(group, "assistant"),
			toolNames: toolInfo.names,
			toolUseCount: toolInfo.count,
			filePaths: extractFilePaths(group),
			hasError: hasErrorContent(group),
			hasWriteOp: hasWriteOperation(group),
			estimatedTokens: estimateTurnTokens(group),
		})
	}

	// Step 3: Build file reference graph
	const files = buildFileGraph(turns)

	// Step 4: Build O(1) message → turn index lookup
	const totalMessages = globalMsgIndex
	const msgToTurnIndex = new Int32Array(totalMessages)
	msgToTurnIndex.fill(-1)
	for (const turn of turns) {
		for (let i = turn.startMsgIndex; i <= turn.endMsgIndex; i++) {
			msgToTurnIndex[i] = turn.turnIndex
		}
	}

	// Step 5: Compute session stats and derive adaptive parameters
	const stats = computeSessionStats(turns, files)
	const targetParams = deriveTargetParams(stats)
	const prev = taskId ? _adaptiveParamsByTask.get(taskId) : undefined
	const adaptiveParams = prev ? emaParams(prev, targetParams) : targetParams
	if (taskId) {
		if (_adaptiveParamsByTask.size >= MAX_CACHED_TASKS && !_adaptiveParamsByTask.has(taskId)) {
			const oldest = _adaptiveParamsByTask.keys().next().value
			if (oldest) _adaptiveParamsByTask.delete(oldest)
		}
		_adaptiveParamsByTask.set(taskId, adaptiveParams)
	}

	// Step 6: Compute turn self-attention matrix with adaptive weights
	const turnAttention = computeTurnAttentionMatrix(turns, adaptiveParams)

	return {
		turns,
		files,
		turnAttention,
		turnCount: turns.length,
		msgToTurnIndex,
		adaptiveParams,
	}
}

/** Reset the EMA cache for a specific task (useful for testing or task restart) */
export function resetAdaptiveParams(taskId?: string): void {
	if (taskId) {
		_adaptiveParamsByTask.delete(taskId)
	} else {
		_adaptiveParamsByTask.clear()
	}
}

/**
 * Find which turn a message (by its global index in the messages array) belongs to.
 * Returns -1 if not found.
 */
export function findTurnIndex(hierarchy: ContextHierarchy, msgIndex: number): number {
	if (msgIndex < 0 || msgIndex >= hierarchy.msgToTurnIndex.length) return -1
	return hierarchy.msgToTurnIndex[msgIndex]
}

/**
 * Compute the mean self-attention score for a given turn.
 * This represents the turn's "centrality" in the conversation.
 */
export function computeTurnSelfAttentionMean(hierarchy: ContextHierarchy, turnIdx: number): number {
	const N = hierarchy.turnCount
	if (turnIdx < 0 || turnIdx >= N) return 0
	let sum = 0
	const base = turnIdx * N
	for (let j = 0; j < N; j++) {
		sum += hierarchy.turnAttention[base + j]
	}
	return sum / N
}

/**
 * Compute turn importance from the attention matrix.
 *
 * If a specific turnIdx is provided, returns that turn's self-attention mean.
 * Otherwise returns the average across all turns.
 *
 * Use getAllTurnImportances() to get per-turn scores as a Float64Array.
 */
export function computeTurnImportance(
	hierarchy: ContextHierarchy,
	turnIdx?: number,
): number {
	const N = hierarchy.turnCount
	if (N === 0) return 0

	if (turnIdx !== undefined) {
		return computeTurnSelfAttentionMean(hierarchy, turnIdx)
	}

	// Return the average across all turns (for telemetry)
	let total = 0
	for (let i = 0; i < N; i++) {
		total += computeTurnSelfAttentionMean(hierarchy, i)
	}
	return total / N
}

/**
 * Get the turn importance for every turn as a plain array (for sorting / telemetry).
 */
export function getAllTurnImportances(hierarchy: ContextHierarchy): Float64Array {
	const N = hierarchy.turnCount
	const result = new Float64Array(N)
	for (let i = 0; i < N; i++) {
		result[i] = computeTurnSelfAttentionMean(hierarchy, i)
	}
	return result
}

/**
 * Get the "hotness" score for a given turn based on how many other turns
 * reference the same files. Returns 0..1.
 */
export function computeFileHotness(hierarchy: ContextHierarchy, turnIdx: number): number {
	const turn = hierarchy.turns[turnIdx]
	if (!turn || turn.filePaths.size === 0) return 0

	let maxHotness = 0
	for (const fp of turn.filePaths) {
		const ref = hierarchy.files.get(fp)
		if (ref && ref.referenceCount > 1) {
			const hotness = Math.min(1, ref.referenceCount / 5)
			maxHotness = Math.max(maxHotness, hotness)
		}
	}
	return maxHotness
}

/**
 * Get the query attention: similarity between the given turn and the LAST turn.
 */
export function getQueryAttention(hierarchy: ContextHierarchy, turnIdx: number): number {
	const N = hierarchy.turnCount
	if (turnIdx < 0 || turnIdx >= N) return 0
	return hierarchy.turnAttention[turnIdx * N + (N - 1)]
}

import * as fs from "fs"
import { ApiMessage } from "../task-persistence/apiMessages"

/** Maximum number of files to restore after compaction */
export const POST_COMPACT_MAX_FILES_TO_RESTORE = 5

/** Total token budget for all restored file content */
export const POST_COMPACT_TOKEN_BUDGET = 50_000

/** Maximum tokens per individual restored file */
export const POST_COMPACT_MAX_TOKENS_PER_FILE = 5_000

/** Maximum tokens per restored skill content */
export const POST_COMPACT_MAX_TOKENS_PER_SKILL = 5_000

/** Total token budget for skill content restoration */
export const POST_COMPACT_SKILLS_TOKEN_BUDGET = 25_000

type AsyncAgentStatus = {
	description?: string
	status: "running" | "completed" | "failed"
	summary?: string | null
	error?: string | null
}

export type RestoreOptions = {
	/** Paths of recently accessed files to re-inject after compaction */
	recentFiles?: string[]
	/** Active skill names/paths with their content to restore */
	activeSkills?: Array<{ name: string; path?: string; content: string }>
	/** MCP instructions delta to re-announce */
	mcpDelta?: string
	/** Deferred tools delta to re-announce (JSON text) */
	toolsDelta?: string
	/** Agent listing delta to re-announce */
	agentListingDelta?: string
	/** Plan file content and path (if user is working with a plan) */
	planFile?: { path: string; content: string } | null
	/** Whether the user is in plan mode */
	isPlanMode?: boolean
	/** Status of background async agents */
	asyncAgents?: AsyncAgentStatus[]
	/** Messages preserved post-compaction (skip re-injecting files visible here) */
	preservedMessages?: ApiMessage[]
}

/**
 * Estimate token count for a given text (~4 chars per token).
 */
function estimateTokens(text: string): number {
	return Math.ceil(text.length / 4)
}

/**
 * Truncate content to fit within a token budget, keeping head and tail
 * with a truncation marker in between.
 */
function truncateToTokenBudget(content: string, maxTokens: number): string {
	const maxChars = maxTokens * 4
	if (content.length <= maxChars) return content
	const headChars = Math.floor(maxChars * 0.6)
	const tailChars = Math.floor(maxChars * 0.3)
	const omittedTokens = estimateTokens(content) - maxTokens
	return (
		content.slice(0, headChars) +
		`\n\n... [truncated: ${omittedTokens} tokens omitted] ...\n\n` +
		content.slice(-tailChars)
	)
}

/**
 * Post-compact context restoration: reads recent files from disk and injects
 * their content (within a token budget) back into the conversation after compaction.
 * Also restores plan state, plan mode instructions, async agent status,
 * skill content, and deferred tools/MCP deltas.
 *
 * Each restoration category has its own token budget to prevent any single
 * category from consuming the entire post-compact headroom.
 */
/**
 * Scan preserved messages for Read tool_use blocks and collect their file_path
 * inputs (normalized). Used to skip re-injecting files already visible in the
 * preserved tail after compaction.
 */
export function collectReadToolFilePaths(preservedMessages: ApiMessage[]): Set<string> {
	const paths = new Set<string>()
	for (const msg of preservedMessages) {
		if (msg.role !== "assistant" || !Array.isArray(msg.content)) continue
		for (const block of msg.content as any[]) {
			if (block.type !== "tool_use") continue
			const name = block.name || ""
			// Only consider read-like tools — writes are worth re-injecting
			if (!/^(read_file|search_files|grep_search|list_files|glob)$/.test(name)) continue
			const input = block.input
			if (input && typeof input === "object") {
				const filePath = input.filePath || input.path || input.file_path
				if (typeof filePath === "string" && filePath.length > 0) {
					paths.add(filePath)
				}
			}
		}
	}
	return paths
}

export function postCompactRestore(messages: ApiMessage[], options?: RestoreOptions): ApiMessage[] {
	if (!options) return messages

	const restoredParts: string[] = []

	// 1. File restoration (budget: POST_COMPACT_TOKEN_BUDGET, per-file: POST_COMPACT_MAX_TOKENS_PER_FILE)
	if (options.recentFiles && options.recentFiles.length > 0) {
		// Dedup: skip files already visible in preserved messages
		const preservedPaths = options.preservedMessages
			? collectReadToolFilePaths(options.preservedMessages)
			: new Set<string>()

		let fileTokensUsed = 0
		const filesToRestore = options.recentFiles
			.filter((f) => !preservedPaths.has(f))
			.slice(0, POST_COMPACT_MAX_FILES_TO_RESTORE)
		for (const filePath of filesToRestore) {
			if (fileTokensUsed >= POST_COMPACT_TOKEN_BUDGET) break
			try {
				const content = fs.readFileSync(filePath, "utf-8")
				const remainingBudget = Math.min(
					POST_COMPACT_MAX_TOKENS_PER_FILE,
					POST_COMPACT_TOKEN_BUDGET - fileTokensUsed,
				)
				const truncated = truncateToTokenBudget(content, remainingBudget)
				const tokens = estimateTokens(truncated)
				fileTokensUsed += tokens
				restoredParts.push(`### File: ${filePath}\n\`\`\`\n${truncated}\n\`\`\``)
			} catch {
				restoredParts.push(`### File: ${filePath}\n(file no longer available)`)
			}
		}
	}

	// 2. Skill content restoration (budget: POST_COMPACT_SKILLS_TOKEN_BUDGET, per-skill: POST_COMPACT_MAX_TOKENS_PER_SKILL)
	if (options.activeSkills && options.activeSkills.length > 0) {
		let skillTokensUsed = 0
		// Sort by recency (assumes caller passes most-recent-first)
		for (const skill of options.activeSkills) {
			if (skillTokensUsed >= POST_COMPACT_SKILLS_TOKEN_BUDGET) break
			const remainingBudget = Math.min(
				POST_COMPACT_MAX_TOKENS_PER_SKILL,
				POST_COMPACT_SKILLS_TOKEN_BUDGET - skillTokensUsed,
			)
			const truncated = truncateToTokenBudget(skill.content, remainingBudget)
			const tokens = estimateTokens(truncated)
			skillTokensUsed += tokens
			const label = skill.path ? `${skill.name} (${skill.path})` : skill.name
			restoredParts.push(
				`### Active Skill: ${label}\n\`\`\`\n${truncated}\n\`\`\`\n` +
				`[... skill content may be truncated; re-read the skill file if you need full context]`,
			)
		}
	}

	// 3. Plan file restoration
	if (options.planFile?.content) {
		const truncated = truncateToTokenBudget(options.planFile.content, POST_COMPACT_MAX_TOKENS_PER_FILE)
		restoredParts.push(`### Plan File: ${options.planFile.path}\n\`\`\`\n${truncated}\n\`\`\``)
	}

	// 4. Plan mode reminder
	if (options.isPlanMode) {
		restoredParts.push(
			`### Plan Mode Active\n` +
			`The user is in plan mode. Do NOT make edits or run tools without explicit approval. ` +
			`Present your plan and wait for the user to approve before implementing.`,
		)
	}

	// 5. Async agent status
	if (options.asyncAgents && options.asyncAgents.length > 0) {
		for (const agent of options.asyncAgents) {
			const desc = agent.description ? ` — ${agent.description}` : ""
			const detail =
				agent.status === "running"
					? ` (in progress${agent.summary ? `: ${agent.summary}` : ""})`
					: agent.status === "failed"
						? ` (failed${agent.error ? `: ${agent.error}` : ""})`
						: " (completed, results may be available)"
			restoredParts.push(`### Background Agent${desc}${detail}`)
		}
	}

	// 6. MCP instructions delta
	if (options.mcpDelta && options.mcpDelta.trim().length > 0) {
		const mcpText = options.mcpDelta.trim().slice(0, 2000)
		restoredParts.push(`### MCP Context\n${mcpText}`)
	}

	// 7. Deferred tools delta
	if (options.toolsDelta && options.toolsDelta.trim().length > 0) {
		const toolsText = options.toolsDelta.trim().slice(0, 2000)
		restoredParts.push(`### Available Tools Update\n${toolsText}`)
	}

	// 8. Agent listing delta
	if (options.agentListingDelta && options.agentListingDelta.trim().length > 0) {
		const agentText = options.agentListingDelta.trim().slice(0, 2000)
		restoredParts.push(`### Available Agents\n${agentText}`)
	}

	if (restoredParts.length === 0) return messages

	const restoreMessage: ApiMessage = {
		role: "user",
		content:
			`<system-reminder>\n` +
			`[Context restored after compaction — these resources were recently used and are re-injected so you don't have to re-read them]\n\n` +
			`${restoredParts.join("\n\n")}\n` +
			`</system-reminder>`,
		ts: Date.now(),
	}

	return [...messages, restoreMessage]
}

import { APIError } from "openai"

export function checkContextWindowExceededError(error: unknown): boolean {
	return (
		checkIsOpenAIContextWindowError(error) ||
		checkIsOpenRouterContextWindowError(error) ||
		checkIsAnthropicContextWindowError(error)
	)
}

function checkIsOpenRouterContextWindowError(error: unknown): boolean {
	try {
		if (!error || typeof error !== "object") {
			return false
		}

		// Use Record<string, any> for proper type narrowing
		const err = error as Record<string, any>
		const status = err.status ?? err.code ?? err.error?.status ?? err.response?.status
		const message: string = String(err.message || err.error?.message || "")

		// Known OpenAI/OpenRouter-style signal (code 400 and message includes "context length")
		const CONTEXT_ERROR_PATTERNS = [
			/\bcontext\s*(?:length|window)\b/i,
			/\bmaximum\s*context\b/i,
			/\b(?:input\s*)?tokens?\s*exceed/i,
			/\btoo\s*many\s*tokens?\b/i,
		] as const

		return String(status) === "400" && CONTEXT_ERROR_PATTERNS.some((pattern) => pattern.test(message))
	} catch {
		return false
	}
}

// Docs: https://platform.openai.com/docs/guides/error-codes/api-errors
function checkIsOpenAIContextWindowError(error: unknown): boolean {
	try {
		// Check for LengthFinishReasonError
		if (error && typeof error === "object" && "name" in error && error.name === "LengthFinishReasonError") {
			return true
		}

		const KNOWN_CONTEXT_ERROR_SUBSTRINGS = ["token", "context length"] as const

		return (
			Boolean(error) &&
			error instanceof APIError &&
			error.code?.toString() === "400" &&
			KNOWN_CONTEXT_ERROR_SUBSTRINGS.some((substring) => error.message.includes(substring))
		)
	} catch {
		return false
	}
}

function checkIsAnthropicContextWindowError(response: unknown): boolean {
	try {
		// Type guard to safely access properties
		if (!response || typeof response !== "object") {
			return false
		}

		// Use type assertions with proper checks
		const res = response as Record<string, any>

		// Check for Anthropic-specific error structure with more specific validation
		if (res.error?.error?.type === "invalid_request_error") {
			const message: string = String(res.error?.error?.message || "")

			// More specific patterns for context window errors
			const contextWindowPatterns = [
				/prompt is too long/i,
				/maximum.*tokens/i,
				/context.*too.*long/i,
				/exceeds.*context/i,
				/token.*limit/i,
				/context_length_exceeded/i,
				/max_tokens_to_sample/i,
			]

			// Additional check for Anthropic-specific error codes
			const errorCode = res.error?.error?.code
			if (errorCode === "context_length_exceeded" || errorCode === "invalid_request_error") {
				return contextWindowPatterns.some((pattern) => pattern.test(message))
			}

			return contextWindowPatterns.some((pattern) => pattern.test(message))
		}

		return false
	} catch {
		return false
	}
}

import { parsePatch, createTwoFilesPatch } from "diff"

/**
 * Diff utilities for backend (extension) use.
 * Source of truth for diff normalization and stats.
 */

export interface DiffStats {
	added: number
	removed: number
}

/**
 * Remove non-semantic diff noise like "No newline at end of file"
 */
export function sanitizeUnifiedDiff(diff: string): string {
	if (!diff) return diff
	return diff.replace(/\r\n/g, "\n").replace(/(^|\n)[ \t]*(?:\\ )?No newline at end of file[ \t]*(?=\n|$)/gi, "$1")
}

/**
 * Compute +/− counts from a unified diff (ignores headers/hunk lines)
 */
export function computeUnifiedDiffStats(diff?: string): DiffStats | null {
	if (!diff) return null

	try {
		const patches = parsePatch(diff)
		if (!patches || patches.length === 0) return null

		let added = 0
		let removed = 0

		for (const p of patches) {
			for (const h of (p as any).hunks ?? []) {
				for (const l of h.lines ?? []) {
					const ch = (l as string)[0]
					if (ch === "+") added++
					else if (ch === "-") removed++
				}
			}
		}

		if (added > 0 || removed > 0) return { added, removed }
		return { added: 0, removed: 0 }
	} catch {
		// If parsing fails for any reason, signal no stats
		return null
	}
}

/**
 * Compute diff stats from any supported diff format (unified or search-replace)
 * Tries unified diff format first, then falls back to search-replace format
 */
export function computeDiffStats(diff?: string): DiffStats | null {
	if (!diff) return null
	return computeUnifiedDiffStats(diff)
}

/**
 * Build a unified diff for a brand new file (all content lines are additions).
 * Trailing newline is ignored for line counting and emission.
 */
export function convertNewFileToUnifiedDiff(content: string, filePath?: string): string {
	const newFileName = filePath || "file"
	// Normalize EOLs; rely on library for unified patch formatting
	const normalized = (content || "").replace(/\r\n/g, "\n")
	// Old file is empty (/dev/null), new file has content; zero context to show all lines as additions
	return createTwoFilesPatch("/dev/null", newFileName, "", normalized, undefined, undefined, { context: 0 })
}

import { distance } from "fastest-levenshtein"

import { ToolProgressStatus } from "@njust-ai-cj/types"

import { addLineNumbers, everyLineHasLineNumbers, stripLineNumbers } from "../../../integrations/misc/extract-text"
import { ToolUse, DiffStrategy, DiffResult } from "../../../shared/tools"
import { normalizeString } from "../../../utils/text-normalization"

const BUFFER_LINES = 40 // Number of extra context lines to show before and after matches

function getSimilarity(original: string, search: string): number {
	// Empty searches are no longer supported
	if (search === "") {
		return 0
	}

	// Use the normalizeString utility to handle smart quotes and other special characters
	const normalizedOriginal = normalizeString(original)
	const normalizedSearch = normalizeString(search)

	if (normalizedOriginal === normalizedSearch) {
		return 1
	}

	// Calculate Levenshtein distance using fastest-levenshtein's distance function
	const dist = distance(normalizedOriginal, normalizedSearch)

	// Calculate similarity ratio (0 to 1, where 1 is an exact match)
	const maxLength = Math.max(normalizedOriginal.length, normalizedSearch.length)
	return 1 - dist / maxLength
}

/**
 * Performs a "middle-out" search of `lines` (between [startIndex, endIndex]) to find
 * the slice that is most similar to `searchChunk`. Returns the best score, index, and matched text.
 */
function fuzzySearch(lines: string[], searchChunk: string, startIndex: number, endIndex: number) {
	let bestScore = 0
	let bestMatchIndex = -1
	let bestMatchContent = ""
	const searchLen = searchChunk.split(/\r?\n/).length

	// Middle-out from the midpoint
	const midPoint = Math.floor((startIndex + endIndex) / 2)
	let leftIndex = midPoint
	let rightIndex = midPoint + 1

	while (leftIndex >= startIndex || rightIndex <= endIndex - searchLen) {
		if (leftIndex >= startIndex) {
			const originalChunk = lines.slice(leftIndex, leftIndex + searchLen).join("\n")
			const similarity = getSimilarity(originalChunk, searchChunk)
			if (similarity > bestScore) {
				bestScore = similarity
				bestMatchIndex = leftIndex
				bestMatchContent = originalChunk
			}
			leftIndex--
		}

		if (rightIndex <= endIndex - searchLen) {
			const originalChunk = lines.slice(rightIndex, rightIndex + searchLen).join("\n")
			const similarity = getSimilarity(originalChunk, searchChunk)
			if (similarity > bestScore) {
				bestScore = similarity
				bestMatchIndex = rightIndex
				bestMatchContent = originalChunk
			}
			rightIndex++
		}
	}

	return { bestScore, bestMatchIndex, bestMatchContent }
}

export class MultiSearchReplaceDiffStrategy implements DiffStrategy {
	private fuzzyThreshold: number
	private bufferLines: number

	getName(): string {
		return "MultiSearchReplace"
	}

	constructor(fuzzyThreshold?: number, bufferLines?: number) {
		// Use provided threshold or default to exact matching (1.0)
		// Note: fuzzyThreshold is inverted in UI (0% = 1.0, 10% = 0.9)
		// so we use it directly here
		this.fuzzyThreshold = fuzzyThreshold ?? 1.0
		this.bufferLines = bufferLines ?? BUFFER_LINES
	}

	private unescapeMarkers(content: string): string {
		return content
			.replace(/^\\<<<<<<</gm, "<<<<<<<")
			.replace(/^\\=======/gm, "=======")
			.replace(/^\\>>>>>>>/gm, ">>>>>>>")
			.replace(/^\\-------/gm, "-------")
			.replace(/^\\:end_line:/gm, ":end_line:")
			.replace(/^\\:start_line:/gm, ":start_line:")
	}

	private validateMarkerSequencing(diffContent: string): { success: boolean; error?: string } {
		enum State {
			START,
			AFTER_SEARCH,
			AFTER_SEPARATOR,
		}
		const state = { current: State.START, line: 0 }

		// Pattern allows optional '>' after SEARCH to handle AI-generated diffs
		// (e.g., Sonnet 4 sometimes adds an extra '>')
		const SEARCH_PATTERN = /^<<<<<<< SEARCH>?$/
		const SEARCH = SEARCH_PATTERN.source.replace(/[\^$]/g, "") // Remove regex anchors for display
		const SEP = "======="
		const REPLACE = ">>>>>>> REPLACE"
		const SEARCH_PREFIX = "<<<<<<<"
		const REPLACE_PREFIX = ">>>>>>>"

		const reportMergeConflictError = (found: string, _expected: string) => ({
			success: false,
			error:
				`ERROR: Special marker '${found}' found in your diff content at line ${state.line}:\n` +
				"\n" +
				`When removing merge conflict markers like '${found}' from files, you MUST escape them\n` +
				"in your SEARCH section by prepending a backslash (\\) at the beginning of the line:\n" +
				"\n" +
				"CORRECT FORMAT:\n\n" +
				"<<<<<<< SEARCH\n" +
				"content before\n" +
				`\\${found}    <-- Note the backslash here in this example\n` +
				"content after\n" +
				"=======\n" +
				"replacement content\n" +
				">>>>>>> REPLACE\n" +
				"\n" +
				"Without escaping, the system confuses your content with diff syntax markers.\n" +
				"You may use multiple diff blocks in a single diff request, but ANY of ONLY the following separators that occur within SEARCH or REPLACE content must be escaped, as follows:\n" +
				`\\${SEARCH}\n` +
				`\\${SEP}\n` +
				`\\${REPLACE}\n`,
		})

		const reportInvalidDiffError = (found: string, expected: string) => ({
			success: false,
			error:
				`ERROR: Diff block is malformed: marker '${found}' found in your diff content at line ${state.line}. Expected: ${expected}\n` +
				"\n" +
				"CORRECT FORMAT:\n\n" +
				"<<<<<<< SEARCH\n" +
				":start_line: (required) The line number of original content where the search block starts.\n" +
				"-------\n" +
				"[exact content to find including whitespace]\n" +
				"=======\n" +
				"[new content to replace with]\n" +
				">>>>>>> REPLACE\n",
		})

		const reportLineMarkerInReplaceError = (marker: string) => ({
			success: false,
			error:
				`ERROR: Invalid line marker '${marker}' found in REPLACE section at line ${state.line}\n` +
				"\n" +
				"Line markers (:start_line: and :end_line:) are only allowed in SEARCH sections.\n" +
				"\n" +
				"CORRECT FORMAT:\n" +
				"<<<<<<< SEARCH\n" +
				":start_line:5\n" +
				"content to find\n" +
				"=======\n" +
				"replacement content\n" +
				">>>>>>> REPLACE\n" +
				"\n" +
				"INCORRECT FORMAT:\n" +
				"<<<<<<< SEARCH\n" +
				"content to find\n" +
				"=======\n" +
				":start_line:5    <-- Invalid location\n" +
				"replacement content\n" +
				">>>>>>> REPLACE\n",
		})

		const lines = diffContent.split("\n")
		const searchCount = lines.filter((l) => SEARCH_PATTERN.test(l.trim())).length
		const sepCount = lines.filter((l) => l.trim() === SEP).length
		const replaceCount = lines.filter((l) => l.trim() === REPLACE).length

		const likelyBadStructure = searchCount !== replaceCount || sepCount < searchCount

		for (const line of diffContent.split("\n")) {
			state.line++
			const marker = line.trim()

			// Check for line markers in REPLACE sections (but allow escaped ones)
			if (state.current === State.AFTER_SEPARATOR) {
				if (marker.startsWith(":start_line:") && !line.trim().startsWith("\\:start_line:")) {
					return reportLineMarkerInReplaceError(":start_line:")
				}
				if (marker.startsWith(":end_line:") && !line.trim().startsWith("\\:end_line:")) {
					return reportLineMarkerInReplaceError(":end_line:")
				}
			}

			switch (state.current) {
				case State.START:
					if (marker === SEP)
						return likelyBadStructure
							? reportInvalidDiffError(SEP, SEARCH)
							: reportMergeConflictError(SEP, SEARCH)
					if (marker === REPLACE) return reportInvalidDiffError(REPLACE, SEARCH)
					if (marker.startsWith(REPLACE_PREFIX)) return reportMergeConflictError(marker, SEARCH)
					if (SEARCH_PATTERN.test(marker)) state.current = State.AFTER_SEARCH
					else if (marker.startsWith(SEARCH_PREFIX)) return reportMergeConflictError(marker, SEARCH)
					break

				case State.AFTER_SEARCH:
					if (SEARCH_PATTERN.test(marker)) return reportInvalidDiffError(SEARCH_PATTERN.source, SEP)
					if (marker.startsWith(SEARCH_PREFIX)) return reportMergeConflictError(marker, SEARCH)
					if (marker === REPLACE) return reportInvalidDiffError(REPLACE, SEP)
					if (marker.startsWith(REPLACE_PREFIX)) return reportMergeConflictError(marker, SEARCH)
					if (marker === SEP) state.current = State.AFTER_SEPARATOR
					break

				case State.AFTER_SEPARATOR:
					if (SEARCH_PATTERN.test(marker)) return reportInvalidDiffError(SEARCH_PATTERN.source, REPLACE)
					if (marker.startsWith(SEARCH_PREFIX)) return reportMergeConflictError(marker, REPLACE)
					if (marker === SEP)
						return likelyBadStructure
							? reportInvalidDiffError(SEP, REPLACE)
							: reportMergeConflictError(SEP, REPLACE)
					if (marker === REPLACE) state.current = State.START
					else if (marker.startsWith(REPLACE_PREFIX)) return reportMergeConflictError(marker, REPLACE)
					break
			}
		}

		return state.current === State.START
			? { success: true }
			: {
					success: false,
					error: `ERROR: Unexpected end of sequence: Expected '${
						state.current === State.AFTER_SEARCH ? "=======" : ">>>>>>> REPLACE"
					}' was not found.`,
				}
	}

	applyDiff(
		originalContent: string,
		diffContent: string,
		_paramStartLine?: number,
		_paramEndLine?: number,
	): Promise<DiffResult> {
		const validseq = this.validateMarkerSequencing(diffContent)
		if (!validseq.success) {
			return {
				success: false,
				error: validseq.error!,
			}
		}

		/*
			Regex parts:
			
			1. (?:^|\n)  
			  Ensures the first marker starts at the beginning of the file or right after a newline.

			2. (?<!\\)<<<<<<< SEARCH\s*\n  
			  Matches the line "<<<<<<< SEARCH" (ignoring any trailing spaces) – the negative lookbehind makes sure it isn't escaped.

			3. ((?:\:start_line:\s*(\d+)\s*\n))?  
			  Optionally matches a ":start_line:" line. The outer capturing group is group 1 and the inner (\d+) is group 2.

			4. ((?:\:end_line:\s*(\d+)\s*\n))?  
			  Optionally matches a ":end_line:" line. Group 3 is the whole match and group 4 is the digits.

			5. ((?<!\\)-------\s*\n)?  
			  Optionally matches the "-------" marker line (group 5).

			6. ([\s\S]*?)(?:\n)?  
			  Non‐greedy match for the "search content" (group 6) up to the next marker.

			7. (?:(?<=\n)(?<!\\)=======\s*\n)  
			  Matches the "=======" marker on its own line.

			8. ([\s\S]*?)(?:\n)?  
			  Non‐greedy match for the "replace content" (group 7).

			9. (?:(?<=\n)(?<!\\)>>>>>>> REPLACE)(?=\n|$)  
			  Matches the final ">>>>>>> REPLACE" marker on its own line (and requires a following newline or the end of file).
		*/

		const matches = [
			...diffContent.matchAll(
				/(?:^|\n)(?<!\\)<<<<<<< SEARCH>?\s*\n((?:\:start_line:\s*(\d+)\s*\n))?((?:\:end_line:\s*(\d+)\s*\n))?((?<!\\)-------\s*\n)?([\s\S]*?)(?:\n)?(?:(?<=\n)(?<!\\)=======\s*\n)([\s\S]*?)(?:\n)?(?:(?<=\n)(?<!\\)>>>>>>> REPLACE)(?=\n|$)/g,
			),
		]

		if (matches.length === 0) {
			return {
				success: false,
				error: `Invalid diff format - missing required sections\n\nDebug Info:\n- Expected Format: <<<<<<< SEARCH\\n:start_line: start line\\n-------\\n[search content]\\n=======\\n[replace content]\\n>>>>>>> REPLACE\n- Tip: Make sure to include start_line/SEARCH/=======/REPLACE sections with correct markers on new lines`,
			}
		}
		// Detect line ending from original content
		const lineEnding = originalContent.includes("\r\n") ? "\r\n" : "\n"
		let resultLines = originalContent.split(/\r?\n/)
		let delta = 0
		const diffResults: DiffResult[] = []
		let appliedCount = 0
		const replacements = matches
			.map((match) => ({
				startLine: Number(match[2] ?? 0),
				searchContent: match[6],
				replaceContent: match[7],
			}))
			.sort((a, b) => a.startLine - b.startLine)

		for (const replacement of replacements) {
			let { searchContent, replaceContent } = replacement
			let startLine = replacement.startLine + (replacement.startLine === 0 ? 0 : delta)

			// First unescape any escaped markers in the content
			searchContent = this.unescapeMarkers(searchContent)
			replaceContent = this.unescapeMarkers(replaceContent)

			// Strip line numbers from search and replace content if every line starts with a line number
			const hasAllLineNumbers =
				(everyLineHasLineNumbers(searchContent) && everyLineHasLineNumbers(replaceContent)) ||
				(everyLineHasLineNumbers(searchContent) && replaceContent.trim() === "")

			if (hasAllLineNumbers && startLine === 0) {
				startLine = parseInt(searchContent.split("\n")[0].split("|")[0])
			}

			if (hasAllLineNumbers) {
				searchContent = stripLineNumbers(searchContent)
				replaceContent = stripLineNumbers(replaceContent)
			}

			// Validate that search and replace content are not identical
			if (searchContent === replaceContent) {
				diffResults.push({
					success: false,
					error:
						`Search and replace content are identical - no changes would be made\n\n` +
						`Debug Info:\n` +
						`- Search and replace must be different to make changes\n` +
						`- Use read_file to verify the content you want to change`,
				})
				continue
			}

			// Split content into lines, handling both \n and \r\n
			let searchLines = searchContent === "" ? [] : searchContent.split(/\r?\n/)
			let replaceLines = replaceContent === "" ? [] : replaceContent.split(/\r?\n/)

			// Validate that search content is not empty
			if (searchLines.length === 0) {
				diffResults.push({
					success: false,
					error: `Empty search content is not allowed\n\nDebug Info:\n- Search content cannot be empty\n- For insertions, provide a specific line using :start_line: and include content to search for\n- For example, match a single line to insert before/after it`,
				})
				continue
			}

			const endLine = replacement.startLine + searchLines.length - 1

			// Initialize search variables
			let matchIndex = -1
			let bestMatchScore = 0
			let bestMatchContent = ""
			const searchChunk = searchLines.join("\n")

			// Determine search bounds
			let searchStartIndex = 0
			let searchEndIndex = resultLines.length

			// Validate and handle line range if provided
			if (startLine) {
				// Convert to 0-based index
				const exactStartIndex = startLine - 1
				const searchLen = searchLines.length
				const exactEndIndex = exactStartIndex + searchLen - 1

				// Try exact match first
				const originalChunk = resultLines.slice(exactStartIndex, exactEndIndex + 1).join("\n")
				const similarity = getSimilarity(originalChunk, searchChunk)
				if (similarity >= this.fuzzyThreshold) {
					matchIndex = exactStartIndex
					bestMatchScore = similarity
					bestMatchContent = originalChunk
				} else {
					// Set bounds for buffered search
					searchStartIndex = Math.max(0, startLine - (this.bufferLines + 1))
					searchEndIndex = Math.min(resultLines.length, startLine + searchLines.length + this.bufferLines)
				}
			}

			// If no match found yet, try middle-out search within bounds
			if (matchIndex === -1) {
				const {
					bestScore,
					bestMatchIndex,
					bestMatchContent: midContent,
				} = fuzzySearch(resultLines, searchChunk, searchStartIndex, searchEndIndex)
				matchIndex = bestMatchIndex
				bestMatchScore = bestScore
				bestMatchContent = midContent
			}

			// Try aggressive line number stripping as a fallback if regular matching fails
			if (matchIndex === -1 || bestMatchScore < this.fuzzyThreshold) {
				// Strip both search and replace content once (simultaneously)
				const aggressiveSearchContent = stripLineNumbers(searchContent, true)
				const aggressiveReplaceContent = stripLineNumbers(replaceContent, true)

				const aggressiveSearchLines = aggressiveSearchContent ? aggressiveSearchContent.split(/\r?\n/) : []
				const aggressiveSearchChunk = aggressiveSearchLines.join("\n")

				// Try middle-out search again with aggressive stripped content (respecting the same search bounds)
				const {
					bestScore,
					bestMatchIndex,
					bestMatchContent: aggContent,
				} = fuzzySearch(resultLines, aggressiveSearchChunk, searchStartIndex, searchEndIndex)
				if (bestMatchIndex !== -1 && bestScore >= this.fuzzyThreshold) {
					matchIndex = bestMatchIndex
					bestMatchScore = bestScore
					bestMatchContent = aggContent
					// Replace the original search/replace with their stripped versions
					searchContent = aggressiveSearchContent
					replaceContent = aggressiveReplaceContent
					searchLines = aggressiveSearchLines
					replaceLines = replaceContent ? replaceContent.split(/\r?\n/) : []
				} else {
					// No match found with either method
					const originalContentSection =
						startLine !== undefined && endLine !== undefined
							? `\n\nOriginal Content:\n${addLineNumbers(
									resultLines
										.slice(
											Math.max(0, startLine - 1 - this.bufferLines),
											Math.min(resultLines.length, endLine + this.bufferLines),
										)
										.join("\n"),
									Math.max(1, startLine - this.bufferLines),
								)}`
							: `\n\nOriginal Content:\n${addLineNumbers(resultLines.join("\n"))}`

					const bestMatchSection = bestMatchContent
						? `\n\nBest Match Found:\n${addLineNumbers(bestMatchContent, matchIndex + 1)}`
						: `\n\nBest Match Found:\n(no match)`

					const lineRange = startLine ? ` at line: ${startLine}` : ""

					diffResults.push({
						success: false,
						error: `No sufficiently similar match found${lineRange} (${Math.floor(bestMatchScore * 100)}% similar, needs ${Math.floor(this.fuzzyThreshold * 100)}%)\n\nDebug Info:\n- Similarity Score: ${Math.floor(bestMatchScore * 100)}%\n- Required Threshold: ${Math.floor(this.fuzzyThreshold * 100)}%\n- Search Range: ${startLine ? `starting at line ${startLine}` : "start to end"}\n- Tried both standard and aggressive line number stripping\n- Tip: Use the read_file tool to get the latest content of the file before attempting to use the apply_diff tool again, as the file content may have changed\n\nSearch Content:\n${searchChunk}${bestMatchSection}${originalContentSection}`,
					})
					continue
				}
			}

			// Get the matched lines from the original content
			const matchedLines = resultLines.slice(matchIndex, matchIndex + searchLines.length)

			// Get the exact indentation (preserving tabs/spaces) of each line
			const originalIndents = matchedLines.map((line) => {
				const match = line.match(/^[\t ]*/)
				return match ? match[0] : ""
			})

			// Get the exact indentation of each line in the search block
			const searchIndents = searchLines.map((line) => {
				const match = line.match(/^[\t ]*/)
				return match ? match[0] : ""
			})

			// Apply the replacement while preserving exact indentation
			const indentedReplaceLines = replaceLines.map((line) => {
				// Get the matched line's exact indentation
				const matchedIndent = originalIndents[0] || ""

				// Get the current line's indentation relative to the search content
				const currentIndentMatch = line.match(/^[\t ]*/)
				const currentIndent = currentIndentMatch ? currentIndentMatch[0] : ""
				const searchBaseIndent = searchIndents[0] || ""

				// Calculate the relative indentation level
				const searchBaseLevel = searchBaseIndent.length
				const currentLevel = currentIndent.length
				const relativeLevel = currentLevel - searchBaseLevel

				// If relative level is negative, remove indentation from matched indent
				// If positive, add to matched indent
				const finalIndent =
					relativeLevel < 0
						? matchedIndent.slice(0, Math.max(0, matchedIndent.length + relativeLevel))
						: matchedIndent + currentIndent.slice(searchBaseLevel)

				return finalIndent + line.trim()
			})

			// Construct the final content
			const beforeMatch = resultLines.slice(0, matchIndex)
			const afterMatch = resultLines.slice(matchIndex + searchLines.length)
			resultLines = [...beforeMatch, ...indentedReplaceLines, ...afterMatch]
			delta = delta - matchedLines.length + replaceLines.length
			appliedCount++
		}
		const finalContent = resultLines.join(lineEnding)
		if (appliedCount === 0) {
			return {
				success: false,
				failParts: diffResults,
			}
		}
		return {
			success: true,
			content: finalContent,
			failParts: diffResults,
		}
	}

	getProgressStatus(toolUse: ToolUse, result?: DiffResult): ToolProgressStatus {
		const diffContent = toolUse.params.diff
		if (diffContent) {
			const icon = "diff-multiple"
			if (toolUse.partial) {
				if (Math.floor(diffContent.length / 10) % 10 === 0) {
					const searchBlockCount = (diffContent.match(/SEARCH/g) || []).length
					return { icon, text: `${searchBlockCount}` }
				}
			} else if (result) {
				const searchBlockCount = (diffContent.match(/SEARCH/g) || []).length
				if (result.failParts?.length) {
					return {
						icon,
						text: `${searchBlockCount - result.failParts.length}/${searchBlockCount}`,
					}
				} else {
					return { icon, text: `${searchBlockCount}` }
				}
			}
		}
		return {}
	}
}

export type ApiErrorKind =
	| "prompt_too_long"
	| "max_output_tokens"
	| "context_window_exceeded"
	| "rate_limit"
	| "auth_error"
	| "model_unavailable"
	| "capacity"
	| "server_error"
	| "network_error"
	| "stale_connection"
	| "timeout"
	// === New error categories (Task 4.2) ===
	| "media_too_large"   // Media file exceeds size limit
	| "model_overloaded"  // Model overloaded (503 with overload signal)
	| "invalid_tool_use"  // Tool call format/schema error
	| "content_policy"    // Content rejected by safety/policy filter
	| "partial_response"  // Incomplete response (stop_reason=max_tokens)
	| "unknown"

/**
 * Classifies an API error into a specific error kind for recovery routing.
 *
 * Classification priority (highest → lowest):
 * 1. Content/format errors (prompt_too_long, media_too_large, content_policy, invalid_tool_use)
 * 2. Token/context limits (max_output_tokens, context_window_exceeded, partial_response)
 * 3. Auth errors (auth_error)
 * 4. Rate/capacity (rate_limit, capacity)
 * 5. Model availability (model_overloaded, model_unavailable)
 * 6. Server errors (server_error)
 * 7. Connection errors (stale_connection, timeout, network_error)
 * 8. Fallback (unknown)
 */
export function classifyApiError(error: unknown): ApiErrorKind {
	const e = error as any
	const msg = String(e?.message ?? "").toLowerCase()
	const status = Number(e?.status ?? 0)
	const code = String(e?.code ?? "").toLowerCase()
	const stopReason = String(e?.stop_reason ?? e?.stopReason ?? "").toLowerCase()

	// ── 1. Content / format errors (most specific first) ────────────────

	// Media file too large: explicit size-related rejection
	if (/too large|size exceeds|payload too large|file.*too.*big|media.*limit/.test(msg) || status === 413)
		return "media_too_large"

	// Content policy violation: safety filter rejection
	if (/content policy|content_policy|safety|content filter|moderation|flagged|blocked by policy/.test(msg))
		return "content_policy"

	// Invalid tool use: schema validation or format error in tool calls
	if (/tool_use|invalid tool|tool.*schema|tool.*format|tool call|invalid_tool/.test(msg))
		return "invalid_tool_use"

	if (/prompt.*too.*long|input.*too.*long|request.*too.*large/.test(msg)) return "prompt_too_long"

	// ── 2. Token / context limits ───────────────────────────────────────

	if (/max[_\s-]?tokens|max[_\s-]?output[_\s-]?tokens|output token limit/.test(msg)) return "max_output_tokens"
	if (/context window|context length|token limit exceeded/.test(msg)) return "context_window_exceeded"

	// Partial response: model stopped at max_tokens but content is incomplete
	if (stopReason === "max_tokens" || stopReason === "length") return "partial_response"

	// ── 3. Auth errors ──────────────────────────────────────────────────

	if (status === 429 || /rate limit|too many requests/.test(msg)) return "rate_limit"
	if (status === 401 || status === 403 || /unauthorized|forbidden|invalid.*api.*key|authentication/.test(msg))
		return "auth_error"

	// ── 4. Rate / capacity ─────────────────────────────────────────────

	// 529 capacity errors: provider-specific overload
	if (status === 529 || /capacity/.test(msg)) return "capacity"

	// ── 5. Model availability ──────────────────────────────────────────

	// 503 with overloaded signal → model_overloaded (distinct from generic 503)
	if (status === 503 || /overloaded|model.*unavailable|service.*unavailable/.test(msg)) return "model_overloaded"

	// ── 6. Server errors ───────────────────────────────────────────────

	if (status >= 500) return "server_error"

	// ── 7. Connection errors ───────────────────────────────────────────

	// Stale connection errors (ECONNRESET/EPIPE) can be retried immediately
	if (/econnreset|epipe|socket hang up/.test(msg)) return "stale_connection"
	// Timeout: ETIMEDOUT, ESOCKETTIMEDOUT, or generic timeout
	if (/etimedout|esockettimedout/.test(msg) || /etimedout|esockettimedout/.test(code) || /timeout/.test(msg))
		return "timeout"
	if (/network|econn|fetch failed|enotfound|econnrefused/.test(msg)) return "network_error"

	// ── 8. Fallback ────────────────────────────────────────────────────

	return "unknown"
}

/**
 * FlagStore — Lightweight feature flag evaluation.
 *
 * Supports three tiers (highest priority wins):
 *   1. Kill switch (force-on / force-off via settings.json)
 *   2. Percentage-based gradual rollout (0–100)
 *   3. Default value (hard-coded fallback)
 *
 * Usage:
 *   const store = new FlagStore(userFlags, { userId: "abc" })
 *   store.isEnabled("imageGeneration") // true | false
 */

export interface FlagDefinition {
	defaultValue: boolean
	description?: string
	rolloutPercent?: number // 0–100
}

export interface FlagContext {
	userId?: string
	workspaceId?: string
}

export type FlagOverrides = Record<string, boolean | undefined> // force on/off

export class FlagStore {
	private flags: Map<string, FlagDefinition>
	private overrides: FlagOverrides
	private context: FlagContext

	constructor(
		flags: Record<string, FlagDefinition>,
		overrides: FlagOverrides = {},
		context: FlagContext = {},
	) {
		this.flags = new Map(Object.entries(flags))
		this.overrides = overrides
		this.context = context
	}

	isEnabled(flagName: string): boolean {
		// 1. Kill switch (highest priority)
		const override = this.overrides[flagName]
		if (override !== undefined) return override

		// 2. Local override file
		const localOverride = this.loadLocalOverride(flagName)
		if (localOverride !== undefined) return localOverride

		// 3. Percentage rollout
		const flag = this.flags.get(flagName)
		if (!flag) return false
		if (flag.rolloutPercent !== undefined && flag.rolloutPercent < 100) {
			const hash = this.hashFlag(flagName)
			if (hash >= flag.rolloutPercent / 100) return false
		}

		// 4. Default
		return flag.defaultValue
	}

	getRolloutPercent(flagName: string): number {
		return this.flags.get(flagName)?.rolloutPercent ?? 100
	}

	getAllFlags(): Record<string, { enabled: boolean; defaultValue: boolean; rolloutPercent?: number }> {
		const result: Record<string, any> = {}
		for (const [name, def] of this.flags) {
			result[name] = {
				enabled: this.isEnabled(name),
				defaultValue: def.defaultValue,
				rolloutPercent: def.rolloutPercent,
			}
		}
		return result
	}

	/**
	 * Deterministic hash of flag name + user ID for consistent rollout assignment.
	 * Returns 0.0–1.0.
	 */
	private hashFlag(flagName: string): number {
		const seed = this.context.userId ?? flagName
		let hash = 0
		for (let i = 0; i < seed.length; i++) {
			hash = ((hash << 5) - hash + seed.charCodeAt(i)) | 0
		}
		return Math.abs(hash % 10000) / 10000
	}

	private loadLocalOverride(flagName: string): boolean | undefined {
		// Intentionally synchronous — called frequently, must be fast.
		// Checks environment variable: FLAG_<NAME> = "1" | "0" | "true" | "false"
		const envKey = `FLAG_${flagName.replace(/([A-Z])/g, "_$1").toUpperCase()}`
		const envVal = typeof process !== "undefined" ? process.env?.[envKey] : undefined
		if (envVal === "1" || envVal?.toLowerCase() === "true") return true
		if (envVal === "0" || envVal?.toLowerCase() === "false") return false
		return undefined
	}
}

import fs from "fs/promises"
import * as path from "path"

import * as vscode from "vscode"
import { isBinaryFile } from "isbinaryfile"

import { mentionRegexGlobal, commandRegexGlobal, unescapeSpaces } from "../../shared/context-mentions"

import { getCommitInfo, getWorkingState } from "../../utils/git"

import { openFile } from "../../integrations/misc/open-file"
import { extractTextFromFileWithMetadata, type ExtractTextResult } from "../../integrations/misc/extract-text"
import { diagnosticsToProblemsString } from "../../integrations/diagnostics"
import { DEFAULT_LINE_LIMIT } from "../prompts/tools/native-tools/read_file"

import { FileContextTracker } from "../context-tracking/FileContextTracker"

import { RooIgnoreController } from "../ignore/RooIgnoreController"
import { getCommand, type Command } from "../../services/command/commands"
import { buildSkillResult, resolveSkillContentForMode, type SkillLookup } from "../../services/skills/skillInvocation"
import type { SkillContent } from "../../shared/skills"
import { getErrorMessage } from "../../shared/error-utils"

export function openMention(cwd: string, mention?: string): Promise<void> {
	if (!mention) {
		return
	}

	if (mention.startsWith("/")) {
		// Slice off the leading slash and unescape any spaces in the path
		const relPath = unescapeSpaces(mention.slice(1))
		const absPath = path.resolve(cwd, relPath)
		if (mention.endsWith("/")) {
			vscode.commands.executeCommand("revealInExplorer", vscode.Uri.file(absPath))
		} else {
			void openFile(absPath)
		}
	} else if (mention === "problems") {
		vscode.commands.executeCommand("workbench.actions.view.problems")
	} else if (mention === "terminal") {
		vscode.commands.executeCommand("workbench.action.terminal.focus")
	} else if (mention.startsWith("http")) {
		vscode.env.openExternal(vscode.Uri.parse(mention))
	}
}

/**
 * Represents a content block generated from an @ mention.
 * These are returned separately from the user's text to enable
 * proper formatting as distinct message blocks.
 */
export interface MentionContentBlock {
	type: "file" | "folder" | "url" | "diagnostics" | "git_changes" | "git_commit" | "terminal" | "command"
	/** Path for file/folder mentions */
	path?: string
	/** The content to display */
	content: string
	/** Metadata about truncation (for files) */
	metadata?: {
		totalLines: number
		returnedLines: number
		wasTruncated: boolean
		linesShown?: [number, number]
	}
}

export interface ParseMentionsResult {
	/** User's text with @ mentions replaced by clean path references */
	text: string
	/** Separate content blocks for each mention (file content, URLs, etc.) */
	contentBlocks: MentionContentBlock[]
	slashCommandHelp?: string
	mode?: string // Mode from the first slash command that has one
}

/**
 * Formats file content to look like a read_file tool result.
 * Includes Gemini-style truncation warning when content is truncated.
 */
function formatFileReadResult(filePath: string, result: ExtractTextResult): string {
	const header = `[read_file for '${filePath}']`

	if (result.wasTruncated && result.linesShown) {
		const [start, end] = result.linesShown
		const nextOffset = end + 1
		return `${header}
IMPORTANT: File content truncated.
Status: Showing lines ${start}-${end} of ${result.totalLines} total lines.
To read more: Use the read_file tool with offset=${nextOffset} and limit=${DEFAULT_LINE_LIMIT}.

File: ${filePath}
${result.content}`
	}

	return `${header}
File: ${filePath}
${result.content}`
}

export async function parseMentions(
	text: string,
	cwd: string,
	fileContextTracker?: FileContextTracker,
	rooIgnoreController?: RooIgnoreController,
	showRooIgnoredFiles: boolean = false,
	includeDiagnosticMessages: boolean = true,
	maxDiagnosticMessages: number = 50,
	skillsManager?: SkillLookup,
	currentMode: string = "code",
): Promise<ParseMentionsResult> {
	const mentions: Set<string> = new Set()
	const validCommands: Map<string, Command> = new Map()
	const validSkills: Map<string, SkillContent> = new Map()
	const contentBlocks: MentionContentBlock[] = []
	let commandMode: string | undefined // Track mode from the first slash command that has one

	// First pass: check which command mentions exist and cache the results
	const commandMatches = Array.from(text.matchAll(commandRegexGlobal))
	const uniqueCommandNames = new Set(commandMatches.map(([, commandName]) => commandName))

	const commandExistenceChecks = await Promise.all(
		Array.from(uniqueCommandNames).map(async (commandName) => {
			try {
				const command = await getCommand(cwd, commandName)
				if (command) {
					return { commandName, command, skillContent: null }
				}

				const skillContent = await resolveSkillContentForMode(skillsManager, commandName, currentMode)
				return { commandName, command: undefined, skillContent }
			} catch {
				// If there's an error checking command existence, treat it as non-existent
				return { commandName, command: undefined, skillContent: null }
			}
		}),
	)

	// Store valid commands for later use and capture the first mode found
	for (const { commandName, command, skillContent } of commandExistenceChecks) {
		if (command) {
			validCommands.set(commandName, command)
			// Capture the mode from the first command that has one
			if (!commandMode && command.mode) {
				commandMode = command.mode
			}
			continue
		}

		if (skillContent) {
			validSkills.set(commandName, skillContent)
		}
	}

	// Only replace text for commands that actually exist (keep "see below" for commands)
	let parsedText = text
	for (const [match, commandName] of commandMatches) {
		if (validCommands.has(commandName) || validSkills.has(commandName)) {
			parsedText = parsedText.replace(match, `Command '${commandName}' (see below for command content)`)
		}
	}

	// Second pass: handle regular mentions - replace with clean references
	// Content will be provided as separate blocks that look like read_file results
	parsedText = parsedText.replace(mentionRegexGlobal, (match, mention) => {
		mentions.add(mention)
		if (mention.startsWith("http")) {
			return `'${mention}'`
		} else if (mention.startsWith("/")) {
			// Clean path reference - no "see below" since we format like tool results
			const mentionPath = mention.slice(1)
			return mentionPath.endsWith("/") ? `'${mentionPath}'` : `'${mentionPath}'`
		} else if (mention === "problems") {
			return `Workspace Problems (see below for diagnostics)`
		} else if (mention === "git-changes") {
			return `Working directory changes (see below for details)`
		} else if (/^[a-f0-9]{7,40}$/.test(mention)) {
			return `Git commit '${mention}' (see below for commit info)`
		} else if (mention === "terminal") {
			return `Terminal Output (see below for output)`
		}
		return match
	})

	for (const mention of mentions) {
		if (mention.startsWith("/")) {
			const mentionPath = mention.slice(1)
			try {
				const fileResult = await getFileOrFolderContentWithMetadata(
					mentionPath,
					cwd,
					rooIgnoreController,
					showRooIgnoredFiles,
					fileContextTracker,
				)
				contentBlocks.push(fileResult)
			} catch (error) {
				const errorMsg = getErrorMessage(error)
				contentBlocks.push({
					type: mention.endsWith("/") ? "folder" : "file",
					path: mentionPath,
					content: `[read_file for '${mentionPath}']\nError: ${errorMsg}`,
				})
			}
		} else if (mention === "problems") {
			try {
				const problems = await getWorkspaceProblems(cwd, includeDiagnosticMessages, maxDiagnosticMessages)
				parsedText += `\n\n<workspace_diagnostics>\n${problems}\n</workspace_diagnostics>`
			} catch (error) {
				parsedText += `\n\n<workspace_diagnostics>\nError fetching diagnostics: ${getErrorMessage(error)}\n</workspace_diagnostics>`
			}
		} else if (mention === "git-changes") {
			try {
				const workingState = await getWorkingState(cwd)
				parsedText += `\n\n<git_working_state>\n${workingState}\n</git_working_state>`
			} catch (error) {
				parsedText += `\n\n<git_working_state>\nError fetching working state: ${getErrorMessage(error)}\n</git_working_state>`
			}
		} else if (/^[a-f0-9]{7,40}$/.test(mention)) {
			try {
				const commitInfo = await getCommitInfo(mention, cwd)
				parsedText += `\n\n<git_commit hash="${mention}">\n${commitInfo}\n</git_commit>`
			} catch (error) {
				parsedText += `\n\n<git_commit hash="${mention}">\nError fetching commit info: ${getErrorMessage(error)}\n</git_commit>`
			}
		} else if (mention === "terminal") {
			try {
				const terminalOutput = await getLatestTerminalOutput()
				parsedText += `\n\n<terminal_output>\n${terminalOutput}\n</terminal_output>`
			} catch (error) {
				parsedText += `\n\n<terminal_output>\nError fetching terminal output: ${getErrorMessage(error)}\n</terminal_output>`
			}
		}
	}

	// Process valid command mentions using cached results
	let slashCommandHelp = ""
	for (const [commandName, command] of validCommands) {
		try {
			let commandOutput = ""
			if (command.description) {
				commandOutput += `Description: ${command.description}\n\n`
			}
			commandOutput += command.content
			slashCommandHelp += `\n\n<command name="${commandName}">\n${commandOutput}\n</command>`
		} catch (error) {
			slashCommandHelp += `\n\n<command name="${commandName}">\nError loading command '${commandName}': ${getErrorMessage(error)}\n</command>`
		}
	}

	for (const [skillName, skillContent] of validSkills) {
		slashCommandHelp += `\n\n${buildSkillResult(skillName, undefined, skillContent)}`
	}

	return {
		text: parsedText,
		contentBlocks,
		mode: commandMode,
		slashCommandHelp: slashCommandHelp.trim() || undefined,
	}
}

/**
 * Gets file or folder content and returns it as a MentionContentBlock
 * formatted to look like a read_file tool result.
 */
async function getFileOrFolderContentWithMetadata(
	mentionPath: string,
	cwd: string,
	rooIgnoreController?: any,
	showRooIgnoredFiles: boolean = false,
	fileContextTracker?: FileContextTracker,
): Promise<MentionContentBlock> {
	const unescapedPath = unescapeSpaces(mentionPath)
	const absPath = path.resolve(cwd, unescapedPath)
	const isFolder = mentionPath.endsWith("/")

	try {
		const stats = await fs.stat(absPath)

		if (stats.isFile()) {
			// Avoid trying to include image binary content as text context.
			// Image mentions are handled separately via image attachment flow.
			const isBinary = await isBinaryFile(absPath).catch(() => false)
			if (isBinary) {
				return {
					type: "file",
					path: mentionPath,
					content: `[read_file for '${mentionPath}']\nNote: Binary file omitted from context.`,
				}
			}
			if (rooIgnoreController && !rooIgnoreController.validateAccess(unescapedPath)) {
				return {
					type: "file",
					path: mentionPath,
					content: `[read_file for '${mentionPath}']\nNote: File is ignored by .rooignore.`,
				}
			}
			try {
				const result = await extractTextFromFileWithMetadata(absPath)

				// Track file context
				if (fileContextTracker) {
					await fileContextTracker.trackFileContext(mentionPath, "file_mentioned")
				}

				return {
					type: "file",
					path: mentionPath,
					content: formatFileReadResult(mentionPath, result),
					metadata: {
						totalLines: result.totalLines,
						returnedLines: result.returnedLines,
						wasTruncated: result.wasTruncated,
						linesShown: result.linesShown,
					},
				}
			} catch (error) {
				const errorMsg = getErrorMessage(error)
				return {
					type: "file",
					path: mentionPath,
					content: `[read_file for '${mentionPath}']\nError: ${errorMsg}`,
				}
			}
		} else if (stats.isDirectory()) {
			const entries = await fs.readdir(absPath, { withFileTypes: true })
			let folderListing = ""
			const fileReadResults: string[] = []
			const LOCK_SYMBOL = "🔒"
			const MAX_FOLDER_FILES = 200
			const MAX_FOLDER_CONTENT_BYTES = 512 * 1024
			let totalContentBytes = 0

			for (let index = 0; index < entries.length; index++) {
				if (index >= MAX_FOLDER_FILES) {
					folderListing += `... (${entries.length - MAX_FOLDER_FILES} more entries omitted)\n`
					break
				}

				const entry = entries[index]
				const isLast = index === entries.length - 1
				const linePrefix = isLast ? "└── " : "├── "
				const entryPath = path.join(absPath, entry.name)

				let isIgnored = false
				if (rooIgnoreController) {
					isIgnored = !rooIgnoreController.validateAccess(entryPath)
				}

				if (isIgnored && !showRooIgnoredFiles) {
					continue
				}

				const displayName = isIgnored ? `${LOCK_SYMBOL} ${entry.name}` : entry.name

				if (entry.isFile()) {
					folderListing += `${linePrefix}${displayName}\n`
					if (!isIgnored && totalContentBytes < MAX_FOLDER_CONTENT_BYTES) {
						const filePath = path.join(mentionPath, entry.name)
						const absoluteFilePath = path.resolve(absPath, entry.name)
						try {
							const isBinary = await isBinaryFile(absoluteFilePath).catch(() => false)
							if (!isBinary) {
								const result = await extractTextFromFileWithMetadata(absoluteFilePath)
								const formatted = formatFileReadResult(filePath.toPosix(), result)
								totalContentBytes += formatted.length
								fileReadResults.push(formatted)
							}
						} catch {
							// Skip files that can't be read
						}
					}
				} else if (entry.isDirectory()) {
					folderListing += `${linePrefix}${displayName}/\n`
				} else {
					folderListing += `${linePrefix}${displayName}\n`
				}
			}

			// Format folder content similar to read_file output
			let content = `[read_file for folder '${mentionPath}']\nFolder listing:\n${folderListing}`
			if (fileReadResults.length > 0) {
				content += `\n\n--- File Contents ---\n\n${fileReadResults.join("\n\n")}`
			}

			return {
				type: "folder",
				path: mentionPath,
				content,
			}
		} else {
			return {
				type: isFolder ? "folder" : "file",
				path: mentionPath,
				content: `[read_file for '${mentionPath}']\nError: Unable to read (not a file or directory)`,
			}
		}
	} catch (error) {
		const errorMsg = getErrorMessage(error)
		throw new Error(`Failed to access path "${mentionPath}": ${errorMsg}`)
	}
}

async function getWorkspaceProblems(
	cwd: string,
	includeDiagnosticMessages: boolean = true,
	maxDiagnosticMessages: number = 50,
): Promise<string> {
	const diagnostics = vscode.languages.getDiagnostics()
	const result = await diagnosticsToProblemsString(
		diagnostics,
		[vscode.DiagnosticSeverity.Error, vscode.DiagnosticSeverity.Warning],
		cwd,
		includeDiagnosticMessages,
		maxDiagnosticMessages,
	)
	if (!result) {
		return "No errors or warnings detected."
	}
	return result
}

/**
 * Gets the contents of the active terminal
 * @returns The terminal contents as a string
 */
export async function getLatestTerminalOutput(): Promise<string> {
	// SECURITY NOTE: VS Code does not expose a non-clipboard API for reading
	// terminal buffer contents.  During the brief window between writing to the
	// clipboard (steps below) and restoring the original content, any process
	// with clipboard access can observe the terminal output.  This is an
	// inherent limitation of the VS Code extension API.
	const nonce = `__terminal_capture_${Date.now()}_${Math.random().toString(36).slice(2)}__`
	const originalClipboard = await vscode.env.clipboard.readText()

	try {
		// Write nonce so we can tell whether the copy overwrote it.
		await vscode.env.clipboard.writeText(nonce)

		await vscode.commands.executeCommand("workbench.action.terminal.selectAll")
		await vscode.commands.executeCommand("workbench.action.terminal.copySelection")
		await vscode.commands.executeCommand("workbench.action.terminal.clearSelection")

		let terminalContents = (await vscode.env.clipboard.readText()).trim()

		if (terminalContents === nonce) {
			return ""
		}

		const lines = terminalContents.split("\n")
		const lastLine = lines.pop()?.trim()

		if (lastLine) {
			let i = lines.length - 1

			while (i >= 0 && !lines[i].trim().startsWith(lastLine)) {
				i--
			}

			terminalContents = lines.slice(Math.max(i, 0)).join("\n")
		}

		return terminalContents
	} finally {
		// Restore original clipboard content as quickly as possible.
		await vscode.env.clipboard.writeText(originalClipboard)
	}
}

// Export processUserContentMentions from its own file
export { processUserContentMentions } from "./processUserContentMentions"
export type { ProcessUserContentMentionsResult } from "./processUserContentMentions"

import Anthropic from "@anthropic-ai/sdk"

import { parseMentions, MentionContentBlock } from "./index"
import { FileContextTracker } from "../context-tracking/FileContextTracker"
import type { SkillLookup } from "../../services/skills/skillInvocation"

// Internal aliases for the Anthropic content block subtypes used during processing.
type TextPart = Anthropic.Messages.TextBlockParam
type ImagePart = Anthropic.Messages.ImageBlockParam
type _ToolResultPart = Anthropic.Messages.ToolResultBlockParam

export interface ProcessUserContentMentionsResult {
	content: Anthropic.Messages.ContentBlockParam[]
	mode?: string // Mode from the first slash command that has one
}

/**
 * Converts MentionContentBlocks to TextPart blocks.
 * Each file/folder mention becomes a separate text block formatted
 * to look like a read_file tool result.
 */
function contentBlocksToTextParts(contentBlocks: MentionContentBlock[]): TextPart[] {
	return contentBlocks.map((block) => ({
		type: "text" as const,
		text: block.content,
	}))
}

/**
 * Process mentions in user content, specifically within task and feedback tags.
 *
 * File/folder @ mentions are now returned as separate text blocks that
 * look like read_file tool results, making it clear to the model that
 * the file has already been read.
 */
export async function processUserContentMentions({
	userContent,
	cwd,
	fileContextTracker,
	rooIgnoreController,
	showRooIgnoredFiles = false,
	includeDiagnosticMessages = true,
	maxDiagnosticMessages = 50,
	skillsManager,
	currentMode = "code",
}: {
	userContent: Anthropic.Messages.ContentBlockParam[]
	cwd: string
	fileContextTracker: FileContextTracker
	rooIgnoreController?: any
	showRooIgnoredFiles?: boolean
	includeDiagnosticMessages?: boolean
	maxDiagnosticMessages?: number
	skillsManager?: SkillLookup
	currentMode?: string
}): Promise<ProcessUserContentMentionsResult> {
	// Track the first mode found from slash commands
	let commandMode: string | undefined

	// Process userContent array, which contains text and image parts.
	// We need to apply parseMentions() to TextPart's text that contains "<user_message>".
	const content = (
		await Promise.all(
			userContent.map(async (block) => {
				const shouldProcessMentions = (text: string) => text.includes("<user_message>")

				if (block.type === "text") {
					if (shouldProcessMentions(block.text)) {
						const result = await parseMentions(
							block.text,
							cwd,
							fileContextTracker,
							rooIgnoreController,
							showRooIgnoredFiles,
							includeDiagnosticMessages,
							maxDiagnosticMessages,
							skillsManager,
							currentMode,
						)
						// Capture the first mode found
						if (!commandMode && result.mode) {
							commandMode = result.mode
						}

						// Build the blocks array:
						// 1. User's text (with @ mentions replaced by clean paths)
						// 2. File/folder content blocks (formatted like read_file results)
						// 3. Slash command help (if any)
						const blocks: Array<TextPart | ImagePart> = [
							{
								...block,
								text: result.text,
							},
						]

						// Add file/folder content as separate blocks
						if (result.contentBlocks.length > 0) {
							blocks.push(...contentBlocksToTextParts(result.contentBlocks))
						}

						if (result.slashCommandHelp) {
							blocks.push({
								type: "text" as const,
								text: result.slashCommandHelp,
							})
						}
						return blocks
					}

					return block
				} else if (block.type === "tool_result") {
					if (typeof block.content === "string") {
						if (shouldProcessMentions(block.content)) {
							const result = await parseMentions(
								block.content,
								cwd,
								fileContextTracker,
								rooIgnoreController,
								showRooIgnoredFiles,
								includeDiagnosticMessages,
								maxDiagnosticMessages,
								skillsManager,
								currentMode,
							)
							// Capture the first mode found
							if (!commandMode && result.mode) {
								commandMode = result.mode
							}

							// Build content array with file blocks included
							const contentParts: Array<{ type: "text"; text: string }> = [
								{
									type: "text" as const,
									text: result.text,
								},
							]

							// Add file/folder content blocks
							for (const contentBlock of result.contentBlocks) {
								contentParts.push({
									type: "text" as const,
									text: contentBlock.content,
								})
							}

							if (result.slashCommandHelp) {
								contentParts.push({
									type: "text" as const,
									text: result.slashCommandHelp,
								})
							}

							return {
								...block,
								content: contentParts,
							}
						}

						return block
					} else if (Array.isArray(block.content)) {
						const parsedContent = (
							await Promise.all(
								block.content.map(async (contentBlock) => {
									if (contentBlock.type === "text" && shouldProcessMentions(contentBlock.text)) {
										const result = await parseMentions(
											contentBlock.text,
											cwd,
											fileContextTracker,
											rooIgnoreController,
											showRooIgnoredFiles,
											includeDiagnosticMessages,
											maxDiagnosticMessages,
											skillsManager,
											currentMode,
										)
										// Capture the first mode found
										if (!commandMode && result.mode) {
											commandMode = result.mode
										}

										// Build blocks array with file content
										const blocks: Array<{ type: "text"; text: string }> = [
											{
												...contentBlock,
												text: result.text,
											},
										]

										// Add file/folder content blocks
										for (const cb of result.contentBlocks) {
											blocks.push({
												type: "text" as const,
												text: cb.content,
											})
										}

										if (result.slashCommandHelp) {
											blocks.push({
												type: "text" as const,
												text: result.slashCommandHelp,
											})
										}
										return blocks
									}

									return contentBlock
								}),
							)
						).flat()

						return { ...block, content: parsedContent }
					}

					return block
				}

				// Legacy backward compat: tool_result / tool-result blocks from older formats
				// are passed through unchanged (tool results are now in separate RooToolMessages).
				return block
			}),
		)
	).flat()

	return { content: content as Anthropic.Messages.ContentBlockParam[], mode: commandMode }
}

import * as path from "path"
import { Task } from "../task/Task"
import { cleanupAfterTruncation } from "../condense"
import { OutputInterceptor } from "../../integrations/terminal/OutputInterceptor"
import { getTaskDirectoryPath } from "../../utils/storage"

import { debugLog } from "../../utils/debugLog"
import { logger } from "../../shared/logger"
export interface RewindOptions {
	/** Whether to include the target message in deletion (edit=true, delete=false) */
	includeTargetMessage?: boolean
	/** Skip cleanup for special cases (default: false) */
	skipCleanup?: boolean
}

interface ContextEventIds {
	condenseIds: Set<string>
	truncationIds: Set<string>
}

/**
 * MessageManager provides centralized handling for all conversation rewind operations.
 *
 * This ensures that whenever UI chat history is rewound (delete, edit, checkpoint restore, etc.),
 * the API conversation history is properly maintained, including:
 * - Removing orphaned Summary messages when their condense_context is removed
 * - Removing orphaned truncation markers when their sliding_window_truncation is removed
 * - Cleaning up orphaned condenseParent/truncationParent tags
 *
 * Usage (always access via Task.messageManager getter):
 * ```typescript
 * await task.messageManager.rewindToTimestamp(messageTs, { includeTargetMessage: false })
 * ```
 *
 * @see Task.messageManager - The getter that provides lazy-initialized access to this manager
 */
export class MessageManager {
	constructor(private task: Task) {}

	/**
	 * Rewind conversation to a specific timestamp.
	 * This is the SINGLE entry point for all message deletion operations.
	 *
	 * @param ts - The timestamp to rewind to
	 * @param options - Rewind options
	 * @throws Error if timestamp not found in clineMessages
	 */
	async rewindToTimestamp(ts: number, options: RewindOptions = {}): Promise<void> {
		const { includeTargetMessage = false, skipCleanup = false } = options

		// Find the index in clineMessages
		const clineIndex = this.task.clineMessages.findIndex((m) => m.ts === ts)
		if (clineIndex === -1) {
			throw new Error(`Message with timestamp ${ts} not found in clineMessages`)
		}

		// Calculate the actual cutoff index
		const cutoffIndex = includeTargetMessage ? clineIndex + 1 : clineIndex

		await this.performRewind(cutoffIndex, ts, { skipCleanup })
	}

	/**
	 * Rewind conversation to a specific index in clineMessages.
	 * Keeps messages [0, toIndex) and removes [toIndex, end].
	 *
	 * @param toIndex - The index to rewind to (exclusive)
	 * @param options - Rewind options
	 */
	async rewindToIndex(toIndex: number, options: RewindOptions = {}): Promise<void> {
		const cutoffTs = this.task.clineMessages[toIndex]?.ts ?? Date.now()
		await this.performRewind(toIndex, cutoffTs, options)
	}

	/**
	 * Internal method that performs the actual rewind operation.
	 */
	private async performRewind(toIndex: number, cutoffTs: number, options: RewindOptions): Promise<void> {
		const { skipCleanup = false } = options

		// Step 1: Collect context event IDs from messages being removed
		const removedIds = this.collectRemovedContextEventIds(toIndex)

		// Step 2: Truncate clineMessages
		await this.truncateClineMessages(toIndex)

		// Step 3: Truncate and clean API history (combined with cleanup for efficiency)
		await this.truncateApiHistoryWithCleanup(cutoffTs, removedIds, skipCleanup)
	}

	/**
	 * Collect condenseIds and truncationIds from context-management events
	 * that will be removed during the rewind.
	 *
	 * This is critical for maintaining the linkage between:
	 * - condense_context (clineMessage) ↔ Summary (apiMessage)
	 * - sliding_window_truncation (clineMessage) ↔ Truncation marker (apiMessage)
	 */
	private collectRemovedContextEventIds(fromIndex: number): ContextEventIds {
		const condenseIds = new Set<string>()
		const truncationIds = new Set<string>()

		for (let i = fromIndex; i < this.task.clineMessages.length; i++) {
			const msg = this.task.clineMessages[i]

			// Collect condenseIds from condense_context events
			if (msg.say === "condense_context" && msg.contextCondense?.condenseId) {
				condenseIds.add(msg.contextCondense.condenseId)
				logger.info("MessageManager", `Found condense_context to remove: ${msg.contextCondense.condenseId}`)
			}

			// Collect truncationIds from sliding_window_truncation events
			if (msg.say === "sliding_window_truncation" && msg.contextTruncation?.truncationId) {
				truncationIds.add(msg.contextTruncation.truncationId)
				logger.info("MessageManager",
					`Found sliding_window_truncation to remove: ${msg.contextTruncation.truncationId}`,
				)
			}
		}

		return { condenseIds, truncationIds }
	}

	/**
	 * Truncate clineMessages to the specified index.
	 */
	private async truncateClineMessages(toIndex: number): Promise<void> {
		await this.task.overwriteClineMessages(this.task.clineMessages.slice(0, toIndex))
	}

	/**
	 * Truncate API history by timestamp, remove orphaned summaries/markers,
	 * and clean up orphaned tags - all in a single write operation.
	 *
	 * This combined approach:
	 * 1. Avoids multiple writes to API history
	 * 2. Only writes if the history actually changed
	 * 3. Handles both truncation and cleanup atomically
	 *
	 * Note on timestamp handling:
	 * Due to async execution during streaming, clineMessage timestamps may not
	 * perfectly align with API message timestamps. Specifically, a "user_feedback"
	 * clineMessage can have a timestamp BEFORE the assistant API message that
	 * triggered it (because tool execution happens concurrently with stream
	 * completion). To handle this race condition, we find the first API user
	 * message at or after the cutoff and use its timestamp as the actual boundary.
	 */
	private async truncateApiHistoryWithCleanup(
		cutoffTs: number,
		removedIds: ContextEventIds,
		skipCleanup: boolean,
	): Promise<void> {
		const originalHistory = this.task.apiConversationHistory
		let apiHistory = [...originalHistory]

		// Step 1: Determine the actual cutoff timestamp
		// Check if there's an API message with an exact timestamp match
		const hasExactMatch = apiHistory.some((m) => m.ts === cutoffTs)
		// Check if there are any messages before the cutoff that would be preserved
		const hasMessageBeforeCutoff = apiHistory.some((m) => m.ts !== undefined && m.ts < cutoffTs)

		let actualCutoff: number = cutoffTs

		if (!hasExactMatch && hasMessageBeforeCutoff) {
			// No exact match but there are earlier messages means we might have a race
			// condition where the clineMessage timestamp is earlier than any API message
			// due to async execution. In this case, look for the first API user message
			// at or after the cutoff to use as the actual boundary.
			// This ensures assistant messages that preceded the user's response are preserved.
			const firstUserMsgIndexToRemove = apiHistory.findIndex(
				(m) => m.ts !== undefined && m.ts >= cutoffTs && m.role === "user",
			)

			if (firstUserMsgIndexToRemove !== -1) {
				// Use the user message's timestamp as the actual cutoff
				actualCutoff = apiHistory[firstUserMsgIndexToRemove].ts!
			}
			// else: no user message found, use original cutoffTs (fallback)
		}

		// Step 2: Filter by the actual cutoff timestamp
		apiHistory = apiHistory.filter((m) => !m.ts || m.ts < actualCutoff)

		// Step 3: Remove Summaries whose condense_context was removed
		if (removedIds.condenseIds.size > 0) {
			apiHistory = apiHistory.filter((msg) => {
				if (msg.isSummary && msg.condenseId && removedIds.condenseIds.has(msg.condenseId)) {
					logger.info("MessageManager", `Removing orphaned Summary with condenseId: ${msg.condenseId}`)
					return false
				}
				return true
			})
		}

		// Step 4: Remove truncation markers whose sliding_window_truncation was removed
		if (removedIds.truncationIds.size > 0) {
			apiHistory = apiHistory.filter((msg) => {
				if (msg.isTruncationMarker && msg.truncationId && removedIds.truncationIds.has(msg.truncationId)) {
					logger.info("MessageManager",
						`Removing orphaned truncation marker with truncationId: ${msg.truncationId}`,
					)
					return false
				}
				return true
			})
		}

		// Step 5: Cleanup orphaned tags (unless skipped)
		if (!skipCleanup) {
			apiHistory = cleanupAfterTruncation(apiHistory)
		}

		// Step 6: Cleanup orphaned command output artifacts
		// Collect timestamps from remaining messages to identify valid artifact IDs
		// Artifacts whose IDs don't match any remaining message timestamp will be removed
		if (!skipCleanup) {
			const validIds = new Set<string>()

			// Collect timestamps from remaining clineMessages
			for (const msg of this.task.clineMessages) {
				if (msg.ts) {
					validIds.add(String(msg.ts))
				}
			}

			// Collect timestamps from remaining apiHistory
			for (const msg of apiHistory) {
				if (msg.ts) {
					validIds.add(String(msg.ts))
				}
			}

			// Cleanup artifacts asynchronously (fire-and-forget with error handling)
			this.cleanupOrphanedArtifacts(validIds).catch((error) => {
				console.error("[MessageManager] Error cleaning up orphaned command output artifacts:", error)
			})
		}

		// Only write if the history actually changed
		const historyChanged =
			apiHistory.length !== originalHistory.length || apiHistory.some((msg, i) => msg !== originalHistory[i])

		if (historyChanged) {
			await this.task.overwriteApiConversationHistory(apiHistory)
		}
	}

	/**
	 * Cleanup orphaned command output artifacts.
	 * Removes artifact files whose execution IDs don't match any remaining message timestamps.
	 */
	private async cleanupOrphanedArtifacts(validIds: Set<string>): Promise<void> {
		try {
			// Access globalStoragePath and taskId through the task reference
			const task = this.task as any // Access private member
			const globalStoragePath = task.globalStoragePath
			const taskId = task.taskId

			if (!globalStoragePath || !taskId) {
				return
			}

			const taskDir = await getTaskDirectoryPath(globalStoragePath, taskId)
			const outputDir = path.join(taskDir, "command-output")
			await OutputInterceptor.cleanupByIds(outputDir, validIds)
		} catch (error) {
			// Silently fail - cleanup is best-effort
			debugLog("[MessageManager] Artifact cleanup skipped:", error)
		}
	}
}

