/**
 * Reverse lookup map - maps alias name to canonical tool name.
 * Built once at module load from the central TOOL_ALIASES constant.
 */
const ALIAS_TO_CANONICAL: Map<string, string> = new Map(
	Object.entries(TOOL_ALIASES).map(([alias, canonical]) => [alias, canonical]),
)

/**
 * Canonical to aliases map - maps canonical tool name to array of alias names.
 * Built once at module load from the central TOOL_ALIASES constant.
 */
const CANONICAL_TO_ALIASES: Map<string, string[]> = new Map()

// Build the reverse mapping (canonical -> aliases)
for (const [alias, canonical] of Object.entries(TOOL_ALIASES)) {
	const existing = CANONICAL_TO_ALIASES.get(canonical) ?? []
	existing.push(alias)
	CANONICAL_TO_ALIASES.set(canonical, existing)
}

/**
 * Pre-computed alias groups map - maps any tool name (canonical or alias) to its full group.
 * Built once at module load for O(1) lookup.
 */
const ALIAS_GROUPS: Map<string, readonly string[]> = new Map()

// Build alias groups for all tools
for (const [canonical, aliases] of CANONICAL_TO_ALIASES.entries()) {
	const group = Object.freeze([canonical, ...aliases])
	// Map canonical to group
	ALIAS_GROUPS.set(canonical, group)
	// Map each alias to the same group
	for (const alias of aliases) {
		ALIAS_GROUPS.set(alias, group)
	}
}

/**
 * Cache for renamed tool definitions.
 * Maps "canonicalName:aliasName" to the pre-built tool definition.
 * This avoids creating new objects via spread operators on every assistant message.
 */
const RENAMED_TOOL_CACHE: Map<string, OpenAI.Chat.ChatCompletionTool> = new Map()

/**
 * Gets or creates a renamed tool definition with the alias name.
 * Uses RENAMED_TOOL_CACHE to avoid repeated object allocation.
 *
 * @param tool - The original tool definition
 * @param aliasName - The alias name to use
 * @returns Cached or newly created renamed tool definition
 */
function getOrCreateRenamedTool(
	tool: OpenAI.Chat.ChatCompletionTool,
	aliasName: string,
): OpenAI.Chat.ChatCompletionTool {
	if (!("function" in tool) || !tool.function) {
		return tool
	}

	const cacheKey = `${tool.function.name}:${aliasName}`
	let renamedTool = RENAMED_TOOL_CACHE.get(cacheKey)

	if (!renamedTool) {
		renamedTool = {
			...tool,
			function: {
				...tool.function,
				name: aliasName,
			},
		}
		RENAMED_TOOL_CACHE.set(cacheKey, renamedTool)
	}

	return renamedTool
}

/**
 * Resolves a tool name to its canonical name.
 * If the tool name is an alias, returns the canonical tool name.
 * If it's already a canonical name or unknown, returns as-is.
 *
 * @param toolName - The tool name to resolve (may be an alias)
 * @returns The canonical tool name
 */
export function resolveToolAlias(toolName: string): string {
	const canonical = ALIAS_TO_CANONICAL.get(toolName)
	return canonical ?? toolName
}

/**
 * Applies tool alias resolution to a set of allowed tools.
 * Resolves any aliases to their canonical tool names.
 *
 * @param allowedTools - Set of tools that may contain aliases
 * @returns Set with aliases resolved to canonical names
 */
export function applyToolAliases(allowedTools: Set<string>): Set<string> {
	const result = new Set<string>()

	for (const tool of allowedTools) {
		// Resolve alias to canonical name
		result.add(resolveToolAlias(tool))
	}

	return result
}

/**
 * Gets all tools in an alias group (including the canonical tool).
 * Uses pre-computed ALIAS_GROUPS map for O(1) lookup.
 *
 * @param toolName - Any tool name in the alias group
 * @returns Array of all tool names in the alias group, or just the tool if not aliased
 */
export function getToolAliasGroup(toolName: string): readonly string[] {
	return ALIAS_GROUPS.get(toolName) ?? [toolName]
}

/**
 * Apply model-specific tool customization to a set of allowed tools.
 *
 * This function filters tools based on model configuration:
 * 1. Removes tools specified in modelInfo.excludedTools
 * 2. Adds tools from modelInfo.includedTools (only if they belong to allowed groups)
 *
 * @param allowedTools - Set of tools already allowed by mode configuration
 * @param modeConfig - Current mode configuration to check tool groups
 * @param modelInfo - Model configuration with tool customization
 * @returns Modified set of tools after applying model customization
 */
/**
 * Result of applying model tool customization.
 * Contains the set of allowed tools and any alias renames to apply.
 */
interface ModelToolCustomizationResult {
	allowedTools: Set<string>
	/** Maps canonical tool name to alias name for tools that should be renamed */
	aliasRenames: Map<string, string>
}

export function applyModelToolCustomization(
	allowedTools: Set<string>,
	modeConfig: ModeConfig,
	modelInfo?: ModelInfo,
): ModelToolCustomizationResult {
	if (!modelInfo) {
		return { allowedTools, aliasRenames: new Map() }
	}

	const result = new Set(allowedTools)
	const aliasRenames = new Map<string, string>()

	// Apply excluded tools (remove from allowed set)
	if (modelInfo.excludedTools && modelInfo.excludedTools.length > 0) {
		modelInfo.excludedTools.forEach((tool) => {
			const resolvedTool = resolveToolAlias(tool)
			result.delete(resolvedTool)
		})
	}

	// Apply included tools (add to allowed set, but only if they belong to an allowed group)
	if (modelInfo.includedTools && modelInfo.includedTools.length > 0) {
		// Build a map of tool -> group for all tools in TOOL_GROUPS (including customTools)
		const toolToGroup = new Map<string, ToolGroup>()
		for (const [groupName, groupConfig] of Object.entries(TOOL_GROUPS)) {
			// Add regular tools
			groupConfig.tools.forEach((tool) => {
				toolToGroup.set(tool, groupName as ToolGroup)
			})
			// Add customTools (opt-in only tools)
			if (groupConfig.customTools) {
				groupConfig.customTools.forEach((tool) => {
					toolToGroup.set(tool, groupName as ToolGroup)
				})
			}
		}

		// Get the list of allowed groups for this mode
		const allowedGroups = new Set(
			modeConfig.groups.map((groupEntry) => (Array.isArray(groupEntry) ? groupEntry[0] : groupEntry)),
		)

		// Add included tools only if they belong to an allowed group
		// If the tool was specified as an alias, track the rename
		modelInfo.includedTools.forEach((tool) => {
			const resolvedTool = resolveToolAlias(tool)
			const toolGroup = toolToGroup.get(resolvedTool)
			if (toolGroup && allowedGroups.has(toolGroup)) {
				result.add(resolvedTool)
				// If the tool was specified as an alias, rename it in the API
				if (tool !== resolvedTool) {
					aliasRenames.set(resolvedTool, tool)
				}
			}
		})
	}

	return { allowedTools: result, aliasRenames }
}

/**
 * Filters native tools based on mode restrictions and model customization.
 * This ensures native tools are filtered consistently with mode/tool permissions.
 *
 * @param nativeTools - Array of all available native tools
 * @param mode - Current mode slug
 * @param customModes - Custom mode configurations
 * @param experiments - Experiment flags
 * @param codeIndexManager - Code index manager for codebase_search feature check
 * @param settings - Additional settings for tool filtering (includes modelInfo for model-specific customization)
 * @param mcpHub - MCP hub for checking available resources
 * @returns Filtered array of tools allowed for the mode
 */
export function filterNativeToolsForMode(
	nativeTools: OpenAI.Chat.ChatCompletionTool[],
	mode: string | undefined,
	customModes: ModeConfig[] | undefined,
	experiments: Record<string, boolean> | undefined,
	codeIndexManager?: CodeIndexManager,
	settings?: Record<string, any>,
	mcpHub?: IMcpHubService,
): OpenAI.Chat.ChatCompletionTool[] {
	// Get mode configuration and all tools for this mode
	const modeSlug = mode ?? defaultModeSlug
	let modeConfig = getModeBySlug(modeSlug, customModes)

	// Fallback to default mode if current mode config is not found
	// This ensures the agent always has functional tools even if a custom mode is deleted
	// or configuration becomes corrupted
	if (!modeConfig) {
		modeConfig = getModeBySlug(defaultModeSlug, customModes)!
	}

	// Get all tools for this mode (including always-available tools)
	const allToolsForMode = getToolsForMode(modeConfig.groups)

	// Filter to only tools that pass permission checks
	let allowedToolNames = new Set(
		allToolsForMode.filter((tool) =>
			isToolAllowedForMode(
				tool as ToolName,
				modeSlug,
				customModes ?? [],
				undefined,
				undefined,
				experiments ?? {},
			),
		),
	)

	// Apply model-specific tool customization
	const modelInfo = settings?.modelInfo as ModelInfo | undefined
	const { allowedTools: customizedTools, aliasRenames } = applyModelToolCustomization(
		allowedToolNames,
		modeConfig,
		modelInfo,
	)
	allowedToolNames = customizedTools

	// Conditionally exclude codebase_search if feature is disabled or not configured
	if (
		!codeIndexManager ||
		!(codeIndexManager.isFeatureEnabled && codeIndexManager.isFeatureConfigured && codeIndexManager.isInitialized)
	) {
		allowedToolNames.delete("codebase_search")
	}

	// Conditionally exclude update_todo_list if disabled in settings
	if (settings?.todoListEnabled === false) {
		allowedToolNames.delete("update_todo_list")
	}

	// Conditionally exclude generate_image if experiment is not enabled
	if (!experiments?.imageGeneration) {
		allowedToolNames.delete("generate_image")
	}

	// Conditionally exclude run_slash_command if experiment is not enabled
	if (!experiments?.runSlashCommand) {
		allowedToolNames.delete("run_slash_command")
	}

	// Remove tools that are explicitly disabled via the disabledTools setting
	if (settings?.disabledTools?.length) {
		for (const toolName of settings.disabledTools) {
			// Normalize aliases so disabling a legacy alias (e.g. "search_and_replace")
			// also disables the canonical tool (e.g. "edit").
			const resolvedToolName = resolveToolAlias(toolName)
			allowedToolNames.delete(resolvedToolName)
		}
	}

	// Conditionally exclude access_mcp_resource if MCP is not enabled or there are no resources
	if (!mcpHub || !hasAnyMcpResources(mcpHub)) {
		allowedToolNames.delete("access_mcp_resource")
	}

	// Filter native tools based on allowed tool names and apply alias renames
	const filteredTools: OpenAI.Chat.ChatCompletionTool[] = []

	for (const tool of nativeTools) {
		// Handle both ChatCompletionTool and ChatCompletionCustomTool
		if ("function" in tool && tool.function) {
			const toolName = tool.function.name
			if (allowedToolNames.has(toolName)) {
				// Check if this tool should be renamed to an alias
				const aliasName = aliasRenames.get(toolName)
				if (aliasName) {
					// Use cached renamed tool definition to avoid per-message object allocation
					filteredTools.push(getOrCreateRenamedTool(tool, aliasName))
				} else {
					filteredTools.push(tool)
				}
			}
		}
	}

	return filteredTools
}

/**
 * Helper function to check if any MCP server has resources available
 */
function hasAnyMcpResources(mcpHub: IMcpHubService): boolean {
	const servers = mcpHub.getServers()
	return servers.some((server) => server.resources && server.resources.length > 0)
}

/**
 * Checks if a specific tool is allowed in the current mode.
 * This is useful for dynamically filtering system prompt content.
 *
 * @param toolName - Name of the tool to check
 * @param mode - Current mode slug
 * @param customModes - Custom mode configurations
 * @param experiments - Experiment flags
 * @param codeIndexManager - Code index manager for codebase_search feature check
 * @param settings - Additional settings for tool filtering
 * @returns true if the tool is allowed in the mode, false otherwise
 */
export function isToolAllowedInMode(
	toolName: ToolName,
	mode: string | undefined,
	customModes: ModeConfig[] | undefined,
	experiments: Record<string, boolean> | undefined,
	codeIndexManager?: CodeIndexManager,
	settings?: Record<string, any>,
): boolean {
	const modeSlug = mode ?? defaultModeSlug

	// Check if it's an always-available tool
	if (ALWAYS_AVAILABLE_TOOLS.includes(toolName)) {
		// But still check for conditional exclusions
		if (toolName === "codebase_search") {
			return !!(
				codeIndexManager &&
				codeIndexManager.isFeatureEnabled &&
				codeIndexManager.isFeatureConfigured &&
				codeIndexManager.isInitialized
			)
		}
		if (toolName === "update_todo_list") {
			return settings?.todoListEnabled !== false
		}
		if (toolName === "generate_image") {
			return experiments?.imageGeneration === true
		}
		if (toolName === "run_slash_command") {
			return experiments?.runSlashCommand === true
		}
		return true
	}

	// Check if the tool is allowed by the mode's groups
	// Resolve to canonical name and check that single value
	const canonicalTool = resolveToolAlias(toolName)
	return isToolAllowedForMode(
		canonicalTool as ToolName,
		modeSlug,
		customModes ?? [],
		undefined,
		undefined,
		experiments ?? {},
	)
}

/**
 * Gets the list of available tools from a specific tool group for the current mode.
 * This is useful for dynamically building system prompt content based on available tools.
 *
 * @param groupName - Name of the tool group to check
 * @param mode - Current mode slug
 * @param customModes - Custom mode configurations
 * @param experiments - Experiment flags
 * @param codeIndexManager - Code index manager for codebase_search feature check
 * @param settings - Additional settings for tool filtering
 * @returns Array of tool names that are available from the group
 */
export function getAvailableToolsInGroup(
	groupName: ToolGroup,
	mode: string | undefined,
	customModes: ModeConfig[] | undefined,
	experiments: Record<string, boolean> | undefined,
	codeIndexManager?: CodeIndexManager,
	settings?: Record<string, any>,
): ToolName[] {
	const toolGroup = TOOL_GROUPS[groupName]
	if (!toolGroup) {
		return []
	}

	return toolGroup.tools.filter((tool) =>
		isToolAllowedInMode(tool as ToolName, mode, customModes, experiments, codeIndexManager, settings),
	) as ToolName[]
}

/**
 * Filters MCP tools based on whether use_mcp_tool is allowed in the current mode.
 *
 * @param mcpTools - Array of MCP tools
 * @param mode - Current mode slug
 * @param customModes - Custom mode configurations
 * @param experiments - Experiment flags
 * @returns Filtered array of MCP tools if use_mcp_tool is allowed, empty array otherwise
 */
export function filterMcpToolsForMode(
	mcpTools: OpenAI.Chat.ChatCompletionTool[],
	mode: string | undefined,
	customModes: ModeConfig[] | undefined,
	experiments: Record<string, boolean> | undefined,
): OpenAI.Chat.ChatCompletionTool[] {
	const modeSlug = mode ?? defaultModeSlug

	// MCP tools are always in the mcp group, check if use_mcp_tool is allowed
	const isMcpAllowed = isToolAllowedForMode(
		"use_mcp_tool",
		modeSlug,
		customModes ?? [],
		undefined,
		undefined,
		experiments ?? {},
	)

	return isMcpAllowed ? mcpTools : []
}

import { describe, it, expect } from "vitest"
import { assessCommandRisk } from "../commandRisk"

describe("assessCommandRisk", () => {
	it("returns high risk for empty command", () => {
		const r = assessCommandRisk("")
		expect(r.level).toBe("high")
	})

	it("returns high risk for rm -rf", () => {
		const r = assessCommandRisk("rm -rf /")
		expect(r.level).toBe("high")
	})

	it("returns high risk for git reset --hard", () => {
		const r = assessCommandRisk("git reset --hard HEAD~1")
		expect(r.level).toBe("high")
	})

	it("returns high risk for del on Windows", () => {
		const r = assessCommandRisk("del /f /q C:\temp\*")
		expect(r.level).toBe("high")
	})

	it("detects shell chaining with pipes", () => {
		const r = assessCommandRisk("cat file | grep foo")
		expect(r.level).toBe("medium")
	})

	it("detects shell chaining with &&", () => {
		const r = assessCommandRisk("npm test && npm run build")
		expect(r.level).toBe("medium")
	})

	it("returns medium for npm install", () => {
		const r = assessCommandRisk("npm install express")
		expect(r.level).toBe("medium")
	})

	it("returns low for git status", () => {
		const r = assessCommandRisk("git status")
		expect(r.level).toBe("low")
	})

	it("returns low for ls", () => {
		const r = assessCommandRisk("ls -la")
		expect(r.level).toBe("low")
	})

	it("returns medium for unknown command", () => {
		const r = assessCommandRisk("some-unknown-command --flag")
		expect(r.level).toBe("medium")
	})

	it("handles PowerShell Remove-Item as high risk", () => {
		const r = assessCommandRisk("Remove-Item -Recurse -Force C:\data")
		expect(r.level).toBe("high")
	})

	it("handles taskkill as high risk", () => {
		const r = assessCommandRisk("taskkill /F /IM node.exe")
		expect(r.level).toBe("high")
	})
})

import { safeWriteJson } from "../../utils/safeWriteJson"
import * as path from "path"
import * as fs from "fs/promises"

import { Anthropic } from "@anthropic-ai/sdk"

import { fileExistsAtPath } from "../../utils/fs"

import { GlobalFileNames } from "../../shared/globalFileNames"
import { getTaskDirectoryPath } from "../../utils/storage"
import { logger } from "../../shared/logger"

export type ApiMessage = Anthropic.MessageParam & {
	ts?: number
	isSummary?: boolean
	id?: string
	// For reasoning items stored in API history
	type?: "reasoning"
	summary?: any[]
	encrypted_content?: string
	text?: string
	// For OpenRouter reasoning_details array format (used by Gemini 3, etc.)
	reasoning_details?: any[]
	// For DeepSeek/Z.ai interleaved thinking: reasoning_content that must be preserved during tool call sequences
	// See: https://api-docs.deepseek.com/guides/thinking_mode#tool-calls
	reasoning_content?: string
	// For non-destructive condense: unique identifier for summary messages
	condenseId?: string
	// For non-destructive condense: points to the condenseId of the summary that replaces this message
	// Messages with condenseParent are filtered out when sending to API if the summary exists
	condenseParent?: string
	// For non-destructive truncation: unique identifier for truncation marker messages
	truncationId?: string
	// For non-destructive truncation: points to the truncationId of the marker that hides this message
	// Messages with truncationParent are filtered out when sending to API if the marker exists
	truncationParent?: string
	// Identifies a message as a truncation boundary marker
	isTruncationMarker?: boolean
	// Metadata attached to summary messages recording compaction details
	compactMetadata?: CompactMetadata
}

export type CompactMetadata = {
	trigger: "auto" | "manual" | "reactive"
	/** Source of the compaction content: lightweight extraction, session memory, or LLM */
	source?: "lightweight" | "session_memory" | "llm"
	preCompactTokenCount: number
	postCompactTokenCount?: number
	truePostCompactTokenCount?: number
	messagesSummarized?: number
	preservedSegment?: {
		headIndex: number
		tailIndex: number
	}
	timestamp?: number
}

export async function readApiMessages({
	taskId,
	globalStoragePath,
}: {
	taskId: string
	globalStoragePath: string
}): Promise<ApiMessage[]> {
	const taskDir = await getTaskDirectoryPath(globalStoragePath, taskId)
	const filePath = path.join(taskDir, GlobalFileNames.apiConversationHistory)

	if (await fileExistsAtPath(filePath)) {
		const fileContent = await fs.readFile(filePath, "utf8")
		try {
			const parsedData = JSON.parse(fileContent)
			if (!Array.isArray(parsedData)) {
				logger.warn("ApiMessages", 
					`[readApiMessages] Parsed data is not an array (got ${typeof parsedData}), returning empty. TaskId: ${taskId}, Path: ${filePath}`,
				)
				return []
			}
			if (parsedData.length === 0) {
				logger.error("ApiMessages", 
					`[Roo-Debug] readApiMessages: Found API conversation history file, but it's empty (parsed as []). TaskId: ${taskId}, Path: ${filePath}`,
				)
			}
			return parsedData
		} catch (error) {
			logger.warn("ApiMessages", 
				`[readApiMessages] Error parsing API conversation history file, returning empty. TaskId: ${taskId}, Path: ${filePath}, Error: ${error}`,
			)
			return []
		}
	} else {
		const oldPath = path.join(taskDir, "claude_messages.json")

		if (await fileExistsAtPath(oldPath)) {
			const fileContent = await fs.readFile(oldPath, "utf8")
			try {
				const parsedData = JSON.parse(fileContent)
				if (!Array.isArray(parsedData)) {
					logger.warn("ApiMessages", 
						`[readApiMessages] Parsed OLD data is not an array (got ${typeof parsedData}), returning empty. TaskId: ${taskId}, Path: ${oldPath}`,
					)
					return []
				}
				if (parsedData.length === 0) {
					logger.error("ApiMessages", 
						`[Roo-Debug] readApiMessages: Found OLD API conversation history file (claude_messages.json), but it's empty (parsed as []). TaskId: ${taskId}, Path: ${oldPath}`,
					)
				}
				await fs.unlink(oldPath)
				return parsedData
			} catch (error) {
				logger.warn("ApiMessages", 
					`[readApiMessages] Error parsing OLD API conversation history file (claude_messages.json), returning empty. TaskId: ${taskId}, Path: ${oldPath}, Error: ${error}`,
				)
				// DO NOT unlink oldPath if parsing failed.
				return []
			}
		}
	}

	// If we reach here, neither the new nor the old history file was found.
	logger.error("ApiMessages", 
		`[Roo-Debug] readApiMessages: API conversation history file not found for taskId: ${taskId}. Expected at: ${filePath}`,
	)
	return []
}

export async function saveApiMessages({
	messages,
	taskId,
	globalStoragePath,
}: {
	messages: ApiMessage[]
	taskId: string
	globalStoragePath: string
}) {
	const taskDir = await getTaskDirectoryPath(globalStoragePath, taskId)
	const filePath = path.join(taskDir, GlobalFileNames.apiConversationHistory)
	await safeWriteJson(filePath, messages)
}

/**
 * ApiRequestHandler — Facade for API request lifecycle management.
 *
 * Extracted from Task.ts to decompose the monolithic 5000+ line file.
 * Encapsulates API request preparation, streaming coordination, and
 * response processing logic. Uses the delegation pattern: accesses
 * Task instance properties via `this.task`.
 *
 * Phase 1: Exposes utility methods that Task.ts can delegate to.
 * Full extraction of `recursivelyMakeClineRequests` and `attemptApiRequest`
 * is deferred to Phase 2 once the delegation surface is stable.
 */

import type { ApiMessage } from "../task-persistence/apiMessages"
import type { TokenUsage } from "@njust-ai-cj/types"

// ─── Request Metadata ────────────────────────────────────────────────────────

export interface ApiRequestMetadata {
	requestId: string
	startedAt: number
	retryAttempt: number
	modelId: string
	contextTokens?: number
}

// ─── Request Rate Limiter ────────────────────────────────────────────────────

/**
 * Global per-provider rate limiter to enforce minimum delay between API requests.
 * Prevents overwhelming the API during rapid tool-execution loops.
 */
export class RequestRateLimiter {
	private lastRequestTime?: number

	constructor(private readonly minDelayMs: number = 0) {}

	/**
	 * Wait until enough time has elapsed since the last request.
	 */
	async waitIfNeeded(): Promise<void> {
		if (this.minDelayMs <= 0 || !this.lastRequestTime) {
			return
		}
		const elapsed = Date.now() - this.lastRequestTime
		if (elapsed < this.minDelayMs) {
			await new Promise<void>((resolve) => setTimeout(resolve, this.minDelayMs - elapsed))
		}
	}

	markRequestSent(): void {
		this.lastRequestTime = Date.now()
	}

	getLastRequestTime(): number | undefined {
		return this.lastRequestTime
	}
}

// ─── Token Usage Tracker ─────────────────────────────────────────────────────

/**
 * Tracks and caches token usage to avoid recomputing on every call.
 * Provides cache invalidation based on staleness.
 */
export class TokenUsageTracker {
	private snapshot?: TokenUsage
	private snapshotAt?: number
	private readonly staleDurationMs: number

	constructor(staleDurationMs: number = 5000) {
		this.staleDurationMs = staleDurationMs
	}

	/**
	 * Get cached token usage or recompute if stale.
	 */
	getUsage(computeFn: () => TokenUsage): TokenUsage {
		const now = Date.now()
		if (this.snapshot && this.snapshotAt && now - this.snapshotAt < this.staleDurationMs) {
			return this.snapshot
		}
		this.snapshot = computeFn()
		this.snapshotAt = now
		return this.snapshot
	}

	invalidate(): void {
		this.snapshot = undefined
		this.snapshotAt = undefined
	}

	/**
	 * Force update the cached snapshot (e.g., after compaction).
	 */
	forceUpdate(usage: TokenUsage): void {
		this.snapshot = usage
		this.snapshotAt = Date.now()
	}
}

// ─── Request Context Builder ─────────────────────────────────────────────────

/**
 * Builds the context window pressure metrics used for adaptive decisions
 * throughout the request lifecycle.
 */
export interface ContextPressure {
	/** Current token count in context */
	currentTokens: number
	/** Maximum context window size */
	contextWindow: number
	/** Usage ratio (0-1) */
	pressure: number
	/** Whether the context is under high pressure (>80%) */
	isHighPressure: boolean
	/** Whether preemptive compaction should be considered */
	shouldPreemptivelyCompact: boolean
}

export function computeContextPressure(
	currentTokens: number,
	contextWindow: number,
	compactThresholdPercent: number = 80,
): ContextPressure {
	const pressure = contextWindow > 0 ? currentTokens / contextWindow : 0
	const thresholdRatio = compactThresholdPercent / 100
	const safetyMargin = 0.15

	return {
		currentTokens,
		contextWindow,
		pressure,
		isHighPressure: pressure > 0.8,
		shouldPreemptivelyCompact: pressure >= thresholdRatio * (1 - safetyMargin),
	}
}

// ─── Request History Validator ───────────────────────────────────────────────

/**
 * Validates API conversation history before sending requests.
 * Ensures message ordering, role alternation, and tool_result pairing.
 */
export function validateConversationHistory(messages: ApiMessage[]): {
	valid: boolean
	errors: string[]
} {
	const errors: string[] = []

	if (messages.length === 0) {
		return { valid: true, errors: [] }
	}

	// First message should be from user
	if (messages[0].role !== "user") {
		errors.push("First message should be from user role")
	}

	// Check role alternation (user/assistant)
	for (let i = 1; i < messages.length; i++) {
		if (messages[i].role === messages[i - 1].role) {
			// Consecutive same-role messages are generally invalid
			// but some edge cases (tool_result chaining) allow it
			if (messages[i].role === "user") {
				// Check if it's a tool_result — those can follow user messages
				const content = messages[i].content
				if (Array.isArray(content)) {
					const hasToolResult = content.some((b: any) => b.type === "tool_result")
					if (!hasToolResult) {
						errors.push(`Consecutive user messages at index ${i - 1} and ${i}`)
					}
				}
			}
		}
	}

	return { valid: errors.length === 0, errors }
}

/**
 * Builds isolated context for sub-tasks based on isolation level.
 *
 * In 'shared' mode: sub-task inherits full parent context (current behavior).
 * In 'forked' mode: sub-task gets a minimal context with only:
 *   - Task description
 *   - Relevant file information
 *   - Essential parent context (no full conversation history)
 *
 * This prevents sub-tasks from inheriting bloated parent contexts,
 * inspired by Claude Code's Fork isolation mode.
 */

import type { SubTaskOptions, ForkedContextConfig, CacheSafeParams } from "./SubTaskOptions"
import { DEFAULT_FORKED_CONTEXT_CONFIG } from "./SubTaskOptions"

export interface ForkedContext {
	/** Task description/objective */
	taskDescription: string
	/** Relevant file paths mentioned in the task */
	relevantFiles: string[]
	/** Essential context extracted from parent (key decisions, current state) */
	essentialContext: string
	/** Context budget for the sub-task */
	contextBudget: number
}

/**
 * Extract relevant file paths from a task description.
 */
export function extractRelevantFiles(taskDescription: string): string[] {
	// Match common file path patterns
	const patterns = [
		/(?:^|\s)((?:\.\/|\/|[a-zA-Z]:\\)[\w\-./\\]+\.\w+)/gm, // absolute/relative paths with extensions
		/`([^`]+\.\w{1,10})`/g, // backtick-quoted file references
		/(?:src|lib|test|tests)\/[\w\-./]+\.\w+/g, // src/lib paths
	]

	const files = new Set<string>()
	for (const pattern of patterns) {
		let match
		while ((match = pattern.exec(taskDescription)) !== null) {
			const filePath = match[1] || match[0]
			if (filePath && !filePath.includes("*")) {
				// exclude globs
				files.add(filePath.trim())
			}
		}
	}

	return Array.from(files)
}

/**
 * Extract essential context from parent conversation for forked sub-tasks.
 * Limits to key decisions and current state, excluding verbose tool results.
 */
export function extractEssentialContext(
	parentMessages: Array<{ role: string; content: string }>,
	maxChars: number = 3000,
): string {
	// Take last few assistant messages as they contain the most relevant state
	const relevantMessages = parentMessages
		.filter((m) => m.role === "assistant")
		.slice(-3)
		.map((m) => {
			// Truncate long messages
			if (m.content.length > 1000) {
				return m.content.slice(0, 1000) + "..."
			}
			return m.content
		})

	const context = relevantMessages.join("\n---\n")

	if (context.length > maxChars) {
		return context.slice(-maxChars) // Keep the most recent context
	}

	return context
}

/**
 * Build forked context for a sub-task.
 */
export function buildForkedContext(
	taskDescription: string,
	parentMessages: Array<{ role: string; content: string }>,
	options: SubTaskOptions,
): ForkedContext {
	return {
		taskDescription,
		relevantFiles: extractRelevantFiles(taskDescription),
		essentialContext: extractEssentialContext(parentMessages),
		contextBudget: options.contextBudget ?? 64_000,
	}
}

/**
 * Metadata describing a forked context relationship between parent and child tasks.
 */
export interface TaskForkContext {
	parentTaskId: string
	forkedAt: number // timestamp
	forkedMessageCount: number // parent message count at fork time
	isForked: boolean
}

/**
 * Generate a concise summary of parent conversation history for a forked sub-task.
 * This avoids passing the full conversation history to the child, keeping context lean.
 *
 * The summary includes:
 * - Recent assistant decisions/conclusions
 * - File modifications mentioned
 * - Commands executed
 * - Key context limited to summaryMaxTokens (approx chars * 0.25)
 */
export function generateParentContextSummary(
	parentMessages: Array<{ role: string; content: any }>,
	summaryMaxTokens: number = 10_000,
	config: ForkedContextConfig = DEFAULT_FORKED_CONTEXT_CONFIG,
): string {
	const maxChars = summaryMaxTokens * 4 // rough token-to-char ratio
	const parts: string[] = []

	// Extract text content from message content (handles both string and array formats)
	const getTextContent = (content: any): string => {
		if (typeof content === "string") return content
		if (Array.isArray(content)) {
			return content
				.filter((block: { type: string; text?: string }) => block.type === "text" && typeof block.text === "string")
				.map((block: { type: string; text?: string }) => block.text!)
				.join("\n")
		}
		return ""
	}

	// Take only the most recent messages
	const recentMessages = parentMessages.slice(-config.maxRecentMessages)

	// Collect file changes and commands from recent messages
	const fileChanges = new Set<string>()
	const commands: string[] = []
	const keyDecisions: string[] = []

	for (const msg of recentMessages) {
		const text = getTextContent(msg.content)
		if (!text) continue

		if (config.includeFileChanges) {
			// Extract file paths from tool use patterns
			const filePatterns = text.match(/(?:write_to_file|apply_diff|read_file).*?(?:path|file)["':>\s]+([^"'<\n]+)/gi)
			if (filePatterns) {
				for (const match of filePatterns) {
					const pathMatch = match.match(/["':>\s]([^"'<\n]+\.[a-zA-Z]{1,10})$/)
					if (pathMatch) fileChanges.add(pathMatch[1].trim())
				}
			}
		}

		if (config.includeCommands) {
			const cmdPatterns = text.match(/(?:execute_command|command)["':>\s]+([^"'<\n]+)/gi)
			if (cmdPatterns) {
				for (const match of cmdPatterns) {
					const cmdMatch = match.match(/["':>\s]([^"'<\n]+)$/)
					if (cmdMatch) commands.push(cmdMatch[1].trim())
				}
			}
		}

		// Collect key assistant decisions (last few assistant messages)
		if (msg.role === "assistant") {
			const truncated = text.length > 800 ? text.slice(0, 800) + "..." : text
			keyDecisions.push(truncated)
		}
	}

	// Build summary sections
	if (fileChanges.size > 0) {
		parts.push(`[Files referenced]\n${Array.from(fileChanges).join("\n")}`)
	}

	if (commands.length > 0) {
		parts.push(`[Commands executed]\n${commands.slice(-5).join("\n")}`)
	}

	if (keyDecisions.length > 0) {
		// Keep only the last 3 decisions
		const recent = keyDecisions.slice(-3)
		parts.push(`[Recent context]\n${recent.join("\n---\n")}`)
	}

	let summary = parts.join("\n\n")

	// Enforce character limit
	if (summary.length > maxChars) {
		summary = summary.slice(-maxChars)
	}

	return summary || "(No parent context available)"
}

/**
 * Cache-aware fork context result: messages that share the parent's prompt
 * cache prefix, with only the final user message differing per child.
 */
export interface CacheAwareForkContext {
	/** Messages to use as the fork's initial conversation */
	messages: Array<{ role: string; content: any }>
	/** Cache-safe params for the forked agent to reuse */
	cacheSafeParams: CacheSafeParams
}

/**
 * Build a cache-aware fork context that maximizes prompt cache reuse.
 *
 * Instead of a plain-text summary (which produces a completely new prompt),
 * this approach preserves the parent's messages as a byte-identical prefix
 * and only appends a single user message with the task description.
 *
 * The provider's prompt cache key includes: system prompt + tools + model +
 * messages (prefix) + thinking config. By keeping all of these identical
 * between parent and fork, the cache hit rate approaches 100%.
 */
export function buildCacheAwareForkContext(
	taskDescription: string,
	cacheSafeParams: CacheSafeParams,
): CacheAwareForkContext {
	const { forkContextMessages } = cacheSafeParams

	// Build the fork's initial message array:
	// 1. Parent's full conversation prefix (byte-identical for cache hit)
	// 2. Single user message with the task description (only new content)
	const messages: Array<{ role: string; content: any }> = []

	if (forkContextMessages && forkContextMessages.length > 0) {
		messages.push(...forkContextMessages)
	}

	messages.push({
		role: "user",
		content: taskDescription,
	})

	return { messages, cacheSafeParams }
}

/**
 * Build a fork placeholder tool_result. Byte-identical across all fork
 * children to maximize cache hits when the parent continues after spawning.
 */
export function buildForkPlaceholderResult(
	toolUseId: string,
	message: string = "Fork started -- processing in background",
): { role: string; content: any } {
	return {
		role: "user",
		content: [
			{
				type: "tool_result",
				tool_use_id: toolUseId,
				content: message,
			},
		],
	}
}

/**
 * Generate a result summary from a completed task for injection into parent context.
 * Extracts key outcomes: files modified, commands run, and final conclusion.
 * Limited to maxResultChars characters.
 */
export function generateTaskResultSummary(
	taskId: string,
	messages: Array<{ role: string; content: any }>,
	maxResultChars: number = 2000,
): string {
	const parts: string[] = [`[Subtask ${taskId} completed]`]

	// Extract text content helper
	const getTextContent = (content: any): string => {
		if (typeof content === "string") return content
		if (Array.isArray(content)) {
			return content
				.filter((block: { type: string; text?: string }) => block.type === "text" && typeof block.text === "string")
				.map((block: { type: string; text?: string }) => block.text!)
				.join("\n")
		}
		return ""
	}

	// Collect files modified
	const filesModified = new Set<string>()
	const commandsExecuted: string[] = []
	let finalConclusion = ""

	for (const msg of messages) {
		const text = getTextContent(msg.content)
		if (!text) continue

		// Extract file modifications
		const writePatterns = text.match(/(?:write_to_file|apply_diff).*?(?:path|file)["':>\s]+([^"'<\n]+)/gi)
		if (writePatterns) {
			for (const match of writePatterns) {
				const pathMatch = match.match(/["':>\s]([^"'<\n]+\.[a-zA-Z]{1,10})$/)
				if (pathMatch) filesModified.add(pathMatch[1].trim())
			}
		}

		// Extract commands
		const cmdPatterns = text.match(/(?:execute_command|command)["':>\s]+([^"'<\n]+)/gi)
		if (cmdPatterns) {
			for (const match of cmdPatterns) {
				const cmdMatch = match.match(/["':>\s]([^"'<\n]+)$/)
				if (cmdMatch) commandsExecuted.push(cmdMatch[1].trim())
			}
		}
	}

	// Get last assistant message as the final conclusion
	for (let i = messages.length - 1; i >= 0; i--) {
		if (messages[i].role === "assistant") {
			finalConclusion = getTextContent(messages[i].content)
			break
		}
	}

	if (filesModified.size > 0) {
		parts.push(`Files modified: ${Array.from(filesModified).join(", ")}`)
	}

	if (commandsExecuted.length > 0) {
		parts.push(`Commands executed: ${commandsExecuted.slice(-5).join(", ")}`)
	}

	if (finalConclusion) {
		// Truncate conclusion to fit within budget
		const remainingBudget = maxResultChars - parts.join("\n").length - 20
		if (remainingBudget > 100) {
			const truncatedConclusion =
				finalConclusion.length > remainingBudget
					? finalConclusion.slice(0, remainingBudget) + "..."
					: finalConclusion
			parts.push(`Conclusion: ${truncatedConclusion}`)
		}
	}

	let result = parts.join("\n")
	if (result.length > maxResultChars) {
		result = result.slice(0, maxResultChars - 3) + "..."
	}

	return result
}

/**
 * Sub-task configuration for context isolation and specialization.
 * Inspired by Claude Code's Fork mode and specialized sub-agents.
 */

export type SubAgentType =
	| "explore" // Code exploration: read-only tools, focused on search and understanding
	| "implement" // Implementation: full write permissions
	| "verify" // Verification: run tests and checks
	| "custom" // Custom: inherits parent tools

export type IsolationLevel = "shared" | "forked"

export interface SubTaskOptions {
	/** Isolation level for the sub-task context */
	isolationLevel: IsolationLevel
	/** Independent context budget for the sub-task (tokens) */
	contextBudget?: number
	/** Sub-task type determines available tools and prompt */
	agentType: SubAgentType
	/** Override: specific tools available (empty = inherit from type) */
	tools?: string[]
	/** Maximum result size to inject back into parent context */
	maxResultChars?: number
	/**
	 * When true, build fork context for prompt cache sharing (byte-identical
	 * prefix) instead of a text summary. Requires the provider to support
	 * prompt caching to benefit.
	 */
	cacheAwareFork?: boolean
	/** Cache-safe params for prompt cache sharing (required if cacheAwareFork is true) */
	cacheSafeParams?: CacheSafeParams
}

/** Default tool sets per agent type */
export const AGENT_TYPE_TOOLS: Record<SubAgentType, string[]> = {
	explore: ["read_file", "search_files", "list_files", "list_code_definition_names", "codebase_search"],
	implement: ["read_file", "write_to_file", "apply_diff", "execute_command", "search_files"],
	verify: ["read_file", "execute_command", "search_files", "list_files"],
	custom: [], // inherits parent task tools
}

/** Default context budgets per agent type */
export const AGENT_TYPE_CONTEXT_BUDGET: Record<SubAgentType, number> = {
	explore: 32_000,
	implement: 64_000,
	verify: 32_000,
	custom: 64_000,
}

/** Get effective tools for a sub-agent type, with optional overrides */
export function getEffectiveTools(options: SubTaskOptions): string[] {
	if (options.tools && options.tools.length > 0) {
		return options.tools
	}
	return AGENT_TYPE_TOOLS[options.agentType]
}

/** Get effective context budget for a sub-agent type */
export function getEffectiveContextBudget(options: SubTaskOptions): number {
	return options.contextBudget ?? AGENT_TYPE_CONTEXT_BUDGET[options.agentType]
}

/**
 * Cache-safe parameters for prompt cache sharing between parent and forked agent.
 * When all five components are byte-identical between parent and fork, the
 * provider can reuse the cached prompt prefix, dramatically reducing latency
 * and cache_creation tokens.
 *
 * Inspired by Claude Code's CacheSafeParams in forkedAgent.ts.
 */
export interface CacheSafeParams {
	/** Parent's rendered system prompt (not re-rendered, to avoid divergence) */
	systemPrompt: string
	/** Parent's user context (CLAUDE.md etc.) */
	userContext?: string
	/** Parent's tool definitions (exact same ToolUseBlock params) */
	toolDefinitions?: string
	/** Parent's conversation messages up to the fork point */
	forkContextMessages?: Array<{ role: string; content: any }>
}

/** Configuration for forked context generation */
export interface ForkedContextConfig {
	/** Maximum tokens for the parent context summary */
	summaryMaxTokens: number
	/** Maximum number of recent parent messages to consider */
	maxRecentMessages: number
	/** Whether to include file modification info in the summary */
	includeFileChanges: boolean
	/** Whether to include command execution info in the summary */
	includeCommands: boolean
	/** Maximum characters for the result summary injected back into parent */
	maxResultChars: number
}

export interface TaskResult {
	success: boolean
	summary: string
	isolationLevel?: IsolationLevel
	error?: string
}

/** Default configuration for forked context */
export const DEFAULT_FORKED_CONTEXT_CONFIG: ForkedContextConfig = {
	summaryMaxTokens: 10_000,
	maxRecentMessages: 10,
	includeFileChanges: true,
	includeCommands: true,
	maxResultChars: 2000,
}

/**
 * TaskAskSayHandler — Ask/say operation handling.
 *
 * Extracted from Task.ts to decompose the monolithic file. Handles all ask()
 * and say() operations including auto-approval, message queuing, and response
 * processing.
 *
 * Phase 1: Extract ask/say logic from Task.ts
 * Phase 2 (future): Move webview response handling here once host surface is reduced
 */
import type { ClineAsk, ClineAskResponse, ClineSay, ToolProgressStatus, ContextCondense, ContextTruncation, ToolName } from "@njust-ai-cj/types"
import {
	isInteractiveAsk,
	isIdleAsk,
	isResumableAsk,
} from "@njust-ai-cj/types"
import { findLastIndex } from "../../shared/array"
import { formatResponse } from "../../core/prompts/responses"
import { NJUST_AI_CJEventName } from "@njust-ai-cj/types"
import type { TaskAskSayHost } from "./interfaces/TaskAskSayHost"
import { logger } from "../../shared/logger"
import pWaitFor from "p-wait-for"

class AskIgnoredError extends Error {
	constructor(public readonly reason: string) {
		super(`Ask ignored: ${reason}`)
		this.name = "AskIgnoredError"
	}
}

function checkAutoApproval({
	state: _state,
	ask: _ask,
	text: _text,
	isProtected: _isProtected,
}: {
	state: any
	ask: ClineAsk
	text?: string
	isProtected?: boolean
}): Promise<{
	decision: "ask" | "approve" | "deny" | "timeout"
	fn?: () => { askResponse: ClineAskResponse; text?: string; images?: string[] }
	timeout?: number
}> {
	// TODO: Implement auto-approval logic
	return { decision: "ask" }
}

export class TaskAskSayHandler {
	constructor(private host: TaskAskSayHost) {}

	async ask(
		type: ClineAsk,
		text?: string,
		partial?: boolean,
		progressStatus?: ToolProgressStatus,
		isProtected?: boolean,
	): Promise<{ response: ClineAskResponse; text?: string; images?: string[] }> {
		if (this.host.abort) {
			throw new Error(`[NJUST_AI_CJ#ask] task ${this.host.taskId}.${this.host.instanceId} aborted`)
		}

		let askTs: number

		if (partial !== undefined) {
			const lastMessage = this.host.clineMessages.at(-1)

			const isUpdatingPreviousPartial =
				lastMessage && lastMessage.partial && lastMessage.type === "ask" && lastMessage.ask === type

			if (partial) {
				if (isUpdatingPreviousPartial) {
					lastMessage.text = text
					lastMessage.partial = partial
					lastMessage.progressStatus = progressStatus
					lastMessage.isProtected = isProtected
					void this.host.updateClineMessage(lastMessage)
					throw new AskIgnoredError("updating existing partial")
				} else {
					askTs = Date.now()
					this.host.lastMessageTs = askTs
					await this.host.addToClineMessages({ ts: askTs, type: "ask", ask: type, text, partial, isProtected })
					throw new AskIgnoredError("new partial")
				}
			} else {
				if (isUpdatingPreviousPartial) {
					this.host.askResponse = undefined
					this.host.askResponseText = undefined
					this.host.askResponseImages = undefined
					askTs = lastMessage.ts
					this.host.lastMessageTs = askTs
					lastMessage.text = text
					lastMessage.partial = false
					lastMessage.progressStatus = progressStatus
					lastMessage.isProtected = isProtected
					await this.host.saveClineMessages()
					void this.host.updateClineMessage(lastMessage)
				} else {
					this.host.askResponse = undefined
					this.host.askResponseText = undefined
					this.host.askResponseImages = undefined
					askTs = Date.now()
					this.host.lastMessageTs = askTs
					await this.host.addToClineMessages({ ts: askTs, type: "ask", ask: type, text, isProtected })
				}
			}
		} else {
			this.host.askResponse = undefined
			this.host.askResponseText = undefined
			this.host.askResponseImages = undefined
			askTs = Date.now()
			this.host.lastMessageTs = askTs
			await this.host.addToClineMessages({ ts: askTs, type: "ask", ask: type, text, isProtected })
		}

		const timeouts: NodeJS.Timeout[] = []

		const provider = this.host.hostRef.deref()
		const state = provider ? await provider.getState() : undefined
		const approval = await checkAutoApproval({ state, ask: type, text, isProtected })

		if (approval.decision === "approve") {
			this.host.approveAsk()
		} else if (approval.decision === "deny") {
			this.host.denyAsk()
		} else if (approval.decision === "timeout") {
			this.host.autoApprovalTimeoutRef = setTimeout(() => {
				const { askResponse, text, images } = approval.fn!()
				this.host.handleWebviewAskResponse(askResponse, text, images)
				this.host.autoApprovalTimeoutRef = undefined
			}, approval.timeout) as NodeJS.Timeout
			timeouts.push(this.host.autoApprovalTimeoutRef)
		}

		const isBlocking = !(this.host.askResponse !== undefined || this.host.lastMessageTs !== askTs)
		const isMessageQueued = !this.host.messageQueueService.isEmpty()
		const shouldDrainQueuedMessageForAsk = type !== "command_output" && !isIdleAsk(type)
		const isStatusMutable = !partial && isBlocking && !isMessageQueued && approval.decision === "ask"

		if (isStatusMutable) {
			const statusMutationTimeout = 2_000

			if (isInteractiveAsk(type)) {
				timeouts.push(
					setTimeout(() => {
						const message = this.host.findMessageByTimestamp(askTs)
						if (message) {
							this.host.interactiveAsk = message
							this.host.emit(NJUST_AI_CJEventName.TaskInteractive, this.host.taskId)
							provider?.postMessageToWebview({ type: "interactionRequired" })
						}
					}, statusMutationTimeout),
				)
			} else if (isResumableAsk(type)) {
				timeouts.push(
					setTimeout(() => {
						const message = this.host.findMessageByTimestamp(askTs)
						if (message) {
							this.host.resumableAsk = message
							this.host.emit(NJUST_AI_CJEventName.TaskResumable, this.host.taskId)
						}
					}, statusMutationTimeout),
				)
			} else if (isIdleAsk(type)) {
				timeouts.push(
					setTimeout(() => {
						const message = this.host.findMessageByTimestamp(askTs)
						if (message) {
							this.host.idleAsk = message
							this.host.emit(NJUST_AI_CJEventName.TaskIdle, this.host.taskId)
						}
					}, statusMutationTimeout),
				)
			}
		} else if (isMessageQueued && shouldDrainQueuedMessageForAsk) {
			const message = this.host.messageQueueService.dequeueMessage()
			if (message) {
				if (type === "tool" || type === "command" || type === "use_mcp_server") {
					this.host.handleWebviewAskResponse("yesButtonClicked", message.text, message.images)
				} else {
					this.host.handleWebviewAskResponse("messageResponse", message.text, message.images)
				}
			}
		}

		await pWaitFor(
			() => {
				if (this.host.askResponse !== undefined || this.host.lastMessageTs !== askTs) {
					return true
				}
				if (shouldDrainQueuedMessageForAsk && !this.host.messageQueueService.isEmpty()) {
					const message = this.host.messageQueueService.dequeueMessage()
					if (message) {
						if (type === "tool" || type === "command" || type === "use_mcp_server") {
							this.host.handleWebviewAskResponse("yesButtonClicked", message.text, message.images)
						} else {
							this.host.handleWebviewAskResponse("messageResponse", message.text, message.images)
						}
					}
				}
				return false
			},
			{ interval: 100 },
		)

		if (this.host.lastMessageTs !== askTs) {
			throw new AskIgnoredError("superseded")
		}

		const result = {
			response: this.host.askResponse!,
			text: this.host.askResponseText,
			images: this.host.askResponseImages,
		}
		this.host.askResponse = undefined
		this.host.askResponseText = undefined
		this.host.askResponseImages = undefined

		timeouts.forEach((timeout) => clearTimeout(timeout))

		if (this.host.idleAsk || this.host.resumableAsk || this.host.interactiveAsk) {
			this.host.idleAsk = undefined
			this.host.resumableAsk = undefined
			this.host.interactiveAsk = undefined
			this.host.emit(NJUST_AI_CJEventName.TaskActive, this.host.taskId)
		}

		this.host.emit(NJUST_AI_CJEventName.TaskAskResponded)
		return result
	}

	handleWebviewAskResponse(askResponse: ClineAskResponse, text?: string, images?: string[]) {
		this.host.cancelAutoApprovalTimeout()

		this.host.askResponse = askResponse
		this.host.askResponseText = text
		this.host.askResponseImages = images

		if (askResponse === "messageResponse") {
			void this.host.checkpointSave(false, true)
		}

		if (askResponse === "messageResponse" || askResponse === "yesButtonClicked") {
			const lastFollowUpIndex = findLastIndex(
				this.host.clineMessages,
				(msg) => msg.type === "ask" && msg.ask === "followup" && !msg.isAnswered,
			)
			if (lastFollowUpIndex !== -1) {
				this.host.clineMessages[lastFollowUpIndex].isAnswered = true
				this.host.saveClineMessages().catch((error) => {
					logger.error("TaskAskSayHandler", "Failed to save answered follow-up state:", error)
				})
			}
		}

		if (askResponse === "yesButtonClicked") {
			const lastToolAskIndex = findLastIndex(
				this.host.clineMessages,
				(msg) => msg.type === "ask" && msg.ask === "tool" && !msg.isAnswered,
			)
			if (lastToolAskIndex !== -1) {
				this.host.clineMessages[lastToolAskIndex].isAnswered = true
				void this.host.updateClineMessage(this.host.clineMessages[lastToolAskIndex])
				this.host.saveClineMessages().catch((error) => {
					logger.error("TaskAskSayHandler", "Failed to save answered tool-ask state:", error)
				})
			}
		}
	}

	async say(
		type: ClineSay,
		text?: string,
		images?: string[],
		partial?: boolean,
		checkpoint?: Record<string, unknown>,
		progressStatus?: ToolProgressStatus,
		options: {
			isNonInteractive?: boolean
		} = {},
		contextCondense?: ContextCondense,
		contextTruncation?: ContextTruncation,
	): Promise<undefined> {
		if (this.host.abort) {
			throw new Error(`[NJUST_AI_CJ#say] task ${this.host.taskId}.${this.host.instanceId} aborted`)
		}

		if (partial !== undefined) {
			const lastMessage = this.host.clineMessages.at(-1)
			const isUpdatingPreviousPartial =
				lastMessage && lastMessage.partial && lastMessage.type === "say" && lastMessage.say === type

			if (partial) {
				if (isUpdatingPreviousPartial) {
					lastMessage.text = text
					lastMessage.images = images
					lastMessage.partial = partial
					lastMessage.progressStatus = progressStatus
					void this.host.updateClineMessage(lastMessage)
				} else {
					const sayTs = Date.now()
					if (!options.isNonInteractive) {
						this.host.lastMessageTs = sayTs
					}
					await this.host.addToClineMessages({
						ts: sayTs,
						type: "say",
						say: type,
						text,
						images,
						partial,
						contextCondense,
						contextTruncation,
					})
				}
			} else {
				if (isUpdatingPreviousPartial) {
					if (!options.isNonInteractive) {
						this.host.lastMessageTs = lastMessage.ts
					}
					lastMessage.text = text
					lastMessage.images = images
					lastMessage.partial = false
					lastMessage.progressStatus = progressStatus
					await this.host.saveClineMessages()
					void this.host.updateClineMessage(lastMessage)
				} else {
					const sayTs = Date.now()
					if (!options.isNonInteractive) {
						this.host.lastMessageTs = sayTs
					}
					await this.host.addToClineMessages({
						ts: sayTs,
						type: "say",
						say: type,
						text,
						images,
						contextCondense,
						contextTruncation,
					})
				}
			}
		} else {
			const sayTs = Date.now()
			if (!options.isNonInteractive) {
				this.host.lastMessageTs = sayTs
			}
			await this.host.addToClineMessages({
				ts: sayTs,
				type: "say",
				say: type,
				text,
				images,
				checkpoint,
				contextCondense,
				contextTruncation,
			})
		}
	}

	async sayAndCreateMissingParamError(toolName: ToolName, paramName: string, relPath?: string) {
		await this.say(
			"error",
			`Roo tried to use ${toolName}${relPath ? ` for '${relPath.toPosix()}'` : ""} without value for required parameter '${paramName}'. Retrying...`,
		)
		return formatResponse.toolError(formatResponse.missingToolParameterError(paramName))
	}
}

/**
 * TaskLifecycleHandler — Owns task start, resume, abort, and dispose logic.
 *
 * Extracted from Task.ts to decompose the monolithic file.
 * Task.ts retains same-signature public facades that delegate to this module.
 *
 * The handler receives the owning Task instance (typed as `TaskLifecycleHost`)
 * and accesses state / methods through that reference. This avoids circular
 * class imports — only the host *interface* is imported here.
 */
import * as path from "path"
import { promises as fs } from "fs"
import type { Anthropic } from "@anthropic-ai/sdk"

import type {
	ClineAsk,
	ClineApiReqInfo,
	ClineMessage,
} from "@njust-ai-cj/types"
import {
	NJUST_AI_CJEventName,
	MAX_MCP_TOOLS_THRESHOLD,
} from "@njust-ai-cj/types"

import { findLastIndex } from "../../shared/array"
import { DEFAULT_MODE_SLUG } from "../../shared/mode-constants"
import { formatResponse } from "../prompts/responses"
import type { ApiMessage } from "../task-persistence"
import { getTaskDirectoryPath } from "../../utils/storage"
import { globalCacheMetrics } from "../../utils/cacheMetrics"
import { globalPromptCacheBreakDetector } from "../prompts/promptCacheBreakDetection"
import { clearMcpInstructionsDelta } from "../prompts/sections/mcp-instructions-delta"
import { deleteGeneratedCangjieTestFilesForTask } from "../../services/cangjie-lsp/cangjieGeneratedTestCleanup"
import { TerminalRegistry } from "../../integrations/terminal/TerminalRegistry"
import { OutputInterceptor } from "../../integrations/terminal/OutputInterceptor"
import { safeDispose } from "./TaskLifecycle"
import { logger } from "../../shared/logger"
import { isToolUseBlock } from "../assistant-message/types"

// ── Host type ────────────────────────────────────────────────────────────
// Structural contract: Task implements this shape at runtime.
// This avoids a hard import of Task (breaks the circular dependency risk).

export interface TaskLifecycleHost {
	readonly taskId: string
	readonly instanceId: string
	readonly globalStoragePath: string
	readonly hostRef: WeakRef<{ off(event: string, listener: () => void): void }>
	readonly errorRecovery: { resetCompactFailure(): void }
	readonly messageQueueService: {
		removeListener(event: string, handler: () => void): void
		dispose(): void
	}
	readonly toolExecution: { dispose(): void }
	readonly fileContextTracker: { dispose(): void }
	readonly diffViewProvider: {
		readonly isEditing: boolean
		revertChanges(): Promise<void>
	}

	abort: boolean
	abandoned: boolean
	abortReason?: string
	isInitialized: boolean
	isDisposed: boolean
	isStreaming: boolean
	consecutiveNoToolUseCount: number
	consecutiveNoAssistantMessagesCount: number
	persistentRetryHandler?: { cancel(): void } | undefined
	providerProfileChangeListener?: (() => void) | undefined
	messageQueueStateChangedHandler?: (() => void) | undefined
	rooIgnoreController?: { dispose(): void } | undefined
	clineMessages: ClineMessage[]
	apiConversationHistory: ApiMessage[]

	refreshWebviewState(): Promise<void>
	say(type: any, text?: string, images?: string[], partial?: boolean, checkpoint?: any, progressStatus?: any, options?: any): Promise<undefined>
	ask(type: any, text?: string, partial?: boolean): Promise<{ response: string; text?: string; images?: string[] }>
	emit(event: string, ...args: any[]): boolean
	getEnabledMcpToolsCount(): Promise<{ enabledToolCount: number; enabledServerCount: number }>
	getTaskMode(): Promise<string>
	initiateCloudAgentLoop(message: string, images?: string[]): Promise<void>
	initiateTaskLoop(userContent: any[]): Promise<void>
	getSavedClineMessages(): Promise<ClineMessage[]>
	getSavedApiConversationHistory(): Promise<ApiMessage[]>
	overwriteClineMessages(messages: ClineMessage[]): Promise<void>
	overwriteApiConversationHistory(history: ApiMessage[]): Promise<void>
	saveClineMessages(): Promise<boolean>
	emitFinalTokenUsageUpdate(): void
	dispose(): void
	cancelCurrentRequest(): void
	removeAllListeners(): void
}

// ── Handler ──────────────────────────────────────────────────────────────

export class TaskLifecycleHandler {
	constructor(private host: TaskLifecycleHost) {}

	// ── startTask ────────────────────────────────────────────────────────

	async startTask(task?: string, images?: string[]): Promise<void> {
		const t = this.host
		try {
			t.clineMessages = []
			t.apiConversationHistory = []

			await t.refreshWebviewState()

			await t.say("text", task, images)

			const { enabledToolCount, enabledServerCount } = await t.getEnabledMcpToolsCount()
			if (enabledToolCount > MAX_MCP_TOOLS_THRESHOLD) {
				await t.say(
					"too_many_tools_warning",
					JSON.stringify({
						toolCount: enabledToolCount,
						serverCount: enabledServerCount,
						threshold: MAX_MCP_TOOLS_THRESHOLD,
					}),
					undefined,
					undefined,
					undefined,
					undefined,
					{ isNonInteractive: true },
				)
			}
			t.isInitialized = true

			const mode = await t.getTaskMode()

			if (mode === DEFAULT_MODE_SLUG) {
				await t.initiateCloudAgentLoop(task ?? "", images).catch((error: any) => {
					if (t.abandoned === true || t.abortReason === "user_cancelled") {
						return
					}
					throw error
				})
			} else {
				const imageBlocks: Anthropic.ImageBlockParam[] = formatResponse.imageBlocks(images)

				await t.initiateTaskLoop([
					{
						type: "text",
						text: `<user_message>\n${task}\n</user_message>`,
					},
					...imageBlocks,
				]).catch((error: any) => {
					if (t.abandoned === true || t.abortReason === "user_cancelled") {
						return
					}
					throw error
				})
			}
		} catch (error) {
			if (t.abandoned === true || t.abort === true || t.abortReason === "user_cancelled") {
				return
			}
			throw error
		}
	}

	// ── resumeTaskFromHistory ────────────────────────────────────────────

	async resumeTaskFromHistory(): Promise<void> {
		const t = this.host
		try {
			const modifiedClineMessages = await t.getSavedClineMessages()

			const lastRelevantMessageIndex = findLastIndex(
				modifiedClineMessages,
				(m: any) => !(m.ask === "resume_task" || m.ask === "resume_completed_task"),
			)

			if (lastRelevantMessageIndex !== -1) {
				modifiedClineMessages.splice(lastRelevantMessageIndex + 1)
			}

			while (modifiedClineMessages.length > 0) {
				const last = modifiedClineMessages[modifiedClineMessages.length - 1]
				if (last.type === "say" && last.say === "reasoning") {
					modifiedClineMessages.pop()
				} else {
					break
				}
			}

			const lastApiReqStartedIndex = findLastIndex(
				modifiedClineMessages,
				(m: any) => m.type === "say" && m.say === "api_req_started",
			)

			if (lastApiReqStartedIndex !== -1) {
				const lastApiReqStarted = modifiedClineMessages[lastApiReqStartedIndex]
				const { cost, cancelReason }: ClineApiReqInfo = JSON.parse(lastApiReqStarted.text || "{}")

				if (cost === undefined && cancelReason === undefined) {
					modifiedClineMessages.splice(lastApiReqStartedIndex, 1)
				}
			}

			await t.overwriteClineMessages(modifiedClineMessages)
			t.clineMessages = await t.getSavedClineMessages()

			t.apiConversationHistory = await t.getSavedApiConversationHistory()

			t.errorRecovery.resetCompactFailure()

			const lastClineMessage = t.clineMessages
				.slice()
				.reverse()
				.find((m: any) => !(m.ask === "resume_task" || m.ask === "resume_completed_task"))

			let askType: ClineAsk
			if (lastClineMessage?.ask === "completion_result") {
				askType = "resume_completed_task"
			} else {
				askType = "resume_task"
			}

			t.isInitialized = true

			const { response, text, images } = await t.ask(askType)

			let responseText: string | undefined
			let responseImages: string[] | undefined

			if (response === "messageResponse") {
				await t.say("user_feedback", text, images)
				responseText = text
				responseImages = images
			}

			const existingApiConversationHistory: ApiMessage[] = await t.getSavedApiConversationHistory()

			let modifiedOldUserContent: Anthropic.Messages.ContentBlockParam[]
			let modifiedApiConversationHistory: ApiMessage[]
			if (existingApiConversationHistory.length > 0) {
				const lastMessage = existingApiConversationHistory[existingApiConversationHistory.length - 1]

				if (lastMessage.isSummary) {
					modifiedApiConversationHistory = [...existingApiConversationHistory]
					modifiedOldUserContent = []
				} else if (lastMessage.role === "assistant") {
					const content = Array.isArray(lastMessage.content)
						? lastMessage.content
						: [{ type: "text" as const, text: lastMessage.content }]
					const hasToolUse = content.some(isToolUseBlock)

					if (hasToolUse) {
						const toolUseBlocks = content.filter(isToolUseBlock) as Anthropic.Messages.ToolUseBlock[]
						const toolResponses: Anthropic.ToolResultBlockParam[] = toolUseBlocks.map((block) => ({
							type: "tool_result" as const,
							tool_use_id: block.id,
							content: "Task was interrupted before this tool call could be completed.",
						}))
						modifiedApiConversationHistory = [...existingApiConversationHistory]
						modifiedOldUserContent = [...toolResponses]
					} else {
						modifiedApiConversationHistory = [...existingApiConversationHistory]
						modifiedOldUserContent = []
					}
				} else if (lastMessage.role === "user") {
					const previousAssistantMessage: ApiMessage | undefined =
						existingApiConversationHistory[existingApiConversationHistory.length - 2]

					const existingUserContent: Anthropic.Messages.ContentBlockParam[] = Array.isArray(
						lastMessage.content,
					)
						? lastMessage.content
						: [{ type: "text" as const, text: lastMessage.content }]
					if (previousAssistantMessage && previousAssistantMessage.role === "assistant") {
						const assistantContent = Array.isArray(previousAssistantMessage.content)
							? previousAssistantMessage.content
							: [{ type: "text" as const, text: previousAssistantMessage.content }]

						const toolUseBlocks = assistantContent.filter(isToolUseBlock) as Anthropic.Messages.ToolUseBlock[]

						if (toolUseBlocks.length > 0) {
							const existingToolResults = existingUserContent.filter(
								(block) => block.type === "tool_result",
							) as Anthropic.ToolResultBlockParam[]

							const missingToolResponses: Anthropic.ToolResultBlockParam[] = toolUseBlocks
								.filter(
									(toolUse) =>
										!existingToolResults.some((result) => result.tool_use_id === toolUse.id),
								)
								.map((toolUse) => ({
									type: "tool_result" as const,
									tool_use_id: toolUse.id,
									content: "Task was interrupted before this tool call could be completed.",
								}))

							modifiedApiConversationHistory = existingApiConversationHistory.slice(0, -1)
							modifiedOldUserContent = [...existingUserContent, ...missingToolResponses]
						} else {
							modifiedApiConversationHistory = existingApiConversationHistory.slice(0, -1)
							modifiedOldUserContent = [...existingUserContent]
						}
					} else {
						modifiedApiConversationHistory = existingApiConversationHistory.slice(0, -1)
						modifiedOldUserContent = [...existingUserContent]
					}
				} else {
					throw new Error("Unexpected: Last message is not a user or assistant message")
				}
			} else {
				throw new Error("Unexpected: No existing API conversation history")
			}

			const newUserContent: Anthropic.Messages.ContentBlockParam[] = [...modifiedOldUserContent]

			const _agoText = ((): string => {
				const timestamp = lastClineMessage?.ts ?? Date.now()
				const now = Date.now()
				const diff = now - timestamp
				const minutes = Math.floor(diff / 60000)
				const hours = Math.floor(minutes / 60)
				const days = Math.floor(hours / 24)

				if (days > 0) {
					return `${days} day${days > 1 ? "s" : ""} ago`
				}
				if (hours > 0) {
					return `${hours} hour${hours > 1 ? "s" : ""} ago`
				}
				if (minutes > 0) {
					return `${minutes} minute${minutes > 1 ? "s" : ""} ago`
				}
				return "just now"
			})()

			if (responseText) {
				newUserContent.push({
					type: "text",
					text: `<user_message>\n${responseText}\n</user_message>`,
				})
			}

			if (responseImages && responseImages.length > 0) {
				newUserContent.push(...formatResponse.imageBlocks(responseImages))
			}

			if (newUserContent.length === 0) {
				newUserContent.push({
					type: "text",
					text: "[TASK RESUMPTION] Resuming task...",
				})
			}

			await t.overwriteApiConversationHistory(modifiedApiConversationHistory)

			await t.initiateTaskLoop(newUserContent)
		} catch (error) {
			if (t.abandoned === true || t.abort === true || t.abortReason === "user_cancelled") {
				return
			}
			throw error
		}
	}

	// ── emitTaskSessionMetricsSummary ────────────────────────────────────

	private emitTaskSessionMetricsSummary(trigger: "abort" | "dispose"): void {
		const t = this.host
		const cacheSummary = globalCacheMetrics.getSummary()
		const breakSummary = globalPromptCacheBreakDetector.getBreaksBySource()
		const payload = {
			timestamp: Date.now(),
			trigger,
			taskId: t.taskId,
			cacheRequests: cacheSummary.totalRequests,
			cacheHitRate: cacheSummary.cacheHitRate,
			cacheReadTokens: cacheSummary.totalCacheReadTokens,
			cacheCreationTokens: cacheSummary.totalCacheCreationTokens,
			estimatedSavingsPercent: cacheSummary.estimatedSavingsPercent,
			cacheBreaks: globalPromptCacheBreakDetector.getTotalBreaks(),
			cacheBreaksBySource: breakSummary,
		}
		logger.info("TaskLifecycleHandler",
			`Task Session Summary: trigger=${payload.trigger} task=${payload.taskId} cacheRequests=${payload.cacheRequests} cacheHitRate=${payload.cacheHitRate.toFixed(3)} cacheRead=${payload.cacheReadTokens} cacheCreate=${payload.cacheCreationTokens} estSavings=${(payload.estimatedSavingsPercent * 100).toFixed(1)}% cacheBreaks=${payload.cacheBreaks} breakBySource=${JSON.stringify(payload.cacheBreaksBySource)}`,
		)

		getTaskDirectoryPath(t.globalStoragePath, t.taskId)
			.then(async (taskDir: string) => {
				const metricsPath = path.join(taskDir, "task-metrics.jsonl")
				await fs.appendFile(metricsPath, `${JSON.stringify(payload)}\n`, "utf8")
			})
			.catch((error: any) => {
				logger.error("TaskLifecycleHandler", `Failed to persist metrics for task ${t.taskId}:`, error)
			})
	}

	// ── abortTask ────────────────────────────────────────────────────────

	async abortTask(isAbandoned = false): Promise<void> {
		const t = this.host

		if (isAbandoned) {
			t.abandoned = true
		}

		t.abort = true
		t.persistentRetryHandler?.cancel()
		t.persistentRetryHandler = undefined

		t.consecutiveNoToolUseCount = 0
		t.consecutiveNoAssistantMessagesCount = 0

		t.emitFinalTokenUsageUpdate()

		t.emit(NJUST_AI_CJEventName.TaskAborted)

		try {
			await t.saveClineMessages()
		} catch (error) {
			logger.error("TaskLifecycleHandler", `Error saving messages during abort for task ${t.taskId}.${t.instanceId}:`, error)
		}
		try {
			t.dispose()
		} catch (error) {
			logger.error("TaskLifecycleHandler", `Error during task ${t.taskId}.${t.instanceId} disposal:`, error)
		}
	}

	// ── dispose ──────────────────────────────────────────────────────────

	dispose(): void {
		const t = this.host

		if (t.isDisposed) {
			return
		}
		t.isDisposed = true

		logger.info("TaskLifecycleHandler", `Disposing task ${t.taskId}.${t.instanceId}`)
		this.emitTaskSessionMetricsSummary(t.abort ? "abort" : "dispose")
		clearMcpInstructionsDelta(t.taskId)

		try {
			deleteGeneratedCangjieTestFilesForTask(t.taskId)
		} catch (e) {
			logger.error("TaskLifecycleHandler", "Error deleting generated Cangjie test files:", e)
		}

		try {
			t.cancelCurrentRequest()
		} catch (error) {
			logger.error("TaskLifecycleHandler", "Error cancelling current request:", error)
		}

		try {
			if (t.providerProfileChangeListener) {
				const provider = t.hostRef.deref()
				if (provider) {
					provider.off(NJUST_AI_CJEventName.ProviderProfileChanged, t.providerProfileChangeListener)
				}
				t.providerProfileChangeListener = undefined
			}
		} catch (error) {
			logger.error("TaskLifecycleHandler", "Error removing provider profile change listener:", error)
		}

		try {
			if (t.messageQueueStateChangedHandler) {
				t.messageQueueService.removeListener("stateChanged", t.messageQueueStateChangedHandler)
				t.messageQueueStateChangedHandler = undefined
			}
			t.messageQueueService.dispose()
		} catch (error) {
			logger.error("TaskLifecycleHandler", "Error disposing message queue:", error)
		}

		try {
			t.removeAllListeners()
		} catch (error) {
			logger.error("TaskLifecycleHandler", "Error removing event listeners:", error)
		}

		try {
			TerminalRegistry.releaseTerminalsForTask(t.taskId)
		} catch (error) {
			logger.error("TaskLifecycleHandler", "Error releasing terminals:", error)
		}

		void getTaskDirectoryPath(t.globalStoragePath, t.taskId)
			.then((taskDir: string) => OutputInterceptor.cleanup(path.join(taskDir, "command-output")))
			.catch((error: any) => {
				logger.error("TaskLifecycleHandler", "Error cleaning up command output artifacts:", error)
			})

		safeDispose("RooIgnoreController", () => {
			if (t.rooIgnoreController) {
				t.rooIgnoreController.dispose()
				t.rooIgnoreController = undefined
			}
		})

		safeDispose("ToolExecution", () => t.toolExecution.dispose())
		safeDispose("FileContextTracker", () => t.fileContextTracker.dispose())

		safeDispose("DiffViewProvider", () => {
			if (t.isStreaming && t.diffViewProvider.isEditing) {
				t.diffViewProvider.revertChanges().catch((error: any) => logger.error("TaskLifecycleHandler", "DiffViewProvider revertChanges failed:", error))
			}
		})
	}
}

/**
 * TaskMessageManager — Manages API conversation history and ClineMessage persistence.
 *
 * Extracted from Task.ts to decompose the monolithic file. Owns persistence
 * operations for both API messages and UI (Cline) messages.
 *
 * Phase 1: persistence and CRUD helpers.
 * Phase 2 (future): move ask/say control flow here once the state surface
 * is reduced via further decoupling.
 */
import type { Anthropic } from "@anthropic-ai/sdk"
import type { ClineMessage, ProviderSettings } from "@njust-ai-cj/types"
import { NJUST_AI_CJEventName, getApiProtocol, getModelId, isRetiredProvider } from "@njust-ai-cj/types"
import { defaultModeSlug } from "../../shared/modes"
import {
	type ApiMessage,
	readApiMessages,
	saveApiMessages,
	readTaskMessages,
	saveTaskMessages,
	taskMetadata,
} from "../task-persistence"
import { getEffectiveApiHistory } from "../condense"
import { validateAndFixToolResultIds } from "./validateToolResultIds"
import { restoreTodoListForTask } from "../tools/UpdateTodoListTool"
import type { ApiHandler } from "../../api"
import { logger } from "../../shared/logger"

/**
 * Minimal surface the message manager needs from its owning Task.
 * Avoids a hard import of Task (breaks the circular dependency risk).
 */
export interface TaskMessageContext {
	readonly taskId: string
	readonly instanceId: string
	readonly globalStoragePath: string
	readonly rootTaskId?: string
	readonly parentTaskId?: string
	readonly taskNumber: number

	abort: boolean
	apiConversationHistory: ApiMessage[]
	clineMessages: ClineMessage[]
	userMessageContent: Anthropic.Messages.ContentBlockParam[]
	assistantMessageSavedToHistory: boolean
	lastMessageTs: number

	readonly api: ApiHandler

	apiConfiguration: ProviderSettings

	_taskMode: string | undefined
	_taskApiConfigName: string | undefined
	taskApiConfigReady: Promise<void>
	initialStatus?: "active" | "delegated" | "completed"

	cwd: string
	debouncedEmitTokenUsage: (tokenUsage: any, toolUsage: any) => void
	toolUsage: any

	emit(event: string, ...args: any[]): boolean

	notifier?: {
		postStateToWebviewWithoutTaskHistory(): Promise<void>
		postMessageToWebview(message: any): Promise<void>
		updateTaskHistory(item: any): Promise<void>
	}
}

export class TaskMessageManager {
	constructor(private ctx: TaskMessageContext) {}

	async getSavedApiConversationHistory(): Promise<ApiMessage[]> {
		return readApiMessages({
			taskId: this.ctx.taskId,
			globalStoragePath: this.ctx.globalStoragePath,
		})
	}

	async addToApiConversationHistory(message: Anthropic.MessageParam, reasoning?: string): Promise<void> {
		// Capture the encrypted_content / thought signatures from the provider (e.g., OpenAI Responses API, Google GenAI) if present.
		// We only persist data reported by the current response body.
		const handler = this.ctx.api as ApiHandler & {
			getResponseId?: () => string | undefined
			getEncryptedContent?: () => { encrypted_content: string; id?: string } | undefined
			getThoughtSignature?: () => string | undefined
			getSummary?: () => any[] | undefined
			getReasoningDetails?: () => any[] | undefined
		}

		if (message.role === "assistant") {
			const responseId = handler.getResponseId?.()
			const reasoningData = handler.getEncryptedContent?.()
			const thoughtSignature = handler.getThoughtSignature?.()
			const reasoningSummary = handler.getSummary?.()
			const reasoningDetails = handler.getReasoningDetails?.()

			// Only Anthropic's API expects/validates the special `thinking` content block signature.
			// Other providers (notably Gemini 3) use different signature semantics (e.g. `thoughtSignature`)
			// and require round-tripping the signature in their own format.
			const modelId = getModelId(this.ctx.apiConfiguration)
			const apiProvider = this.ctx.apiConfiguration.apiProvider
			const apiProtocol = getApiProtocol(
				apiProvider && !isRetiredProvider(apiProvider) ? apiProvider : undefined,
				modelId,
			)
			const isAnthropicProtocol = apiProtocol === "anthropic"

			// Start from the original assistant message
			const messageWithTs: any = {
				...message,
				...(responseId ? { id: responseId } : {}),
				ts: Date.now(),
			}

			// Store reasoning_details array if present (for models like Gemini 3)
			if (reasoningDetails) {
				messageWithTs.reasoning_details = reasoningDetails
			}

			// Store reasoning: Anthropic thinking (with signature), plain text (most providers), or encrypted (OpenAI Native)
			// Skip if reasoning_details already contains the reasoning (to avoid duplication)
			if (isAnthropicProtocol && reasoning && thoughtSignature && !reasoningDetails) {
				// Anthropic provider with extended thinking: Store as proper `thinking` block
				// This format passes through anthropic-filter.ts and is properly round-tripped
				// for interleaved thinking with tool use (required by Anthropic API)
				const thinkingBlock = {
					type: "thinking",
					thinking: reasoning,
					signature: thoughtSignature,
				}

				if (typeof messageWithTs.content === "string") {
					messageWithTs.content = [
						thinkingBlock,
						{ type: "text", text: messageWithTs.content } satisfies Anthropic.Messages.TextBlockParam,
					]
				} else if (Array.isArray(messageWithTs.content)) {
					messageWithTs.content = [thinkingBlock, ...messageWithTs.content]
				} else if (!messageWithTs.content) {
					messageWithTs.content = [thinkingBlock]
				}
			} else if (reasoning && !reasoningDetails) {
				// Other providers (non-Anthropic): Store as generic reasoning block
				const reasoningBlock = {
					type: "reasoning",
					text: reasoning,
					summary: reasoningSummary ?? ([] as any[]),
				}

				// Also store reasoning_content as a top-level field so that it
				// survives content-array transformations (e.g., buildCleanConversationHistory
				// converting the array to a string when the model doesn't set preserveReasoning).
				// DeepSeek/Z.ai require this field to be passed back in thinking mode.
				messageWithTs.reasoning_content = reasoning

				if (typeof messageWithTs.content === "string") {
					messageWithTs.content = [
						reasoningBlock,
						{ type: "text", text: messageWithTs.content } satisfies Anthropic.Messages.TextBlockParam,
					]
				} else if (Array.isArray(messageWithTs.content)) {
					messageWithTs.content = [reasoningBlock, ...messageWithTs.content]
				} else if (!messageWithTs.content) {
					messageWithTs.content = [reasoningBlock]
				}
			} else if (reasoningData?.encrypted_content) {
				// OpenAI Native encrypted reasoning
				const reasoningBlock = {
					type: "reasoning",
					summary: [] as any[],
					encrypted_content: reasoningData.encrypted_content,
					...(reasoningData.id ? { id: reasoningData.id } : {}),
				}

				if (typeof messageWithTs.content === "string") {
					messageWithTs.content = [
						reasoningBlock,
						{ type: "text", text: messageWithTs.content } satisfies Anthropic.Messages.TextBlockParam,
					]
				} else if (Array.isArray(messageWithTs.content)) {
					messageWithTs.content = [reasoningBlock, ...messageWithTs.content]
				} else if (!messageWithTs.content) {
					messageWithTs.content = [reasoningBlock]
				}
			}

			// For non-Anthropic providers (e.g., Gemini 3), persist the thought signature as its own
			// content block so converters can attach it back to the correct provider-specific fields.
			// Note: For Anthropic extended thinking, the signature is already included in the thinking block above.
			if (thoughtSignature && !isAnthropicProtocol) {
				const thoughtSignatureBlock = {
					type: "thoughtSignature",
					thoughtSignature,
				}

				if (typeof messageWithTs.content === "string") {
					messageWithTs.content = [
						{ type: "text", text: messageWithTs.content } satisfies Anthropic.Messages.TextBlockParam,
						thoughtSignatureBlock,
					]
				} else if (Array.isArray(messageWithTs.content)) {
					messageWithTs.content = [...messageWithTs.content, thoughtSignatureBlock]
				} else if (!messageWithTs.content) {
					messageWithTs.content = [thoughtSignatureBlock]
				}
			}

			this.ctx.apiConversationHistory.push(messageWithTs)
		} else {
			// For user messages, validate tool_result IDs ONLY when the immediately previous *effective* message
			// is an assistant message.
			//
			// If the previous effective message is also a user message (e.g., summary + a new user message),
			// validating against any earlier assistant message can incorrectly inject placeholder tool_results.
			const effectiveHistoryForValidation = getEffectiveApiHistory(this.ctx.apiConversationHistory)
			const lastEffective = effectiveHistoryForValidation[effectiveHistoryForValidation.length - 1]
			const historyForValidation = lastEffective?.role === "assistant" ? effectiveHistoryForValidation : []

			// If the previous effective message is NOT an assistant, convert tool_result blocks to text blocks.
			// This prevents orphaned tool_results from being filtered out by getEffectiveApiHistory.
			// This can happen when condensing occurs after the assistant sends tool_uses but before
			// the user responds - the tool_use blocks get condensed away, leaving orphaned tool_results.
			let messageToAdd = message
			if (lastEffective?.role !== "assistant" && Array.isArray(message.content)) {
				messageToAdd = {
					...message,
					content: message.content.map((block) =>
						block.type === "tool_result"
							? {
									type: "text" as const,
									text: `Tool result:\n${typeof block.content === "string" ? block.content : JSON.stringify(block.content)}`,
								}
							: block,
					),
				}
			}

			const validatedMessage = validateAndFixToolResultIds(messageToAdd, historyForValidation)
			const messageWithTs = { ...validatedMessage, ts: Date.now() }
			this.ctx.apiConversationHistory.push(messageWithTs)
		}

		await this.saveApiConversationHistory()
	}

	async overwriteApiConversationHistory(newHistory: ApiMessage[]): Promise<void> {
		this.ctx.apiConversationHistory = newHistory
		await this.saveApiConversationHistory()
	}

	async flushPendingToolResultsToHistory(): Promise<boolean> {
		if (this.ctx.userMessageContent.length === 0) {
			return true
		}

		if (!this.ctx.assistantMessageSavedToHistory) {
			const pWaitFor = (await import("p-wait-for")).default
			await pWaitFor(() => this.ctx.assistantMessageSavedToHistory || this.ctx.abort, {
				interval: 50,
				timeout: 30_000,
			}).catch(() => {
				logger.warn("TaskMessageManager",
					`flushPendingToolResultsToHistory: timed out waiting for assistant message to be saved for task ${this.ctx.taskId}`,
				)
			})
		}

		if (this.ctx.abort) {
			return false
		}

		const userMessage: Anthropic.MessageParam = {
			role: "user",
			content: this.ctx.userMessageContent,
		}

		const effectiveHistoryForValidation = getEffectiveApiHistory(this.ctx.apiConversationHistory)
		const lastEffective = effectiveHistoryForValidation[effectiveHistoryForValidation.length - 1]
		const historyForValidation = lastEffective?.role === "assistant" ? effectiveHistoryForValidation : []
		const validatedMessage = validateAndFixToolResultIds(userMessage, historyForValidation)
		const userMessageWithTs = { ...validatedMessage, ts: Date.now() }
		this.ctx.apiConversationHistory.push(userMessageWithTs as ApiMessage)

		const saved = await this.saveApiConversationHistory()

		if (saved) {
			this.ctx.userMessageContent = []
		} else {
			logger.warn("TaskMessageManager",
				`flushPendingToolResultsToHistory: save failed for task ${this.ctx.taskId}, retaining pending tool results in memory`,
			)
		}

		return saved
	}

	async saveApiConversationHistory(): Promise<boolean> {
		try {
			await saveApiMessages({
				messages: structuredClone(this.ctx.apiConversationHistory),
				taskId: this.ctx.taskId,
				globalStoragePath: this.ctx.globalStoragePath,
			})
			return true
		} catch (error) {
			logger.error("TaskMessageManager", "Failed to save API conversation history:", error)
			return false
		}
	}

	async retrySaveApiConversationHistory(): Promise<boolean> {
		const delays = [100, 500, 1500]

		for (let attempt = 0; attempt < delays.length; attempt++) {
			await new Promise<void>((resolve) => setTimeout(resolve, delays[attempt]))
			logger.warn("TaskMessageManager",
				`retrySaveApiConversationHistory: retry attempt ${attempt + 1}/${delays.length} for task ${this.ctx.taskId}`,
			)

			const success = await this.saveApiConversationHistory()
			if (success) {
				return true
			}
		}

		return false
	}

	// ── ClineMessage persistence ─────────────────────────────────────────

	async getSavedClineMessages(): Promise<ClineMessage[]> {
		return readTaskMessages({
			taskId: this.ctx.taskId,
			globalStoragePath: this.ctx.globalStoragePath,
		})
	}

	async addToClineMessages(message: ClineMessage): Promise<void> {
		this.ctx.clineMessages.push(message)
		await this.ctx.notifier?.postStateToWebviewWithoutTaskHistory()
		this.ctx.emit(NJUST_AI_CJEventName.Message, { action: "created", message })
		await this.saveClineMessages()
	}

	async overwriteClineMessages(newMessages: ClineMessage[]): Promise<void> {
		this.ctx.clineMessages = newMessages
		restoreTodoListForTask(this.ctx as any)
		await this.saveClineMessages()
	}

	async updateClineMessage(message: ClineMessage): Promise<void> {
		await this.ctx.notifier?.postMessageToWebview({ type: "messageUpdated", clineMessage: message })
		this.ctx.emit(NJUST_AI_CJEventName.Message, { action: "updated", message })
	}

	async saveClineMessages(): Promise<boolean> {
		try {
			await saveTaskMessages({
				messages: structuredClone(this.ctx.clineMessages),
				taskId: this.ctx.taskId,
				globalStoragePath: this.ctx.globalStoragePath,
			})

			if (this.ctx._taskApiConfigName === undefined) {
				await this.ctx.taskApiConfigReady
			}

			const { historyItem, tokenUsage } = await taskMetadata({
				taskId: this.ctx.taskId,
				rootTaskId: this.ctx.rootTaskId,
				parentTaskId: this.ctx.parentTaskId,
				taskNumber: this.ctx.taskNumber,
				messages: this.ctx.clineMessages,
				globalStoragePath: this.ctx.globalStoragePath,
				workspace: this.ctx.cwd,
				mode: this.ctx._taskMode || defaultModeSlug,
				apiConfigName: this.ctx._taskApiConfigName,
				initialStatus: this.ctx.initialStatus,
			})

			this.ctx.debouncedEmitTokenUsage(tokenUsage, this.ctx.toolUsage)
			await this.ctx.notifier?.updateTaskHistory(historyItem)
			return true
		} catch (error) {
			logger.error("TaskMessageManager", "Failed to save Roo messages:", error)
			return false
		}
	}

	findMessageByTimestamp(ts: number): ClineMessage | undefined {
		for (let i = this.ctx.clineMessages.length - 1; i >= 0; i--) {
			if (this.ctx.clineMessages[i].ts === ts) {
				return this.ctx.clineMessages[i]
			}
		}
		return undefined
	}

	findMessageById(id: string): ClineMessage | undefined {
		for (let i = this.ctx.clineMessages.length - 1; i >= 0; i--) {
			if (this.ctx.clineMessages[i].id === id) {
				return this.ctx.clineMessages[i]
			}
		}
		return undefined
	}
}

import * as vscode from "vscode"
import pWaitFor from "p-wait-for"
import crypto from "crypto"

import {
	type ContextCondense,
} from "@njust-ai-cj/types"
import { Package } from "../../shared/package"
import { defaultModeSlug } from "../../shared/modes"

import type { ApiHandlerCreateMessageMetadata } from "../../api"
import { resolveParallelNativeToolCalls } from "../../shared/parallelToolCalls"

import type { IMcpHubService } from "../../services/mcp/interfaces/IMcpHubService"
import { McpServerManager } from "../../services/mcp/McpServerManager"

import {
	SYSTEM_PROMPT_PARTS,
	type SystemPromptParts,
	deriveCangjieContextTokenBudgetFromContextWindow,
} from "../prompts/system"
import { getCangjieSystemPromptCacheKeySuffix } from "../prompts/sections/cangjie-context"
import type { ApiMessage } from "../task-persistence"
import { buildNativeToolsArrayWithRestrictions } from "./build-tools"
import { getEnvironmentDetails } from "../environment/getEnvironmentDetails"
import { summarizeConversation } from "../condense"

import type { Task } from "./Task"
import { logger } from "../../shared/logger"

/**
 * TaskRequestBuilder handles system prompt generation, prompt caching,
 * and context condensation logic extracted from Task.ts.
 *
 * Uses the delegation pattern: accesses Task instance properties via `this.task`.
 */
export class TaskRequestBuilder {
	private systemPromptPartsCache?: { key: string; parts: SystemPromptParts; time: number }

	/** In-flight prefetch promise to avoid duplicate concurrent prefetches. */
	private prefetchInFlight?: Promise<void>

	constructor(private task: Task) {}

	/** Last user message text for Ask/Architect 仓颉语料相关性检测（与缓存键一致）。 */
	private getLastUserMessageTextForCangjieHint(): string | undefined {
		const history = this.task.apiConversationHistory
		for (let i = history.length - 1; i >= 0; i--) {
			const m = history[i] as ApiMessage
			if (m.role !== "user") continue
			const c = m.content
			if (typeof c === "string") return c
			if (Array.isArray(c)) {
				const parts: string[] = []
				for (const block of c) {
					if (block && typeof block === "object" && (block as { type?: string }).type === "text") {
						const t = (block as { text?: string }).text
						if (typeof t === "string") parts.push(t)
					}
				}
				if (parts.length > 0) return parts.join("\n")
			}
		}
		return undefined
	}

	/**
	 * Inherit system prompt parts cache from a parent task's builder.
	 */
	inheritCacheFromParent(parentTask: Task): void {
		const parentCache = parentTask.requestBuilder?.systemPromptPartsCache
		if (!parentCache) return

		// Skip cache inheritance if parent and child modes are known to differ.
		// Different modes produce different system prompts, making parent cache invalid.
		const parentMode = parentTask.taskMode
		const childMode = this.task.taskMode
		if (parentMode !== undefined && childMode !== undefined && parentMode !== childMode) return

		this.systemPromptPartsCache = {
			key: parentCache.key,
			parts: parentCache.parts,
			time: Date.now(),
		}
		if (parentTask.cachedStreamingModel) {
			this.task.cachedStreamingModel = parentTask.cachedStreamingModel
		}

		// Inherit cached tool definitions so child tasks skip redundant tool building.
		if (parentTask.cachedToolDefinitions) {
			this.task.cachedToolDefinitions = { ...parentTask.cachedToolDefinitions, time: Date.now() }
		}
	}

	/**
	 * Generate system prompt parts with caching support.
	 */
	async getSystemPromptParts(): Promise<SystemPromptParts> {
		const { mcpEnabled } = (await this.task.providerRef.deref()?.getState()) ?? {}
		let mcpHub: IMcpHubService | undefined
		if (mcpEnabled ?? true) {
			const provider = this.task.providerRef.deref()

			if (!provider) {
				throw new Error("Provider reference lost during view transition")
			}

			// Wait for MCP hub initialization through McpServerManager
			mcpHub = await McpServerManager.getInstance(provider.context, provider)

			if (!mcpHub) {
				throw new Error("Failed to get MCP hub from server manager")
			}

			// Wait for MCP servers to be connected before generating system prompt
			await pWaitFor(() => !mcpHub!.isConnecting, { timeout: 10_000 }).catch(() => {
				logger.error("TaskRequestBuilder", "MCP servers failed to connect in time")
			})
		}

		const rooIgnoreInstructions = this.task.rooIgnoreController?.getInstructions()

		const state = await this.task.providerRef.deref()?.getState()

		const {
			mode,
			customModes,
			customModePrompts,
			customInstructions,
			experiments,
			language,
			apiConfiguration,
			enableSubfolderRules,
			enableWebSearch,
		} = state ?? {}

		return await (async () => {
			const mcpServers = mcpHub?.getServers() ?? []
			const mcpToolNames = mcpServers
				.flatMap((server) =>
					(server.tools ?? []).map((tool) => `${server.name}:${tool.name}`),
				)
				.sort()
			const mcpToolsHash = crypto.createHash("sha256").update(mcpToolNames.join("|")).digest("hex").slice(0, 12)
			const instructionHash = crypto
				.createHash("sha256")
				.update(`${customInstructions ?? ""}|${JSON.stringify(customModePrompts ?? {})}`)
				.digest("hex")
				.slice(0, 12)
			const lastUserForCangjie = this.getLastUserMessageTextForCangjieHint()
			const staticKey = JSON.stringify({
				cwd: this.task.cwd,
				mode,
				lang: language,
				enableWebSearch,
				useAgentRules: vscode.workspace.getConfiguration(Package.name).get<boolean>("useAgentRules") ?? true,
				enableSubfolderRules: enableSubfolderRules ?? false,
				mcpEnabled: Boolean(mcpHub),
				mcpServerCount: mcpServers.length,
				mcpToolsHash,
				instructionHash,
				cangjieAugmentKey: getCangjieSystemPromptCacheKeySuffix(
					this.task.cwd,
					mode ?? defaultModeSlug,
					lastUserForCangjie,
				),
			})
			const cacheKey = `${mode ?? defaultModeSlug}:${staticKey}`
			const now = Date.now()
			if (this.systemPromptPartsCache && this.systemPromptPartsCache.key === cacheKey && now - this.systemPromptPartsCache.time < 30_000) {
				return this.systemPromptPartsCache.parts
			}
			const provider = this.task.providerRef.deref()

			if (!provider) {
				throw new Error("Provider not available")
			}

			const modelInfo = this.task.api.getModel().info

			const parts = await SYSTEM_PROMPT_PARTS(
				provider.context,
				this.task.cwd,
				false,
				mcpHub,
				this.task.diffStrategy,
				mode ?? defaultModeSlug,
				customModePrompts,
				customModes,
				customInstructions,
				experiments,
				language,
				rooIgnoreInstructions,
				{
					todoListEnabled: apiConfiguration?.todoListEnabled ?? true,
					useAgentRules:
						vscode.workspace.getConfiguration(Package.name).get<boolean>("useAgentRules") ?? true,
					enableSubfolderRules: enableSubfolderRules ?? false,
					newTaskRequireTodos: vscode.workspace
						.getConfiguration(Package.name)
						.get<boolean>("newTaskRequireTodos", false),
					isStealthModel: modelInfo?.isStealthModel,
					enableWebSearch: enableWebSearch ?? false,
					cangjieContextTokenBudget: deriveCangjieContextTokenBudgetFromContextWindow(
						modelInfo?.contextWindow,
					),
					cangjieContextIntensity: this.task.cangjieRuntimePolicy.getContextIntensity(
						Math.max(0, this.task.apiConversationHistory.length - 1),
					),
					cangjieRecentBuildRootCauses: this.task.cangjieRuntimePolicy.getRecentBuildRootCauses(),
					cangjieRepairDirective: this.task.cangjieRuntimePolicy.getRepairDirective(),
					contextWindow: modelInfo?.contextWindow,
					taskId: this.task.taskId,
					turnIndex: Math.max(0, this.task.apiConversationHistory.length - 1),
					enableTurnAwarePromptPruning: (state as any)?.enableTurnAwarePromptPruning ?? true,
					lastUserMessageForCangjieHint: lastUserForCangjie,
				},
				undefined, // todoList
				this.task.api.getModel().id,
				provider.getSkillsManager(),
			)
			this.systemPromptPartsCache = { key: cacheKey, parts, time: now }
			return parts
		})()
	}

	/**
	 * Get the full system prompt string.
	 */
	async getSystemPrompt(): Promise<string> {
		const parts = await this.getSystemPromptParts()
		return parts.fullPrompt
	}

	/**
	 * Condense the conversation context to reduce token usage.
	 */
	async condenseContext(): Promise<void> {
		// CRITICAL: Flush any pending tool results before condensing
		// to ensure tool_use/tool_result pairs are complete in history
		await this.task.flushPendingToolResultsToHistory()

		const systemPrompt = await this.getSystemPrompt()

		// Get condensing configuration
		const state = await this.task.providerRef.deref()?.getState()
		this.systemPromptPartsCache = undefined
		const customCondensingPrompt = state?.customSupportPrompts?.CONDENSE
		const { mode, apiConfiguration } = state ?? {}

		const { contextTokens: prevContextTokens } = this.task.getTokenUsage()

		// Build tools for condensing metadata (same tools used for normal API calls)
		const provider = this.task.providerRef.deref()
		let allTools: import("openai").default.Chat.ChatCompletionTool[] = []
		if (provider) {
			const modelInfo = this.task.api.getModel().info
			const toolsResult = await buildNativeToolsArrayWithRestrictions({
				provider,
				cwd: this.task.cwd,
				mode,
				customModes: state?.customModes,
				experiments: state?.experiments,
				apiConfiguration,
				disabledTools: state?.disabledTools,
				enableWebSearch: state?.enableWebSearch,
				modelInfo,
				includeAllToolsWithRestrictions: false,
			})
			allTools = toolsResult.tools
		}

		// Build metadata with tools and taskId for the condensing API call
		const metadata: ApiHandlerCreateMessageMetadata = {
			mode,
			taskId: this.task.taskId,
			...(allTools.length > 0
				? {
						tools: allTools,
						tool_choice: "auto",
						parallelToolCalls: resolveParallelNativeToolCalls(apiConfiguration),
					}
				: {}),
		}
		// Generate environment details to include in the condensed summary
		const environmentDetails = await getEnvironmentDetails(this.task, true)

		const filesReadByRoo = await this.getFilesReadByRooSafely("condenseContext")

		const {
			messages,
			summary,
			cost,
			newContextTokens = 0,
			error,
			condenseId,
		} = await summarizeConversation({
			messages: this.task.apiConversationHistory,
			apiHandler: this.task.api,
			systemPrompt,
			taskId: this.task.taskId,
			isAutomaticTrigger: false,
			customCondensingPrompt,
			metadata,
			environmentDetails,
			filesReadByRoo,
			cwd: this.task.cwd,
			rooIgnoreController: this.task.rooIgnoreController,
		})
		if (error) {
			await this.task.say(
				"condense_context_error",
				error,
				undefined /* images */,
				false /* partial */,
				undefined /* checkpoint */,
				undefined /* progressStatus */,
				{ isNonInteractive: true } /* options */,
			)
			return
		}
		await this.task.overwriteApiConversationHistory(messages)

		const contextCondense: ContextCondense = {
			summary,
			cost,
			newContextTokens,
			prevContextTokens,
			condenseId: condenseId!,
		}
		await this.task.say(
			"condense_context",
			undefined /* text */,
			undefined /* images */,
			false /* partial */,
			undefined /* checkpoint */,
			undefined /* progressStatus */,
			{ isNonInteractive: true } /* options */,
			contextCondense,
		)

		// Process any queued messages after condensing completes
		this.task.processQueuedMessages()
	}

	/**
	 * Prefetch system prompt data in the background.
	 * Triggers `getSystemPromptParts()` which populates the 30-second cache.
	 * Uses `Promise.allSettled` so individual failures don't block others.
	 * Returns immediately if a valid cache exists or a prefetch is already in flight.
	 */
	async prefetchSystemPromptData(): Promise<void> {
		// Skip if we already have a valid cache (< 30s old)
		if (this.systemPromptPartsCache && Date.now() - this.systemPromptPartsCache.time < 30_000) {
			return
		}

		// Deduplicate: if a prefetch is already running, wait for it instead of starting another.
		if (this.prefetchInFlight) {
			return this.prefetchInFlight
		}

		const startTime = Date.now()
		this.prefetchInFlight = (async () => {
			try {
				// getSystemPromptParts() internally calls SYSTEM_PROMPT_PARTS which
				// runs I/O-heavy operations (skills discovery, Cangjie context,
				// rules loading, modes section, custom instructions) and caches
				// the result for 30 seconds.
				const results = await Promise.allSettled([
					this.getSystemPromptParts(),
				])

				const elapsed = Date.now() - startTime
				const failures = results.filter((r) => r.status === "rejected")
				if (failures.length > 0) {
			logger.warn("TaskRequestBuilder",
					`System prompt data prefetched in ${elapsed}ms with ${failures.length} failure(s)`,
					failures.map((f) => (f as PromiseRejectedResult).reason),
				)
				} else {
					logger.info("TaskRequestBuilder", `System prompt data prefetched in ${elapsed}ms`)
				}
			} catch (error) {
				logger.warn("TaskRequestBuilder", "System prompt prefetch failed:", error)
			}
		})().finally(() => {
			this.prefetchInFlight = undefined
		})

		return this.prefetchInFlight
	}

	/**
	 * Clear the system prompt parts cache.
	 */
	clearCache(): void {
		this.systemPromptPartsCache = undefined
	}

	/**
	 * Safely get files read by Roo, catching errors.
	 */
	private async getFilesReadByRooSafely(_context: string): Promise<string[] | undefined> {
		try {
			return await this.task.fileContextTracker.getFilesReadByRoo()
		} catch (error) {
			logger.error("TaskRequestBuilder", `Failed to get files read by Roo:`, error)
			return undefined
		}
	}
}

/**
 * Task Result Aggregator
 *
 * Aggregates results from multiple subtasks into a structured summary
 * for injection back into the parent task's context.
 *
 * Strategies:
 * - Code modifications: preserve file paths + diff summaries
 * - Search/analysis: preserve conclusions + key references
 * - Failed subtasks: preserve error reason + suggested alternatives
 */

import type { ApiMessage } from "../task-persistence/apiMessages"

export interface SubtaskResult {
	taskId: string
	taskDescription: string
	status: "completed" | "failed" | "partial"
	resultType: "code_modification" | "search_analysis" | "command_execution" | "general"
	filesModified: string[]
	filesRead: string[]
	commandsExecuted: string[]
	summary: string
	error?: string
	duration: number // ms
}

export interface AggregatedResult {
	subtaskCount: number
	successCount: number
	failureCount: number
	sections: AggregatedSection[]
	totalTokens: number
}

interface AggregatedSection {
	title: string
	content: string
	tokenCount: number
}

/** Maximum tokens for the entire aggregated result */
const MAX_AGGREGATED_TOKENS = 8000

/** Maximum tokens per subtask summary */
const MAX_PER_SUBTASK_TOKENS = 2000

/**
 * Estimate token count from text using a rough 4-chars-per-token heuristic.
 */
function estimateTokens(text: string): number {
	return Math.ceil(text.length / 4)
}

/**
 * Extract text content from an ApiMessage content field.
 * Handles both plain string and Anthropic content-block array formats.
 */
function getTextContent(content: any): string {
	if (typeof content === "string") return content
	if (Array.isArray(content)) {
		return (content as Array<{ type: string; text?: string }>)
			.filter((block) => block.type === "text" && typeof block.text === "string")
			.map((block) => block.text!)
			.join("\n")
	}
	return ""
}

export class TaskResultAggregator {
	private results: SubtaskResult[] = []

	/**
	 * Add a subtask result to the aggregation queue.
	 */
	addResult(result: SubtaskResult): void {
		this.results.push(result)
	}

	/**
	 * Get all currently collected results.
	 */
	getResults(): readonly SubtaskResult[] {
		return this.results
	}

	/**
	 * Classify a subtask result based on its conversation messages.
	 *
	 * Analyzes message content to determine the dominant activity type:
	 * - Contains write_to_file / apply_diff → code_modification
	 * - Contains search_files / read_file → search_analysis
	 * - Contains execute_command → command_execution
	 * - Otherwise → general
	 */
	classifyResult(messages: ApiMessage[], _taskDescription: string): SubtaskResult["resultType"] {
		let codeScore = 0
		let searchScore = 0
		let commandScore = 0

		for (const msg of messages) {
			const text = getTextContent(msg.content)
			if (!text) continue

			// Score code modification signals
			if (/write_to_file/i.test(text)) codeScore += 3
			if (/apply_diff/i.test(text)) codeScore += 3
			if (/create_file/i.test(text)) codeScore += 2

			// Score search/analysis signals
			if (/search_files/i.test(text)) searchScore += 2
			if (/read_file/i.test(text)) searchScore += 1
			if (/list_files/i.test(text)) searchScore += 1

			// Score command execution signals
			if (/execute_command/i.test(text)) commandScore += 3
		}

		const maxScore = Math.max(codeScore, searchScore, commandScore)
		if (maxScore === 0) return "general"
		if (codeScore === maxScore) return "code_modification"
		if (commandScore === maxScore) return "command_execution"
		return "search_analysis"
	}

	/**
	 * Generate the aggregated result for injection into parent context.
	 *
	 * Groups subtask results by type, builds structured sections, and
	 * enforces a token budget by proportionally truncating sections.
	 */
	aggregate(): AggregatedResult {
		const sections: AggregatedSection[] = []

		// Group results by type (failed tasks are collected separately regardless of type)
		const codeResults = this.results.filter((r) => r.resultType === "code_modification" && r.status !== "failed")
		const searchResults = this.results.filter((r) => r.resultType === "search_analysis" && r.status !== "failed")
		const commandResults = this.results.filter(
			(r) => r.resultType === "command_execution" && r.status !== "failed",
		)
		const generalResults = this.results.filter((r) => r.resultType === "general" && r.status !== "failed")
		const failedResults = this.results.filter((r) => r.status === "failed")

		// --- Aggregate code modifications ---
		if (codeResults.length > 0) {
			const content = codeResults
				.map((r) => {
					const files = r.filesModified.length > 0 ? r.filesModified.join(", ") : "(no files)"
					const summary = truncateText(r.summary, MAX_PER_SUBTASK_TOKENS * 4)
					return `- ${r.taskDescription}: modified ${files}\n  ${summary}`
				})
				.join("\n")
			sections.push({ title: "Code Changes", content, tokenCount: estimateTokens(content) })
		}

		// --- Aggregate search/analysis results ---
		if (searchResults.length > 0) {
			const content = searchResults
				.map((r) => {
					const summary = truncateText(r.summary, MAX_PER_SUBTASK_TOKENS * 4)
					const refs =
						r.filesRead.length > 0 ? `\n  References: ${r.filesRead.slice(0, 10).join(", ")}` : ""
					return `- ${r.taskDescription}: ${summary}${refs}`
				})
				.join("\n")
			sections.push({ title: "Analysis Results", content, tokenCount: estimateTokens(content) })
		}

		// --- Aggregate command executions ---
		if (commandResults.length > 0) {
			const content = commandResults
				.map((r) => {
					const cmds = r.commandsExecuted.length > 0 ? r.commandsExecuted.join("; ") : "(no commands)"
					const summary = truncateText(r.summary, MAX_PER_SUBTASK_TOKENS * 4)
					return `- ${cmds}: ${summary}`
				})
				.join("\n")
			sections.push({ title: "Command Results", content, tokenCount: estimateTokens(content) })
		}

		// --- Aggregate general results ---
		if (generalResults.length > 0) {
			const content = generalResults
				.map((r) => {
					const summary = truncateText(r.summary, MAX_PER_SUBTASK_TOKENS * 4)
					return `- ${summary}`
				})
				.join("\n")
			sections.push({ title: "Other Results", content, tokenCount: estimateTokens(content) })
		}

		// --- Aggregate failures with recovery suggestions ---
		if (failedResults.length > 0) {
			const content = failedResults
				.map((r) => {
					const errorInfo = r.error ? r.error : "Unknown error"
					return (
						`- FAILED: ${r.taskDescription}\n` +
						`  Error: ${truncateText(errorInfo, 500)}\n` +
						`  Duration: ${(r.duration / 1000).toFixed(1)}s\n` +
						`  Suggestion: Review and retry manually`
					)
				})
				.join("\n")
			sections.push({ title: "Failed Subtasks", content, tokenCount: estimateTokens(content) })
		}

		// --- Apply token budget ---
		this.applyTokenBudget(sections)

		const totalTokens = sections.reduce((sum, s) => sum + s.tokenCount, 0)

		return {
			subtaskCount: this.results.length,
			successCount: this.results.filter((r) => r.status === "completed").length,
			failureCount: this.results.filter((r) => r.status === "failed").length,
			sections,
			totalTokens,
		}
	}

	/**
	 * Format aggregated result as a message string for injection into parent context.
	 */
	formatAsMessage(): string {
		const result = this.aggregate()
		const header = `## Subtask Results (${result.successCount}/${result.subtaskCount} succeeded)`
		const lines = [header, ""]

		for (const section of result.sections) {
			lines.push(`### ${section.title}`)
			lines.push(section.content)
			lines.push("")
		}

		if (result.failureCount > 0) {
			lines.push(
				`> **Note:** ${result.failureCount} subtask(s) failed. See "Failed Subtasks" section for details.`,
			)
			lines.push("")
		}

		return lines.join("\n")
	}

	/**
	 * Reset the aggregator, clearing all collected results.
	 */
	reset(): void {
		this.results = []
	}

	// ─── Private helpers ──────────────────────────────────────────────

	/**
	 * Enforce the MAX_AGGREGATED_TOKENS budget across all sections.
	 * If total tokens exceed the budget, proportionally truncate each section.
	 */
	private applyTokenBudget(sections: AggregatedSection[]): void {
		const totalTokens = sections.reduce((sum, s) => sum + s.tokenCount, 0)
		if (totalTokens <= MAX_AGGREGATED_TOKENS) return

		// Proportionally truncate each section
		const ratio = MAX_AGGREGATED_TOKENS / totalTokens

		for (const section of sections) {
			const targetChars = Math.floor(section.content.length * ratio)
			if (section.content.length > targetChars) {
				section.content = section.content.slice(0, targetChars) + "\n  ...(truncated)"
				section.tokenCount = estimateTokens(section.content)
			}
		}
	}
}

/**
 * Truncate text to a maximum character length, appending "..." if truncated.
 */
function truncateText(text: string, maxChars: number): string {
	if (text.length <= maxChars) return text
	return text.slice(0, maxChars - 3) + "..."
}

import delay from "delay"
import { Anthropic } from "@anthropic-ai/sdk"

import {
	type ContextCondense,
	type ContextTruncation,
	DEFAULT_REQUEST_DELAY_SECONDS,
} from "@njust-ai-cj/types"

import type { Task } from "./Task"
import type { ApiHandlerCreateMessageMetadata } from "../../api"
import { resolveParallelNativeToolCalls } from "../../shared/parallelToolCalls"
import { getModelMaxOutputTokens } from "../../shared/api"

import { manageContext } from "../context-management"
import { getEnvironmentDetails } from "../environment/getEnvironmentDetails"
import { buildNativeToolsArrayWithRestrictions } from "./build-tools"

import type { ApiMessage } from "../task-persistence"
import { getLastGlobalApiRequestTime } from "./globalApiTiming"
import { PersistentRetryManager } from "./PersistentRetry"
import { logger } from "../../shared/logger"
import { TIMING, LIMITS } from "../../shared/constants"
import { getErrorMessage } from "../../shared/error-utils"

const MAX_EXPONENTIAL_BACKOFF_SECONDS = TIMING.MAX_EXPONENTIAL_BACKOFF_MS / 1000
const FORCED_CONTEXT_REDUCTION_PERCENT = LIMITS.FORCED_CONTEXT_REDUCTION_PERCENT

/**
 * TaskStreamProcessor handles stream-related helper logic extracted from Task.ts,
 * including rate limiting, exponential backoff, context window recovery,
 * conversation history cleaning, and safe file listing.
 *
 * Uses the delegation pattern: accesses Task instance properties via `this.task`.
 */
export class TaskStreamProcessor {
	public persistentRetry: PersistentRetryManager = new PersistentRetryManager()

	constructor(private task: Task) {}

	/**
	 * Safely get files read by Roo, catching errors.
	 */
	async getFilesReadByRooSafely(_context: string): Promise<string[] | undefined> {
		try {
			return await this.task.fileContextTracker.getFilesReadByRoo()
		} catch (error) {
			logger.error("TaskStreamProcessor", `Failed to get files read by Roo:`, error)
			return undefined
		}
	}

	/**
	 * Get the current profile ID from provider state.
	 */
	getCurrentProfileId(state: any): string {
		return (
			state?.listApiConfigMeta?.find((profile: any) => profile.name === state?.currentApiConfigName)?.id ??
			"default"
		)
	}

	/**
	 * Enforce the user-configured provider rate limit.
	 *
	 * NOTE: This is intentionally treated as expected behavior and is surfaced via
	 * the `api_req_rate_limit_wait` say type (not an error).
	 */
	async maybeWaitForProviderRateLimit(retryAttempt: number): Promise<void> {
		const state = await this.task.providerRef.deref()?.getState()
		const rateLimitSeconds =
			state?.apiConfiguration?.rateLimitSeconds ?? this.task.apiConfiguration?.rateLimitSeconds ?? 0

		if (rateLimitSeconds <= 0 || !getLastGlobalApiRequestTime()) {
			return
		}

		const now = performance.now()
		const timeSinceLastRequest = now - getLastGlobalApiRequestTime()!
		const rateLimitDelay = Math.ceil(
			Math.min(rateLimitSeconds, Math.max(0, rateLimitSeconds * 1000 - timeSinceLastRequest) / 1000),
		)

		// Only show the countdown UX on the first attempt. Retry flows have their own delay messaging.
		if (rateLimitDelay > 0 && retryAttempt === 0) {
			for (let i = rateLimitDelay; i > 0; i--) {
				// Send structured JSON data for i18n-safe transport
				const delayMessage = JSON.stringify({ seconds: i })
				await this.task.say("api_req_rate_limit_wait", delayMessage, undefined, true)
				await delay(1000)
			}
			// Finalize the partial message so the UI doesn't keep rendering an in-progress spinner.
			await this.task.say("api_req_rate_limit_wait", undefined, undefined, false)
		}
	}

	/**
	 * Check if a timeout error should be retried or if model fallback is needed.
	 * Returns { allowed, shouldFallback, suggestedDelayMs } based on persistent retry state.
	 */
	checkTimeoutRetry(): {
		allowed: boolean
		shouldFallback: boolean
		suggestedDelayMs: number
		reason: string
	} {
		const result = this.persistentRetry.canRetry("timeout")
		return {
			allowed: result.allowed,
			shouldFallback: result.shouldFallback,
			suggestedDelayMs: result.suggestedDelayMs,
			reason: result.reason,
		}
	}

	/**
	 * Shared exponential backoff for retries (first-chunk and mid-stream).
	 * Integrates with PersistentRetryManager for cross-request retry tracking
	 * and timeout degradation.
	 */
	async backoffAndAnnounce(retryAttempt: number, error: any): Promise<void> {
		try {
			// Determine error category for persistent retry tracking
			const errorCategory = this.inferErrorCategory(error)

			// Check persistent retry budget before proceeding
			const retryCheck = this.persistentRetry.canRetry(errorCategory)
			if (!retryCheck.allowed) {
		logger.warn("TaskStreamProcessor",
				`Persistent retry denied for '${errorCategory}' on task ${this.task.taskId}: ${retryCheck.reason}` +
					(retryCheck.shouldFallback ? " → suggesting model fallback" : ""),
			)
			}

			const state = await this.task.providerRef.deref()?.getState()
			const baseDelay = state?.requestDelaySeconds ?? DEFAULT_REQUEST_DELAY_SECONDS

			const unattendedMaxBackoffSeconds = state?.unattendedMaxBackoffSeconds ?? MAX_EXPONENTIAL_BACKOFF_SECONDS
			let exponentialDelay = Math.min(
				Math.ceil(baseDelay * Math.pow(2, retryAttempt)),
				unattendedMaxBackoffSeconds,
			)

			// Use persistent retry suggested delay if it's larger
			const persistentSuggestedDelaySec = Math.ceil(retryCheck.suggestedDelayMs / 1000)
			exponentialDelay = Math.max(exponentialDelay, persistentSuggestedDelaySec)

			// Respect provider rate limit window
			let rateLimitDelay = 0
			const rateLimit = (state?.apiConfiguration ?? this.task.apiConfiguration)?.rateLimitSeconds || 0
			if (getLastGlobalApiRequestTime() && rateLimit > 0) {
				const elapsed = performance.now() - getLastGlobalApiRequestTime()!
				rateLimitDelay = Math.ceil(Math.min(rateLimit, Math.max(0, rateLimit * 1000 - elapsed) / 1000))
			}

			// Drain token bucket on 429 (enforce proactive backoff)
			if (error?.status === 429) {
				const providerKey = this.task.apiConfiguration?.apiProvider ?? "default"
				try {
					const { TokenBucketRateLimiter } = require("../../services/rate-limiter/TokenBucketRateLimiter")
					TokenBucketRateLimiter.getInstance().drain(providerKey)
				} catch { /* best-effort */ }
			}

			// Prefer RetryInfo on 429 if present
			if (error?.status === 429) {
				const retryInfo = error?.errorDetails?.find(
					(d: any) => d["@type"] === "type.googleapis.com/google.rpc.RetryInfo",
				)
				const match = retryInfo?.retryDelay?.match?.(/^(\d+)s$/)
				if (match) {
					exponentialDelay = Number(match[1]) + 1
				}
			}

			const finalDelay = Math.max(exponentialDelay, rateLimitDelay)

			// Record the retry in persistent state
			this.persistentRetry.recordRetry(errorCategory, finalDelay * 1000)

			if (finalDelay <= 0) {
				return
			}

			// Build header text; fall back to error message if none provided
			let headerText
			if (error.status) {
				// Include both status code (for ChatRow parsing) and detailed message (for error details)
				// Format: "<status>\n<message>" allows ChatRow to extract status via parseInt(text.substring(0,3))
				// while preserving the full error message in errorDetails for debugging
				const errorMessage = error?.message || "Unknown error"
				headerText = `${error.status}\n${errorMessage}`
			} else if (error?.message) {
				headerText = error.message
			} else {
				headerText = "Unknown error"
			}

			headerText = headerText ? `${headerText}\n` : ""

			// Show countdown timer with exponential backoff
			for (let i = finalDelay; i > 0; i--) {
				// Check abort flag during countdown to allow early exit
				if (this.task.abort) {
					throw new Error(`[Task#${this.task.taskId}] Aborted during retry countdown`)
				}

				await this.task.say("api_req_retry_delayed", `${headerText}<retry_timer>${i}</retry_timer>`, undefined, true)
				await delay(1000)
			}

			await this.task.say("api_req_retry_delayed", headerText, undefined, false)

			// Log persistent retry stats after each backoff for diagnostics
			const stats = this.persistentRetry.getStats()
			if (stats.totalRetries > 0) {
		logger.info("TaskStreamProcessor",
				`Persistent retry stats for task ${this.task.taskId}: total=${stats.totalRetries}, ` +
					`exhausted=${stats.isExhausted}, category='${errorCategory}' count=${stats.records.get(errorCategory)?.count ?? 0}`,
			)
			}
		} catch (err) {
			const message = getErrorMessage(err)

			if (this.task.abort && message.includes("Aborted during retry countdown")) {
				return
			}

			logger.error("TaskStreamProcessor", "Exponential backoff failed:", err)
		}
	}

	/**
	 * Infer the error category from an error object for persistent retry tracking.
	 * Uses status codes and error messages as heuristics.
	 */
	private inferErrorCategory(error: any): string {
		if (!error) {
			return "unknown"
		}

		const status = error.status ?? error.statusCode
		const message = (error.message ?? "").toLowerCase()

		// Timeout detection
		if (
			message.includes("timeout") ||
			message.includes("timed out") ||
			message.includes("etimedout") ||
			error.code === "ETIMEDOUT" ||
			error.code === "ESOCKETTIMEDOUT"
		) {
			return "timeout"
		}

		// Connection errors
		if (
			message.includes("econnreset") ||
			message.includes("econnrefused") ||
			message.includes("epipe") ||
			error.code === "ECONNRESET" ||
			error.code === "ECONNREFUSED"
		) {
			return "connection"
		}

		// HTTP status-based classification
		if (status === 429) {
			return "rate_limit"
		}
		if (status === 529) {
			return "capacity"
		}
		if (status === 503) {
			return "model_overloaded"
		}
		if (status === 500) {
			return "server_error"
		}
		if (status === 401 || status === 403) {
			return "authentication"
		}
		if (status === 413) {
			return "media_too_large"
		}

		return "unknown"
	}

	/**
	 * Handle context window exceeded errors by forcing truncation.
	 */
	async handleContextWindowExceededError(): Promise<void> {
		const state = await this.task.providerRef.deref()?.getState()
		const { profileThresholds = {}, mode, apiConfiguration } = state ?? {}

		const { contextTokens } = this.task.getTokenUsage()
		const modelInfo = this.task.api.getModel().info

		const maxTokens = getModelMaxOutputTokens({
			modelId: this.task.api.getModel().id,
			model: modelInfo,
			settings: this.task.apiConfiguration,
		})

		const contextWindow = modelInfo.contextWindow

		// Get the current profile ID using the helper method
		const currentProfileId = this.getCurrentProfileId(state)

		// Log the context window error for debugging
		logger.warn("TaskStreamProcessor",
			`Context window exceeded for task ${this.task.taskId}, model ${this.task.api.getModel().id}. ` +
				`Current tokens: ${contextTokens}, Context window: ${contextWindow}. ` +
				`Forcing truncation to ${FORCED_CONTEXT_REDUCTION_PERCENT}% of current context.`,
		)
		// Send condenseTaskContextStarted to show in-progress indicator
		await this.task.providerRef.deref()?.postMessageToWebview({ type: "condenseTaskContextStarted", text: this.task.taskId })

		// Build tools for condensing metadata (same tools used for normal API calls)
		const provider = this.task.providerRef.deref()
		let allTools: import("openai").default.Chat.ChatCompletionTool[] = []
		if (provider) {
			const toolsResult = await buildNativeToolsArrayWithRestrictions({
				provider,
				cwd: this.task.cwd,
				mode,
				customModes: state?.customModes,
				experiments: state?.experiments,
				apiConfiguration,
				disabledTools: state?.disabledTools,
				enableWebSearch: state?.enableWebSearch,
				modelInfo,
				includeAllToolsWithRestrictions: false,
			})
			allTools = toolsResult.tools
		}

		// Build metadata with tools and taskId for the condensing API call
		const metadata: ApiHandlerCreateMessageMetadata = {
			mode,
			taskId: this.task.taskId,
			...(allTools.length > 0
				? {
						tools: allTools,
						tool_choice: "auto",
						parallelToolCalls: resolveParallelNativeToolCalls(apiConfiguration),
					}
				: {}),
		}

		try {
			// Generate environment details to include in the condensed summary
			const environmentDetails = await getEnvironmentDetails(this.task, true)

			// Force aggressive truncation by keeping only 75% of the conversation history
			const truncateResult = await manageContext({
				messages: this.task.apiConversationHistory,
				totalTokens: contextTokens || 0,
				maxTokens,
				contextWindow,
				apiHandler: this.task.api,
				autoCondenseContext: true,
				autoCondenseContextPercent: FORCED_CONTEXT_REDUCTION_PERCENT,
				systemPrompt: await this.task.requestBuilder.getSystemPrompt(),
				taskId: this.task.taskId,
				profileThresholds,
				currentProfileId,
				metadata,
				environmentDetails,
			})

			if (truncateResult.messages !== this.task.apiConversationHistory) {
				await this.task.overwriteApiConversationHistory(truncateResult.messages)
			}

			if (truncateResult.summary) {
				const { summary, cost, prevContextTokens, newContextTokens = 0 } = truncateResult
				const contextCondense: ContextCondense = { summary, cost, newContextTokens, prevContextTokens }
				await this.task.say(
					"condense_context",
					undefined /* text */,
					undefined /* images */,
					false /* partial */,
					undefined /* checkpoint */,
					undefined /* progressStatus */,
					{ isNonInteractive: true } /* options */,
					contextCondense,
				)
			} else if (truncateResult.truncationId) {
				// Sliding window truncation occurred (fallback when condensing fails or is disabled)
				const isCircuitBreaker = /circuit.breaker/i.test(truncateResult.error ?? "")
				const contextTruncation: ContextTruncation = {
					truncationId: truncateResult.truncationId,
					messagesRemoved: truncateResult.messagesRemoved ?? 0,
					prevContextTokens: truncateResult.prevContextTokens,
					newContextTokens: truncateResult.newContextTokensAfterTruncation ?? 0,
					reason: isCircuitBreaker ? "circuit_breaker" : "sliding_window",
				}
				await this.task.say(
					"sliding_window_truncation",
					undefined /* text */,
					undefined /* images */,
					false /* partial */,
					undefined /* checkpoint */,
					undefined /* progressStatus */,
					{ isNonInteractive: true } /* options */,
					undefined /* contextCondense */,
					contextTruncation,
				)
			}
		} finally {
			// Notify webview that context management is complete (removes in-progress spinner)
			// IMPORTANT: Must always be sent to dismiss the spinner, even on error
			await this.task.providerRef
				.deref()
				?.postMessageToWebview({ type: "condenseTaskContextResponse", text: this.task.taskId })
		}
	}

	/**
	 * Build a clean conversation history suitable for API requests.
	 * Handles reasoning blocks (encrypted, plain text, reasoning_details) and
	 * produces a sanitized message array.
	 */
	buildCleanConversationHistory(
		messages: ApiMessage[],
	): Array<
		Anthropic.Messages.MessageParam | ReasoningBlock
	> {
		type ReasoningItemForRequest = {
			type: "reasoning"
			encrypted_content: string
			id?: string
			summary?: any[]
		}

		const cleanConversationHistory: (Anthropic.Messages.MessageParam | ReasoningItemForRequest)[] = []

		for (const msg of messages) {
			// Standalone reasoning: send encrypted, skip plain text
			if (msg.type === "reasoning") {
				if (msg.encrypted_content) {
					cleanConversationHistory.push({
						type: "reasoning",
						summary: msg.summary,
						encrypted_content: msg.encrypted_content!,
						...(msg.id ? { id: msg.id } : {}),
					})
				}
				continue
			}

			// Preferred path: assistant message with embedded reasoning as first content block
			if (msg.role === "assistant") {
				const rawContent = msg.content

				const contentArray: Anthropic.Messages.ContentBlockParam[] = Array.isArray(rawContent)
					? (rawContent as Anthropic.Messages.ContentBlockParam[])
					: rawContent !== undefined
						? ([
								{ type: "text", text: rawContent } satisfies Anthropic.Messages.TextBlockParam,
							] as Anthropic.Messages.ContentBlockParam[])
						: []

				const [first, ...rest] = contentArray

				// Check if this message has reasoning_details (OpenRouter format for Gemini 3, etc.)
				const msgWithDetails = msg
				if (msgWithDetails.reasoning_details && Array.isArray(msgWithDetails.reasoning_details)) {
					// Build the assistant message with reasoning_details
					let assistantContent: Anthropic.Messages.MessageParam["content"]

					if (contentArray.length === 0) {
						assistantContent = ""
					} else if (contentArray.length === 1 && contentArray[0].type === "text") {
						assistantContent = (contentArray[0] as Anthropic.Messages.TextBlockParam).text
					} else {
						assistantContent = contentArray
					}

					// Create message with reasoning_details property
					cleanConversationHistory.push({
						role: "assistant",
						content: assistantContent,
						reasoning_details: msgWithDetails.reasoning_details,
					} as any)

					continue
				}

				// Embedded reasoning: encrypted (send) or plain text (skip)
				const hasEncryptedReasoning =
					first && (first as unknown as ReasoningBlock).type === "reasoning" && typeof (first as unknown as ReasoningBlock).encrypted_content === "string"
				const hasPlainTextReasoning =
					first && (first as unknown as ReasoningBlock).type === "reasoning" && typeof (first as unknown as ReasoningBlock).text === "string"

				if (hasEncryptedReasoning) {
					const reasoningBlock = first as unknown as ReasoningBlock

					// Send as separate reasoning item (OpenAI Native)
					cleanConversationHistory.push({
						type: "reasoning",
						summary: reasoningBlock.summary ?? [],
						encrypted_content: reasoningBlock.encrypted_content!,
						...(reasoningBlock.id ? { id: reasoningBlock.id } : {}),
					})

					// Send assistant message without reasoning
					let assistantContent: Anthropic.Messages.MessageParam["content"]

					if (rest.length === 0) {
						assistantContent = ""
					} else if (rest.length === 1 && rest[0].type === "text") {
						assistantContent = (rest[0] as Anthropic.Messages.TextBlockParam).text
					} else {
						assistantContent = rest
					}

					cleanConversationHistory.push({
						role: "assistant",
						content: assistantContent,
					} satisfies Anthropic.Messages.MessageParam)

					continue
				} else if (hasPlainTextReasoning) {
					// Check if the model's preserveReasoning flag is set
					// If true, include the reasoning block in API requests
					// If false/undefined, strip it out (stored for history only, not sent back to API)
					const shouldPreserveForApi = this.task.api.getModel().info.preserveReasoning === true
					let assistantContent: Anthropic.Messages.MessageParam["content"]

					if (shouldPreserveForApi) {
						// Include reasoning block in the content sent to API
						assistantContent = contentArray
					} else {
						// Strip reasoning out - stored for history only, not sent back to API
						if (rest.length === 0) {
							assistantContent = ""
						} else if (rest.length === 1 && rest[0].type === "text") {
							assistantContent = (rest[0] as Anthropic.Messages.TextBlockParam).text
						} else {
							assistantContent = rest
						}
					}

					// Propagate reasoning_content as a top-level field when present on the
					// stored ApiMessage. DeepSeek / Z.ai require it to be passed back in
					// thinking mode, and convertToR1Format picks it up from the top level.
					const msgWithReasoning = msg as ApiMessage & { reasoning_content?: string }
					const topLevelReasoning = msgWithReasoning.reasoning_content
					if (topLevelReasoning && typeof topLevelReasoning === "string" && topLevelReasoning.trim()) {
						const msgObj: any = {
							role: "assistant",
							content: assistantContent,
						}
						// Only set reasoning_content when preserveReasoning signals that the
						// model / provider requires it. Otherwise keep it out of the request.
						if (shouldPreserveForApi) {
							msgObj.reasoning_content = topLevelReasoning
						}
						cleanConversationHistory.push(msgObj)
					} else {
						cleanConversationHistory.push({
							role: "assistant",
							content: assistantContent,
						} satisfies Anthropic.Messages.MessageParam)
					}

					continue
				}
			}

			// Default path for regular messages (no embedded reasoning at first content position)
			if (msg.role) {
				const msgWithReasoning = msg as ApiMessage & { reasoning_content?: string }
				const topLevelReasoning = msgWithReasoning.reasoning_content
				if (topLevelReasoning && typeof topLevelReasoning === "string" && topLevelReasoning.trim()) {
					const shouldPreserveForApi = this.task.api.getModel().info.preserveReasoning === true
					const msgObj: any = {
						role: msg.role,
						content: msg.content as Anthropic.Messages.ContentBlockParam[] | string,
					}
					if (shouldPreserveForApi) {
						msgObj.reasoning_content = topLevelReasoning
					}
					cleanConversationHistory.push(msgObj)
				} else {
					cleanConversationHistory.push({
						role: msg.role,
						content: msg.content as Anthropic.Messages.ContentBlockParam[] | string,
					})
				}
			}
		}

		return cleanConversationHistory
	}
}

interface ReasoningBlock {
	type: "reasoning"
	text?: string
	encrypted_content?: string
	id?: string
	summary?: Array<{ type?: string; text?: string }>
}

/**
 * TaskSubtaskHandler — Subtask orchestration handling.
 *
 * Extracted from Task.ts to decompose the monolithic file. Handles startSubtask()
 * and resumeAfterDelegation() operations.
 *
 * Phase 1: Extract subtask logic from Task.ts
 */

import type { Anthropic } from "@anthropic-ai/sdk"
import type { TaskSubtaskHost } from "./interfaces/TaskSubtaskHost"
import { NJUST_AI_CJEventName } from "@njust-ai-cj/types"
import { generateParentContextSummary } from "./SubTaskContextBuilder"
import { getEnvironmentDetails } from "../environment/getEnvironmentDetails"
import { DEFAULT_FORKED_CONTEXT_CONFIG } from "./SubTaskOptions"
import type { IsolationLevel, ForkedContextConfig, CacheSafeParams } from "./SubTaskOptions"
import type { TodoItem } from "@njust-ai-cj/types"

export class TaskSubtaskHandler {
	constructor(private host: TaskSubtaskHost) {}

	async startSubtask(
		message: string,
		initialTodos: TodoItem[],
		mode: string,
		isolationLevel: IsolationLevel = "shared",
		forkedConfig?: ForkedContextConfig,
		cacheSafeParams?: CacheSafeParams,
	) {
		const provider = this.host.hostRef.deref()

		if (!provider) {
			throw new Error("Provider not available")
		}

		let forkedContextSummary: string | undefined
		let effectiveCacheSafeParams: CacheSafeParams | undefined

		if (isolationLevel === "forked") {
			if (cacheSafeParams) {
				effectiveCacheSafeParams = cacheSafeParams
				forkedContextSummary = message
			} else {
				const config = forkedConfig ?? DEFAULT_FORKED_CONTEXT_CONFIG
				forkedContextSummary = generateParentContextSummary(
					this.host.apiConversationHistory,
					config.summaryMaxTokens,
					config,
				)
			}
		}

		const child = await provider.delegateParentAndOpenChild({
			parentTaskId: this.host.taskId,
			message,
			initialTodos,
			mode,
			isolationLevel,
			forkedContextSummary,
			cacheSafeParams: effectiveCacheSafeParams,
		})
		return child
	}

	async resumeAfterDelegation(): Promise<void> {
		this.host.idleAsk = undefined
		this.host.resumableAsk = undefined
		this.host.interactiveAsk = undefined

		this.host.abort = false
		this.host.abandoned = false
		this.host.abortReason = undefined
		this.host.didFinishAbortingStream = false
		this.host.isStreaming = false
		this.host.isWaitingForFirstChunk = false

		this.host.skipPrevResponseIdOnce = true

		this.host.isInitialized = true
		this.host.emit(NJUST_AI_CJEventName.TaskActive, this.host.taskId)

		if (this.host.apiConversationHistory.length === 0) {
			this.host.apiConversationHistory = await this.host.getSavedApiConversationHistory()
		}

		const environmentDetails = await getEnvironmentDetails(this.host as any, true)
		let lastUserMsgIndex = -1
		for (let i = this.host.apiConversationHistory.length - 1; i >= 0; i--) {
			const msg = this.host.apiConversationHistory[i]
			if (msg.role === "user") {
				lastUserMsgIndex = i
				break
			}
		}
		if (lastUserMsgIndex >= 0) {
			const lastUserMsg = this.host.apiConversationHistory[lastUserMsgIndex]
			if (Array.isArray(lastUserMsg.content)) {
				const contentWithoutEnvDetails = lastUserMsg.content.filter(
					(block: Anthropic.Messages.ContentBlockParam) => {
						if (block.type === "text" && typeof block.text === "string") {
							const isEnvironmentDetailsBlock =
								block.text.trim().startsWith("<environment_details>") &&
								block.text.trim().endsWith("</environment_details>")
							return !isEnvironmentDetailsBlock
						}
						return true
					},
				)
				lastUserMsg.content = [
					...contentWithoutEnvDetails,
					{ type: "text" as const, text: environmentDetails },
				]
			}
		}

		await this.host.saveApiConversationHistory()

		await this.host.initiateTaskLoop([])
	}
}

