import type { ToolUse } from "../../shared/tools"
import type { Task } from "../task/Task"
import { ConcurrentToolExecutor } from "./ConcurrentToolExecutor"
import { logger } from "../../shared/logger"
import { toolRegistry } from "./ToolRegistry"
import { classifyToolCategory, ToolExecutionScheduler } from "../task/ToolExecutionOrchestrator"
import type { AdaptiveConcurrencyController } from "./AdaptiveConcurrencyController"

export type EagerToolDecision = "eager" | "deferred"

/**
 * Result of a tool execution that was interrupted by max_output_tokens.
 * The partial output is preserved and marked with a truncation notice.
 */
export interface WithheldToolResult {
	toolUseId: string
	toolName: string
	partialOutput: string
	truncated: true
}

/**
 * Manages eager (streaming) tool execution.
 *
 * Delegates execution decisions to individual tools via:
 * - tool.isPartialArgsStable() — whether partial streaming args are stable enough
 * - tool.getEagerExecutionDecision() — whether the tool opts into eager execution
 *
 * Also handles max_output_tokens interruption recovery:
 * - Detects when a tool execution is interrupted due to token limits
 * - Preserves partial output with a truncation marker
 * - Allows the next API turn to continue based on partial results
 */
export class StreamingToolExecutor {
	private readonly executor: ConcurrentToolExecutor
	private withheldResults: WithheldToolResult[] = []

	/**
	 * Shared abort controller for sibling tools. Set before running eager batches.
	 * When one tool in a batch fails (especially bash), all siblings are signaled.
	 */
	private siblingAbortController: AbortController | null = null

	constructor(
		maxConcurrency = 10,
		concurrencyController?: AdaptiveConcurrencyController,
		scheduler?: ToolExecutionScheduler,
	) {
		this.executor = new ConcurrentToolExecutor({ maxConcurrency, concurrencyController, scheduler })
	}

	/** Wire in the sibling abort controller for the current batch */
	setSiblingAbortController(controller: AbortController): void {
		this.siblingAbortController = controller
	}

	/** Get the current sibling abort signal, or undefined if none */
	getSiblingAbortSignal(): AbortSignal | undefined {
		return this.siblingAbortController?.signal
	}

	/**
	 * Check if a tool's partial streaming arguments have stabilized.
	 * Delegates to the tool's own isPartialArgsStable() method via the registry.
	 */
	private isPartialArgsStable(toolUse: ToolUse): boolean {
		if (!toolUse.partial) {
			return true
		}
		const tool = toolRegistry.get(toolUse.name)
		if (!tool) {
			return false
		}
		return tool.isPartialArgsStable((toolUse.nativeArgs ?? {}) as Record<string, unknown>)
	}

	/**
	 * Determine whether a tool should be eagerly executed during streaming.
	 * Delegates to the tool's own getEagerExecutionDecision() method.
	 */
	shouldEagerExecute(task: Task, toolUse: ToolUse): EagerToolDecision {
		if (task.didRejectTool) return "deferred"
		if (!this.isPartialArgsStable(toolUse)) return "deferred"
		const tool = toolRegistry.get(toolUse.name)
		if (!tool) return "deferred"
		return tool.getEagerExecutionDecision(
			(toolUse.nativeArgs ?? {}) as Parameters<typeof tool.getEagerExecutionDecision>[0],
		)
	}

	async runEagerBatch(task: Task, batch: ToolUse[], runOne: (toolUse: ToolUse, signal: AbortSignal) => Promise<void>): Promise<void> {
		const itemCategories = new Map<number, ReturnType<typeof classifyToolCategory>>()
		batch.forEach((toolUse, index) => {
			itemCategories.set(index, classifyToolCategory(toolUse.name, false))
		})
		// Reset sibling controller for the new batch
		this.siblingAbortController = new AbortController()

		try {
			await this.executor.run(
				batch,
				async (toolUse, _index, ctx) => {
					// Check both the executor's signal and the sibling abort signal
					const siblingAborted = this.siblingAbortController?.signal.aborted
					if (task.abort || task.didRejectTool || ctx.signal.aborted || siblingAborted) return
					try {
						await runOne(toolUse, ctx.signal)
					} catch (err) {
						// Bash failures propagate to sibling tools
						const category = classifyToolCategory(toolUse.name, false)
						if (category === "bash") {
							this.siblingAbortController?.abort("sibling_error")
						}
						throw err
					}
				},
				{ abortStrategy: "continueOnError", itemCategories },
			)
		} catch (err) {
			// Each tool in the batch has already pushed its own result (success or error).
			// Log the aggregate error but don't re-throw — doing so would trigger the
			// serial fallback path and re-execute already-completed tools.
			logger.error("StreamingToolExecutor", "eager batch completed with errors:", err)
		}
	}

	// ── max_output_tokens interruption recovery ──────────────────────

	/**
	 * Detect if an error represents a max_output_tokens interruption.
	 */
	static isMaxOutputTokensError(error: unknown): boolean {
		if (!error) return false
		const msg = String((error as any)?.message ?? "").toLowerCase()
		const stopReason = String((error as any)?.stop_reason ?? (error as any)?.stopReason ?? "").toLowerCase()

		return (
			/max[_\s-]?output[_\s-]?tokens/.test(msg) ||
			stopReason === "max_tokens" ||
			stopReason === "length"
		)
	}

	/**
	 * Record a withheld (partially completed) tool result.
	 * Called when a tool execution is interrupted by max_output_tokens.
	 *
	 * The partial output is preserved with a truncation marker so the model
	 * can continue from where it left off in the next API turn.
	 */
	recordWithheldResult(toolUseId: string, toolName: string, partialOutput: string): void {
		this.withheldResults.push({
			toolUseId,
			toolName,
			partialOutput: partialOutput + "\n\n[Output truncated due to token limit]",
			truncated: true,
		})
	}

	/**
	 * Get and clear all withheld results.
	 * These should be included in the next API request as partial tool results.
	 */
	drainWithheldResults(): WithheldToolResult[] {
		const results = this.withheldResults
		this.withheldResults = []
		return results
	}

	/**
	 * Whether there are withheld results waiting to be sent.
	 */
	hasWithheldResults(): boolean {
		return this.withheldResults.length > 0
	}
}

import { Task } from "../task/Task"
import { BaseTool, ToolCallbacks } from "./BaseTool"
import { formatResponse } from "../prompts/responses"

interface TaskStopParams {
	taskId: string
	reason?: string
}

type TaskStopMode = "self_only" | "tree_only" | "admin"

function getTaskStopMode(): TaskStopMode {
	const raw = (process.env.ROO_TASK_STOP_MODE || "tree_only").toLowerCase()
	if (raw === "self_only" || raw === "tree_only" || raw === "admin") {
		return raw
	}
	return "tree_only"
}

export class TaskStopTool extends BaseTool<"task_stop"> {
	readonly name = "task_stop" as const

	override userFacingName(): string {
		return "Task Stop"
	}

	override async execute(params: TaskStopParams, task: Task, callbacks: ToolCallbacks): Promise<void> {
		const { pushToolResult } = callbacks
		if (!params.taskId) {
			pushToolResult(await task.sayAndCreateMissingParamError("task_stop", "taskId"))
			return
		}

		const provider = task.providerRef.deref() as any
		if (!provider?.getTaskWithId) {
			pushToolResult(formatResponse.toolError("Task provider is unavailable for task_stop."))
			return
		}

		try {
			const found = await provider.getTaskWithId(params.taskId)
			if (!found?.historyItem) {
				pushToolResult(formatResponse.toolError(`Task not found: ${params.taskId}`))
				return
			}

			const mode = getTaskStopMode()
			const targetRootTaskId = found.historyItem.rootTaskId || found.historyItem.id
			const callerRootTaskId = task.rootTaskId || task.taskId
			if (mode === "self_only" && params.taskId !== task.taskId) {
				pushToolResult(formatResponse.toolError("Permission denied: task_stop mode is self_only."))
				return
			}
			if (mode === "tree_only" && targetRootTaskId !== callerRootTaskId && params.taskId !== task.taskId) {
				pushToolResult(
					formatResponse.toolError(
						`Permission denied: task_stop can only stop tasks within the same delegation tree (caller root: ${callerRootTaskId}, target root: ${targetRootTaskId}).`,
					),
				)
				return
			}

			const runningTask = provider
				.getAllTaskInstances?.()
				?.find((t: Task) => t.taskId === params.taskId)

			if (!runningTask) {
				pushToolResult(`Task ${params.taskId} is not currently running (already stopped or completed).`)
				return
			}

			await runningTask.abortTask(true)
			pushToolResult(
				`Stopped task ${params.taskId}${params.reason ? ` (reason: ${params.reason})` : ""}.`,
			)
		} catch (error) {
			pushToolResult(formatResponse.toolError(`Failed to stop task ${params.taskId}: ${String(error)}`))
		}
	}
}

export const taskStopTool = new TaskStopTool()

import type { ToolName } from "@njust-ai-cj/types"
import type { BaseTool } from "./BaseTool"
import type { ToolRegistry as IToolRegistry } from "./ToolSearchTool"
import { TOOL_ALIASES } from "../../shared/tools"
import { ToolDependencyGraph } from "./ToolDependencyGraph"

/**
 * Entry for a conditionally registered tool.
 * The tool is only available when its condition returns true.
 */
interface ConditionalToolEntry {
	tool: BaseTool<any>
	condition: () => boolean
}

/**
 * Central registry for all tool instances.
 *
 * Replaces the implicit registration pattern (scattered singleton imports + manual arrays)
 * with a single authoritative Map-based registry. Supports:
 * - Canonical name lookup
 * - Alias resolution (seeded from TOOL_ALIASES + per-tool aliases)
 * - Concurrency-safe and checkpoint queries
 *
 * Inspired by Claude Code's findToolByName() dynamic lookup pattern.
 */
export class ToolRegistryImpl implements IToolRegistry {
	private readonly tools = new Map<string, BaseTool<any>>()
	private readonly aliasMap = new Map<string, string>() // alias -> canonical name
	private readonly conditionalTools: ConditionalToolEntry[] = []

	// Cached query results (invalidated on register)
	private concurrencySafeCache: Set<ToolName> | null = null
	private checkpointCache: Set<ToolName> | null = null
	private dependencyGraphCache: ToolDependencyGraph | null = null

	constructor() {
		// Seed alias map from the shared TOOL_ALIASES constant
		for (const [alias, canonical] of Object.entries(TOOL_ALIASES)) {
			this.aliasMap.set(alias, canonical)
		}
	}

	/**
	 * Register a tool instance. Automatically indexes the tool's aliases.
	 * Throws if the canonical name is already registered.
	 */
	register(tool: BaseTool<any>): void {
		const name = tool.name
		if (this.tools.has(name)) {
			throw new Error(`ToolRegistry: tool '${name}' is already registered`)
		}
		this.tools.set(name, tool)

		// Index per-tool aliases
		for (const alias of tool.aliases) {
			if (!this.aliasMap.has(alias)) {
				this.aliasMap.set(alias, name)
			}
		}

		// Invalidate caches
		this.concurrencySafeCache = null
		this.checkpointCache = null
		this.dependencyGraphCache = null
	}

	/**
	 * Look up a tool by name, resolving aliases to canonical names.
	 */
	get(name: string): BaseTool<any> | undefined {
		const tool = this.tools.get(name)
		if (tool) return tool

		// Try alias resolution
		const canonical = this.aliasMap.get(name)
		if (canonical) {
			return this.tools.get(canonical)
		}

		return undefined
	}

	/**
	 * Check if a tool name (or alias) is registered.
	 */
	has(name: string): boolean {
		return this.get(name) !== undefined
	}

	/**
	 * Return all registered tool instances (no duplicates from aliases).
	 * Implements the ToolSearchTool's ToolRegistry interface.
	 */
	getAllTools(): BaseTool<any>[] {
		return Array.from(this.tools.values())
	}

	/**
	 * Return the set of tool names that are concurrency-safe (can be executed in parallel).
	 * Result is cached until the next register() call.
	 */
	getConcurrencySafeNames(): Set<ToolName> {
		if (!this.concurrencySafeCache) {
			this.concurrencySafeCache = new Set<ToolName>(
				this.getAllTools()
					.filter((tool) => {
						try {
							return tool.isConcurrencySafe(undefined as never)
						} catch {
							return false
						}
					})
					.map((tool) => tool.name as ToolName),
			)
		}
		return this.concurrencySafeCache
	}

	/**
	 * Return the set of tool names that require a checkpoint save before execution.
	 * Result is cached until the next register() call.
	 */
	getToolsRequiringCheckpoint(): Set<ToolName> {
		if (!this.checkpointCache) {
			this.checkpointCache = new Set<ToolName>(
				this.getAllTools()
					.filter((tool) => tool.requiresCheckpoint)
					.map((tool) => tool.name as ToolName),
			)
		}
		return this.checkpointCache
	}

	/**
	 * Return all tools that are not deferred (included in initial prompt).
	 */
	getNonDeferredTools(): BaseTool<any>[] {
		return this.getAllTools().filter((t) => !t.shouldDefer)
	}

	/**
	 * Return all tools that are deferred (only discovered via ToolSearchTool).
	 */
	getDeferredTools(): BaseTool<any>[] {
		return this.getAllTools().filter((t) => t.shouldDefer)
	}

	/**
	 * Resolve an alias to its canonical tool name, or return the name unchanged.
	 */
	resolveAlias(name: string): string {
		return this.aliasMap.get(name) ?? name
	}

	// ── Conditional registration ─────────────────────────────────────

	/**
	 * Register a tool that is only available when its condition returns true.
	 * Conditional tools are re-evaluated on each getAvailableTools() call.
	 *
	 * Use for tools that depend on environment variables, feature flags,
	 * or platform checks (e.g., PowerShellTool on Windows only).
	 */
	registerConditional(tool: BaseTool<any>, condition: () => boolean): void {
		this.conditionalTools.push({ tool, condition })
		// Index aliases for conditional tools too
		for (const alias of tool.aliases) {
			if (!this.aliasMap.has(alias)) {
				this.aliasMap.set(alias, tool.name)
			}
		}
	}

	/**
	 * Return all currently available tools: always-registered + conditional tools
	 * whose conditions are satisfied.
	 */
	getAvailableTools(): BaseTool<any>[] {
		const conditional = this.conditionalTools
			.filter(({ condition }) => {
				try {
					return condition()
				} catch {
					return false
				}
			})
			.map(({ tool }) => tool)
		return [...this.tools.values(), ...conditional]
	}

	// ── Dependency graph ─────────────────────────────────────────────

	/**
	 * Build and cache a ToolDependencyGraph from all registered tools'
	 * `dependsOn` declarations. Invalidated on register().
	 */
	getDependencyGraph(): ToolDependencyGraph {
		if (!this.dependencyGraphCache) {
			const allTools = this.getAllTools()
			this.dependencyGraphCache = ToolDependencyGraph.fromTools(
				allTools.map((t) => ({ name: t.name, dependsOn: t.dependsOn })),
			)
		}
		return this.dependencyGraphCache
	}

	/**
	 * Return the number of registered tools.
	 */
	get size(): number {
		return this.tools.size
	}
}

/**
 * Singleton tool registry instance.
 */
export const toolRegistry = new ToolRegistryImpl()

import stringify from "safe-stable-stringify"
import { ToolUse } from "../../shared/tools"
import { t } from "../../i18n"

/**
 * Class for detecting consecutive identical tool calls
 * to prevent the AI from getting stuck in a loop.
 */
export class ToolRepetitionDetector {
	private previousToolCallJson: string | null = null
	private consecutiveIdenticalToolCallCount: number = 0
	private readonly consecutiveIdenticalToolCallLimit: number

	/**
	 * Creates a new ToolRepetitionDetector
	 * @param limit The maximum number of identical consecutive tool calls allowed
	 */
	constructor(limit: number = 3) {
		this.consecutiveIdenticalToolCallLimit = limit
	}

	/**
	 * Checks if the current tool call is identical to the previous one
	 * and determines if execution should be allowed
	 *
	 * @param currentToolCallBlock ToolUse object representing the current tool call
	 * @returns Object indicating if execution is allowed and a message to show if not
	 */
	public check(currentToolCallBlock: ToolUse): {
		allowExecution: boolean
		askUser?: {
			messageKey: string
			messageDetail: string
		}
	} {
		// Serialize the block to a canonical JSON string for comparison
		const currentToolCallJson = this.serializeToolUse(currentToolCallBlock)

		// Compare with previous tool call
		if (this.previousToolCallJson === currentToolCallJson) {
			this.consecutiveIdenticalToolCallCount++
		} else {
			this.consecutiveIdenticalToolCallCount = 0 // Reset to 0 for a new tool
			this.previousToolCallJson = currentToolCallJson
		}

		// Check if limit is reached (0 means unlimited)
		if (
			this.consecutiveIdenticalToolCallLimit > 0 &&
			this.consecutiveIdenticalToolCallCount >= this.consecutiveIdenticalToolCallLimit
		) {
			// Reset counters to allow recovery if user guides the AI past this point
			this.consecutiveIdenticalToolCallCount = 0
			this.previousToolCallJson = null

			// Return result indicating execution should not be allowed
			return {
				allowExecution: false,
				askUser: {
					messageKey: "mistake_limit_reached",
					messageDetail: t("tools:toolRepetitionLimitReached", { toolName: currentToolCallBlock.name }),
				},
			}
		}

		// Execution is allowed
		return { allowExecution: true }
	}

	/**
	 * Serializes a ToolUse object into a canonical JSON string for comparison
	 *
	 * @param toolUse The ToolUse object to serialize
	 * @returns JSON string representation of the tool use with sorted parameter keys
	 */
	private serializeToolUse(toolUse: ToolUse): string {
		const toolObject: Record<string, any> = {
			name: toolUse.name,
			params: toolUse.params,
		}

		// Only include nativeArgs if it has content
		if (toolUse.nativeArgs && Object.keys(toolUse.nativeArgs).length > 0) {
			toolObject.nativeArgs = toolUse.nativeArgs
		}

		return stringify(toolObject)
	}
}

import { BaseTool, type ToolCallbacks } from "./BaseTool"
import type { Task } from "../task/Task"

/**
 * Registry of tool instances that ToolSearchTool can search through.
 * Tools with shouldDefer=true are candidates for deferred loading.
 */
export interface ToolRegistry {
	/** Return all registered BaseTool instances */
	getAllTools(): BaseTool<any>[]
}

/**
 * ToolSearchTool — searches deferred tools by keyword and returns their
 * full descriptions so the model can discover and invoke them.
 *
 * This tool itself is NOT deferred (shouldDefer = false) and is always
 * included in the initial system prompt.
 */
class ToolSearchToolImpl extends BaseTool<"tool_search"> {
	readonly name = "tool_search" as const

	private registry: ToolRegistry | undefined

	/**
	 * Inject the tool registry so this tool can enumerate all registered tools.
	 * Called once during system initialisation (e.g. in build-tools or global registration).
	 */
	setToolRegistry(registry: ToolRegistry): void {
		this.registry = registry
	}

	getToolRegistry(): ToolRegistry {
		if (!this.registry) {
			throw new Error("Tool registry is not configured")
		}
		return this.registry
	}

	// ── BaseTool overrides ──────────────────────────────────────────────

	override get shouldDefer(): boolean {
		return false
	}

	override isReadOnly(): boolean {
		return true
	}

	override isConcurrencySafe(): boolean {
		return true
	}

	override userFacingName(): string {
		return "Tool Search"
	}

	// ── Execution ───────────────────────────────────────────────────────

	override execute(
		params: { query: string },
		_task: Task,
		{ pushToolResult }: ToolCallbacks,
	): Promise<void> {
		const { query } = params

		if (!query || query.trim().length === 0) {
			pushToolResult("Error: query parameter is required and cannot be empty.")
			return
		}

		if (!this.registry) {
			pushToolResult("Error: Tool registry is not configured. No tools available to search.")
			return
		}

		const allTools = this.registry.getAllTools()
		const deferredTools = allTools.filter((t) => t.shouldDefer)

		if (deferredTools.length === 0) {
			pushToolResult("No deferred tools are currently registered.")
			return
		}

		const keywords = query
			.toLowerCase()
			.split(/\s+/)
			.filter((k) => k.length > 0)

		const matched = deferredTools.filter((tool) => {
			const searchableText = [
				tool.name,
				tool.userFacingName(),
				tool.searchHint ?? "",
			]
				.join(" ")
				.toLowerCase()

			return keywords.some((kw) => searchableText.includes(kw))
		})

		if (matched.length === 0) {
			pushToolResult(
				`No deferred tools matched the query "${query}". ` +
					`Available deferred tools: ${deferredTools.map((t) => t.userFacingName()).join(", ")}.`,
			)
			return
		}

		// Build a description block for each matched tool
		const descriptions = matched.map((tool) => {
			const lines: string[] = [
				`## ${tool.userFacingName()} (${tool.name})`,
			]

			if (tool.searchHint) {
				lines.push(`Keywords: ${tool.searchHint}`)
			}

			lines.push(`Read-only: ${tool.isReadOnly() ? "yes" : "no"}`)
			lines.push(`Concurrent-safe: ${tool.isConcurrencySafe(undefined as any) ? "yes" : "no"}`)

			return lines.join("\n")
		})

		pushToolResult(
			`Found ${matched.length} deferred tool(s) matching "${query}":\n\n` +
				descriptions.join("\n\n"),
		)
	}
}

export const toolSearchTool = new ToolSearchToolImpl()

