 *   - Recovery strategy selection
 *
 * Integrates with (but does not replace) the existing RetryableError system.
 */

/**
 * Structured classification of a tool error.
 */
export interface ToolErrorClassification {
	/** High-level error category. */
	category: ToolErrorCategory
	/** Whether this error is retryable. */
	retryable: boolean
	/** Whether the error is safe to include in telemetry (no PII). */
	telemetrySafe: boolean
	/** Sanitized error message for logging. */
	sanitizedMessage: string
	/** Optional suggested user-facing message. */
	userMessage?: string
	/** Optional error code for programmatic handling. */
	code?: string
}

export type ToolErrorCategory =
	| "filesystem"    // ENOENT, EACCES, EPERM, ENOSPC, EISDIR, etc.
	| "network"       // ECONNREFUSED, ETIMEDOUT, ECONNRESET, DNS failures
	| "permission"    // Permission denied by the security system
	| "timeout"       // Operation timed out
	| "validation"    // Invalid input parameters
	| "not_found"     // Resource not found (file, tool, MCP server)
	| "conflict"      // Resource conflict (file locked, merge conflict)
	| "quota"         // Rate limit, token budget, disk quota
	| "external"      // External service error (MCP server, API)
	| "internal"      // Internal/unexpected error
	| "unknown"       // Cannot classify

/**
 * Classify a tool execution error into a structured category.
 *
 * This function examines the error's message, code, and status to determine
 * the most specific category. It is designed to be used alongside
 * RetryableError.isRetryable() — not as a replacement.
 */
export function classifyToolError(error: unknown): ToolErrorClassification {
	const e = error as any
	const msg = String(e?.message ?? "").toLowerCase()
	const code = String(e?.code ?? "")
	const _errno = String(e?.errno ?? "")

	// ── Filesystem errors ────────────────────────────────────────────
	if (code === "ENOENT" || /no such file|file not found|enoent/i.test(msg)) {
		return {
			category: "filesystem",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "File or directory not found",
			userMessage: "The specified file or directory does not exist.",
			code: "ENOENT",
		}
	}
	if (code === "EACCES" || code === "EPERM" || /permission denied|access denied|eacces|eperm/i.test(msg)) {
		return {
			category: "filesystem",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "File system permission denied",
			userMessage: "Insufficient permissions to access this file or directory.",
			code: code || "EACCES",
		}
	}
	if (code === "ENOSPC" || /no space|disk full|enospc/i.test(msg)) {
		return {
			category: "filesystem",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "No disk space remaining",
			userMessage: "The disk is full. Free up space and try again.",
			code: "ENOSPC",
		}
	}
	if (code === "EISDIR" || /is a directory/i.test(msg)) {
		return {
			category: "filesystem",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "Path is a directory, expected a file",
			code: "EISDIR",
		}
	}

	// ── Network errors ───────────────────────────────────────────────
	if (/econnrefused|connection refused/i.test(msg) || code === "ECONNREFUSED") {
		return {
			category: "network",
			retryable: true,
			telemetrySafe: true,
			sanitizedMessage: "Connection refused",
			userMessage: "Unable to connect to the remote service.",
			code: "ECONNREFUSED",
		}
	}
	if (/etimedout|esockettimedout|timed?\s?out/i.test(msg) || code === "ETIMEDOUT") {
		return {
			category: "timeout",
			retryable: true,
			telemetrySafe: true,
			sanitizedMessage: "Connection timed out",
			userMessage: "The operation timed out. Try again.",
			code: "ETIMEDOUT",
		}
	}
	if (/econnreset|socket hang up|epipe/i.test(msg)) {
		return {
			category: "network",
			retryable: true,
			telemetrySafe: true,
			sanitizedMessage: "Connection reset",
			code: code || "ECONNRESET",
		}
	}
	if (/enotfound|dns|getaddrinfo/i.test(msg)) {
		return {
			category: "network",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "DNS resolution failed",
			userMessage: "Could not resolve the hostname.",
			code: "ENOTFOUND",
		}
	}

	// ── Permission errors ────────────────────────────────────────────
	if (/permission denied for tool|blocked by hook|permission.*deny/i.test(msg)) {
		return {
			category: "permission",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "Tool permission denied",
		}
	}

	// ── Validation errors ────────────────────────────────────────────
	if (/invalid.*input|validation.*fail|schema.*error|missing.*param/i.test(msg)) {
		return {
			category: "validation",
			retryable: false,
			telemetrySafe: true,
			sanitizedMessage: "Input validation failed",
		}
	}

	// ── Rate/quota errors ────────────────────────────────────────────
	if (/rate.?limit|too many requests|429|quota.*exceeded/i.test(msg)) {
		return {
			category: "quota",
			retryable: true,
			telemetrySafe: true,
			sanitizedMessage: "Rate limit or quota exceeded",
			userMessage: "Too many requests. Please wait and try again.",
		}
	}

	// ── Unknown ──────────────────────────────────────────────────────
	return {
		category: "unknown",
		retryable: false,
		telemetrySafe: false,
		sanitizedMessage: "Unexpected error",
	}
}

/**
 * Formats tool invocation parameters for display.
 */
export function formatToolInvocation(toolName: string, params: Record<string, any>): string {
	// Native-only: readable format
	const paramsList = Object.entries(params)
		.map(([key, value]) => `${key}: ${typeof value === "string" ? value : JSON.stringify(value)}`)
		.join(", ")
	return `Called ${toolName}${paramsList ? ` with ${paramsList}` : ""}`
}

/**
 * Tool Result Budget Management
 *
 * Provides token budget calculation and truncation for tool results to prevent
 * single tool results from consuming excessive context window space.
 * Inspired by Claude Code's `applyToolResultBudget` design.
 */

import { Tiktoken } from "tiktoken/lite"
import o200kBase from "tiktoken/encoders/o200k_base"
import type { Anthropic } from "@anthropic-ai/sdk"
import type { ApiMessage } from "../task-persistence/apiMessages"

// ─── Budget Constants ────────────────────────────────────────────────────────

/** Single result maximum ratio of context window */
const SINGLE_RESULT_MAX_RATIO = 0.15

/** Absolute upper limit for a single result (tokens) */
const SINGLE_RESULT_MAX_TOKENS = 30_000

/** All tool results total budget ratio of context window */
const TOTAL_TOOL_RESULT_RATIO = 0.4

/** History result decay period: budget halves every N turns */
const HISTORY_DECAY_TURNS = 3

/** Minimum budget floor to avoid over-aggressive truncation */
const MIN_BUDGET_TOKENS = 500

/** Fraction of preserved content allocated to head */
const HEAD_RATIO = 0.3

/** Fraction of preserved content allocated to tail */
const TAIL_RATIO = 0.2

// ─── Encoder (module-level, init is fast) ──────────────────────────────────────

const _encoder = new Tiktoken(o200kBase.bpe_ranks, o200kBase.special_tokens, o200kBase.pat_str)

/**
 * Estimate token count for a string.
 * Uses tiktoken for accuracy with a small fudge factor.
 */
export function estimateTokens(text: string): number {
	if (!text || text.length === 0) return 0
	return _encoder.encode(text, undefined, []).length
}

// ─── Core Functions ──────────────────────────────────────────────────────────

export interface ToolResultBudget {
	/** Max tokens for a single tool result */
	singleMax: number
	/** Max tokens for all tool results combined */
	totalMax: number
}

/**
 * Calculate tool result token budgets based on context window size.
 */
export function getToolResultBudget(contextWindow: number): ToolResultBudget {
	const singleMax = Math.min(
		Math.floor(contextWindow * SINGLE_RESULT_MAX_RATIO),
		SINGLE_RESULT_MAX_TOKENS,
	)
	const totalMax = Math.floor(contextWindow * TOTAL_TOOL_RESULT_RATIO)
	return {
		singleMax: Math.max(singleMax, MIN_BUDGET_TOKENS),
		totalMax: Math.max(totalMax, MIN_BUDGET_TOKENS),
	}
}

/**
 * Truncate a single tool result string to fit within a token budget.
 *
 * Strategy:
 *  - If within budget, return as-is
 *  - Otherwise keep head (30%) and tail (20%), replace middle with summary
 *  - For code results, attempt to preserve complete function/class boundaries
 *
 * @param result   - The tool result text
 * @param budgetTokens - Maximum allowed tokens
 * @returns The (possibly truncated) result string
 */
export function truncateToolResult(result: string, budgetTokens: number): string {
	if (!result || result.length === 0) return result

	const currentTokens = estimateTokens(result)
	if (currentTokens <= budgetTokens) return result

	// Calculate how many tokens we can keep
	const keepTokens = Math.max(budgetTokens - 30, MIN_BUDGET_TOKENS) // 30 tokens reserved for the summary line

	// Convert token budget to approximate character positions
	// Average ~4 chars per token for English/code content
	const avgCharsPerToken = Math.max(result.length / currentTokens, 1)
	const headChars = Math.floor(keepTokens * HEAD_RATIO * avgCharsPerToken)
	const tailChars = Math.floor(keepTokens * TAIL_RATIO * avgCharsPerToken)

	if (headChars + tailChars >= result.length) return result

	let headEnd = headChars
	let tailStart = result.length - tailChars

	// For code content, try to snap to line boundaries
	const headNewline = result.indexOf("\n", headEnd)
	if (headNewline !== -1 && headNewline < headEnd + 200) {
		headEnd = headNewline + 1
	}
	const tailNewline = result.lastIndexOf("\n", tailStart)
	if (tailNewline !== -1 && tailNewline > tailStart - 200) {
		tailStart = tailNewline + 1
	}

	// Make sure we don't overlap
	if (headEnd >= tailStart) return result

	const headPart = result.slice(0, headEnd)
	const tailPart = result.slice(tailStart)

	const keptTokens = estimateTokens(headPart) + estimateTokens(tailPart)
	const summaryLine = `\n[... 内容已裁剪，原始 ${currentTokens} tokens，保留 ${keptTokens} tokens ...]\n`

	return headPart + summaryLine + tailPart
}

/**
 * Check if a content block contains image data (should not be truncated).
 */
function isImageContent(content: unknown): boolean {
	if (Array.isArray(content)) {
		return content.some((block) => (block as unknown as Record<string, unknown>).type === "image")
	}
	return false
}

/**
 * Extract the text content from a tool_result block.
 * Returns null if the content is non-text (e.g. image).
 */
function getToolResultText(block: Anthropic.Messages.ToolResultBlockParam): string | null {
	if (typeof block.content === "string") {
		return block.content
	}
	if (Array.isArray(block.content)) {
		// If it contains images, don't truncate
		if (block.content.some((item: any) => item.type === "image")) {
			return null
		}
		const textParts = block.content
			.filter((item: any) => item.type === "text")
			.map((item: any) => item.text || "")
		return textParts.join("\n")
	}
	return null
}

/**
 * Set the text content of a tool_result block, preserving its format.
 */
function setToolResultText(
	block: Anthropic.Messages.ToolResultBlockParam,
	newText: string,
): Anthropic.Messages.ToolResultBlockParam {
	if (typeof block.content === "string") {
		return { ...block, content: newText }
	}
	if (Array.isArray(block.content)) {
		// Replace text blocks, keep non-text blocks
		const nonTextBlocks = block.content.filter((item: any) => item.type !== "text")
		return {
			...block,
			content: [{ type: "text" as const, text: newText }, ...nonTextBlocks],
		}
	}
	return { ...block, content: newText }
}

/**
 * Apply progressive compression to tool results in message history.
 *
 * Older tool results get smaller budgets (decay by half every HISTORY_DECAY_TURNS turns).
 * Only compresses history messages, not the current turn.
 *
 * @param messages       - Full API conversation history
 * @param contextWindow  - Model context window size in tokens
 * @param currentTurn    - The current turn number (0-based, counted by user messages)
 * @returns A new messages array with compressed tool results (does NOT mutate the original)
 */
export function applyToolResultBudget(
	messages: ApiMessage[],
	contextWindow: number,
	currentTurn: number,
): ApiMessage[] {
	const budget = getToolResultBudget(contextWindow)

	// Count user messages to determine turn numbers
	let turnIndex = 0
	const result: ApiMessage[] = []

	for (const message of messages) {
		if (message.role === "user") {
			turnIndex++
		}

		// Only compress tool results in history (not the current turn)
		if (message.role === "user" && turnIndex < currentTurn && Array.isArray(message.content)) {
			const turnsAgo = currentTurn - turnIndex
			// Decay: budget halves every HISTORY_DECAY_TURNS
			const decayFactor = Math.pow(0.5, Math.floor(turnsAgo / HISTORY_DECAY_TURNS))
			const turnBudget = Math.max(
				Math.floor(budget.singleMax * decayFactor),
				MIN_BUDGET_TOKENS,
			)

			let modified = false
			const newContent = message.content.map((block) => {
				if ((block as unknown as Record<string, unknown>).type !== "tool_result") return block

				const toolResultBlock = block as Anthropic.Messages.ToolResultBlockParam

				// Skip image results
				if (isImageContent(toolResultBlock.content)) return block

				const text = getToolResultText(toolResultBlock)
				if (text === null) return block

				// Skip short results
				const tokens = estimateTokens(text)
				if (tokens <= turnBudget) return block

				// Truncate
				const truncated = truncateToolResult(text, turnBudget)
				if (truncated !== text) {
					modified = true
					return setToolResultText(toolResultBlock, truncated)
				}
				return block
			})

			if (modified) {
				result.push({ ...message, content: newContent })
			} else {
				result.push(message)
			}
		} else {
			result.push(message)
		}
	}

	return result
}

import type { ToolName, ModeConfig, GroupOptions, GroupEntry } from "@njust-ai-cj/types"
import { toolNames as validToolNames } from "@njust-ai-cj/types"
import { customToolRegistry } from "@njust-ai-cj/core"

import { type Mode, FileRestrictionError, getModeBySlug, getGroupName } from "../../shared/modes"
import { TOOL_GROUPS, ALWAYS_AVAILABLE_TOOLS, TOOL_ALIASES } from "../../shared/tools"
import { isAllowedCangjieCommand } from "../task/CangjieRuntimePolicy"
import { logger } from "../../shared/logger"

/**
 * Merge `params` with typed `nativeArgs` for mode and schema validation.
 * Some tool blocks only populate `nativeArgs`; validating with empty `params` can skip path checks
 * or mis-classify edit operations in modes with `edit` group options.
 *
 * **Important:** Preserve booleans, numbers, and structured values from `nativeArgs`.
 * Previously, non-string values were `JSON.stringify`d, which turned `false` into the string `"false"`
 * and `60` into `"60"`, breaking zod validation and tool execution.
 */
function mergeNativeValueForValidation(value: unknown): unknown {
	if (value === undefined || value === null) {
		return value
	}
	const t = typeof value
	if (t === "string" || t === "boolean" || t === "number" || t === "bigint") {
		return value
	}
	if (t === "object") {
		return value
	}
	return String(value)
}

export function mergeToolParamsForValidation(block: {
	params?: Record<string, unknown>
	nativeArgs?: unknown
}): Record<string, unknown> {
	const merged: Record<string, unknown> = { ...(block.params ?? {}) }
	const na = block.nativeArgs
	if (na && typeof na === "object" && !Array.isArray(na)) {
		for (const [key, value] of Object.entries(na as Record<string, unknown>)) {
			if (merged[key] !== undefined && merged[key] !== "") {
				continue
			}
			if (value === undefined || value === null) {
				continue
			}
			merged[key] = mergeNativeValueForValidation(value)
		}
	}
	return merged
}

/**
 * Checks if a tool name is a valid, known tool.
 * Note: This does NOT check if the tool is allowed for a specific mode,
 * only that the tool actually exists.
 */
export function isValidToolName(toolName: string, experiments?: Record<string, boolean>): toolName is ToolName {
	// Check if it's a valid static tool
	if ((validToolNames as readonly string[]).includes(toolName)) {
		return true
	}

	if (experiments?.customTools && customToolRegistry.has(toolName)) {
		return true
	}

	// Check if it's a dynamic MCP tool (mcp_serverName_toolName format).
	if (toolName.startsWith("mcp_")) {
		return true
	}

	return false
}

export function validateToolUse(
	toolName: ToolName,
	mode: Mode,
	customModes?: ModeConfig[],
	toolRequirements?: Record<string, boolean>,
	toolParams?: Record<string, unknown>,
	experiments?: Record<string, boolean>,
	includedTools?: string[],
	allowedTools?: string[],
): void {
	// First, check if the tool name is actually a valid/known tool
	// This catches completely invalid tool names like "edit_file" that don't exist
	if (!isValidToolName(toolName, experiments)) {
		throw new Error(
			`Unknown tool "${toolName}". This tool does not exist. Please use one of the available tools: ${validToolNames.join(", ")}.`,
		)
	}

	if (allowedTools && allowedTools.length > 0 && !allowedTools.includes(toolName)) {
		throw new Error(`Tool "${toolName}" is not allowed for this delegated agent context.`)
	}

	// Then check if the tool is allowed for the current mode
	if (
		!isToolAllowedForMode(
			toolName,
			mode,
			customModes ?? [],
			toolRequirements,
			toolParams,
			experiments,
			includedTools,
		)
	) {
		throw new Error(`Tool "${toolName}" is not allowed in ${mode} mode.`)
	}
}

const EDIT_OPERATION_PARAMS = [
	"diff",
	"content",
	"operations",
	"search",
	"replace",
	"args",
	"line",
	"patch", // Used by apply_patch
	"old_string", // Used by search_replace and edit_file
	"new_string", // Used by search_replace and edit_file
] as const

// Markers used in apply_patch format to identify file operations
const PATCH_FILE_MARKERS = ["*** Add File: ", "*** Delete File: ", "*** Update File: "] as const

// Standard unified diff markers (--- a/path, +++ b/path)
const UNIFIED_DIFF_MARKERS = ["--- a/", "+++ b/", "--- ", "+++ "] as const

/**
 * Extract file paths from apply_patch content.
 * The patch format uses markers like "*** Add File: path", "*** Delete File: path", "*** Update File: path"
 * @param patchContent The patch content string
 * @returns Array of file paths found in the patch
 */
function extractFilePathsFromPatch(patchContent: string): string[] {
	const filePaths: string[] = []
	const lines = patchContent.split("\n")

	for (const line of lines) {
		// Check custom patch markers first
		for (const marker of PATCH_FILE_MARKERS) {
			if (line.startsWith(marker)) {
				const path = line.substring(marker.length).trim()
				if (path) {
					filePaths.push(path)
				}
				break
			}
		}

		// Check standard unified diff markers (--- a/path or +++ b/path)
		for (const marker of UNIFIED_DIFF_MARKERS) {
			if (line.startsWith(marker)) {
				// Extract path, handling optional tab-separated timestamp (e.g., "--- a/file.txt\t2024-01-01")
				const rawPath = line.substring(marker.length).split("\t")[0].trim()
				// Skip /dev/null entries (used for new/deleted files in unified diff)
				if (rawPath && rawPath !== "/dev/null") {
					filePaths.push(rawPath)
				}
				break
			}
		}
	}

	return filePaths
}

function getGroupOptions(group: GroupEntry): GroupOptions | undefined {
	return Array.isArray(group) ? group[1] : undefined
}

function doesFileMatchRegex(filePath: string, pattern: string): boolean {
	// ReDoS protection: reject overly long or potentially catastrophic patterns
	if (pattern.length > 500) return false
	if (/([+*?{])\s*\1/.test(pattern)) return false
	try {
		const regex = new RegExp(pattern)
		return regex.test(filePath)
	} catch (error) {
		logger.error("ValidateToolUse", `Invalid regex pattern: ${pattern}`, error)
		return false
	}
}

export function isToolAllowedForMode(
	tool: string,
	modeSlug: string,
	customModes: ModeConfig[],
	toolRequirements?: Record<string, boolean>,
	toolParams?: Record<string, any>, // All tool parameters
	experiments?: Record<string, boolean>,
	includedTools?: string[], // Opt-in tools explicitly included (e.g., from modelInfo)
): boolean {
	// Resolve alias to canonical name (e.g., "search_and_replace" → "edit")
	const resolvedTool = TOOL_ALIASES[tool] ?? tool
	const resolvedIncludedTools = includedTools?.map((t) => TOOL_ALIASES[t] ?? t)

	if (modeSlug === "cangjie") {
		if (resolvedTool === "web_fetch" || resolvedTool === "config" || resolvedTool === "sleep") {
			return false
		}
		if (resolvedTool === "execute_command") {
			const command = typeof toolParams?.command === "string" ? toolParams.command : undefined
			if (command && !isAllowedCangjieCommand(command)) {
				return false
			}
		}
	}

	// Check tool requirements first — explicit disabling takes priority over everything,
	// including ALWAYS_AVAILABLE_TOOLS. This ensures disabledTools works consistently
	// at both the filtering layer and the execution-time validation layer.
	if (toolRequirements && typeof toolRequirements === "object") {
		if (
			(tool in toolRequirements && !toolRequirements[tool]) ||
			(resolvedTool in toolRequirements && !toolRequirements[resolvedTool])
		) {
			return false
		}
	} else if (toolRequirements === false) {
		// If toolRequirements is a boolean false, all tools are disabled
		return false
	}

	// Always allow these tools (unless explicitly disabled above)
	if (ALWAYS_AVAILABLE_TOOLS.includes(tool as any)) {
		return true
	}

	// For now, allow all custom tools in any mode.
	// As a follow-up we should expand the custom tool definition to include mode restrictions.
	if (experiments?.customTools && customToolRegistry.has(tool)) {
		return true
	}

	// Check if this is a dynamic MCP tool (mcp_serverName_toolName)
	// These should be allowed if the mcp group is allowed for the mode
	const isDynamicMcpTool = tool.startsWith("mcp_")

	const mode = getModeBySlug(modeSlug, customModes)

	if (!mode) {
		return false
	}

	// Check if tool is in any of the mode's groups and respects any group options
	for (const group of mode.groups) {
		const groupName = getGroupName(group)
		const options = getGroupOptions(group)

		const groupConfig = TOOL_GROUPS[groupName]

		// Check if this is a dynamic MCP tool and the mcp group is allowed
		if (isDynamicMcpTool && groupName === "mcp") {
			// Dynamic MCP tools are allowed if the mcp group is in the mode's groups
			return true
		}

		// Check if the tool is in the group's regular tools
		const isRegularTool = groupConfig.tools.includes(resolvedTool)

		// Check if the tool is a custom tool that has been explicitly included
		const isCustomTool =
			groupConfig.customTools?.includes(resolvedTool) && resolvedIncludedTools?.includes(resolvedTool)

		// If the tool isn't in regular tools and isn't an included custom tool, continue to next group
		if (!isRegularTool && !isCustomTool) {
			continue
		}

		// If there are no options, allow the tool
		if (!options) {
			return true
		}

		// For the edit group, check file regex if specified
		if (groupName === "edit" && options.fileRegex) {
			const filePath = toolParams?.path || toolParams?.file_path
			// Check if this is an actual edit operation (not just path-only for streaming)
			const isEditOperation = EDIT_OPERATION_PARAMS.some((param) => toolParams?.[param])

			// Handle single file path validation
			if (filePath && isEditOperation && !doesFileMatchRegex(filePath, options.fileRegex)) {
				throw new FileRestrictionError(mode.name, options.fileRegex, options.description, filePath, tool)
			}

			// Handle apply_patch: extract file paths from patch content and validate each
			if (tool === "apply_patch" && typeof toolParams?.patch === "string") {
				const patchFilePaths = extractFilePathsFromPatch(toolParams.patch)
				for (const patchFilePath of patchFilePaths) {
					if (!doesFileMatchRegex(patchFilePath, options.fileRegex)) {
						throw new FileRestrictionError(
							mode.name,
							options.fileRegex,
							options.description,
							patchFilePath,
							tool,
						)
					}
				}
			}

			// Native-only: multi-file edits provide structured params; no legacy XML args parsing.
		}

		return true
	}

	return false
}

