	}

	/**
	 * Delegate parent task and open child task.
	 *
	 * - Enforce single-open invariant
	 * - Persist parent delegation metadata
	 * - Emit TaskDelegated (task-level; API forwards to provider/bridge)
	 * - Create child as sole active and switch mode to child's mode
	 */
	public async delegateParentAndOpenChild(params: {
		parentTaskId: string
		message: string
		initialTodos: TodoItem[]
		mode: string
		isolationLevel?: string
		forkedContextSummary?: string
	}): Promise<Task> {
		const { parentTaskId, message, initialTodos, mode, isolationLevel, forkedContextSummary } = params

		// Metadata-driven delegation is always enabled

		// 1) Get parent (must be current task)
		const parent = this.getCurrentTask()
		if (!parent) {
			throw new Error("[delegateParentAndOpenChild] No current task")
		}
		if (parent.taskId !== parentTaskId) {
			throw new Error(
				`[delegateParentAndOpenChild] Parent mismatch: expected ${parentTaskId}, current ${parent.taskId}`,
			)
		}
		// 2) Flush pending tool results to API history BEFORE disposing the parent.
		//    This is critical: when tools are called before new_task,
		//    their tool_result blocks are in userMessageContent but not yet saved to API history.
		//    If we don't flush them, the parent's API conversation will be incomplete and
		//    cause 400 errors when resumed (missing tool_result for tool_use blocks).
		//
		//    NOTE: We do NOT pass the assistant message here because the assistant message
		//    is already added to apiConversationHistory by the normal flow in
		//    recursivelyMakeClineRequests BEFORE tools start executing. We only need to
		//    flush the pending user message with tool_results.
		try {
			const flushSuccess = await parent.flushPendingToolResultsToHistory()

			if (!flushSuccess) {
				logger.warn("ClineProvider", `delegateParentAndOpenChild: Flush failed for parent ${parentTaskId}, retrying...`)
				const retrySuccess = await parent.retrySaveApiConversationHistory()

				if (!retrySuccess) {
					logger.error(
						"ClineProvider",
						`delegateParentAndOpenChild: CRITICAL: Parent ${parentTaskId} API history not persisted to disk. Child return may produce stale state.`,
					)
					vscode.window.showWarningMessage(
						"Warning: Parent task state could not be saved. The parent task may lose recent context when resumed.",
					)
				}
			}
		} catch (error) {
			this.log(
				`[delegateParentAndOpenChild] Error flushing pending tool results (non-fatal): ${
					getErrorMessage(error)
				}`,
			)
		}

		// 3) Enforce single-open invariant by closing/disposing the parent first
		//    This ensures we never have >1 tasks open at any time during delegation.
		//    Await abort completion to ensure clean disposal and prevent unhandled rejections.
		try {
			await this.stack.pop({ skipDelegationRepair: true })
		} catch (error) {
			this.log(
				`[delegateParentAndOpenChild] Error during parent disposal (non-fatal): ${
					getErrorMessage(error)
				}`,
			)
			// Non-fatal: proceed with child creation even if parent cleanup had issues
		}

		// 3) Switch provider mode to child's requested mode BEFORE creating the child task
		//    This ensures the child's system prompt and configuration are based on the correct mode.
		//    The mode switch must happen before createTask() because the Task constructor
		//    initializes its mode from provider.getState() during initializeTaskMode().
		try {
			await this.handleModeSwitch(mode as any)
		} catch (e) {
			this.log(
				`[delegateParentAndOpenChild] handleModeSwitch failed for mode '${mode}': ${
					(e as Error)?.message ?? String(e)
				}`,
			)
		}

		// 4) Create child as sole active (parent reference preserved for lineage)
		// Pass initialStatus: "active" to ensure the child task's historyItem is created
		// with status from the start, avoiding race conditions where the task might
		// call attempt_completion before status is persisted separately.
		//
		// Pass startTask: false to prevent the child from beginning its task loop
		// (and writing to globalState via saveClineMessages → updateTaskHistory)
		// before we persist the parent's delegation metadata in step 5.
		// Without this, the child's fire-and-forget startTask() races with step 5,
		// and the last writer to globalState overwrites the other's changes—
		// causing the parent's delegation fields to be lost.
		const child = await this.createTask(message, undefined, parent as any, {
			initialTodos,
			initialStatus: "active",
			startTask: false,
		})
		// Inherit streaming model snapshot for better prompt-cache/tool-schema reuse continuity.
		if (parent.cachedStreamingModel) {
			child.cachedStreamingModel = parent.cachedStreamingModel
		}

		// Apply forked isolation context if specified
		let effectiveForkedSummary = forkedContextSummary
		if (isolationLevel === "forked" && !effectiveForkedSummary) {
			// Auto-generate context summary from parent when caller (e.g. NewTaskTool)
			// requests forked isolation but doesn't provide a pre-built summary.
			try {
				const { generateParentContextSummary } = await import("../task/SubTaskContextBuilder")
				const { DEFAULT_FORKED_CONTEXT_CONFIG } = await import("../task/SubTaskOptions")
				if (parent.apiConversationHistory && parent.apiConversationHistory.length > 0) {
					effectiveForkedSummary = generateParentContextSummary(
						parent.apiConversationHistory,
						DEFAULT_FORKED_CONTEXT_CONFIG.summaryMaxTokens,
						DEFAULT_FORKED_CONTEXT_CONFIG,
					)
				}
			} catch (e) {
				this.log(
					`[delegateParentAndOpenChild] Failed to auto-generate forked context summary: ${
						(e as Error)?.message ?? String(e)
					}`,
				)
			}
		}
		if (isolationLevel === "forked" && effectiveForkedSummary) {
			child.forkedContextSummary = effectiveForkedSummary
			child.isolationLevel = "forked"
		}

		// 5) Persist parent delegation metadata BEFORE the child starts writing.
		try {
			const { historyItem } = await this.getTaskWithId(parentTaskId)
			const childIds = Array.from(new Set([...(historyItem.childIds ?? []), child.taskId]))
			const updatedHistory: typeof historyItem = {
				...historyItem,
				status: "delegated",
				delegatedToId: child.taskId,
				awaitingChildId: child.taskId,
				childIds,
			}
			await this.updateTaskHistory(updatedHistory)
		} catch (err) {
			this.log(
				`[delegateParentAndOpenChild] Failed to persist parent metadata for ${parentTaskId} -> ${child.taskId}: ${
					(err as Error)?.message ?? String(err)
				}`,
			)
		}

		// 6) Start the child task now that parent metadata is safely persisted.
		child.start()

		// 7) Emit TaskDelegated (provider-level)
		try {
			this.emit(NJUST_AI_CJEventName.TaskDelegated, parentTaskId, child.taskId)
		} catch (error) {
			// non-fatal
			logger.warn("ClineProvider", "TaskDelegated event emission failed", error)
		}

		return child
	}

	/**
	 * Reopen parent task from delegation with write-back and events.
	 */
	public async reopenParentFromDelegation(params: {
		parentTaskId: string
		childTaskId: string
		completionResultSummary: string
	}): Promise<void> {
		const { parentTaskId, childTaskId, completionResultSummary } = params
		const globalStoragePath = this.contextProxy.globalStorageUri.fsPath

		// 1) Load parent from history and current persisted messages
		const { historyItem } = await this.getTaskWithId(parentTaskId)

		let parentClineMessages: ClineMessage[] = []
		try {
			parentClineMessages = await readTaskMessages({
				taskId: parentTaskId,
				globalStoragePath,
			})
		} catch (error) {
			logger.debug("ClineProvider", "Failed to read parent cline messages", error)
			parentClineMessages = []
		}

		let parentApiMessages: any[] = []
		try {
			parentApiMessages = (await readApiMessages({
				taskId: parentTaskId,
				globalStoragePath,
			})) as any[]
		} catch (error) {
			logger.debug("ClineProvider", "Failed to read parent api messages", error)
			parentApiMessages = []
		}

		// 2) Inject synthetic records: UI subtask_result and update API tool_result
		const ts = Date.now()

		// Defensive: ensure arrays
		if (!Array.isArray(parentClineMessages)) parentClineMessages = []
		if (!Array.isArray(parentApiMessages)) parentApiMessages = []

		const subtaskUiMessage: ClineMessage = {
			type: "say",
			say: "subtask_result",
			text: completionResultSummary,
			ts,
				id: crypto.randomUUID(),
		}
		parentClineMessages.push(subtaskUiMessage)
		await saveTaskMessages({ messages: parentClineMessages, taskId: parentTaskId, globalStoragePath })

		// Find the tool_use_id from the last assistant message's new_task tool_use
		let toolUseId: string | undefined
		for (let i = parentApiMessages.length - 1; i >= 0; i--) {
			const msg = parentApiMessages[i]
			if (msg.role === "assistant" && Array.isArray(msg.content)) {
				for (const block of msg.content) {
					if (block.type === "tool_use" && block.name === "new_task") {
						toolUseId = block.id
						break
					}
				}
				if (toolUseId) break
			}
		}

		// Preferred: if the parent history contains the native tool_use for new_task,
		// inject a matching tool_result for the Anthropic message contract:
		// user → assistant (tool_use) → user (tool_result)
		if (toolUseId) {
			// Check if the last message is already a user message with a tool_result for this tool_use_id
			// (in case this is a retry or the history was already updated)
			const lastMsg = parentApiMessages[parentApiMessages.length - 1]
			let alreadyHasToolResult = false
			if (lastMsg?.role === "user" && Array.isArray(lastMsg.content)) {
				for (const block of lastMsg.content) {
					if (block.type === "tool_result" && block.tool_use_id === toolUseId) {
						// Update the existing tool_result content
						block.content = `Subtask ${childTaskId} completed.\n\nResult:\n${completionResultSummary}`
						alreadyHasToolResult = true
						break
					}
				}
			}

			// If no existing tool_result found, create a NEW user message with the tool_result
			if (!alreadyHasToolResult) {
				parentApiMessages.push({
					role: "user",
					content: [
						{
							type: "tool_result" as const,
							tool_use_id: toolUseId,
							content: `Subtask ${childTaskId} completed.\n\nResult:\n${completionResultSummary}`,
						},
					],
					ts,
				})
			}

			// Validate the newly injected tool_result against the preceding assistant message.
			// This ensures the tool_result's tool_use_id matches a tool_use in the immediately
			// preceding assistant message (Anthropic API requirement).
			const lastMessage = parentApiMessages[parentApiMessages.length - 1]
			if (lastMessage?.role === "user") {
				const validatedMessage = validateAndFixToolResultIds(lastMessage, parentApiMessages.slice(0, -1))
				parentApiMessages[parentApiMessages.length - 1] = validatedMessage
			}
		} else {
			// If there is no corresponding tool_use in the parent API history, we cannot emit a
			// tool_result. Fall back to a plain user text note so the parent can still resume.
			parentApiMessages.push({
				role: "user",
				content: [
					{
						type: "text" as const,
						text: `Subtask ${childTaskId} completed.\n\nResult:\n${completionResultSummary}`,
					},
				],
				ts,
			})
		}

		await saveApiMessages({ messages: parentApiMessages as any, taskId: parentTaskId, globalStoragePath })

		// 3) Close child instance if still open (single-open-task invariant).
		//    This MUST happen BEFORE updating the child's status to "completed" because
		//    stack.pop() → abortTask(true) → saveClineMessages() writes
		//    the historyItem with initialStatus (typically "active"), which would
		//    overwrite a "completed" status set earlier.
		const current = this.getCurrentTask()
		if (current?.taskId === childTaskId) {
			await this.stack.pop()
		}

		// 4) Update child metadata to "completed" status.
		//    This runs after the abort so it overwrites the stale "active" status
		//    that saveClineMessages() may have written during step 3.
		try {
			const { historyItem: childHistory } = await this.getTaskWithId(childTaskId)
			await this.updateTaskHistory({
				...childHistory,
				status: "completed",
			})
		} catch (err) {
			this.log(
				`[reopenParentFromDelegation] Failed to persist child completed status for ${childTaskId}: ${
					(err as Error)?.message ?? String(err)
				}`,
			)
		}

		// 5) Update parent metadata and persist BEFORE emitting completion event
		const childIds = Array.from(new Set([...(historyItem.childIds ?? []), childTaskId]))
		const updatedHistory: typeof historyItem = {
			...historyItem,
			status: "active",
			completedByChildId: childTaskId,
			completionResultSummary,
			awaitingChildId: undefined,
			childIds,
		}
		await this.updateTaskHistory(updatedHistory)

		// 6) Emit TaskDelegationCompleted (provider-level)
		try {
			this.emit(NJUST_AI_CJEventName.TaskDelegationCompleted, parentTaskId, childTaskId, completionResultSummary)
		} catch (error) {
			// non-fatal
			logger.warn("ClineProvider", "TaskDelegationCompleted event emission failed", error)
		}

		// 7) Reopen the parent from history as the sole active task (restores saved mode)
		//    IMPORTANT: startTask=false to suppress resume-from-history ask scheduling
		const parentInstance = await this.createTaskWithHistoryItem(updatedHistory, { startTask: false })

		// 8) Inject restored histories into the in-memory instance before resuming
		if (parentInstance) {
			try {
				await parentInstance.overwriteClineMessages(parentClineMessages)
			} catch (error) {
				// non-fatal
				logger.warn("ClineProvider", "overwriteClineMessages failed", error)
			}
			try {
				await parentInstance.overwriteApiConversationHistory(parentApiMessages as any)
			} catch (error) {
				// non-fatal
				logger.warn("ClineProvider", "overwriteApiConversationHistory failed", error)
			}

			// Auto-resume parent without ask("resume_task")
			await parentInstance.resumeAfterDelegation()
		}

		// 9) Emit TaskDelegationResumed (provider-level)
		try {
			this.emit(NJUST_AI_CJEventName.TaskDelegationResumed, parentTaskId, childTaskId)
		} catch (error) {
			// non-fatal
			logger.warn("ClineProvider", "TaskDelegationResumed event emission failed", error)
		}
	}

	/**
	 * Convert a file path to a webview-accessible URI
	 * This method safely converts file paths to URIs that can be loaded in the webview
	 *
	 * @param filePath - The absolute file path to convert
	 * @returns The webview URI string, or the original file URI if conversion fails
	 * @throws {Error} When webview is not available
	 * @throws {TypeError} When file path is invalid
	 */
	public convertToWebviewUri(filePath: string): string {
		try {
			const fileUri = vscode.Uri.file(filePath)

			// Check if we have a webview available
			if (this.view?.webview) {
				const webviewUri = this.view.webview.asWebviewUri(fileUri)
				return webviewUri.toString()
			}

			// Specific error for no webview available
			logger.error("ClineProvider", "No webview available for URI conversion")
			// Fallback to file URI if no webview available
			return fileUri.toString()
		} catch (error) {
			// More specific error handling
			if (error instanceof TypeError) {
				logger.error("ClineProvider", "Invalid file path provided for URI conversion:", error)
			} else {
				logger.error("ClineProvider", "Failed to convert to webview URI:", error)
			}
			// Return file URI as fallback
			return vscode.Uri.file(filePath).toString()
		}
	}

}

/**
 * TaskHistoryService — Task history CRUD, search, export, and globalState sync.
 *
 * Extracted from ClineProvider.ts to decompose the monolithic provider.
 */

import * as path from "path"
import fs from "fs/promises"
import type { Anthropic } from "@anthropic-ai/sdk"
import type * as vscode from "vscode"

import type { HistoryItem, ExtensionMessage } from "@njust-ai-cj/types"

import type { Task } from "../task/Task"
import type { TaskHistoryStore } from "../task-persistence"
import type { TaskStackManager } from "./TaskStackManager"
import { fileExistsAtPath } from "../../utils/fs"
import { GlobalFileNames } from "../../shared/globalFileNames"
import { downloadTask, getTaskFileName } from "../../integrations/misc/export-markdown"
import { resolveDefaultSaveUri, saveLastExportPath } from "../../utils/export"
import { ShadowCheckpointService } from "../../services/checkpoints/ShadowCheckpointService"
import { pruneStaleRegistrations, NO_TASK_KEY } from "../../services/cangjie-lsp/cangjieGeneratedTestCleanup"
import { aggregateTaskCostsRecursive, type AggregatedCosts } from "./aggregateTaskCosts"
import { logger } from "../../shared/logger"
import { getErrorMessage } from "../../shared/error-utils"

export interface TaskHistoryHost {
	readonly context: vscode.ExtensionContext
	readonly contextProxy: {
		readonly globalStorageUri: vscode.Uri
		getValue<K extends string>(key: K): any
		setValue<K extends string>(key: K, value: any): Promise<void>
	}
	readonly taskHistoryStore: TaskHistoryStore
	readonly outputChannel: vscode.OutputChannel
	readonly cwd: string
	isViewLaunched: boolean
	readonly stack: TaskStackManager
	postMessageToWebview(message: ExtensionMessage): Promise<void>
}

export class TaskHistoryService {
	private static readonly GLOBAL_STATE_WRITE_THROUGH_DEBOUNCE_MS = 5000

	private _initialized = false
	private _recentTasksCache?: string[]
	private _globalStateWriteThroughTimer: ReturnType<typeof setTimeout> | null = null

	constructor(private host: TaskHistoryHost) {}

	get initialized(): boolean {
		return this._initialized
	}

	// ── Initialization ──────────────────────────────────────────────

	async initialize(): Promise<void> {
		try {
			await this.host.taskHistoryStore.initialize()

			const migrationKey = "taskHistoryMigratedToFiles"
			const alreadyMigrated = this.host.context.globalState.get<boolean>(migrationKey)

			if (!alreadyMigrated) {
				const legacyHistory = this.host.context.globalState.get<HistoryItem[]>("taskHistory") ?? []

				if (legacyHistory.length > 0) {
					this.log(`[TaskHistoryService] Migrating ${legacyHistory.length} entries from globalState`)
					await this.host.taskHistoryStore.migrateFromGlobalState(legacyHistory)
				}

				await this.host.context.globalState.update(migrationKey, true)
				this.log("[TaskHistoryService] Migration complete")
			}

			this._initialized = true

			try {
				const { filesRemoved, taskEntriesRemoved } = pruneStaleRegistrations((id) => {
					if (id === NO_TASK_KEY) return false
					const h = this.host.taskHistoryStore.get(id)
					if (!h || h.status === "completed") return false
					return true
				})
				if (filesRemoved > 0) {
					this.host.outputChannel.appendLine(
						`[CangjieTestCleanup] 启动修剪：移除 ${filesRemoved} 个生成测试文件（${taskEntriesRemoved} 个任务桶）。`,
					)
				}
			} catch (e) {
				this.log(`[CangjieTestCleanup] prune failed: ${getErrorMessage(e)}`)
			}

			const items = this.host.taskHistoryStore.getAll().filter((item: HistoryItem) => item.ts && item.task)
			void this.host.postMessageToWebview({ type: "taskHistoryUpdated", taskHistory: items })
		} catch (error) {
			this.log(`[TaskHistoryService] Init error: ${getErrorMessage(error)}`)
		}
	}

	// ── Task Retrieval ──────────────────────────────────────────────

	async getTaskWithId(id: string): Promise<{
		historyItem: HistoryItem
		taskDirPath: string
		apiConversationHistoryFilePath: string
		uiMessagesFilePath: string
		apiConversationHistory: Anthropic.MessageParam[]
	}> {
		const historyItem =
			this.host.taskHistoryStore.get(id) ?? (this.host.context.globalState.get<HistoryItem[]>("taskHistory") ?? []).find((item) => item.id === id)

		if (!historyItem) {
			throw new Error("Task not found")
		}

		const { getTaskDirectoryPath } = await import("../../utils/storage")
		const globalStoragePath = this.host.contextProxy.globalStorageUri.fsPath
		const taskDirPath = await getTaskDirectoryPath(globalStoragePath, id)
		const apiConversationHistoryFilePath = path.join(taskDirPath, GlobalFileNames.apiConversationHistory)
		const uiMessagesFilePath = path.join(taskDirPath, GlobalFileNames.uiMessages)
		const fileExists = await fileExistsAtPath(apiConversationHistoryFilePath)

		let apiConversationHistory: Anthropic.MessageParam[] = []

		if (fileExists) {
			try {
				apiConversationHistory = JSON.parse(await fs.readFile(apiConversationHistoryFilePath, "utf8"))
			} catch (error) {
				logger.warn(
					"TaskHistoryService",
					`getTaskWithId: api_conversation_history.json corrupted for task ${id}, returning empty history: ${getErrorMessage(error)}`,
				)
			}
		} else {
			logger.warn(
				"TaskHistoryService",
				`getTaskWithId: api_conversation_history.json missing for task ${id}, returning empty history`,
			)
		}

		return {
			historyItem,
			taskDirPath,
			apiConversationHistoryFilePath,
			uiMessagesFilePath,
			apiConversationHistory,
		}
	}

	async getTaskWithAggregatedCosts(taskId: string): Promise<{
		historyItem: HistoryItem
		aggregatedCosts: AggregatedCosts
	}> {
		const { historyItem } = await this.getTaskWithId(taskId)

		const aggregatedCosts = await aggregateTaskCostsRecursive(taskId, async (id: string) => {
			const result = await this.getTaskWithId(id)
			return result.historyItem
		})

		return { historyItem, aggregatedCosts }
	}

	async showTaskWithId(id: string, createTaskWithHistoryItem: (item: HistoryItem) => Promise<void>): Promise<void> {
		const currentTask = this.host.stack.current
		if (id !== currentTask?.taskId) {
			const { historyItem } = await this.getTaskWithId(id)
			await createTaskWithHistoryItem(historyItem)
		}
		void this.host.postMessageToWebview({ type: "action", action: "chatButtonClicked" })
	}

	async exportTaskWithId(id: string): Promise<void> {
		const { historyItem, apiConversationHistory } = await this.getTaskWithId(id)
		const fileName = getTaskFileName(historyItem.ts)
		const homedir = (await import("os")).homedir()
		const defaultUri = await resolveDefaultSaveUri(this.host.contextProxy as any, "lastTaskExportPath", fileName, {
			useWorkspace: false,
			fallbackDir: path.join(homedir, "Downloads"),
		})
		const saveUri = await downloadTask(historyItem.ts, apiConversationHistory, defaultUri)

		if (saveUri) {
			await saveLastExportPath(this.host.contextProxy as any, "lastTaskExportPath", saveUri)
		}
	}

	async condenseTaskContext(taskId: string): Promise<void> {
		let task: Task | undefined
		const stack = this.host.stack.getStack()
		for (let i = stack.length - 1; i >= 0; i--) {
			if (stack[i].taskId === taskId) {
				task = stack[i]
				break
			}
		}
		if (!task) {
			throw new Error(`Task with id ${taskId} not found in stack`)
		}
		await task.condenseContext()
		void this.host.postMessageToWebview({ type: "condenseTaskContextResponse", text: taskId })
	}

	// ── Task Deletion ───────────────────────────────────────────────

	async deleteTaskWithId(id: string, cascadeSubtasks: boolean = true): Promise<void> {
		try {
			const { taskDirPath: _taskDirPath, historyItem: _historyItem } = await this.getTaskWithId(id)

			const allIdsToDelete: string[] = [id]

			if (cascadeSubtasks) {
				const collectChildIds = async (taskId: string): Promise<void> => {
					try {
						const { historyItem: item } = await this.getTaskWithId(taskId)
						if (item.childIds && item.childIds.length > 0) {
							for (const childId of item.childIds) {
								allIdsToDelete.push(childId)
								await collectChildIds(childId)
							}
						}
					} catch (_error) {
						logger.info("TaskHistoryService", `deleteTaskWithId: child task ${taskId} not found, skipping`)
					}
				}

				await collectChildIds(id)
			}

			for (const taskId of allIdsToDelete) {
				const currentTask = this.host.stack.current
				if (taskId === currentTask?.taskId) {
					await this.host.stack.pop()
					break
				}
			}

			await this.host.taskHistoryStore.deleteMany(allIdsToDelete)
			this._recentTasksCache = undefined

			const globalStorageDir = this.host.contextProxy.globalStorageUri.fsPath
			const workspaceDir = this.host.cwd
			const { getTaskDirectoryPath } = await import("../../utils/storage")
			const globalStoragePath = this.host.contextProxy.globalStorageUri.fsPath

			for (const taskId of allIdsToDelete) {
				try {
					await ShadowCheckpointService.deleteTask({ taskId, globalStorageDir, workspaceDir })
				} catch (error) {
					logger.error(
						"TaskHistoryService",
						`deleteTaskWithId: failed to delete associated shadow repository or branch: ${getErrorMessage(error)}`,
					)
				}

				try {
					const dirPath = await getTaskDirectoryPath(globalStoragePath, taskId)
					await fs.rm(dirPath, { recursive: true, force: true })
					logger.info("TaskHistoryService", `deleteTaskWithId: removed task directory for ${taskId}`)
				} catch (error) {
					logger.error(
						"TaskHistoryService",
						`deleteTaskWithId: failed to remove task directory: ${getErrorMessage(error)}`,
					)
				}
			}
		} catch (error) {
			if (error instanceof Error && error.message === "Task not found") {
				await this.deleteTaskFromState(id)
				return
			}
			throw error
		}
	}

	async deleteTaskFromState(id: string): Promise<void> {
		await this.host.taskHistoryStore.delete(id)
		this._recentTasksCache = undefined
	}

	// ── Task History Mutations ──────────────────────────────────────

	async updateTaskHistory(item: HistoryItem, options: { broadcast?: boolean } = {}): Promise<HistoryItem[]> {
		const { broadcast = true } = options

		const history = await this.host.taskHistoryStore.upsert(item)
		this._recentTasksCache = undefined

		if (broadcast && this.host.isViewLaunched) {
			const updatedItem = this.host.taskHistoryStore.get(item.id) ?? item
			await this.host.postMessageToWebview({ type: "taskHistoryItemUpdated", taskHistoryItem: updatedItem })
		}

		return history
	}

	async broadcastTaskHistoryUpdate(history?: HistoryItem[]): Promise<void> {
		if (!this.host.isViewLaunched) {
			return
		}

		const taskHistory = history ?? this.host.taskHistoryStore.getAll()

		const sortedHistory = taskHistory
			.filter((item: HistoryItem) => item.ts && item.task)
			.sort((a: HistoryItem, b: HistoryItem) => b.ts - a.ts)

		await this.host.postMessageToWebview({
			type: "taskHistoryUpdated",
			taskHistory: sortedHistory,
		})
	}

	// ── Recent Tasks ────────────────────────────────────────────────

	getRecentTasks(): string[] {
		if (this._recentTasksCache) {
			return this._recentTasksCache
		}

		const history = this.host.taskHistoryStore.getAll()
		const workspaceTasks: HistoryItem[] = []

		for (const item of history) {
			if (!item.ts || !item.task || item.workspace !== this.host.cwd) {
				continue
			}

			workspaceTasks.push(item)
		}

		if (workspaceTasks.length === 0) {
			this._recentTasksCache = []
			return this._recentTasksCache
		}

		workspaceTasks.sort((a, b) => b.ts - a.ts)
		let recentTaskIds: string[] = []

		if (workspaceTasks.length >= 100) {
			const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000

			for (const item of workspaceTasks) {
				if (item.ts < sevenDaysAgo) {
					break
				}

				recentTaskIds.push(item.id)
			}
		} else {
			recentTaskIds = workspaceTasks.slice(0, Math.min(100, workspaceTasks.length)).map((item) => item.id)
		}

		this._recentTasksCache = recentTaskIds
		return this._recentTasksCache
	}

	// ── GlobalState Write-Through ───────────────────────────────────

	scheduleGlobalStateWriteThrough(): void {
		if (this._globalStateWriteThroughTimer) {
			clearTimeout(this._globalStateWriteThroughTimer)
		}

		this._globalStateWriteThroughTimer = setTimeout(async () => {
			this._globalStateWriteThroughTimer = null
			try {
				const items = this.host.taskHistoryStore.getAll()
				await this.host.contextProxy.setValue("taskHistory", items)
			} catch (err) {
				this.log(
					`[scheduleGlobalStateWriteThrough] Failed: ${getErrorMessage(err)}`,
				)
			}
		}, TaskHistoryService.GLOBAL_STATE_WRITE_THROUGH_DEBOUNCE_MS)
	}

	flushGlobalStateWriteThrough(): void {
		if (this._globalStateWriteThroughTimer) {
			clearTimeout(this._globalStateWriteThroughTimer)
			this._globalStateWriteThroughTimer = null
		}

		const items = this.host.taskHistoryStore.getAll()
		this.host.contextProxy.setValue("taskHistory", items).catch((err: unknown) => {
			this.log(`[flushGlobalStateWriteThrough] Failed: ${getErrorMessage(err)}`)
		})
	}

	// ── Cleanup ─────────────────────────────────────────────────────

	dispose(): void {
		this.flushGlobalStateWriteThrough()
	}

	// ── Helpers ─────────────────────────────────────────────────────

	private log(message: string): void {
		this.host.outputChannel.appendLine(message)
		logger.info("TaskHistoryService", message)
	}
}

/**
 * WebviewContentProvider generates HTML content for the webview.
 *
 * Supports both production builds and HMR (Hot Module Replacement) for development.
 */

import * as vscode from "vscode"
import axios from "axios"

import { getNonce } from "./getNonce"
import { getUri } from "./getUri"
import { t } from "../../i18n"
import { logger } from "../../shared/logger"

export interface WebviewContentProviderHost {
	readonly extensionUri: vscode.Uri
	getValues(): { openRouterBaseUrl?: string }
}

export class WebviewContentProvider {
	constructor(private host: WebviewContentProviderHost) {}

	/**
	 * Generates HTML content for HMR (Hot Module Replacement) development mode.
	 * Falls back to production build if dev server is not running.
	 */
	async getHMRHtmlContent(webview: vscode.Webview): Promise<string> {
		let localPort = "5173"

		try {
			const fs = require("fs")
			const path = require("path")
			const portFilePath = path.resolve(__dirname, "../../.vite-port")

			if (fs.existsSync(portFilePath)) {
				localPort = fs.readFileSync(portFilePath, "utf8").trim()
				logger.info("WebviewContentProvider", `Using Vite server port from ${portFilePath}: ${localPort}`)
			} else {
				logger.info("WebviewContentProvider", `Port file not found at ${portFilePath}, using default port: ${localPort}`,
				)
			}
		} catch (err) {
			logger.error("WebviewContentProvider", "Failed to read Vite port file:", err)
		}

		const localServerUrl = `localhost:${localPort}`

		// Check if local dev server is running.
		try {
			await axios.get(`http://${localServerUrl}`)
		} catch (_error) {
			vscode.window.showErrorMessage(t("common:errors.hmr_not_running"))
			return this.getHtmlContent(webview)
		}

		const nonce = getNonce()

		const openRouterBaseUrl = this.host.getValues().openRouterBaseUrl || "https://openrouter.ai"
		const openRouterDomain = openRouterBaseUrl.match(/^(https?:\/\/[^\/]+)/)?.[1] || "https://openrouter.ai"

		const stylesUri = getUri(webview, this.host.extensionUri, [
			"webview-ui",
			"build",
			"assets",
			"index.css",
		])

		const codiconsUri = getUri(webview, this.host.extensionUri, ["assets", "codicons", "codicon.css"])
		const materialIconsUri = getUri(webview, this.host.extensionUri, [
			"assets",
			"vscode-material-icons",
			"icons",
		])
		const imagesUri = getUri(webview, this.host.extensionUri, ["assets", "images"])
		const audioUri = getUri(webview, this.host.extensionUri, ["webview-ui", "audio"])

		const file = "src/index.tsx"
		const scriptUri = `http://${localServerUrl}/${file}`

		const reactRefresh = /*html*/ `
			<script nonce="${nonce}" type="module">
				import RefreshRuntime from "http://localhost:${localPort}/@react-refresh"
				RefreshRuntime.injectIntoGlobalHook(window)
				window.$RefreshReg$ = () => {}
				window.$RefreshSig$ = () => (type) => type
				window.__vite_plugin_react_preamble_installed__ = true
			</script>
		`

		const csp = [
			"default-src 'none'",
			`font-src ${webview.cspSource} data:`,
			`style-src ${webview.cspSource} 'unsafe-inline' http://${localServerUrl} http://0.0.0.0:${localPort}`,
			`img-src ${webview.cspSource} https://storage.googleapis.com https://img.clerk.com data:`,
			`media-src ${webview.cspSource} blob:`,
			`script-src 'unsafe-eval' ${webview.cspSource} http://${localServerUrl} http://0.0.0.0:${localPort} 'nonce-${nonce}'`,
			`connect-src ${webview.cspSource} ${openRouterDomain} ws://${localServerUrl} ws://0.0.0.0:${localPort} http://${localServerUrl} http://0.0.0.0:${localPort}`,
		]

		return /*html*/ `
			<!DOCTYPE html>
			<html lang="en">
				<head>
					<meta charset="utf-8">
					<meta name="viewport" content="width=device-width,initial-scale=1,shrink-to-fit=no">
					<meta http-equiv="Content-Security-Policy" content="${csp.join("; ")}">
					<link rel="stylesheet" type="text/css" href="${stylesUri}">
					<link href="${codiconsUri}" rel="stylesheet" />
					<script nonce="${nonce}">
						window.IMAGES_BASE_URI = "${imagesUri}"
						window.AUDIO_BASE_URI = "${audioUri}"
						window.MATERIAL_ICONS_BASE_URI = "${materialIconsUri}"
					</script>
					<title>NJUST_AI_CJ</title>
				</head>
				<body>
					<div id="root"></div>
					${reactRefresh}
					<script type="module" src="${scriptUri}"></script>
				</body>
			</html>
		`
	}

	/**
	 * Generates HTML content for production build.
	 */
	getHtmlContent(webview: vscode.Webview): Promise<string> {
		const stylesUri = getUri(webview, this.host.extensionUri, [
			"webview-ui",
			"build",
			"assets",
			"index.css",
		])

		const scriptUri = getUri(webview, this.host.extensionUri, ["webview-ui", "build", "assets", "index.js"])
		const codiconsUri = getUri(webview, this.host.extensionUri, ["assets", "codicons", "codicon.css"])
		const materialIconsUri = getUri(webview, this.host.extensionUri, [
			"assets",
			"vscode-material-icons",
			"icons",
		])
		const imagesUri = getUri(webview, this.host.extensionUri, ["assets", "images"])
		const audioUri = getUri(webview, this.host.extensionUri, ["webview-ui", "audio"])

		const nonce = getNonce()

		const openRouterBaseUrl = this.host.getValues().openRouterBaseUrl || "https://openrouter.ai"
		const openRouterDomain = openRouterBaseUrl.match(/^(https?:\/\/[^\/]+)/)?.[1] || "https://openrouter.ai"

		return /*html*/ `
        <!DOCTYPE html>
        <html lang="en">
          <head>
            <meta charset="utf-8">
            <meta name="viewport" content="width=device-width,initial-scale=1,shrink-to-fit=no">
            <meta name="theme-color" content="#000000">
            <meta http-equiv="Content-Security-Policy" content="default-src 'none'; font-src ${webview.cspSource} data:; style-src ${webview.cspSource} 'unsafe-inline'; img-src ${webview.cspSource} https://storage.googleapis.com https://img.clerk.com data:; media-src ${webview.cspSource} blob:; script-src ${webview.cspSource} 'wasm-unsafe-eval' 'nonce-${nonce}' 'strict-dynamic'; connect-src ${webview.cspSource} ${openRouterDomain} https://api.requesty.ai;">
            <link rel="stylesheet" type="text/css" href="${stylesUri}">
			<link href="${codiconsUri}" rel="stylesheet" />
			<script nonce="${nonce}">
				window.IMAGES_BASE_URI = "${imagesUri}"
				window.AUDIO_BASE_URI = "${audioUri}"
				window.MATERIAL_ICONS_BASE_URI = "${materialIconsUri}"
			</script>
            <title>NJUST_AI_CJ</title>
          </head>
          <body>
            <noscript>You need to enable JavaScript to run this app.</noscript>
            <div id="root"></div>
            <script nonce="${nonce}" type="module" src="${scriptUri}"></script>
          </body>
        </html>
      `
	}
}

