	private async waitForWebviewLaunch(timeoutMs: number): Promise<boolean> {
		try {
			await pWaitFor(() => this.sidebarProvider.viewLaunched, {
				timeout: timeoutMs,
				interval: 50,
			})

			return true
		} catch {
			this.log(`[API#waitForWebviewLaunch] webview did not launch within ${timeoutMs}ms`)
			return false
		}
	}

	private registerListeners(provider: ClineProvider) {
		provider.on(NJUST_AI_CJEventName.TaskCreated, (task) => {
			// Task Lifecycle

			task.on(NJUST_AI_CJEventName.TaskStarted, async () => {
				this.emit(NJUST_AI_CJEventName.TaskStarted, task.taskId)
				await this.fileLog(`[${new Date().toISOString()}] taskStarted -> ${task.taskId}\n`)
			})

			task.on(NJUST_AI_CJEventName.TaskCompleted, async (_, tokenUsage, toolUsage) => {
				this.emit(NJUST_AI_CJEventName.TaskCompleted, task.taskId, tokenUsage, toolUsage, {
					isSubtask: !!task.parentTaskId,
				})

				await this.fileLog(
					`[${new Date().toISOString()}] taskCompleted -> ${task.taskId} | ${JSON.stringify(tokenUsage, null, 2)} | ${JSON.stringify(toolUsage, null, 2)}\n`,
				)
			})

			task.on(NJUST_AI_CJEventName.TaskAborted, () => {
				this.emit(NJUST_AI_CJEventName.TaskAborted, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskFocused, () => {
				this.emit(NJUST_AI_CJEventName.TaskFocused, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskUnfocused, () => {
				this.emit(NJUST_AI_CJEventName.TaskUnfocused, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskActive, () => {
				this.emit(NJUST_AI_CJEventName.TaskActive, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskInteractive, () => {
				this.emit(NJUST_AI_CJEventName.TaskInteractive, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskResumable, () => {
				this.emit(NJUST_AI_CJEventName.TaskResumable, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskIdle, () => {
				this.emit(NJUST_AI_CJEventName.TaskIdle, task.taskId)
			})

			// Subtask Lifecycle

			task.on(NJUST_AI_CJEventName.TaskPaused, () => {
				this.emit(NJUST_AI_CJEventName.TaskPaused, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskUnpaused, () => {
				this.emit(NJUST_AI_CJEventName.TaskUnpaused, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.TaskSpawned, (childTaskId) => {
				this.emit(NJUST_AI_CJEventName.TaskSpawned, task.taskId, childTaskId)
			})

			task.on(NJUST_AI_CJEventName.TaskDelegated as any, (childTaskId: string) => {
				;(this.emit as any)(NJUST_AI_CJEventName.TaskDelegated, task.taskId, childTaskId)
			})

			task.on(NJUST_AI_CJEventName.TaskDelegationCompleted as any, (childTaskId: string, summary: string) => {
				;(this.emit as any)(NJUST_AI_CJEventName.TaskDelegationCompleted, task.taskId, childTaskId, summary)
			})

			task.on(NJUST_AI_CJEventName.TaskDelegationResumed as any, (childTaskId: string) => {
				;(this.emit as any)(NJUST_AI_CJEventName.TaskDelegationResumed, task.taskId, childTaskId)
			})

			// Task Execution

			task.on(NJUST_AI_CJEventName.Message, async (message) => {
				this.emit(NJUST_AI_CJEventName.Message, { taskId: task.taskId, ...message })

				if (message.message.partial !== true) {
					await this.fileLog(`[${new Date().toISOString()}] ${JSON.stringify(message.message, null, 2)}\n`)
				}
			})

			task.on(NJUST_AI_CJEventName.TaskModeSwitched, (taskId, mode) => {
				this.emit(NJUST_AI_CJEventName.TaskModeSwitched, taskId, mode)
			})

			task.on(NJUST_AI_CJEventName.TaskAskResponded, () => {
				this.emit(NJUST_AI_CJEventName.TaskAskResponded, task.taskId)
			})

			task.on(NJUST_AI_CJEventName.QueuedMessagesUpdated, (taskId, messages) => {
				this.emit(NJUST_AI_CJEventName.QueuedMessagesUpdated, taskId, messages)
			})

			// Task Analytics

			task.on(NJUST_AI_CJEventName.TaskToolFailed, (taskId, tool, error) => {
				this.emit(NJUST_AI_CJEventName.TaskToolFailed, taskId, tool, error)
			})

			task.on(NJUST_AI_CJEventName.TaskTokenUsageUpdated, (_, tokenUsage, toolUsage) => {
				this.emit(NJUST_AI_CJEventName.TaskTokenUsageUpdated, task.taskId, tokenUsage, toolUsage)
			})

			// Let's go!

			this.emit(NJUST_AI_CJEventName.TaskCreated, task.taskId)
		})
	}

	// Logging

	private outputChannelLog(...args: unknown[]) {
		for (const arg of args) {
			if (arg === null) {
				this.outputChannel.appendLine("null")
			} else if (arg === undefined) {
				this.outputChannel.appendLine("undefined")
			} else if (typeof arg === "string") {
				this.outputChannel.appendLine(arg)
			} else if (arg instanceof Error) {
				this.outputChannel.appendLine(`Error: ${arg.message}\n${arg.stack || ""}`)
			} else {
				try {
					this.outputChannel.appendLine(
						JSON.stringify(
							arg,
							(key, value) => {
								if (typeof value === "bigint") return `BigInt(${value})`
								if (typeof value === "function") return `Function: ${value.name || "anonymous"}`
								if (typeof value === "symbol") return value.toString()
								return value
							},
							2,
						),
					)
				} catch {
					this.outputChannel.appendLine(`[Non-serializable object: ${Object.prototype.toString.call(arg)}]`)
				}
			}
		}
	}

	private async fileLog(message: string) {
		if (!this.logfile) {
			return
		}

		try {
			await fs.appendFile(this.logfile, message, "utf8")
		} catch (_) {
			this.logfile = undefined
		}
	}

	// Global Settings Management

	public getConfiguration(): NJUST_AI_CJSettings {
		return Object.fromEntries(
			Object.entries(this.sidebarProvider.getValues()).filter(([key]) => !isSecretStateKey(key)),
		)
	}

	public async setConfiguration(values: NJUST_AI_CJSettings) {
		await this.sidebarProvider.contextProxy.setValues(values)
		await this.sidebarProvider.providerSettingsManager.saveConfig(values.currentApiConfigName || "default", values)
		await this.sidebarProvider.postStateToWebview()
	}

	// Provider Profile Management

	public getProfiles(): string[] {
		return this.sidebarProvider.getProviderProfileEntries().map(({ name }) => name)
	}

	public getProfileEntry(name: string): ProviderSettingsEntry | undefined {
		return this.sidebarProvider.getProviderProfileEntry(name)
	}

	public async createProfile(name: string, profile?: ProviderSettings, activate: boolean = true) {
		const entry = this.getProfileEntry(name)

		if (entry) {
			throw new Error(`Profile with name "${name}" already exists`)
		}

		const id = await this.sidebarProvider.upsertProviderProfile(name, profile ?? {}, activate)

		if (!id) {
			throw new Error(`Failed to create profile with name "${name}"`)
		}

		return id
	}

	public async updateProfile(
		name: string,
		profile: ProviderSettings,
		activate: boolean = true,
	): Promise<string | undefined> {
		const entry = this.getProfileEntry(name)

		if (!entry) {
			throw new Error(`Profile with name "${name}" does not exist`)
		}

		const id = await this.sidebarProvider.upsertProviderProfile(name, profile, activate)

		if (!id) {
			throw new Error(`Failed to update profile with name "${name}"`)
		}

		return id
	}

	public async upsertProfile(
		name: string,
		profile: ProviderSettings,
		activate: boolean = true,
	): Promise<string | undefined> {
		const id = await this.sidebarProvider.upsertProviderProfile(name, profile, activate)

		if (!id) {
			throw new Error(`Failed to upsert profile with name "${name}"`)
		}

		return id
	}

	public async deleteProfile(name: string): Promise<void> {
		const entry = this.getProfileEntry(name)

		if (!entry) {
			throw new Error(`Profile with name "${name}" does not exist`)
		}

		await this.sidebarProvider.deleteProviderProfile(entry)
	}

	public getActiveProfile(): string | undefined {
		return this.getConfiguration().currentApiConfigName
	}

	public async setActiveProfile(name: string): Promise<string | undefined> {
		const entry = this.getProfileEntry(name)

		if (!entry) {
			throw new Error(`Profile with name "${name}" does not exist`)
		}

		await this.sidebarProvider.activateProviderProfile({ name })
		return this.getActiveProfile()
	}
}

