	it("should clear resetTimer when calling workspaceDidReset multiple times", async () => {
		expect(registeredTabChangeCallback).not.toBeNull()

		// Set initial workspace path
		;(getWorkspacePath as Mock).mockReturnValue("/test/workspace")

		// Create tracker instance to set initial prevWorkSpacePath
		workspaceTracker = new WorkspaceTracker(mockProvider)

		// Change workspace path to trigger update
		;(getWorkspacePath as Mock).mockReturnValue("/test/new-workspace")

		// Call workspaceDidReset through tab change event
		await registeredTabChangeCallback!()

		// Call again before timer completes
		await registeredTabChangeCallback!()

		// Advance timer
		vitest.advanceTimersByTime(300)

		// Should only have one call to postMessageToWebview
		expect(mockProvider.postMessageToWebview).toHaveBeenCalledWith({
			type: "workspaceUpdated",
			filePaths: [],
			openedTabs: [],
		})
		expect(mockProvider.postMessageToWebview).toHaveBeenCalledTimes(1)
	})

	it("should handle dispose with active resetTimer", async () => {
		expect(registeredTabChangeCallback).not.toBeNull()

		// Mock workspace path change to trigger resetTimer
		;(getWorkspacePath as Mock).mockReturnValueOnce("/test/workspace").mockReturnValueOnce("/test/new-workspace")

		// Trigger resetTimer
		await registeredTabChangeCallback!()

		// Dispose before timer completes
		workspaceTracker.dispose()

		// Advance timer
		vitest.advanceTimersByTime(300)

		// Should have called dispose on all disposables
		expect(mockDispose).toHaveBeenCalled()

		// No postMessage should be called after dispose
		expect(mockProvider.postMessageToWebview).not.toHaveBeenCalled()
	})
})

import * as vscode from "vscode"
import * as path from "path"
import * as fs from "fs"
import { detectCangjieHome } from "./cangjieToolUtils"
import type { CangjieCompileGuard } from "./CangjieCompileGuard"
import { Package } from "../../shared/package"
import { getErrorMessage } from "../../shared/error-utils"

/**
 * Provides a DebugAdapterDescriptor for the "cangjie" debug type.
 * Looks for the CJDB debugger executable in the Cangjie SDK.
 * Supports hot-reload: when a .cj file is saved during a debug session,
 * the changed module is recompiled and (if cjdb supports it) hot-swapped.
 */
const HOT_RELOAD_DAP_TIMEOUT_MS = 2000

function substituteWorkspaceFolder(program: string, workspaceRoot?: string): string {
	if (!workspaceRoot) return program
	return program.replace(/\$\{workspaceFolder\}/gi, workspaceRoot)
}

/**
 * Find a runnable under target/ when the default `target/output` is missing.
 */
function findCangjieExecutableInTarget(workspaceRoot: string): string | undefined {
	const targetDir = path.join(workspaceRoot, "target")
	if (!fs.existsSync(targetDir) || !fs.statSync(targetDir).isDirectory()) {
		return undefined
	}

	const preferred = process.platform === "win32"
		? [path.join(targetDir, "output.exe"), path.join(targetDir, "output")]
		: [path.join(targetDir, "output")]
	for (const p of preferred) {
		try {
			if (fs.existsSync(p) && fs.statSync(p).isFile()) return p
		} catch {
			/* ignore */
		}
	}

	const maxDepth = 3
	const walk = (dir: string, depth: number): string | undefined => {
		if (depth > maxDepth) return undefined
		let entries: fs.Dirent[]
		try {
			entries = fs.readdirSync(dir, { withFileTypes: true })
		} catch {
			return undefined
		}
		for (const e of entries) {
			if (e.name.startsWith(".") || e.name === "deps" || e.name === "incremental") continue
			const full = path.join(dir, e.name)
			if (e.isDirectory()) {
				const hit = walk(full, depth + 1)
				if (hit) return hit
			} else if (e.isFile()) {
				if (process.platform === "win32") {
					if (e.name.endsWith(".exe")) return full
				} else if (e.name === "output" || !e.name.includes(".")) {
					// Check executable permission on Unix to avoid returning data files.
					try {
						const s = fs.statSync(full, { throwIfNoEntry: true } as any)
						if ((s.mode & 0o111) === 0) continue
					} catch { continue }
					return full
				}
			}
		}
		return undefined
	}

	return walk(targetDir, 0)
}

export class CangjieDebugAdapterFactory implements vscode.DebugAdapterDescriptorFactory, vscode.Disposable {
	private disposables: vscode.Disposable[] = []
	private activeSession: vscode.DebugSession | undefined
	private hotReloadWatcher: vscode.Disposable | undefined
	private compileGuard: CangjieCompileGuard | undefined

	constructor(
		compileGuard?: CangjieCompileGuard,
		private readonly logChannel?: vscode.OutputChannel,
	) {
		this.compileGuard = compileGuard
	}

	/** Called when CangjieCompileGuard is created lazily (after first .cj activation). */
	setCompileGuard(guard: CangjieCompileGuard | undefined): void {
		this.compileGuard = guard
	}

	createDebugAdapterDescriptor(
		session: vscode.DebugSession,
		_executable: vscode.DebugAdapterExecutable | undefined,
	): vscode.ProviderResult<vscode.DebugAdapterDescriptor> {
		const cangjieHome = detectCangjieHome()
		if (!cangjieHome) {
			vscode.window.showErrorMessage("未找到 CANGJIE_HOME。请配置仓颉 SDK 路径以使用调试功能。")
			return undefined
		}

		const debuggerPath = this.resolveDebuggerPath(cangjieHome)
		if (!debuggerPath) {
			vscode.window.showErrorMessage(
				`未在 SDK 中找到调试器。请确认仓颉 SDK 包含 cjdb 工具。(CANGJIE_HOME=${cangjieHome})`,
			)
			return undefined
		}

		this.activeSession = session
		this.startHotReloadWatcher(session)

		const args = (session.configuration.debuggerArgs as string[] || []).filter((a) => typeof a === "string" && /^--[a-zA-Z][a-zA-Z0-9._-]*(?:[=:].+)?$/.test(a))
		return new vscode.DebugAdapterExecutable(debuggerPath, ["--dap", ...args])
	}

	/**
	 * Watch for .cj file saves during debug and trigger incremental recompile.
	 * If the debug adapter supports hot-swap, the updated module is swapped in.
	 */
	private startHotReloadWatcher(session: vscode.DebugSession): void {
		this.stopHotReloadWatcher()

		const hotReloadEnabled = vscode.workspace
			.getConfiguration(Package.name)
			.get<boolean>("cangjieTools.hotReload", false)

		if (!hotReloadEnabled || !this.compileGuard) return

		this.hotReloadWatcher = vscode.workspace.onDidSaveTextDocument(async (doc) => {
			if (doc.languageId !== "cangjie" && !doc.fileName.endsWith(".cj")) return
			if (!this.activeSession) return

			const folder = vscode.workspace.getWorkspaceFolder(doc.uri)
			if (!folder) return

			const cwd = folder.uri.fsPath
			const cjpmToml = path.join(cwd, "cjpm.toml")
			if (!fs.existsSync(cjpmToml)) return

			const result = await this.compileGuard!.compile(cwd)
			if (result.success) {
				try {
					await Promise.race([
						session.customRequest("hotReload", {
							file: doc.fileName,
						}),
						new Promise<never>((_, reject) =>
							setTimeout(() => reject(new Error("hotReload timeout")), HOT_RELOAD_DAP_TIMEOUT_MS),
						),
					])
				} catch (e) {
					const msg = getErrorMessage(e)
					this.logChannel?.appendLine(`[Cangjie DAP] hotReload skipped or timed out: ${msg}`)
				}
			}
		})

		// Clean up when the session ends
		const sessionEnd = vscode.debug.onDidTerminateDebugSession((s) => {
			if (s === session) {
				this.stopHotReloadWatcher()
				this.activeSession = undefined
				sessionEnd.dispose()
			}
		})
		this.disposables.push(sessionEnd)
	}

	private stopHotReloadWatcher(): void {
		this.hotReloadWatcher?.dispose()
		this.hotReloadWatcher = undefined
	}

	private resolveDebuggerPath(cangjieHome: string): string | undefined {
		const exeName = process.platform === "win32" ? "cjdb.exe" : "cjdb"
		const candidates = [
			path.join(cangjieHome, "tools", "bin", exeName),
			path.join(cangjieHome, "bin", exeName),
		]
		return candidates.find((p) => fs.existsSync(p))
	}

	dispose(): void {
		this.stopHotReloadWatcher()
		this.disposables.forEach((d) => d.dispose())
	}
}

/**
 * Provides initial launch.json configurations for the "cangjie" debug type.
 */
export class CangjieDebugConfigurationProvider implements vscode.DebugConfigurationProvider {
	resolveDebugConfiguration(
		folder: vscode.WorkspaceFolder | undefined,
		config: vscode.DebugConfiguration,
		_token?: vscode.CancellationToken,
	): vscode.ProviderResult<vscode.DebugConfiguration> {
		if (!config.type && !config.request && !config.name) {
			const editor = vscode.window.activeTextEditor
			if (editor && editor.document.languageId === "cangjie") {
				config.type = "cangjie"
				config.name = "调试仓颉程序"
				config.request = "launch"
				config.program = "${workspaceFolder}/target/output"
				config.cwd = "${workspaceFolder}"
				config.preLaunchTask = "cjpm: build"
			}
		}

		if (!config.program) {
			return vscode.window.showInformationMessage("请在 launch.json 中配置 program 路径").then(
				() => undefined,
			)
		}

		const ws = folder?.uri.fsPath
		const programStr = String(config.program)
		const resolvedOnDisk = ws ? substituteWorkspaceFolder(programStr, ws) : programStr

		if (ws && !fs.existsSync(resolvedOnDisk)) {
			const found = findCangjieExecutableInTarget(ws)
			if (found) {
				const rel = path.relative(ws, found).replace(/\\/g, "/")
				config.program = "${workspaceFolder}/" + rel
			} else {
				return vscode.window
					.showWarningMessage(
						"未在 target/ 下找到可执行文件。可使用带调试信息的构建任务 cjpm: build (debug)，或先执行 cjpm build。",
						"使用 cjpm: build (debug)",
						"仍继续启动",
					)
					.then((choice) => {
						if (choice === undefined) return undefined
						if (choice === "使用 cjpm: build (debug)") {
							config.preLaunchTask = "cjpm: build (debug)"
						}
						config.cwd = config.cwd || folder?.uri.fsPath || "${workspaceFolder}"
						return config
					})
			}
		}

		config.cwd = config.cwd || folder?.uri.fsPath || "${workspaceFolder}"

		return config
	}

	provideDebugConfigurations(
		_folder: vscode.WorkspaceFolder | undefined,
		_token?: vscode.CancellationToken,
	): vscode.ProviderResult<vscode.DebugConfiguration[]> {
		return [
			{
				type: "cangjie",
				request: "launch",
				name: "调试仓颉程序",
				program: "${workspaceFolder}/target/output",
				args: [],
				cwd: "${workspaceFolder}",
				preLaunchTask: "cjpm: build",
			},
			{
				type: "cangjie",
				request: "launch",
				name: "调试仓颉测试",
				program: "${workspaceFolder}/target/output",
				args: ["--test"],
				cwd: "${workspaceFolder}",
				preLaunchTask: "cjpm: build",
			},
		]
	}
}

import * as vscode from "vscode"
import * as path from "path"
import * as fs from "fs"
import * as os from "os"
import { execFile } from "child_process"
import { promisify } from "util"
import { resolveCangjieToolPath, buildCangjieToolEnv, CJC_CONFIG_KEY } from "./cangjieToolUtils"
import type { CangjieSymbolIndex } from "./CangjieSymbolIndex"
import { logger } from "../../shared/logger"
import { getErrorMessage } from "../../shared/error-utils"

const execFileAsync = promisify(execFile)

async function formatExpandedCangjieWithCjfmt(expanded: string, outputChannel: vscode.OutputChannel): Promise<string> {
	const cjfmtPath = resolveCangjieToolPath("cjfmt", "cangjieTools.cjfmtPath")
	if (!cjfmtPath) return expanded

	const id = `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`
	const tmpIn = path.join(os.tmpdir(), `cjc_expand_${id}.cj`)
	const tmpOut = path.join(os.tmpdir(), `cjc_expand_${id}_out.cj`)
	try {
		fs.writeFileSync(tmpIn, expanded, "utf-8")
		await execFileAsync(cjfmtPath, ["-f", tmpIn, "-o", tmpOut], {
			timeout: 15_000,
			env: buildCangjieToolEnv() as NodeJS.ProcessEnv,
		})
		if (fs.existsSync(tmpOut)) {
			return fs.readFileSync(tmpOut, "utf-8")
		}
	} catch (e) {
		const msg = getErrorMessage(e)
		outputChannel.appendLine(`[MacroExpand] cjfmt skipped: ${msg}`)
	} finally {
		try {
			fs.unlinkSync(tmpIn)
		} catch {
			/* ignore */
		}
		try {
			fs.unlinkSync(tmpOut)
		} catch {
			/* ignore */
		}
	}
	return expanded
}

const MACRO_CALL_RE = /@(\w+)(?=\s*\(|\s+\w|$)/g
const _MACRO_DEF_RE = /^\s*(?:public\s+|private\s+|protected\s+|internal\s+)*macro\s+(\w+)/

/**
 * CodeLens provider that shows "Expand Macro" / "Go to Macro Definition"
 * above lines containing macro invocations (@MacroName).
 */
export class CangjieMacroCodeLensProvider implements vscode.CodeLensProvider {
	constructor(private readonly index: CangjieSymbolIndex) {}

	provideCodeLenses(document: vscode.TextDocument, _token: vscode.CancellationToken): vscode.CodeLens[] {
		const lenses: vscode.CodeLens[] = []

		for (let i = 0; i < document.lineCount; i++) {
			const lineText = document.lineAt(i).text
			MACRO_CALL_RE.lastIndex = 0
			let match: RegExpExecArray | null

			while ((match = MACRO_CALL_RE.exec(lineText)) !== null) {
				const macroName = match[1]
				if (this.isBuiltinAnnotation(macroName)) continue

				const range = new vscode.Range(i, 0, i, 0)

				const macroDefs = this.index.findDefinitionsByKind(macroName, "macro")
				if (macroDefs.length > 0) {
					lenses.push(new vscode.CodeLens(range, {
						title: `$(symbol-event) 跳转到宏定义: ${macroName}`,
						command: "njust-ai-cj.cangjieGoToMacroDef",
						arguments: [macroDefs[0].filePath, macroDefs[0].startLine],
					}))
				}

				lenses.push(new vscode.CodeLens(range, {
					title: `$(unfold) 展开宏: @${macroName}`,
					command: "njust-ai-cj.cangjieExpandMacro",
					arguments: [document.uri, i],
				}))
			}
		}

		return lenses
	}

	private isBuiltinAnnotation(name: string): boolean {
		return ["Test", "TestCase", "Assert", "Deprecated", "Suppress", "Override"].includes(name)
	}
}

/**
 * Hover provider that shows macro expansion preview when hovering over @MacroName.
 */
export class CangjieMacroHoverProvider implements vscode.HoverProvider {
	constructor(private readonly index: CangjieSymbolIndex) {}

	provideHover(
		document: vscode.TextDocument,
		position: vscode.Position,
		_token: vscode.CancellationToken,
	): vscode.Hover | undefined {
		const lineText = document.lineAt(position.line).text
		MACRO_CALL_RE.lastIndex = 0
		let match: RegExpExecArray | null

		while ((match = MACRO_CALL_RE.exec(lineText)) !== null) {
			const macroName = match[1]
			const atIndex = match.index + (match[0].length - macroName.length - 1)
			const nameStart = atIndex + 1

			if (position.character >= atIndex && position.character <= nameStart + macroName.length) {
				const defs = this.index.findDefinitionsByKind(macroName, "macro")

				const md = new vscode.MarkdownString()
				md.appendMarkdown(`**宏调用:** \`@${macroName}\`\n\n`)

				if (defs.length > 0) {
					const def = defs[0]
					md.appendMarkdown(`**定义位置:** ${path.basename(def.filePath)}:${def.startLine + 1}\n\n`)
					md.appendCodeblock(def.signature, "cangjie")
				} else {
					md.appendMarkdown(`*未在本地索引中找到宏定义（可能来自标准库或外部包）*`)
				}

				return new vscode.Hover(md, new vscode.Range(
					position.line, atIndex,
					position.line, nameStart + macroName.length,
				))
			}
		}

		return undefined
	}
}

/**
 * Register commands for macro expansion and navigation.
 */
export function registerMacroCommands(context: vscode.ExtensionContext, outputChannel: vscode.OutputChannel): void {
	context.subscriptions.push(
		vscode.commands.registerCommand(
			"njust-ai-cj.cangjieGoToMacroDef",
			async (filePath: string, startLine: number) => {
				const uri = vscode.Uri.file(filePath)
				const doc = await vscode.workspace.openTextDocument(uri)
				const editor = await vscode.window.showTextDocument(doc)
				const pos = new vscode.Position(startLine, 0)
				editor.selection = new vscode.Selection(pos, pos)
				editor.revealRange(new vscode.Range(pos, pos), vscode.TextEditorRevealType.InCenter)
			},
		),
	)

	context.subscriptions.push(
		vscode.commands.registerCommand(
			"njust-ai-cj.cangjieExpandMacro",
			async (uri: vscode.Uri, _line: number) => {
				const cjcPath = resolveCangjieToolPath("cjc", CJC_CONFIG_KEY)
				if (!cjcPath) {
					vscode.window.showWarningMessage("未找到 cjc 编译器，无法展开宏。")
					return
				}

				const filePath = uri.fsPath
				if (!fs.existsSync(filePath)) return

				try {
					const { stdout, stderr } = await execFileAsync(
						cjcPath,
						["--expand-macros", "--dump-to-screen", filePath],
						{ timeout: 15_000, env: buildCangjieToolEnv() as NodeJS.ProcessEnv },
					)

					let expanded = stdout
					if (stderr && stderr.trim()) {
						logger.warn("CangjieMacro", `cjc stderr:\n${stderr}`)
					}
					if (!expanded || expanded.trim().length === 0) {
						vscode.window.showInformationMessage("宏展开未产生输出（可能 cjc 不支持 --expand-macros 标志）。")
						return
					}

					expanded = await formatExpandedCangjieWithCjfmt(expanded, outputChannel)

					const doc = await vscode.workspace.openTextDocument({
						content: expanded,
						language: "cangjie",
					})
					await vscode.window.showTextDocument(doc, { preview: true, viewColumn: vscode.ViewColumn.Beside })
				} catch (err) {
					const msg = getErrorMessage(err)
					outputChannel.appendLine(`[MacroExpand] Error: ${msg}`)

					if (msg.includes("--expand-macros")) {
						vscode.window.showWarningMessage(
							"当前版本的 cjc 不支持 --expand-macros 参数。宏展开功能需要更高版本的仓颉 SDK。",
						)
					} else {
						vscode.window.showWarningMessage(`宏展开失败: ${msg}`)
					}
				}
			},
		),
	)
}

import * as vscode from "vscode"
import * as path from "path"
import * as fs from "fs"
import { execFile } from "child_process"
import { promisify } from "util"
import { Package } from "../../shared/package"
import { logger } from "../../shared/logger"
import { getErrorMessage } from "../../shared/error-utils"

const execFileAsync = promisify(execFile)

/** Relative key under `Package.name` for the Cangjie compiler path (shared by runCode, macro expand, status bar). */
export const CJC_CONFIG_KEY = "cangjieLsp.cjcPath"

let homeDetectCache: string | undefined | null = null
let envBuildCache: { key: string; env: Record<string, string> } | null = null

/** Call when workspace settings that affect SDK paths may have changed. */
export function invalidateCangjieToolEnvCache(): void {
	homeDetectCache = null
	envBuildCache = null
}

/**
 * Detect CANGJIE_HOME from environment or well-known install locations.
 */
export function detectCangjieHome(): string | undefined {
	if (homeDetectCache !== null) return homeDetectCache

	// 1. Environment variable
	if (process.env.CANGJIE_HOME && fs.existsSync(process.env.CANGJIE_HOME)) {
		homeDetectCache = process.env.CANGJIE_HOME
		return homeDetectCache
	}

	// 2. Infer from VS Code LSP serverPath config (aligns with CangjieLspClient)
	try {
		const vscodeModule = require("vscode") as any
		const serverPath = vscodeModule.workspace
			.getConfiguration("njust-ai-cj.cangjieLsp")
			.get("serverPath")
		if (serverPath && fs.existsSync(serverPath)) {
			const sdkRoot = path.resolve(serverPath, "..", "..")
			if (fs.existsSync(path.join(sdkRoot, "bin"))) {
				homeDetectCache = sdkRoot
				return homeDetectCache
			}
		}
	} catch { /* vscode not available (tests) */ }

	const wellKnownPaths = process.platform === "win32"
		? ["D:\\cangjie", "C:\\cangjie", path.join(process.env.LOCALAPPDATA || "", "cangjie")]
		: ["/usr/local/cangjie", path.join(process.env.HOME || "", ".cangjie")]

	for (const p of wellKnownPaths) {
		if (p && fs.existsSync(path.join(p, "bin"))) {
			homeDetectCache = p
			return homeDetectCache
		}
	}

	homeDetectCache = undefined
	return undefined
}

/**
 * Build environment variables for running Cangjie SDK tools.
 * Ensures runtime libraries are on PATH / LD_LIBRARY_PATH.
 */
export function buildCangjieToolEnv(cangjieHome?: string): Record<string, string> {
	const home = cangjieHome ?? detectCangjieHome()
	const cacheKey = `${home ?? "__nohome__"}|${process.platform}`
	if (envBuildCache && envBuildCache.key === cacheKey) {
		return { ...envBuildCache.env }
	}

	if (!home) {
		const env = { ...process.env } as Record<string, string>
		envBuildCache = { key: cacheKey, env }
		return env
	}

	const env = { ...process.env } as Record<string, string>
	env["CANGJIE_HOME"] = home

	const sep = process.platform === "win32" ? ";" : ":"
	const extraPaths: string[] = []

	if (process.platform === "win32") {
		extraPaths.push(path.join(home, "runtime", "lib", "windows_x86_64_llvm"))
		extraPaths.push(path.join(home, "lib", "windows_x86_64_llvm"))
	} else {
		extraPaths.push(path.join(home, "runtime", "lib", "linux_x86_64_llvm"))
		extraPaths.push(path.join(home, "lib", "linux_x86_64_llvm"))
	}
	extraPaths.push(path.join(home, "bin"))
	extraPaths.push(path.join(home, "tools", "bin"))
	extraPaths.push(path.join(home, "tools", "lib"))

	const existing = env["PATH"] || env["Path"] || ""
	const pathKey = process.platform === "win32" ? "Path" : "PATH"
	env[pathKey] = extraPaths.filter((p) => fs.existsSync(p)).join(sep) + sep + existing

	if (process.platform !== "win32") {
		const ldPaths = extraPaths.filter((p) => fs.existsSync(p))
		const existingLd = env["LD_LIBRARY_PATH"] || ""
		if (ldPaths.length > 0) {
			env["LD_LIBRARY_PATH"] = ldPaths.join(sep) + (existingLd ? sep + existingLd : "")
		}
	}

	envBuildCache = { key: cacheKey, env }
	return { ...env }
}

/**
 * Resolve a Cangjie SDK tool executable by checking:
 * 1. User-configured path in settings
 * 2. CANGJIE_HOME environment variable
 * 3. Well-known install locations
 * 4. System PATH (fallback)
 */
export function resolveCangjieToolPath(
	toolName: string,
	configKey?: string,
): string | undefined {
	if (configKey) {
		const configured = vscode.workspace
			.getConfiguration(Package.name)
			.get<string>(configKey, "")
		if (configured) {
			const resolved = path.resolve(configured)
			if (fs.existsSync(resolved)) return resolved
			return undefined
		}
	}

	const exeName = process.platform === "win32" ? `${toolName}.exe` : toolName

	const cangjieHome = detectCangjieHome()
	if (cangjieHome) {
		const candidates = [
			path.join(cangjieHome, "bin", exeName),
			path.join(cangjieHome, "tools", "bin", exeName),
		]
		for (const c of candidates) {
			if (fs.existsSync(c)) return c
		}
	}

	logger.warn("CangjieToolUtils",
		`Cannot locate ${toolName}: no configured path, ` +
		`CANGJIE_HOME not set, and not found in well-known install locations. ` +
		`Falling back to bare "${exeName}" — commands may fail with ENOENT.`,
	)
	return exeName
}

export type CangjieToolkitId = "cjc" | "cjpm" | "cjfmt" | "cjlint"

/** cjfmt / cjc / cjpm 各发行版 CLI 略有差异；探测时依次尝试。 */
function probeTryArgsForTool(id: CangjieToolkitId): string[][] {
	if (id === "cjlint") {
		return [["--version"], ["-V"], ["--help"]]
	}
	if (id === "cjfmt") {
		// 多数 Cangjie SDK 中 cjfmt 不支持 `--version`，会误解析为 `--`；优先 -V / -h
		return [["-V"], ["-h"], ["--help"], ["--version"]]
	}
	return [["--version"]]
}

/**
 * 当 resolve 回落为裸可执行名时，再按 CANGJIE_HOME 拼绝对路径，避免 Windows 下 PATH/spawn 未命中。
 */
function absolutizeSdkToolIfBare(id: CangjieToolkitId, invokedPath: string): string {
	const hasSep = invokedPath.includes(path.sep) || invokedPath.includes("/") || invokedPath.includes("\\")
	if (path.isAbsolute(invokedPath) || hasSep) {
		return invokedPath
	}
	const home = detectCangjieHome()
	if (!home) return invokedPath
	const exe = process.platform === "win32" ? `${id}.exe` : id
	for (const rel of ["bin", path.join("tools", "bin")]) {
		const candidate = path.join(home, rel, exe)
		if (fs.existsSync(candidate)) return candidate
	}
	return invokedPath
}

export interface CangjieToolProbeResult {
	id: CangjieToolkitId
	label: string
	configKey?: string
	invokedPath: string
	ok: boolean
	versionLine?: string
	hint?: string
}

/**
 * Run version/help probes on each tool; used by **Cangjie: Verify SDK Installation**.
 */
export async function probeCangjieToolchain(): Promise<CangjieToolProbeResult[]> {
	const defs: Array<{ id: CangjieToolkitId; configKey?: string }> = [
		{ id: "cjc", configKey: CJC_CONFIG_KEY },
		{ id: "cjpm", configKey: "cangjieTools.cjpmPath" },
		{ id: "cjfmt", configKey: "cangjieTools.cjfmtPath" },
		{ id: "cjlint", configKey: "cangjieTools.cjlintPath" },
	]
	const env = buildCangjieToolEnv() as NodeJS.ProcessEnv
	const out: CangjieToolProbeResult[] = []

	for (const { id, configKey } of defs) {
		const resolved = resolveCangjieToolPath(id, configKey)
		const configured = configKey
			? vscode.workspace.getConfiguration(Package.name).get<string>(configKey, "")
			: ""
		const looksConfigured = Boolean(configKey && configured.length > 0)

		if (looksConfigured && resolved === undefined) {
			out.push({
				id,
				label: id,
				configKey,
				invokedPath: path.resolve(configured),
				ok: false,
				hint: `已启用 ${configKey}，但文件不存在`,
			})
			continue
		}

		let invokedPath = resolved ?? (process.platform === "win32" ? `${id}.exe` : id)
		invokedPath = absolutizeSdkToolIfBare(id, invokedPath)
		const isConcretePath =
			path.isAbsolute(invokedPath) ||
			invokedPath.includes(path.sep) ||
			invokedPath.includes("/") ||
			invokedPath.includes("\\")

		if (looksConfigured && isConcretePath && !fs.existsSync(invokedPath)) {
			out.push({
				id,
				label: id,
				configKey,
				invokedPath,
				ok: false,
				hint: `已启用 ${configKey}，但文件不存在`,
			})
			continue
		}

		try {
			const tryArgs = probeTryArgsForTool(id)
			let stdout = ""
			let lastErr: unknown
			for (const args of tryArgs) {
				try {
					const r = await execFileAsync(invokedPath, args, { timeout: 12_000, env })
					stdout = [r.stdout, r.stderr].filter((s) => s && String(s).trim()).join("\n")
					lastErr = undefined
					break
				} catch (e) {
					lastErr = e
				}
			}
			if (lastErr !== undefined) throw lastErr
			const versionLine = stdout.trim().split("\n").filter((l) => l.trim())[0] ?? ""
			out.push({
				id,
				label: id,
				configKey,
				invokedPath,
				ok: true,
				versionLine: versionLine || "(no output)",
			})
		} catch (e) {
			const msg = getErrorMessage(e)
			out.push({
				id,
				label: id,
				configKey,
				invokedPath,
				ok: false,
				hint: msg.slice(0, 200),
			})
		}
	}

	return out
}

export function formatCangjieToolchainReport(probes: CangjieToolProbeResult[]): string {
	const lines = ["=== Cangjie 工具链诊断 ===", `CANGJIE_HOME: ${detectCangjieHome() ?? "(未检测到)"}`, ""]
	for (const p of probes) {
		const cfg = p.configKey ? ` [${p.configKey}]` : ""
		if (p.ok) {
			lines.push(`✓ ${p.label}${cfg}: ${p.versionLine} (${p.invokedPath})`)
		} else {
			lines.push(`✗ ${p.label}${cfg}: ${p.hint ?? "不可用"} (${p.invokedPath})`)
		}
	}
	return lines.join("\n")
}

/** Short checklist for onboarding toast after SDK path is set. */
export async function formatCangjieToolchainSummaryLine(): Promise<string | undefined> {
	const probes = await probeCangjieToolchain()
	const parts = probes.map((p) => `${p.label}${p.ok ? "✓" : "✗"}`).join(" ")
	const allOk = probes.every((p) => p.ok)
	if (!allOk) {
		const missing = probes.filter((p) => !p.ok).map((p) => p.label)
		return `Cangjie 工具链: ${parts}\n缺失: ${missing.join(", ")} — 可在命令面板运行「Cangjie: Verify SDK Installation」`
	}
	const ver = probes.find((p) => p.id === "cjc")?.versionLine
	return ver ? `Cangjie SDK 已就绪: ${ver} (${parts})` : `Cangjie SDK 已就绪 (${parts})`
}

