// ApiHandlerOptions
// Extend ProviderSettings (minus apiProvider) with handler-specific toggles.
export type ApiHandlerOptions = Omit<ProviderSettings, "apiProvider"> & {
	/** Injected by {@link createHandler} in api/index (native tool-call parsing). */
	toolCallParser?: import("../api/interfaces/IToolCallParser").IToolCallParser
	/**
	 * When true and using OpenAI Responses API models that support reasoning summaries,
	 * include reasoning.summary: "auto" so the API returns summaries (we already parse
	 * and surface them). Defaults to true; set to false to disable summaries.
	 */
	enableResponsesReasoningSummary?: boolean
	/**
	 * Optional override for Ollama's num_ctx parameter.
	 * When set, this value will be used in Ollama chat requests.
	 * When undefined, Ollama will use the model's default num_ctx from the Modelfile.
	 */
	ollamaNumCtx?: number
}

// RouterName

export type RouterName = DynamicProvider | LocalProvider

export const isRouterName = (value: string): value is RouterName => isDynamicProvider(value) || isLocalProvider(value)

export function toRouterName(value?: string): RouterName {
	if (value && isRouterName(value)) {
		return value
	}

	throw new Error(`Invalid router name: ${value}`)
}

// Reasoning

export const shouldUseReasoningBudget = ({
	model,
	settings,
}: {
	model: ModelInfo
	settings?: ProviderSettings
}): boolean => !!model.requiredReasoningBudget || (!!model.supportsReasoningBudget && !!settings?.enableReasoningEffort)

export const shouldUseReasoningEffort = ({
	model,
	settings,
}: {
	model: ModelInfo
	settings?: ProviderSettings
}): boolean => {
	// Explicit off switch
	if (settings?.enableReasoningEffort === false) return false

	// Selected effort from settings or model default
	const selectedEffort = (settings?.reasoningEffort ?? (model as any).reasoningEffort) as
		| "disable"
		| "none"
		| "minimal"
		| "low"
		| "medium"
		| "high"
		| undefined

	// "disable" explicitly omits reasoning
	if (selectedEffort === "disable") return false

	const cap = model.supportsReasoningEffort as unknown

	// Capability array: use only if selected is included (treat "none"/"minimal" as valid)
	if (Array.isArray(cap)) {
		return !!selectedEffort && (cap as ReadonlyArray<string>).includes(selectedEffort as string)
	}

	// Boolean capability: true → require a selected effort
	if (model.supportsReasoningEffort === true) {
		return !!selectedEffort
	}

	// Not explicitly supported: only allow when the model itself defines a default effort
	// Ignore settings-only selections when capability is absent/false
	const modelDefaultEffort = (model as any).reasoningEffort as
		| "none"
		| "minimal"
		| "low"
		| "medium"
		| "high"
		| undefined
	return !!modelDefaultEffort
}

export const DEFAULT_HYBRID_REASONING_MODEL_MAX_TOKENS = 16_384
export const DEFAULT_HYBRID_REASONING_MODEL_THINKING_TOKENS = 8_192
export const GEMINI_25_PRO_MIN_THINKING_TOKENS = 128

// Max Tokens

export const getModelMaxOutputTokens = ({
	modelId,
	model,
	settings,
	format,
}: {
	modelId: string
	model: ModelInfo
	settings?: ProviderSettings
	format?: "anthropic" | "openai" | "gemini" | "openrouter"
}): number | undefined => {
	if (shouldUseReasoningBudget({ model, settings })) {
		return settings?.modelMaxTokens || DEFAULT_HYBRID_REASONING_MODEL_MAX_TOKENS
	}

	const isAnthropicContext =
		modelId.includes("claude") ||
		format === "anthropic" ||
		(format === "openrouter" && modelId.startsWith("anthropic/"))

	// For "Hybrid" reasoning models, discard the model's actual maxTokens for Anthropic contexts
	if (model.supportsReasoningBudget && isAnthropicContext) {
		return ANTHROPIC_DEFAULT_MAX_TOKENS
	}

	// For Anthropic contexts, always ensure a maxTokens value is set
	if (isAnthropicContext && (!model.maxTokens || model.maxTokens === 0)) {
		return ANTHROPIC_DEFAULT_MAX_TOKENS
	}

	// If model has explicit maxTokens, clamp it to 20% of the context window
	// Exception: GPT-5 models should use their exact configured max output tokens
	if (model.maxTokens) {
		// Check if this is a GPT-5 model (case-insensitive)
		const isGpt5Model = modelId.toLowerCase().includes("gpt-5")

		// GPT-5 models bypass the 20% cap and use their full configured max tokens
		if (isGpt5Model) {
			return model.maxTokens
		}

		// All other models are clamped to 20% of context window
		return Math.min(model.maxTokens, Math.ceil(model.contextWindow * 0.2))
	}

	// For non-Anthropic formats without explicit maxTokens, return undefined
	if (format) {
		return undefined
	}

	// Default fallback
	return ANTHROPIC_DEFAULT_MAX_TOKENS
}

// GetModelsOptions

// Allow callers to always pass apiKey/baseUrl without excess property errors,
// while still enforcing required fields per provider where applicable.
type CommonFetchParams = {
	apiKey?: string
	baseUrl?: string
}

// Exhaustive, value-level map for all dynamic providers.
// If a new dynamic provider is added in packages/types, this will fail to compile
// until a corresponding entry is added here.
const _dynamicProviderExtras = {
	openrouter: {} as {}, // eslint-disable-line @typescript-eslint/no-empty-object-type
	"vercel-ai-gateway": {} as {}, // eslint-disable-line @typescript-eslint/no-empty-object-type
	litellm: {} as { apiKey: string; baseUrl: string },
	requesty: {} as { apiKey?: string; baseUrl?: string },
	unbound: {} as { apiKey?: string },
	ollama: {} as {}, // eslint-disable-line @typescript-eslint/no-empty-object-type
	lmstudio: {} as {}, // eslint-disable-line @typescript-eslint/no-empty-object-type
	roo: {} as { apiKey?: string; baseUrl?: string },
} as const satisfies Record<RouterName, object>

// Build the dynamic options union from the map, intersected with CommonFetchParams
// so extra fields are always allowed while required ones are enforced.
export type GetModelsOptions = {
	[P in keyof typeof _dynamicProviderExtras]: ({ provider: P } & (typeof _dynamicProviderExtras)[P]) & CommonFetchParams
}[RouterName]

import { SECRET_STATE_KEYS, GLOBAL_SECRET_KEYS, ProviderSettings } from "@njust-ai-cj/types"

export function checkExistKey(config: ProviderSettings | undefined) {
	if (!config) {
		return false
	}

	// Special case for fake-ai, openai-codex, qwen-code, and roo providers which don't need any configuration.
	if (config.apiProvider && ["fake-ai", "openai-codex", "qwen-code", "roo"].includes(config.apiProvider)) {
		return true
	}

	// Check all secret keys from the centralized SECRET_STATE_KEYS array.
	// Filter out keys that are not part of ProviderSettings (global secrets are stored separately)
	const providerSecretKeys = SECRET_STATE_KEYS.filter((key) => !GLOBAL_SECRET_KEYS.includes(key as any))
	const hasSecretKey = providerSecretKeys.some((key) => config[key as keyof ProviderSettings] !== undefined)

	// Check additional non-secret configuration properties
	const hasOtherConfig = [
		config.awsRegion,
		config.vertexProjectId,
		config.ollamaModelId,
		config.lmStudioModelId,
		config.vsCodeLmModelSelector,
	].some((value) => value !== undefined)

	return hasSecretKey || hasOtherConfig
}

import { logger } from "./logger"
import type { ModelInfo } from "@njust-ai-cj/types"
import type { ServiceTier } from "@njust-ai-cj/types"

/**
 * Normalize OpenAI-style usage numbers before billing.
 *
 * - `input_tokens` / `prompt_tokens` are usually **total** prompt tokens including cache reads/writes,
 *   but some responses only report the non-cached slice while still emitting `cache_read_input_tokens`.
 * - When `input_tokens_details` / `prompt_tokens_details` expose `cache_miss_tokens` + `cached_tokens`,
 *   we prefer that breakdown for the non-cached slice (avoids mis-pricing when totals are inconsistent).
 */
export function resolveOpenAiUsageForCost(args: {
	inputTokensReported: number
	cacheWriteTokens: number
	cacheReadTokens: number
	cacheMissTokensFromDetails?: number
	cachedTokensFromDetails?: number
}): {
	totalInputTokens: number
	cacheWriteTokens: number
	cacheReadTokens: number
	nonCachedInputTokens: number
} {
	const cw = Math.max(0, args.cacheWriteTokens || 0)
	let cr = Math.max(0, args.cacheReadTokens || 0)
	let total = Math.max(0, args.inputTokensReported || 0)

	const miss = args.cacheMissTokensFromDetails
	const cachedD = args.cachedTokensFromDetails

	if (typeof miss === "number" && typeof cachedD === "number") {
		cr = Math.max(cr, cachedD)
		const sumParts = miss + cachedD + cw
		if (sumParts > 0) {
			const tolerance = Math.max(1, Math.ceil(sumParts * 0.005))
			if (total === 0 || Math.abs(total - sumParts) <= tolerance) {
				total = sumParts
			} else if (total < sumParts - tolerance) {
				logger.warn("Cost", `Token mismatch beyond tolerance: reported=${total}, sumParts=${sumParts} (miss=${miss}, cached=${cachedD}, writes=${cw}), tolerance=${tolerance}`)
				// Total likely excludes cached portion; reconstruct billable prompt size
				total = sumParts
			}
		}
		return {
			totalInputTokens: total,
			cacheWriteTokens: cw,
			cacheReadTokens: cr,
			nonCachedInputTokens: Math.max(0, miss),
		}
	}

	// If prompt total is smaller than cache rows alone, input is almost certainly non-cached-only —
	// expand so base+discount math stays consistent with OpenAI billing.
	const minTotal = cw + cr
	if (total < minTotal) {
		total = minTotal
	}

	const nonCached = Math.max(0, total - cw - cr)
	return {
		totalInputTokens: total,
		cacheWriteTokens: cw,
		cacheReadTokens: cr,
		nonCachedInputTokens: nonCached,
	}
}

export interface ApiCostResult {
	totalInputTokens: number
	totalOutputTokens: number
	totalCost: number
}

function applyLongContextPricing(modelInfo: ModelInfo, totalInputTokens: number, serviceTier?: ServiceTier): ModelInfo {
	const pricing = modelInfo.longContextPricing
	if (!pricing || totalInputTokens <= pricing.thresholdTokens) {
		return modelInfo
	}

	const effectiveServiceTier = serviceTier ?? "default"
	if (pricing.appliesToServiceTiers && !pricing.appliesToServiceTiers.includes(effectiveServiceTier)) {
		return modelInfo
	}

	return {
		...modelInfo,
		inputPrice:
			modelInfo.inputPrice !== undefined && pricing.inputPriceMultiplier !== undefined
				? modelInfo.inputPrice * pricing.inputPriceMultiplier
				: modelInfo.inputPrice,
		outputPrice:
			modelInfo.outputPrice !== undefined && pricing.outputPriceMultiplier !== undefined
				? modelInfo.outputPrice * pricing.outputPriceMultiplier
				: modelInfo.outputPrice,
		cacheWritesPrice:
			modelInfo.cacheWritesPrice !== undefined && pricing.cacheWritesPriceMultiplier !== undefined
				? modelInfo.cacheWritesPrice * pricing.cacheWritesPriceMultiplier
				: modelInfo.cacheWritesPrice,
		cacheReadsPrice:
			modelInfo.cacheReadsPrice !== undefined && pricing.cacheReadsPriceMultiplier !== undefined
				? modelInfo.cacheReadsPrice * pricing.cacheReadsPriceMultiplier
				: modelInfo.cacheReadsPrice,
	}
}

function calculateApiCostInternal(
	modelInfo: ModelInfo,
	inputTokens: number,
	outputTokens: number,
	cacheCreationInputTokens: number,
	cacheReadInputTokens: number,
	totalInputTokens: number,
	totalOutputTokens: number,
): ApiCostResult {
	const cacheWritesCost = ((modelInfo.cacheWritesPrice || 0) / 1_000_000) * cacheCreationInputTokens
	const cacheReadsCost = ((modelInfo.cacheReadsPrice || 0) / 1_000_000) * cacheReadInputTokens
	const baseInputCost = ((modelInfo.inputPrice || 0) / 1_000_000) * inputTokens
	const outputCost = ((modelInfo.outputPrice || 0) / 1_000_000) * outputTokens
	const totalCost = cacheWritesCost + cacheReadsCost + baseInputCost + outputCost

	return {
		totalInputTokens,
		totalOutputTokens,
		totalCost,
	}
}

// For Anthropic compliant usage, the input tokens count does NOT include the
// cached tokens.
export function calculateApiCostAnthropic(
	modelInfo: ModelInfo,
	inputTokens: number,
	outputTokens: number,
	cacheCreationInputTokens?: number,
	cacheReadInputTokens?: number,
): ApiCostResult {
	const cacheCreation = cacheCreationInputTokens || 0
	const cacheRead = cacheReadInputTokens || 0

	// For Anthropic: inputTokens does NOT include cached tokens
	// Total input = base input + cache creation + cache reads
	const totalInputTokens = inputTokens + cacheCreation + cacheRead

	return calculateApiCostInternal(
		modelInfo,
		inputTokens,
		outputTokens,
		cacheCreation,
		cacheRead,
		totalInputTokens,
		outputTokens,
	)
}

/** Optional refinement for OpenAI-style usage (see {@link resolveOpenAiUsageForCost}). */
export type OpenAiCostOptions = {
	serviceTier?: ServiceTier
	/** When set, refines non-cached vs cache breakdown (prompt_tokens_details / input_tokens_details). */
	inputTokenDetails?: { cache_miss_tokens?: number; cached_tokens?: number }
}

function normalizeOpenAiCostOptions(
	sixth?: ServiceTier | OpenAiCostOptions,
): OpenAiCostOptions {
	if (sixth === undefined) {
		return {}
	}
	if (typeof sixth === "object" && sixth !== null) {
		return sixth as OpenAiCostOptions
	}
	return { serviceTier: sixth as ServiceTier }
}

// For OpenAI compliant usage, the input tokens count usually INCLUDES cached tokens;
// some responses only report non-cached totals — see resolveOpenAiUsageForCost.
export function calculateApiCostOpenAI(
	modelInfo: ModelInfo,
	inputTokens: number,
	outputTokens: number,
	cacheCreationInputTokens?: number,
	cacheReadInputTokens?: number,
	sixth?: ServiceTier | OpenAiCostOptions,
): ApiCostResult {
	const opt = normalizeOpenAiCostOptions(sixth)
	const resolved = resolveOpenAiUsageForCost({
		inputTokensReported: inputTokens,
		cacheWriteTokens: cacheCreationInputTokens || 0,
		cacheReadTokens: cacheReadInputTokens || 0,
		cacheMissTokensFromDetails: opt.inputTokenDetails?.cache_miss_tokens,
		cachedTokensFromDetails: opt.inputTokenDetails?.cached_tokens,
	})
	const effectiveModelInfo = applyLongContextPricing(modelInfo, resolved.totalInputTokens, opt.serviceTier)

	return calculateApiCostInternal(
		effectiveModelInfo,
		resolved.nonCachedInputTokens,
		outputTokens,
		resolved.cacheWriteTokens,
		resolved.cacheReadTokens,
		resolved.totalInputTokens,
		outputTokens,
	)
}

export const parseApiPrice = (price: any) => (price ? parseFloat(price) * 1_000_000 : undefined)

